var CH=[{"title": "AFIRANDIN", "quotes": [{"text": "Balindeyên qefesê di ewlehiyê de ne, lê Xwedê balinde ne ji bo qefesê afirandine.", "author": "Paulo Coelho"}, {"text": "Xwedê te azad afirandiye. Wekî ku tu hatiye afirandin azad bimîne. Azad ew e ku aqilê xwe, fikrê xwe, helwesta xwe û welatê xwe nafiroşe.", "author": "Omar Mokhtar"}, {"text": "Eger wêrekîya çêkirina tiştên nûjen bi me re tunebûya, dê jiyana me çawa bûya?", "author": "Van Gogh"}, {"text": "Du Xweda hene.Yek, yê ku em afirandine.Didu, yê ku me ew afirandiye.", "author": "PK (fîlm)"}, {"text": "Xwedê em di sûretê xwe de neafirandine. Me ew di sûretê xwe de afirandiye.", "author": "Spinoza"}, {"text": "Yekemîn tiştê ku Xwedê ew afirandiye, aqil e.", "author": "Suhrewerdî"}]}, {"title": "AJAL", "quotes": [{"text": "Beşek ji giyanê mirovî şîyar nabe,heta ji ajalan hez neke.", "author": "Anatole France"}, {"text": "Heger ga û berazan bikariba biaxivin,dê henekên xwe bi wan kesên ku ji xeynî êm û alîf xeber didin, bikira.", "author": "Epiktetos"}, {"text": "Ramîn, dijraberîya xwezayê ye.(Ramîn ne xwezayî ye) mirovê xwedîfikr ajalekî ji rê derketî ye.", "author": "JeanJacques Rousseau"}, {"text": "Ajalek qet nikare mîna mirovekî bibe stemkar; tenê mirov dikarin stemkariyeke bi hostetî û hûnerî pêk bînin.", "author": "Fyodor Dostoevsky"}, {"text": "Çiqas mirovan nas dikim,hezkirina min bo ajalan zêdetir dibe.", "author": "Schopenhauer"}]}, {"title": "AMADEHÎ", "quotes": [{"text": "Beriya tu tî bibî, bîrê bikole.", "author": "Gotina Çîniyan"}, {"text": "Ger ji bo birrîna darekêşeş demjimêran bidin min,ez ê çar demjimêranji bo tûjkirina bivir veqetînim.", "author": "Abraham Lincoln"}, {"text": "Tu ji bo çi amade bî,ew ji bo te amade ye.", "author": "Mark Victor Hansen"}, {"text": "Kî dikare te bextewer bike,ger tu ne amade bî?", "author": "Nietzsche"}, {"text": "Eger tu ji rûbirûbûnagûran re ne amade bî,noqî daristanê nebe.", "author": "Alexandra Udinov"}, {"text": "Heger tu ji rîskeke nepenî rene amade bî,“jirêzêbûna” xwe razî be.", "author": "Jim Rohn"}]}, {"title": "AMÛR Û ALAV", "quotes": [{"text": "Tu dikarî bi werîsekîxwe bixeniqînî jîû tu dikarî bi heman werîsîhêlekanê jî çêbikî.Bendikên jiyanêdi destê te de ne.", "author": "Fyodor Dostoevsky"}, {"text": "Kesê ji bilî çakûç tiştekî dindi destê wî de tune be,her tiştî mîna bizmaran dibîne.", "author": "Harold Maslow"}, {"text": "Karkerê xirab,bi amûr û alavan re şer dike.", "author": "Gotina Romanan"}]}, {"title": "ANARŞÎ", "quotes": [{"text": "Kesê gulî û çiqlîyê te bişkêne, tu dara wî ji erq rake. Ev ne psîkopatî ye.", "author": "Donnie Brasco"}, {"text": "Anarşî, rizgarîya ji efendî û serweran e.", "author": "Joseph Proudhon"}, {"text": "Anarşiya ku civakeke pespaye tehdît dike, ne siza ye, dewa ye.", "author": "Goméz Dávila"}, {"text": "Mirov bûne du beş:Hinek ji ber birçîbûnê ranazên,hinek jî ji tirsa wan birçîyan ranazên.", "author": "Paulo Freire"}, {"text": "Eger hêza we ji bo şewitandina sindoqan tune be,wateya boykot kirinê tune ye.", "author": "Lenin"}]}, {"title": "AQIL - FIKR Û RAMAN", "quotes": [{"text": "-çima niha qet tiştekî nakî?\n-dikim.\n-çi dikî?\n-difikirim.", "author": "Fyodor Dostoevsky"}, {"text": "Fikr û ramanekî ku dema wî hatibe, jê hêzdartir tiştek tune ye.", "author": "Victor Hugo"}, {"text": "Per û baskên fikr û ramanan hene. Kes nikare wan ji bo gihîştina mirovan asteng bike.", "author": "Îbn Ruşd"}, {"text": "Ti artêş bi qasî fikrekî ku dema wî hatibe, ne hêzdar e.", "author": "Victor Hugo"}, {"text": "Aqilê xwe bo hemî karên xwe bike serwer; çimkî tevizandina aqil cureyekî mirinê ye.", "author": "Hipokrates"}, {"text": "Çima ez fikrên xwe diguherînim? Çimkî ez xwediyê fikrên xwe me; ne xûlamê wan.", "author": "Cenab Şahabettin"}]}, {"title": "AQILMENDÎ", "quotes": [{"text": "Kesê bi aqil, aqilê xwe bi kar tîne. Kesê biaqiltir, aqilê kesên din jî bi kar tîne.", "author": "Bernard Shaw"}, {"text": "Ji bo serkeftinê,aqilê rovî ji neynûkên şêr bikêrhatîtir e.", "author": "Gotina Swêdiyan"}, {"text": "Ji xeynî aqil, ti îmam (pêşeng) tune ye.", "author": "Ebû Ala el-Maarrî"}, {"text": "Zîrek, pirsgirêkan çareser dike. Aqilmend, pirsgirêkan asteng dike.", "author": "Einstein"}, {"text": "Aqilê rovî ji nehperoşkên şêr bikêrhatîtir e.", "author": "Gotina Swêdiyan"}, {"text": "Dema mirov ne hêzdar be, divê biaqil be.", "author": "Emile Zola"}]}, {"title": "ARAMÎ", "quotes": [{"text": "Dilxweşiya tu li bendê yî, ji ya ku te tehm kiriye xweştir e.", "author": "Andre Maurois"}, {"text": "Kesê dikare ji bîr bike, dikare aram bibe.", "author": "Nietzsche"}, {"text": "Kesê xwediyê azadiyê,pirtûkan, kulilkan, rojê û hîvê be,dê çawa bibe bextreş?", "author": "Oscar Wilde"}, {"text": "Rêya ku ber bi aramiyê diçe, bi kelem û xeyal şikestinan hatiye raxistin.", "author": "Mark Manson"}, {"text": "Aramiya bêqisur tune ye,binêre li ser rojê jî leke heye.", "author": "Confucius"}, {"text": "Ha mîr ha gede, mirovê herî bextewar ew e ku di mala wî de hizûr heye.", "author": "Goethe"}]}, {"title": "ARMANC", "quotes": [{"text": "Tenê mirovê ku bê hedef dijî, tehma têkçûnê nahilîne.", "author": "Nietzsche"}, {"text": "Eger hûn bixwazin jiyaneke aram bijîn, jiyana xwe bi armancekê ve girê bidin, ne bi kes ûtiştan ve.", "author": "Einstein"}, {"text": "Keştiyeke ku li benderê ye di ewlehîyê de ye. Lê keştî ne ji bo li benderê rawestin têne çêkirin.", "author": "Jack Canfield"}, {"text": "Wêrekî ew e ku, tu bi hindiktirîn zerarê bigihîjî amanca xwe.", "author": "Socrates"}, {"text": "Mirovê ku ji bilî bextewariya wî tu armanceke wî tune be, ew mirovekî neqenc e.", "author": "Tolstoy"}, {"text": "Eger hûn ne ji bo armancekêli ser pîyan bin,her derbek dikarewe bavêje erdê.", "author": "Malcolm X"}]}, {"title": "ASÎMÎLASYON", "quotes": [{"text": "Asîmîlasyon:kesê bi vê nexweşiyê dikeve,kokên xwe,taybetmendîyen xwe yên neteweyîû karakterê xwe yê çandî jibîr dike. Heger ev tişt bên bîra wî jî,li dijî wan nefreteke mezin hîs dike.", "author": "Elî Şerîetî"}, {"text": "Gelên têkçûyî,sazî û dezgeyên têkbiran teqlîd dikin.", "author": "Îbn Xeldûn"}, {"text": "Nûsîna bi kurdî, li hember hemû bêqîmetkirinan qaqiboyek e, berûpaşkirina asîmîlasyonekê ye, zindikirina ruhekî vemirî ye...", "author": "Remezan Alan"}]}, {"title": "AVAKIRIN", "quotes": [{"text": "Destpêka her avakirinê,xirabkirine.", "author": "Rollo May"}, {"text": "Xerakirin, ji avakirinê hêsantir e.", "author": "Suzanne Collins"}, {"text": "Ku dîwarên te ji hundir ve rizîbin,wan ji binî hilweşîne û ji nû ve lê bike.", "author": "Madeline Miller"}, {"text": "Carinan ji bo hin tişt têkevin rêya xwe, divê her tişt ji rê derkeve.", "author": "Eliot"}]}, {"title": "AXAFTINA ZÊDE", "quotes": [{"text": "Kesê ji bîst xulekan zêdetir biaxive, di guhdarvanan de hesta kuştinê peyde dike.", "author": "Fyodor Dostoevsky"}, {"text": "Kesê dirêj bipeyive, kin lê guhdarî bike.", "author": "Farabî"}, {"text": "Nîqaşeke dirêj danîşana neheqiya herdû alîyan e.", "author": "Voltaire"}, {"text": "Raweste, bihishise... Her tim biaxivî, tu tiştekî seh nakî.", "author": "Gotina Çermsoran"}, {"text": "Kêmgotin ji zêdegotinê çêtir e.", "author": "Anton Chekhov"}, {"text": "Kêm kes guhdarvanên baş in.", "author": "Michael Ende"}]}, {"title": "AZADIYA FIKR Û RAMAN", "quotes": [{"text": "Tevlî fikrên te nabim, lê ji bo tu fikrên xwe serbest îfade bikî, dikarim canê xwe bidim.", "author": "Evelyn Beatrice Hall"}, {"text": "Xwedê sê nîmet kirine para me,azadiya ramanê, azadiya beyankirina hizrên cûda û azadiyako em yekê ji wan jî pêkneînin!", "author": "Mark Twain"}, {"text": "Ji bo em nikarin rasterast ji mirovan re bêjin “tu tam kerekî çolê yî” em dibêjin; “belê ew jî nêrîna te ye.”", "author": "George Carlin"}]}, {"title": "AZADÎ", "quotes": [{"text": "Balindeyek ji bo ku çêlikên wê hînî dîlbûnê nebin, di qefesê de hêlînê çêneke.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Azadî ew her pênc xulekên ewil bûn,ku ez hatibûm dinê...Digiriyam, tazî bûm,bêgûneh bûm, bê qible bûmû nefreta mirovandi dilê min de tune bû.", "author": "Gorki"}, {"text": "Kesê azadiya xwe winda dike, mirovbûna xwe jî winda dike.", "author": "La Boètie"}, {"text": "Azadî ji nan xweştir, ji rojê xweşiktir e.", "author": "Fyodor Dostoevsky"}, {"text": "Ez dikarim bê nan bijîm, lê ez nikarim bê azadî bijîm.", "author": "Seîdê Kurdî"}, {"text": "Ne zewq, ne navdarî, ne hikimdarî. Azad î, tenê azadî.", "author": "Fernando Pessoa"}]}, {"title": "AZWERÎ Û ÇAVBIRÇÎTÎ", "quotes": [{"text": "Mirovên vê serdemêji bo ku ne xwedîyêhemî dinyayê ne dikesirin.", "author": "Camus"}, {"text": "Kesê bide dûv çend kîvroşkan,yekê jî bi dest naxe.", "author": "Fyodor Dostoevsky"}, {"text": "Çavê mirov dişibe çavkaniyê;heta bi ax û xwelîyê tije nebe,têr nabe.", "author": "Gotina Asûriyan"}, {"text": "Dinya têra pêdiviyênmirovan gişkan dike,lê têra hêrs û azweriyênwan nake.", "author": "Mahatma Gandhi"}, {"text": "Ku mijar dibe çavbirçîtî,di navbera gundî û esilzade deferq namîne.", "author": "Max Weber"}, {"text": "Çavbirçîtî,encama valahîyeke hundirîn e.", "author": "Erich Fromm"}]}, {"title": "BÊAQILÎ – DÎNÎTÎ", "quotes": [{"text": "Yan hin tişt hene ku dibin sedema winda kirina aqilê we, yan jî aqilekî we yê ku winda bibe, tuneye.", "author": "Victor Frankl"}, {"text": "Yên ku ol çêkirine, dewlet rûxandine, girse rakirine raperînê û mirov sewq û îdare kirine, hemû kesên dîn in. Heger li cîhanê di şuna dînîtiyê de aqil hikûmran bibûya, dê dîrok bi awayekî din bihata nivîsandin.", "author": "Gustave Le Bon"}, {"text": "Vêga hemî mirovên rast û durist şêt bûne. Tenê fîke fîka kesên weset û bêkêr e.", "author": "Dostoyevski"}, {"text": "Ev demeke dirêj e ku dinya bûye timarxane.", "author": "Nietzsche"}, {"text": "Dînitî, protestoya mirovên hestiyar e.", "author": "Victor Hugo"}, {"text": "Dînbûn, li hemberî raserîya aqil rêzgirtin e.", "author": "Sigmund Freud"}]}, {"title": "BÊDENGÎ", "quotes": [{"text": "Du tişt nîşandariya aqilê sivik in: Bêdengiya di ciyê axaftinê de û axaftina di ciyê bêdengiyê de.", "author": "Sadî Şîrazî"}, {"text": "Kesê bêdengiya te fêhm neke, ji axaftina te qet fêhm nake.", "author": "Albert Hobart"}, {"text": "An bêdeng bimîne, an gotineke ji bêdengîyê biqîmettir bêje.", "author": "Pisagor"}, {"text": "Heybet û gewretîya bêdengîyê, nefiroşe bi gotineke ji rêzê.", "author": "Suhrewerdî"}, {"text": "Beriya tu biaxivî, bifikire: gelo pêdivî bi axaftina te heye? Ew axaftin dilovaniyê di xwe de dihewîne? Ew axaftin dê kesekî biêşîne û bi qasî ku bêdengiyê xira bike, bi qedr e?", "author": "Lao Tzu"}, {"text": "Mirov bi bêdengiyê jî dikare tiştekî bibêje.", "author": "Umberto Eco"}]}, {"title": "BÊKÊRÎ", "quotes": [{"text": "Ev serdem, bo mirovên ji rêzê re serdemeke rewnaq e. Lewra ev serdema nifşekî bêhest, nezan, tenbel, bêkêr û bêked e.", "author": "Fyodor Dostoevsky"}, {"text": "Zana, dike. Kêmzan, şîretan dike. Nezan, rexne dike. Bêkêr, kurtepistê dike.", "author": "Confucius"}, {"text": "Ker beşdarî pêşbirka hespan nabe, lê her tim tinazê xwe bi hespê têkçûyî dike.", "author": "Gotina Yewnanan"}, {"text": "Dema tu dênê xwe didî mirovan,tu dibînî zimanê bêkêran ji yê her kesî dirêjtir e.", "author": "Cahiz"}]}, {"title": "BÊMINETÎ", "quotes": [{"text": "Ji niha û şûn de ez bûm wek kişikê: min birc firot, fîlan serî hilda, wezîr xwe kuşt, min hesp jî berdan. Û min ji pîyonên derdora xwe jî ti hêvîyek nekir. Niha ên kû xwe şah dihesibînin, bila derkevin pêşberî min.", "author": "Oscar Wilde"}, {"text": "Ji malê belaş bihatir tiştek nîne.", "author": "Gotina Japonan"}, {"text": "Derheqê min de çi bifikirî, bi kêfa xwe yî. Ez ne ji bo razîkirina te hatime vê dinyayê.", "author": "Milan Kundera"}, {"text": "Dema zerera min negihaştibe kesekî, heskirin an heznekirina mirovan bo min ne grîng e. Ez ne ji bo kêfxweşkirina hemî mirovan hatime vê dinê.", "author": "Woody Allen"}, {"text": "Eger tu tenê alîyê min ê xirab dibînî, dibe ku ez her timî tiştên layîqê te nîşanî te didim.", "author": "Will Smith"}, {"text": "Tu bixwazî hêzdar bî, hêviya hezkirinê ji kesekî neke.", "author": "Tolstoy"}]}, {"title": "BERDÊL", "quotes": [{"text": "Tiştek, ji tiştê ku belaş didin tene bihatir e.", "author": "Gotina Japonan"}, {"text": "Talibê heqîqetê, divê her berdêlê bide ber çavên xwe.", "author": "Arthur Schopenhauer"}, {"text": "Çi zû, çi dereng... Her kesek berdêla kiryarên xwe dide.", "author": "Oscar Wilde"}, {"text": "Jîyan dersa belaş nade tu kesî. Dema tu dibêjî “jîyanê fêrî min kir,” teqez te berdêlek daye!", "author": "Necîb Mehfûz"}, {"text": "Heta aştî bi xwe jî,bi berdêlên mezin tê kirîn.", "author": "Voltaire"}, {"text": "Heya tu tiştekî nedî, hêviya tiştekî neke.", "author": "Gotina Portugaliyan"}]}, {"title": "BÊRÎ KIRIN", "quotes": [{"text": "Bêrîkirin derdekî bêderman e,di çaya tu vedixwî de,di strana tu dibêjî de tê bîra te.", "author": "Khalid Hosseini"}, {"text": "Bêrîkirina herî dijwar ew e ku,tu bêriya ‘xwebûna xwe ya berê’ dikî.Kenê berê, dilê berê...", "author": "Samuel Butler"}, {"text": "Çima weke me bêrî nakin?Qey li welatên wan şev tune ye?", "author": "Mehmûd Derwîş"}, {"text": "Bêrîkirinên me yên ku di bin pêlên şerûd û şemûz de dixeniqin, li hêviya rojên zelal in.", "author": "Suzan Samancî"}, {"text": "Carinan tu bêriya kesekî dikî; eger ew kes bi xwe bihise, dê ji nehazirbûna xwe ya li wê derê şerm bike.", "author": "Azîz Nesîn"}]}, {"title": "BERJEWENDÎ", "quotes": [{"text": "Jibîr neke, dema berjewendiyên mirovan diguherin, nêrîn û tevgerên wan jî zûzûka diguherin.", "author": "Arthur Schopenhauer"}, {"text": "Ew barana kuderyavan lanetê lê tîninû cotyar bo wê nimêj dikin;heman baran e.", "author": "Gotina Efrîqiyan"}, {"text": "Mirov ji bo firotinê ziman hîn dibe.Lê dema dikire, her kes wî fêhm dike.", "author": "Gabriel Garcia Marquez"}, {"text": "Mirovên birûmet ji bo edaletê,Mirovên nemerd ji bo menfeetê têdikoşin.", "author": "Confucius"}, {"text": "Dema mirov herî zêde ji te hez dikin,ew dem e ku herî zêde tu bi kêrî wan tê.", "author": "Charles Bukowskî"}, {"text": "Mirov, ji xwe pêve li berjewendiyên ti aferîdî miqate nabe.", "author": "George Orwell"}]}, {"title": "BERPIRSIYARÎ", "quotes": [{"text": "Dizanim xwedê barekî ku ez nikaribim hilbigirim li min nake, lê dîsa jî dibêjim, xwezî ewqasî baweriya xwe bi min neanîba.", "author": "Fyodor Dostoevsky"}, {"text": "Pir ê mirov azadiyê naxwazin. Ji ber ku azadî berpirsiyarî ye, pir ê mirovan ji berpirsiyariyê ditirsin.", "author": "Sigmund Freud"}, {"text": "Berpirsiyara rewşenbîran, acizkirina desthilatdarîyên har e.", "author": "Sartre"}, {"text": "Rewşenbîr ji gotina heqîqetê û eşkere kirina derewan berpirsiyar in.", "author": "Naom Chomsky"}, {"text": "Heger bixwazî piyên zarokê te li ser erdê baş rawestin, hinek berpirsiyarên giran li ser milên wan bar bike.", "author": "Pauline Phillips"}, {"text": "Pêkanîna qenciyê ne berpirsiyarî ye, bezm û şahî ye.", "author": "Zerdeşt"}]}, {"title": "BÊXEMÎ – XEMSARÎ", "quotes": [{"text": "Ma mirov e, ew kesê jiyana wî tenê bi xwarin-vexwarin û razanê derbas dibe?", "author": "Shakespeare"}, {"text": "Wekî haya kesekî ji te tune ye dans bike, wekî ku qet dilê te neşikestiye hez bike, wekî ku dengê te naçe tu kesî stranan bibêje, wekî ku dinya bihişt be bijî.", "author": "Mark Twain"}, {"text": "Di nezera min de her tişt bûye wek hev. Êdî tiştek ne xema min e. Gelo ji vê rewşê xirabtir tiştek heye?", "author": "Tolstoy"}, {"text": "Tabûta li ser milê kesên din, sivik xûya dike.", "author": "Gotina Ukrainan"}, {"text": "Kes giraniya barê ser milê kesê din nizane.", "author": "George Herbert"}, {"text": "Em li welatekî wisa dijîn ku, tu tişt ne xema kesî ye.", "author": "Ernest Hemingway"}]}, {"title": "BIHÛŞT Û DOJEH", "quotes": [{"text": "Hin kes ji bo biçin beheştê, radibin kesên din dikujin. Ji vê dojehê dojehtir çi heye?", "author": "Adonis"}, {"text": "Her ûtopya, senaryoya bihûştekê an jî dojehekê ye.", "author": "Thomas Hobbes"}, {"text": "Pirrê mirovan li dinyayê di dojehê de dijîn. Ji ber ku gelekî zêde girîngîyê didin nêrîna mirovan.", "author": "Sartre"}, {"text": "Ez her tim bihûştê di şiklê pirtûkxaneyekê de xeyal dikim.", "author": "Borges"}, {"text": "Her ûtopya, senaryoya bihûştekê an jî dojehekê ye.", "author": "Thomas Hobbes"}, {"text": "Bihûşt jî dojeh jî di hundirê me de ye.", "author": "Oscar Wilde"}]}, {"title": "BIRYAR Û BİJARTIN", "quotes": [{"text": "Berî tu biçî, baş bifikire. Ji ber ku dema tu vegeriyayî tiştê tu bibînî û dema tu çûyî tiştê te li pey xwe hiştibû dê ne heman tişt be.", "author": "Aragon"}, {"text": "Biryarên baş ji pisporiyê tên, lê pisporî bi biryarên xirab çêdibe.", "author": "Mark Twain"}, {"text": "Devjêberdana cixarê tiştê herî hêsan e. Heya niha min pêncî carî dev jê berda ye.", "author": "Mark Twain"}, {"text": "Eger tu nizanibî bê tu çi dixwazî, tu yê bibînî ku vaye gelek tiştên ku te nedixwestin, rû dane.", "author": "Chuck Palahniuk"}, {"text": "Kesê berî gav avêtinê zêde difikire, jîyana xwe li ser pîyekî derbas dike.", "author": "Gotina Çîniyan"}, {"text": "Mezintirîn dizên demê, bêbiryarî û dudilî ne.", "author": "Charles Flory"}]}, {"title": "BIXWEBAWERÎ", "quotes": [{"text": "Çi mirovên serkeftî ku ez tûşî wan hatime, ji min re wiha gotine: “kengî min bi xwe bawer kir, jîyana min hingê destpê kir.”", "author": "Tony Robbins"}, {"text": "Ku keştiya te mezin be, firtoneye te jî mezin dibe.", "author": "Saramago"}, {"text": "Eger baweriya te bi rêya ku pê de diçî temam be, astengên ku derkevin pêşberî te, tenê ji bo te cihê bêhnvedanê ne.", "author": "Paulo Coelho"}, {"text": "Heft caran bikeve, heşt caran rabe.", "author": "Gotina Japonan"}, {"text": "Ko tu bitirsî, dest pê neke, ko te dest pê kir, netirse.", "author": "Gotina Portugaliyan"}, {"text": "Em bi ser neketin, ji ber ku me ji xwe re got, em ê bi ser nekevin.", "author": "Tolstoy"}]}, {"title": "BÎR – BINBÎR", "quotes": [{"text": "Nexwazî li kuderê binêrî, hişê te li wir e.", "author": "Sigmund Freud"}, {"text": "Ax bîr! dijmina sereke ya aramiya min.", "author": "Cervantes"}, {"text": "Tu kêrek î, ez jî bê navber hundirê xwe bi wê kêrê diqewêrim.", "author": "Kafka"}, {"text": "Mirov ji çi bireve,di reva xwe de rastî wî tiştî tê.", "author": "Elîyê kurê Ebûtalib"}, {"text": "Tiştek zû bi zû ji hîşê min dernayê, trajediya min jî ev e.", "author": "Isaac B. Singer"}, {"text": "Ji xeynî serpêhatiyên em dixwazin ji bîr bikin, tiştek di hişê me de namîne.", "author": "Fyodor Dostoevsky"}]}, {"title": "BÎRANÎN", "quotes": [{"text": "Nehêle sê tişt bibin serwerê jiyana te: mal, mirov û bîranînên xirab.", "author": "Shakespeare"}, {"text": "Bîranîn wekî zêrên di tûrikê şeytên de ne; dema tu devê turîk vedikî, dibînî ku ne zêr, lê pelên mirî têde ne...", "author": "JeanPaul Sartre"}, {"text": "Tirsa ji mirinê, can dide serpêhatiyan.", "author": "Umberto Eco"}, {"text": "Min dixwest êdî serboriyên rasteqîn bijîm. Lê difikirîm ku serboriyên rasteqîn nayên serê kesên li malê rûniştî...", "author": "James Joyce"}, {"text": "Ji xeynî tiştên em dixwazin ji bîr bikin, tiştek namîne di bîra me de.", "author": "Fyodor Dostoevsky"}, {"text": "Ne ku dilê me reş bûye, lê em naxwazin wan ruyên ku roja me kembax û xopan dikin, bibînin.", "author": "Necîb Mehfûz"}]}, {"title": "BÎRKARÎ", "quotes": [{"text": "Huner tune ye,her tişt matematîk e.", "author": "Antoni Gaudi"}, {"text": "Bîrkarî ew ziman e ku,Xwedê gerdûn pê ava kiriye.", "author": "Galileo"}]}, {"title": "CEHALET", "quotes": [{"text": "Kesên biaqil ji herkesî hîn dibin. Kesên ji rêzê ji serboriyên xwe hîn dibin. Kesên cahil jî, jixwe her tiştî dizanin.", "author": "Socrates"}, {"text": "Cehalet tirsê, tirs nefretê, nefret tundiyê encam dide. Ev hevsengî ye.", "author": "Îbn Ruşd"}, {"text": "-Te dixwest ji gelê xwe re çi bikî?\n-Min dixwest ji nezaniyê xelas bibin.", "author": "Hemingway"}, {"text": "Gewretirîn girtîgeha ser rûyê erdê, hundirê qahfê kesên cahil e.", "author": "Montaigne"}, {"text": "Tu jîyaneke rehet dixwazî? Nêzîkî kerîyekî bibe û xwe ji bîr bike.", "author": "Nietzsche"}, {"text": "Kesê naxwaze bixwîne, ji yê nizane bixwîne ne çêtir e.", "author": "Mark Twain"}]}, {"title": "CERIBANDIN - METOD", "quotes": [{"text": "Sîr xistiye pozê xwe, li bêhna gulê digere!", "author": "Celaleddîn Rûmî"}, {"text": "Kesê qet çewtiyek nekiriye, qet tiştekî nûjen neceribandiye.", "author": "Einstein"}, {"text": "Deriyê girtî tune ye, kilîta şaş heye.", "author": "Celaleddîn Rûmî"}, {"text": "Ji bo destpêkirinê ne hewce ye tu nûwaze bî, lê ji bo tu bibî nûwaze, divê tu dest pê bikî.", "author": "Zig Ziglar"}, {"text": "Min hemî pergal mîna şepqeyên nebikêrhatî bi dîwêr ve kirin. Hebek jî ne li gorî min bû.", "author": "William Golding"}, {"text": "Em dilxweşî û kovanên xwe, berîya ceribandinê hildibijêrin.", "author": "Cîbran Xelîl Cîbran"}]}, {"title": "CIHÛ(YEHUDÎ)", "quotes": [{"text": "Cihûyên ku li Almanyayê di serdema Hîtler de bê têkoşîn li benda tunekirina xwe disekinîn, dema hatin Fîlîstînê bi wêrekî şer kirin. Ev tiştekî ecêb e.", "author": "Eric Hoffer"}, {"text": "Nifûsa Cihûyan li ser rûyê dinyayê ji hezarî didu ye, lê ji sedî bîst xelatên Nobelê bi dest xistine.", "author": "Yuval Noah Harari"}, {"text": "Filîstîn goristana pêxemberên benî Îsraîl e û pêxemberên kevin jî ji qewmê Îsraîl in. Doza yehudiyan hem netewî ye hem jî dînî ye. Ji ber wilo zû bi zû kes nikare zora wan bibe.", "author": "Seîdê Kurdî"}, {"text": "Ji hêla disîplînên mîna helbest, gramer, bawerî, felsefe, tib, astronomî, tesewûf û tefsîrê ve cudahiyeke mezin di navbera çanda Îslamiyetê û yahûdîtiyê de tune ye.", "author": "Hesen Henefi"}, {"text": "Dakeve jêr ey Mûsa,Here welatê Misrê,Bêje wî Fîrewnê gewre,\nBila qewmê min azad bihêle.", "author": "William Faulkner"}]}, {"title": "CIVAK", "quotes": [{"text": "Civakek ji rastiyê çiqas dûr bikeve,ji rastbêjan ewqas nefret dike.", "author": "George Orwell"}, {"text": "Ku di civakekê de pizîşk û dadnas biqedr bibin, ew civak çilvirî ye. Nexweşî û bêdadî di wê civakê de zêde bûne.", "author": "Socrates"}, {"text": "Civaka ji jinê ditirse, nexweş e.Jina ji azadiyê ditirse, mirî ye.", "author": "Nawal El Saadawi"}, {"text": "Hema bêje hemî tiştên ku ji aliyê civakê ve “rast” tên dîtin, “şaş” in. Kapasîteya hizirîna civakê kêm e, hêza muhakemeya wê, hê kêmtir e.", "author": "Schopenhauer"}, {"text": "Kuçik çawa ji guran nefret dikin, ha wilo civak ji giyanên azad nefret dike.", "author": "Nietzsche"}, {"text": "Qerebalix bi kîjan rexî ve here,tu berê xwe bide rexê din.Ji ber ku qerebalixher tim li ser şaşiyê ye.", "author": "Charles Bukowskî"}]}, {"title": "COMERDÎ", "quotes": [{"text": "Kesek bi dayînê feqîr nabe.", "author": "Anne Frank"}, {"text": "Comerdî dayîna bêbergîdan e. Kesê ji bo pesn û qezenckirina xêrê bide, ev ne comerdî ye, danûstandin e.", "author": "Suhrewerdî"}, {"text": "Dayîn ji stendinê bixêrtir e.", "author": "Încîl"}]}, {"title": "CUDAHÎ - RESENÎ", "quotes": [{"text": "Mirovê ji rêzê, berhemeke fabrîkasyon a xwezayê ye. Û xweza, her roj bi hezaran kesên wisa diafirîne.", "author": "Schopenhauer"}, {"text": "Hûn wek kesayetekî bêhempa hatine dinê. Wekî “teqlîdek” nemirin.", "author": "John Mason"}, {"text": "Bi şopandina rêçika kesekî din, tu yê qet nebî yekemîn.", "author": "Gotina Swêdiyan"}, {"text": "Ew mirovê ku herî zêde li xweşa me diçe, ew kese ku me şibandiye xwe.", "author": "Moliere"}, {"text": "Dixwazin te kategorîze bikin. Dixwazin li gor şablona di mêjiyê xwe de, te li deverekê bicih bikin. Û ger tu li gorî wan dernekevî, pir aciz dibin.", "author": "William Burroughs"}, {"text": "Ez naxwazim tu wekî min bifikirî.Tenê dixwazim tu bifikirî.", "author": "Elî Şerîetî"}]}, {"title": "ÇAND", "quotes": [{"text": "Piştî te her tişt ji bîr kir,tiştê mayî “çand” e.Ji ber ku tiştên mayî hêmanênsereke yên çandê ne,yên jibîrbûyî jî yên guhêrbar in.Aqilê Netewî jî ew e.", "author": "Cabîrî"}, {"text": "Civakek çiqas di nav mîstîsîzmû eklektîzmê de bimîne,ji hêla çandî veewqasî li paş dikeve.", "author": "Murray Bookchin"}, {"text": "Neteweyên ku ji hêla zimên ve serkeftin bidest nexistibin, ji hêla çandî ve jî li paş dimînin. Çanda gelên ziman lawaz, tiroviro ye.", "author": "Humboldt"}, {"text": "Destana Ferhad û Şîrîn di çand û folklora kurdî de cihekî xwe yê taybet heye. Nemaze di nav kurdên Kirmanşahê de.", "author": "Henry Rawlinson"}, {"text": "Axaftina bi zimanekî,hilgirtina giranîya çandekê ye.", "author": "MerleauPonty"}, {"text": "Çand di xizmeta olê de ye,ol jî di xizmeta sîyasetê de ye.", "author": "Terry Eagleton"}]}, {"title": "ÇAPEMENÎ", "quotes": [{"text": "Çapemenî di bin kontrola kî de be, mejîyan jî ew kontrol dikin.", "author": "Jim Morrison"}, {"text": "Dema desthilatdar bi ser serê gel de dimîzin, çapemenî derdikeve û dibêje baran tê.", "author": "Anonîm"}, {"text": "Êdî tenê amûrên ragihandinê hene, ragihandin tuneye.", "author": "Jean-Luc Godard"}, {"text": "Mişk li kolanan,mirov jî di malên xwe de dimirin.Û rojname tenê bi kolanan vemijûl dibin.", "author": "Albert Camus"}, {"text": "Berê amûr û alavên îşkenceyê hebûn,lê niha êdî rojnameyan ciyê wan girtiye.", "author": "Oscar Wilde"}]}, {"title": "ÇARENÛS - QEDER", "quotes": [{"text": "Mirov planan çêdikin, Xwedê dikene.", "author": "Gotina Cihûyan"}, {"text": "Ji te hez dikim. Ji ber ku hemî gerdunê bo hevgihîştina min û te hevkarî kiriye.", "author": "Paulo Coelho"}, {"text": "Ger tu tiştekî bi dil û can bixwazî, ji bo pêkanîna wî tiştî, hemî gerdûn hevkariyê dike.", "author": "Paulo Coelho"}, {"text": "Bê vîna xwe heme, bê vîna xwe dimirim.", "author": "Fernando Pessoa"}, {"text": "Hûn bixwazin siberoja xwe bi xwe binivîsin, pênûsê nedin destê kesên din.", "author": "Puşkin"}, {"text": "Bêyî ku bi min bişêwirin, derbarê çarenûsa min de biryar didan.", "author": "Albert Camus"}]}, {"title": "ÇARESERÎ Û BÊÇARETÎ", "quotes": [{"text": "Her çareseriyek pirsgirêkeke nû encam dide.", "author": "Gotina Ingilîzan"}, {"text": "Hincet wekî mû ye, bi herkesî re heye. Çareserî wekî aqil e, bi kêm kesan re peyde dibe.", "author": "Lao Tzu"}, {"text": "Di jiyanê de zehmettirîn tişt ew e ku; tu mecbûr dimînî xwe bi xwe teselî dikî.", "author": "Shakespeare"}, {"text": "We dît girêk venabe,hûn jî ben bibirrin.", "author": "Frida Kahlo"}, {"text": "Ji dêvla hûn ji bo xeyd û enirînê li hincetan bigerin, ji bo hezkirin û jêhezkirinê li çareyan bigerin.", "author": "Celaleddîn Rûmî"}, {"text": "Dema tu xwe li nezaniyê deynî, nîvê pirsgirêkên jîyana te çareser dibin.", "author": "Necîb Mehfûz"}]}, {"title": "ÇÎN", "quotes": [{"text": "Çîna serdest qencî û xerabiya diyar dike.", "author": "Karl Marx"}, {"text": "Çîna serdest ji pereyan re, çîna navîn ji serokan re, çîna bindest jî ji xwedawendan re perestîyê dike.", "author": "Einstein"}, {"text": "Ol, êdî ne amûreke ku çîna bindest ber bi azadiyê ve bibe; belkî di destê çîna serdest de bûye amûra bendîkirin û koletiyê.", "author": "Alî Şerîetî"}, {"text": "Ji dêvla ez bibim qeşmerê sifreya qral, ez ê bibim eşqîyayê şerê gel.", "author": "Yilmaz Guney"}, {"text": "Bênamûsan têr û sertêra xwe dixwarin û cilên biha li xwe dikirin, kesên dirist bi bermayîyên wan debara xwe dikirin.", "author": "Anton Chekhov"}, {"text": "Pasîfbûna we,we dike alîgirê çîna serdest.", "author": "Frantz Fanon"}]}, {"title": "ÇÎROK", "quotes": [{"text": "Keç û lawên ademîji çîrokan hez dikin.", "author": "Hesenê Metê"}, {"text": "Jîyan çîrok e.Dema tu ji kesekî hez dikî,tu ji çîroka wî hez dikî.", "author": "Heidegger"}, {"text": "Hûn bixwazin zarokên we şareza bibin,ji wan re çîrok û çîrvanokan bixwînin.Ku hûn bixwazin ew şarezatir bibin, ji wan re bêhtir çîrok û çîrvanokan bixwînin.", "author": "Albert Einstein"}, {"text": "Tu gurekî di çîroka pezekî deû pezekî, di çîroka gurekî de.", "author": "Gotina Ereban"}, {"text": "Kenê xwe bi çîroka kesî meke.Rê dirêj e û hê ya te jî bi dawî nebûye.", "author": "José Mauro de Vasconcelos"}, {"text": "Êşa herî giran,ew çîrok e ku hûndi hundirê xwe de vedişêrin.", "author": "Maya Angelou"}]}, {"title": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT", "quotes": [{"text": "Jiyan pirtûk e. Kesên nagerin û nabînin, her tim heman rûpelî dixwînin.", "author": "Aurelius Agustine"}, {"text": "Bimeşe, bimeşe û dîsa bimeşe... Heta ku êşa piyê te bi ser hemî êşên din bikeve.", "author": "Ferid Amara"}, {"text": "Min dixwest bimeşim di rêyeke kesnezan de...", "author": "R.M. Rilke"}, {"text": "Kes kesî winda nake. Yê diçe yekî din dibine, yê dimîne xwe dibine.", "author": "Kinsun"}, {"text": "Ku pêlava te teng be, çi fêdeya firehiya dinyayê heye.", "author": "John Williams"}, {"text": "Jimalderketin macerayeke xeternak e.", "author": "Kafka"}]}, {"title": "DADMENDÎ", "quotes": [{"text": "Ji bo Kurdan çi dixwazim, heman tiştî ji bo neteweyên din jî dixwazim. Neteweyên din xwediyê çi mafî bin, heman tiştî ji bo Kurdan jî dixwazim. Ne yek kêm ne yek zêde. Gelo ez nijadperest im?", "author": "Îbrahîm Sediyanî"}, {"text": "Mehkeme dezgehekî desthilatê ye; lîberal carinan vê rastiyê jibîr dikin, lê jibîrkirina vê rastiyê ji hêla marksîstekî, sûc e.", "author": "Vladimir Lenin"}, {"text": "Dema hûn li hember bêdadîyê bêalî dimînin, hûn dibin alîgirên zordaran.", "author": "Desmond Tutu"}, {"text": "Kesê mala cîranê xwe bihejîne,mala xwe xira dike.", "author": "Gotina Swîsrîyan"}, {"text": "Her tişt berovajî bûye.Kujer bêrîyan didarizînin.", "author": "Charles Dickens"}, {"text": "Neheqîya li deverekê,ji bo edaleta hemî deveran gef e.", "author": "Martin Luther King"}]}, {"title": "DAYÎK Û BAV", "quotes": [{"text": "Şêrîntirîn peyva li ser lêvên mirovan, «dê» ye. Xweştirîn bang jî «yadê» ye.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Destê Xwedê nedigihaşt her derê, ji bo vê jî dayîkan afirand.", "author": "Rudyard Kipling"}, {"text": "Dilovaniya bav ji sertaran bilindtir e, dilovaniya dayikê ji deryayan kûrtir e.", "author": "Gotina Japonan"}, {"text": "Kesê nikaribe erka bavtiyê bicih bîne, mafê wî tune ku bizewice u bibe xwedî zarok.", "author": "JeanJacques Rousseau"}, {"text": "Hemî cîhanê deynin alîyekî û dayîka min deynin alîyekî, ez ê dayîka xwe hilbijêrim.", "author": "J.J. Rousseau"}, {"text": "Serhildana li hemberî bav komedî ye, ne trajedî.", "author": "Deleuze"}]}, {"title": "DEM", "quotes": [{"text": "Bi saetan em li benda hatina hin saetên din radiwestin.", "author": "Cioran"}, {"text": "Dema vala tune ye, dema ku vala derbas dibe heye.", "author": "Tagore"}, {"text": "Heman salê heftê û pênc caran dijîn û jê re dibêjin “jîyan”", "author": "Robin Sharma"}, {"text": "Dem, birrekeke bêdeng e.", "author": "Immanuel Kant"}, {"text": "Her tişt bi demê tê telafîkirin, lê herikîna demê bi tiştekî din nayê telafîkirin.", "author": "Goethe"}, {"text": "Dem her birînê derman dike. Lê ku dem bi xwe nexweşîyek be?", "author": "Wim Wenders"}]}, {"title": "DEMOKRASÎ", "quotes": [{"text": "Eger diktatorî tiştekî guneh jî qedexe bike, bêexlaq e. Heger demokrasî destûra gunehan jî bide xwedî exlaq e. Exlaq û azadî ji hev naqetin. Tenê kiryarên azad, dibin mijara exlaq.", "author": "Alija Izetbegović"}, {"text": "Em dê jinûveavakirina demokrasiyê,ji Kurdan hîn bibin.", "author": "Slavoj Žižek"}, {"text": "Berî perwerdeyê, demokrasî çênabe. Civakeke neperwerdekirî derbasî demokrasiyê bibe, dê bibe olîgarşî. Wisa dewam bike, dê demagog peyde bibin. Ji demagogan jî dê dîktator derkevin.", "author": "Platon"}, {"text": "Bê demokrasîyê,ne pirsgirêka Kurdan çareser dibe,ne jî Kurd dikarin mafê serxwebûnêbi dest bixin.", "author": "Abdurrahman Qasimlo"}, {"text": "Demokrasî ji civateke cahil re bêfêde ye, ji ber ku pirraniya keran dê biryara çarenûsa te bidin.", "author": "Bernard Shaw"}, {"text": "Demokrasî ew e ku,tu li hember namzetê xirabtir dengê xwe didî namzetê xirab.", "author": "Robert Byrne"}]}, {"title": "DERS Û ÊBRET", "quotes": [{"text": "Tu ji derba ewilî ders negirî,ya duyemîn jî heq dikî.", "author": "Necîb Mehfûz"}, {"text": "Ji kesên berîya xwe êbret bistîne,lê ji yên pişt xwe re nebe êbret.", "author": "Socrates"}, {"text": "Her tişt xipxuya eşkere ye,lê heta em şeqaman nexwin em ji îşaretan fêhm nakin.", "author": "Necîb Mehfûz"}, {"text": "“Zikekî birçî, berîkeke vala û dilekî şikestî dersa herî mezin a jiyanê fêrî te dike.”", "author": "Robin Williams"}]}, {"title": "DERÛNNASÎ", "quotes": [{"text": "Kesê ku tiştekî bi her awayî red dike,bi rastî ew di bin bandora wî tiştî de ye.", "author": "Hans-Georg Gadamer"}, {"text": "Têrnebûna zaroktiyê şûnên gelekî kûr ku qet jê neçin, li pey xwe dihêle.Di pêşerojê de dabînkirina van têrnebûnan ne pêkan e.", "author": "Emile Ajar"}, {"text": "Dema em diwestin, an jî cesareta xwe winda dikin; fikr û ramanên ku me berê zora wan biribû, dîsa êrîşî me dikin.", "author": "Nietzsche"}, {"text": "Her mirovek di hundirê xwe de potansiyela xerabîyê dihewîne.Kesên haya wan ji vî tiştî tune ye,ji yên din talûketir in.", "author": "Carl Gustav Jung"}, {"text": "Di hundirê serê her kesekî de,li gor xwe odeyeke îşkenceyê heye.", "author": "Erich Maria Remarque"}, {"text": "Em hemî, zîndanên xwe, keskûjîyên xwe, hilweşînên xwe di hundirê xwe de digerînin.", "author": "Albert Camus"}]}, {"title": "DESPOTÎZM – ZORDESTÎ", "quotes": [{"text": "Tu xaniyê xwe li ser rondikê çavê mezlûman ava bikî, wê dîwar bi ser te de bihêrivin!", "author": "Gotina Aşûriyan"}, {"text": "Mirovên ku li vî welatî bi ser hev de hatine dewisandin, hew dikarin xetên sereke yên mirovahîyê ji hev veqetînin. Her mirovek azadî ji wan re “ecêb” tê.", "author": "Walter Benjamin"}, {"text": "Tu xaniyê xwe li ser rondikê çavê mezlûman ava bikî, wê dîwar bi ser te de bihêrivin!", "author": "Gotina Aşûriyan"}, {"text": "Kesê mafê mirovan binpê dike, welew ku hemî temenê xwe bi rojî, nimêj û xwendina Quranê jî derbas bike, li gor hemî baweriyan lanetkirî ye.”", "author": "Cemaledîn Efxanî"}, {"text": "Zordarî, rêya herî bêkêr e ji bo dabînkirina asayîşê.", "author": "Ursula K. Le Guin"}, {"text": "Heta qralê dawîn bi rûvîkên rehbikê dawîn neyê xeniqandin, ademîzad azad nabe.", "author": "Diderot"}]}, {"title": "DESTHILATDARÎ", "quotes": [{"text": "Serwerî (hikûmranî) bê qeyd û şert ya gel e.", "author": "Jean Jacques Rousseau"}, {"text": "Serkeftina herî mezin a desthilatdariyê ew e ku; zordariyê normal, koletiyê mecbûrî û bêdengmayînê jî wekî xûypakî û dilpakiyê dide nîşandan.", "author": "Étienne de La Boétie"}, {"text": "Hûn bixwazin welatekî nas bikin,li şêweyê mirina welatiyan binêrin.", "author": "Albert Camus"}, {"text": "Dar di destê kê de be, hukimdar ew e.", "author": "Jack London"}, {"text": "Gava hikûmet ji gelê xwe bitirse,ev azadî ye. Gava gel ji hikûmetê bitirse, ev zorbetî ye.", "author": "Thomas Jefferson"}, {"text": "Desthilatdar û rayedarên herî kirêt û bêbext ew in ku, zik û berîkên wan tije ne û gelê wan birçî ye.", "author": "Selahaddîn Eyyûbî el- Kurdî"}]}, {"title": "DEWLET", "quotes": [{"text": "“Dewlet” ketîye şûna Xwedê.Hemî dîktatorî bûne ol û koletiya ji dewletê re, ketiye şûna îbadetê.", "author": "Carl Gustav Jung"}, {"text": "Heger Xwedê diayên wan erê bikira,ji ber ku her tim li dijî hev dia dikirin dê koka mirovan biqeliya.", "author": "Epicurusus"}, {"text": "Dostên dewletan tune ne, berjewendiyên wan hene.", "author": "Charles de Gaulle"}, {"text": "Pir ê caran gotinên şoforê taksîyê yên derbareyê welêt de,ji yên serokê dewletê rasttir in.", "author": "Anonîm"}, {"text": "Dewleta te tune be,dîn û îmana te jî nîne.", "author": "Evdilrehman Durre"}, {"text": "Dewlet dema amadekariya cînayetekê dike, her tim navê “welat” li xwe dike.", "author": "Friedrich Dürrenmatt"}]}, {"title": "DEYN", "quotes": [{"text": "Kesê mal bi deyn dide hevalê xwe, herdûyan jî winda dike.", "author": "Gotina Frensiyan"}, {"text": "Malê tu bi deyn didî dostekî,tê ji dijminekî bistînî.", "author": "Gotina Almanan"}, {"text": "Eger 1000 dolar deynê banqê li we hebe û hûn nikaribin bidin, hûn rûbirûyî pirsgirêkeke cidî ne. Eger 1 mîlyon dolar deynê banqê li we hebe û hûn nikaribin bidin, banqe rûbirûyî pirsgirêkeke cidî ye.", "author": "John Maynard Keynes"}, {"text": "Deynkirin bi qasî ganê hêsan e,deyndan bi qasî zanyinê zehmet e.", "author": "Gotina Sumeriyan"}, {"text": "Kesê ne deyndar,mirovê herî bextewer e.", "author": "Gotina Someriyan"}]}, {"title": "DIJBERÎ - NAKOKÎ", "quotes": [{"text": "Her tişt bi dijberê xwe tê xwedî kirin;ti fêdeya hevşêwe ji hevşêwe re tune ye.", "author": "Platon"}, {"text": "Mirovê rast, dema şaş. Dema rast, mirovê şaş. Her timî jiyan bi vî hawî bi mirov dilîze.", "author": "Paul Auster"}, {"text": "Ji bo rabûnê ketin, ji bo dîtinê jî windabûn divê.", "author": "Vincent van Gogh"}, {"text": "Raqîbên xwe jî bi baldarî hilbijêrin. Payeya dijberiyê nedin pîs û çepelan û wan neyînin qama xwe.", "author": "Che Guevara"}, {"text": "Her mirov dişibe hîvê. Aliyekî wî yê tarî heye û wî alî nîşanî kesên din nade.", "author": "Mark Twain"}, {"text": "Heger zivistanê gotiba “bihar di dilê min de ye” kî yê jê bawer bikira.", "author": "Cîbran Xelîl Cîbran"}]}, {"title": "DIJMIN - DIJMINATÎ", "quotes": [{"text": "Yê ku bi dijminê xwe\nAnî bîr û bawerî\nÇerxa wî çep digere\nDoza wî naçe serî", "author": "Gernas Koçer"}, {"text": "Di rojên giran tu serê xwe li kevirekî bixî, dê ji kevir rondik bibarin. Lê hêvîya merhemetê ji dijmin neke.", "author": "Zabel Yesayan"}, {"text": "Ku dijminê te nebin,tu mirovekî bêqîmet î.", "author": "Gotina Sirbiyan"}, {"text": "Baş guh bide gotinên neyarê xwe.Di wan gotinan de gelek rastî hene ku, dostên te ji te vedişêrin.", "author": "Platon"}, {"text": "Dijminatîya hin kesan,ji dostanîyê kêrhatîtir e.", "author": "Dostoyevski"}, {"text": "Ji bîr meke, dijmin nîşangirekî kor e.Lê dost dizane dê kuderê nîşan bigre.", "author": "Descartes"}]}, {"title": "DIL", "quotes": [{"text": "Dil li kuderê be, hêlîn li wir e.", "author": "John Green"}, {"text": "Di awirên wê debirîna dilê wê xwe dida der.", "author": "James Joyce"}, {"text": "Dilê kesekî neşikînin,sitargeha Xwedê ye ew.", "author": "Nikos Kazancaskis"}, {"text": "Ji herkesî zêdetir keniya, xûya ye dilê wî diêşe.", "author": "Tolstoy"}, {"text": "Dilekî aram, rû jî ronak dike.", "author": "Harper Lee"}, {"text": "Heger derîyê dil hebûya, dê li ser ev bihata nivîsandin: bikeve hundir, lê neêşîne.", "author": "Hermann Hesse"}]}, {"title": "DILOVANÎ", "quotes": [{"text": "Mirov li hember zîrekîyê xwe ditewîne; lê li hember dilovanîyê çok datîne erdê.", "author": "Voltaire"}, {"text": "Tu bixwazî mirovekî baş nas bikî, binêre ka ew bi kesên ji xwe zeîftir re çawa tevdigere.", "author": "Sirius Black"}, {"text": "Tu bi xwe, bi qasî hemû kesên di gerdûnê de, hezkirin û dilovaniya xwe heq dikî.", "author": "Buddha"}, {"text": "Dema fêr bûn ku dilovaniya Yusiv bi te re ye, gelek caran te avêtin binê bîran.", "author": "Xellacê Mensûr"}, {"text": "Nazikbûn ew ziman e ku, kerr jî dibihîze û kor jî dixwîne.", "author": "Mark Twain"}, {"text": "Dilovanî, Empatî, Nazikbûn... Ev ji makyajê û ji cil û bergên biha bêhtir, mirovan xweşik dikin.", "author": "Audrey Hepburn"}]}, {"title": "DILPAKÎ", "quotes": [{"text": "Mirovên dilpak qet nikarin jiyaneke asûde bijîn. Ji ber ku xwe ji bo jîyana kesên din feda dikin.", "author": "Jean de La Bruyère"}, {"text": "Dev ji niqirandina peykerê xwe bernede. Ta ku şemla dilpakiya Xwedayî li ser te bibiriqe û belav bibe.", "author": "Platinos"}, {"text": "Camêriya heqîqî ew e, tu qenciyê bi kesekî ku qet haya wî jî te çênebe bikî.", "author": "Frank Clark"}, {"text": "Di jiyanê de sê tiştan baş bifikire; dilekî beriya tu bişkînî, deriyekî beriya tu lêxî, gotineke beriya tu dawiyê lê bînî.", "author": "Confucius"}, {"text": "Mêjiyekî baş û dilekî pak, her tim kombînasyoneke zehmet e.", "author": "Nelson Mandela"}, {"text": "Di kubariyê de asta herî bilind ew e ku, tu guhdariya tiştekî tu dizanî, dikî.", "author": "Îbn Xeldûn"}]}, {"title": "DILSOZÎ", "quotes": [{"text": "Dilsozî nirxekî biha ye.Bi kesên erzan re peyda nabe.", "author": "Necîb Mehfûz"}, {"text": "Dema “dilsozî” xisletê te yê herî zeîf be, mirovê herî hêzdar tu yî li vê dinyayê.", "author": "Abraham Lincoln"}, {"text": "Pişt bide pişta min, bila ji paş ve li me nexin.", "author": "Maxim Gorky"}, {"text": "Hevalê rasteqîn ew e ku bi her tiştê te dizane, dîsa jî ji te hez dike...", "author": "Elbert Hubbard"}, {"text": "Kesê di rewşa te ya herî xirab de ji te hez kiribe, ew layiqê dilê te ye.", "author": "Shakespeare"}, {"text": "Keçika ku di hevdîtina ewil de bêje “ji te hez dikim,” bêyî xatirxwestinekê jî terka te dike.", "author": "Shakespeare"}]}, {"title": "DILŞADÎ Û BEXTEWERÎ", "quotes": [{"text": "Hinek mirov bextewer in, hinek jî ne bextewar. Yên mayî ew bextreş in ku, xwe mîna bexteweran nîşan didin.", "author": "Oscar Wilde"}, {"text": "Tu bixwazî bextewer bibî, bibe.", "author": "Tolstoy"}, {"text": "Ji bo dilşadî û bexteweriya demjimêrekê, rakeve. ji bo rojekê, masiyan bigre. ji bo mehekê, derkeve bêhnvedanê. ji bo salekê, bizewice. ji bo temenekî, karekî tu jê hez dikî bike.", "author": "Gotina Çîniyan"}, {"text": "Ji bo bexteweriyê rê tune ye, bextewerî rê ye.", "author": "Gotina Çîniyan"}, {"text": "Divê em ji wan kesên ku me şad û bextewar dikin re spasdar bin. Ew bexçevanên wisa şîrîn in ku, di dilê me de kulîlkan vedikin.", "author": "Marcel Proust"}, {"text": "Bextewarî û bextreşî du rewş in ku em sînorên wan nizanin.", "author": "John Locke"}]}, {"title": "DINYA", "quotes": [{"text": "Dinya keştiya bobelatan e.", "author": "Socrates"}, {"text": "Dinya nexweşxaneyeke dêwasa ye û hemî mirovên tê de, dixwazin nivîna xwe biguherinîn.", "author": "Charles Baudelaire"}, {"text": "Êdî dinya pîr bûye û qermîçonkê wê zêde bûne.", "author": "Vincent van Gogh"}, {"text": "Xuya ye dinya ne kargeha mirazan e.", "author": "John Green"}, {"text": "... û ji xwe ev der dinya ye. Li vê derê dê her tim tiştin nîvco bimînin.", "author": "Chinghiz Aitmatov"}, {"text": "Ev dinyaya ewqas tirsehêz ne bes bû, bi ser de dojeha wê jî heye?", "author": "Umberto Eco"}]}, {"title": "DIZÎ", "quotes": [{"text": "Dizên biçûk siza dikin, dizên mezin jî tînin ser karên fermî.", "author": "Ezop"}, {"text": "Kesê ji bo te bidize, dê ji te jî bidize.", "author": "Gotina Efrîqiyan"}, {"text": "Nedize. Çimkî hikûmet ji raqîban hez nake.", "author": "Paulo Coelho"}, {"text": "Kesên bi keştiyên biçûk dizî û talanê dikin, ji wan re dibêjin ‘korsan’; yên ku bi keştiyên mezin dizî û talanê dikin ji wan re dibêjin ‘fatîh.’", "author": "Gotina Yewnanan"}, {"text": "Derew jî dizî ye. Tu mafê rastbihîstina kesên din didizî.", "author": "Khalid Hosseini"}, {"text": "Bi şev di tarîtiyê de hatin û agirê me dizîn. Belê dizîn. Ku xwestibana, me dê agir bida wan. Lê dizîn.", "author": "William Golding"}]}, {"title": "DÎROK", "quotes": [{"text": "Dersa herî ron û eşkere ya dîrokê: heq nayê dayîn, tê stendin.", "author": "Noam Chomsky"}, {"text": "Sedsala me sîtileke qirase ye ku, hemû serdemên dîrokî tê de li hev dikevin û tevdigerin.", "author": "John Berger"}, {"text": "Dîrok, ji berzkirina kûjer û şêlînkeran pêve ne tiştekî din e.", "author": "Karl Popper"}, {"text": "Dîroka ku bi xwînê hatibe nivîsandin, ne mimkûn e bi derewên ku bi hibrê hatine nivîsandin sererast bibe.", "author": "Gotina Efrîqiyan"}, {"text": "Dîroka mirovahîyê ji şerê navbera serdest û bindestan pêk tê.", "author": "Nasr Hamîd Ebuzeyd"}, {"text": "Ku ewqas vir û derew li ber çavên me tên kirin, em çawa baweriya xwe bi dîrokê bînin?", "author": "Amin Al-Saadani"}]}, {"title": "DOSTANÎ Û HEVALTÎ", "quotes": [{"text": "Kesên te li hember mirovan diparêzin û haya te jî jê tune ye, ew hevalên rasteqîn in.", "author": "Mahatma Gandhi"}, {"text": "Ji dêvla ku wê bi qasî stêrkan hevalên te hebin, bila dostekî te yê ku di şevereşê de mîna çardehîvê şewq û biraq jê diçe hebe, bes e.", "author": "Goethe"}, {"text": "Kêlîya moralê te xirab be, ne yên ku dibêjin “çima?” yên dibêjin “tu li kuderê yî?” heval in.", "author": "Gore Vidal"}, {"text": "Dostên têkberan pir in, lê dostên têkçûyîyan ji dil in.", "author": "Machiavelli"}, {"text": "Ger dostekî te tune be ji bo tu derd û kulên xwe parve bikî, tu dibî goştxwer û dilê xwe dikeritînî.", "author": "Francis Bacon"}, {"text": "Çiqas dostên we yên ji dil hebin, hêz û semaxa we ya li dijî zehmetiyên jîyanê bilindtir dibe.", "author": "JeanJacques Rousseau"}]}, {"title": "DÛR KETIN", "quotes": [{"text": "Carinan ji bo tu bixwe werî, divê ji hinên din herî. Dûrketin azadî ye.", "author": "Charles Bukowskî"}, {"text": "Carinan ji bo em zirerê nedin hezkiriyên xwe, tenê yek rê li ber me dimîne: “dûrketin”", "author": "Prison Break"}, {"text": "Beguman biryara min a herî rast ew bû; ez ji wan kesên ku xwe wekî ‘jêneger’ didîtin, dûr bûm.", "author": "Charles Bukowskî"}, {"text": "Devera tu lê yî ger ku te bextewar nake, ciyê xwe biguherîne.", "author": "Jim Rohn"}, {"text": "Hêla dûrbûyînê ya herî baş ev e ku; nikarin lêpirsînê li biryarên te bikin, nikarin fikr û ramanên te darizînin û heta tu destûr nedî, nikarin tevlî jiyana te bibin.", "author": "La Case De Papel"}, {"text": "Tu bixwazî bilez herî, bi tena serê xwe here. Tu bixwazî dûr herî, bi hezkiriya/ê xwe re here.", "author": "Gotina Efrîqiyan"}]}, {"title": "DURÛTÎ", "quotes": [{"text": "Bi gur re dixwe, bi kuçik re direye û bi şivan re digirî.", "author": "Gotina Kurdan"}, {"text": "Gelek ji van kesên ku dibêjin em medenî ne, eger derveyê wan û hundirê wan bi hev bête guherandin; dê wek gur, hirç, mar, beraz û meymûnan werin xûya kirin.", "author": "Seîdê Kurdî"}, {"text": "Durûtî dişibe şûrekî ku herdu aliyên wî tûj bin. Rexekî wî mirovê ku pê tê xapandin dibirre, rexê din jî, xwediyê xwe dibirre.", "author": "Cervantes"}, {"text": "Sanamê herkesî pê şîrîn e Herkes Îbrahîmê putê kesên din e", "author": "Omer Lutfî"}, {"text": "Ev civak dijminê xwebûn, xwezayîbûn û sadebûnê; evîndarê tevlîhevî, durûtî û rûpoşîyê ye.", "author": "Fyodor Dostoevsky"}, {"text": "Ku durûtiya mirovan ji te re ecêb were, xûya tu hê jî mirovekî baş î.", "author": "Eliot"}]}, {"title": "EDEB Û REZDARÎ", "quotes": [{"text": "Bi nezanan re nekeve gengeşî û niqaşê. Yan wê hêrsa te rabe qarçikan, yan jî heyf û xebîneta rêz û edeba te.", "author": "Celaleddîn Rûmî"}, {"text": "Gotinên ne xweş ji Xwedayên wan re nebêjin. Ji bo ku ew jî gotinên ne xweş ji Xwedayê we re nebêjin.", "author": "Qur’an"}, {"text": "Biedeb ji edeba xwe bêdeng dimîne, bêedeb dibêje min dengê wî birî.", "author": "Celaleddîn Rûmî"}, {"text": "Ku li pêşberî min kesekî/e baş hebe ez ê bi dil û can pê re biaxivim û di cî de bibim heval. Ez dê li gel wî/wê çayê jî vexwim. Tu dizanî çima? Ji ber ku mirovên qenc rêzdar in.", "author": "Nikolay Vasilyeviç Gogol"}, {"text": "Axaftina dê û bavan, zarokan, û mirovên dilbikul nebire û li wan guhdarî bike. Çimkî ew ji dil diaxivin.", "author": "Cahiz"}, {"text": "Bênfireh bin; çimkî her mirovekî ku hûn li rastî wî/ê tên, bawer bikin herî kêm bi qasî we di nav kefteleftê de ye.", "author": "Platon"}]}, {"title": "EDEBÎYAT (WÊJE)", "quotes": [{"text": "Xweşikbûna gotinê, di kûrtbûna wê de ye.", "author": "Îbn Sîna"}, {"text": "Hêza peyvê, nêzî hêza Xwedê ye.", "author": "Gotina Yewnanan"}, {"text": "Neteweyên ku çîrok û çîrvanokên wan tune ne, ji sir û sermayê diqufilin", "author": "Anonîm"}, {"text": "Ziman, bi helbestê pêş dikeve û geş û gûrr dibe.", "author": "Mikhail Bakhtin"}, {"text": "Hişmendiya neteweyî, bi awayekî mecbûrî bi edebiyatê ve girêdayî ye.", "author": "Deleuze"}, {"text": "Di vê erdnîgariya ku temenê perperokan ji yên zarokan dirêjtir e de, ez kîjan helbestê ji we re binivîsim?", "author": "Ahmed Arîf"}]}, {"title": "EGO – XWEPERESTÎ – EZ EZÎ", "quotes": [{"text": "Tenê li xwe difikirî, ji ber ku tenê xwe nas dikir.", "author": "Albert Camus"}, {"text": "Kes ji halê xwe ne razî ye, lê her kes ji aqilê xwe razî ye.", "author": "Tolstoy"}, {"text": "Nebêjin “ez” bêjin “em!”", "author": "Seîdê Kurdî"}, {"text": "Gazinan ji kesê ku gelekî qala xwe dike, neke. Ji ber ku ew nizane qala tiştekî din bike.", "author": "Alexandre Dumas"}, {"text": "Çiqas keleşêr (dîk) hene ku bawer dikin roj bi banga wan hiltê!", "author": "Theodor Fontane"}, {"text": "Temam me fêhm kir tu qenc î, lê bi kêrî çi tê qenciya te?", "author": "Bertolt Brecht"}]}, {"title": "EKOLOJÎ – XWEZA", "quotes": [{"text": "Ekolojî, tenê ne tevgereke hawîrparêz e. Di heman demê de felsefeyeke civakî û zanistî, projeyeke komelayetî ya dijhîyerarşîk û dijotorîter û şêwaza jîyaneke çalakger e.", "author": "Murray Bookchin"}, {"text": "Kulîlk, peyv u hîyeroglîfên delal ên xwezayê ne. Xweza hezkirina xwe bi me dide nîşandan", "author": "Goethe"}, {"text": "Ez bawer im em gelekî zêde li xwezayê temaşe dikin, lê em pir hindik tê de û pê re dijîn.", "author": "Oscar Wilde"}, {"text": "Kesên ti carî nebûne şahidê hilatina rojê, ji avaçûna wê re dibêjin romantîzm.", "author": "Nietzsche"}, {"text": "Em li dijî xwezayê di têkoşînê de ne. Eger em bi ser kevin, em ê têk biçin.", "author": "Hubert Reeves"}, {"text": "Li ser rûyê erdê gelek mirovên ne layîqê şewqa rojê hene. Lê roj her sibê ji nû ve hiltê.", "author": "Seneca"}]}, {"title": "ENDÛSTRÎ", "quotes": [{"text": "Endûstrîbûn çiqasî pêş bikeve, fanatîzma olî ewqasî kêm dibe.", "author": "Noam Chomsky"}, {"text": "Di şerê cîhanê yê sêyemîn de kîjan çek dê bêtin bikaranîn, ez nizanim; lê yê çaremîn wê bi kevir û daran be.", "author": "Albert Einstein"}, {"text": "Yan zarokên xwe hînî nivîsandina kodên kompîturê bikin; an jî wan fêrî bikaranîna çekan bikin.", "author": "Yuval Noah Harari"}, {"text": "Hûn wan zombîyên ku rûyê wan bi telefonên biaqil ve hatiye zeliqandin û li kolanan digerin dibînin. Gelo ew teknolojiyê kontrol dikin, an teknolojî wan kontrol dike?", "author": "Yuval Noah Harari"}, {"text": "Ajara dînazoran qeliya, ji ber ku bernemeyeke wan ya fezayê tune bû.", "author": "Larry Niven"}]}, {"title": "ESTETÎK", "quotes": [{"text": "Her xweşik, dê rojekê xweşikahîya xwe winda bike.", "author": "Shakespeare"}, {"text": "Xweşikatî, tenê tebeqeyeke derveyî ye. Lê kirêtî û pîsîtî heta ser hestûyan jî reng vedide.", "author": "Dorothy Parker"}, {"text": "Jina delal bihûşta çavan, dojeha giyanan û paqijkera berîkan e.", "author": "Gotina Estoniyan"}, {"text": "Min her tim bawer kiribû û ez hê jî li ser baweriya xwe me ku; ji jineke bedew, xweşiktir tiştek tune ye.", "author": "Gabriel Garcia Marquez"}, {"text": "Sererastkirin: Jina ne xweşik tune ye, lê hin ji yên din xweşiktir in.", "author": "Robert A. Heinlein"}, {"text": "Delalî û nedelal î leylanok e. Dawîya dawî dê herkes hundirê we bibîne.", "author": "Frida Kahlo"}]}, {"title": "ÊŞ Û JAN", "quotes": [{"text": "Êşa her rojê, besî xwe ye.", "author": "Andre Maurois"}, {"text": "Şêrîntirîn çêj, di janê de veşartî ye.", "author": "Dostoyevski"}, {"text": "Êşên kûr, bêziman in.", "author": "Denis Diderot"}, {"text": "Di her xweşî û êşê de nîyazeke nepenî heye ku, dixwazin zû bi zû bidawî bibin.", "author": "Jean Baudrillard"}, {"text": "Her kesek dişibe êşa xwe.", "author": "André Malraux"}, {"text": "Dibêjin, “tu çima guherî? Dibêjim, “ji ber ku min ji heq kirina xwe zêdetir êş kişand.”", "author": "Cîbran Xelîl Cîbran"}]}, {"title": "EZMÛN", "quotes": [{"text": "Xwedêyo min çi guneh kiriye ku, hema serê kêlîyekê tu min wek şagirtekî radikî ber dep?", "author": "Karl Georg Büchner"}, {"text": "Tecrûbe, mamosteyekî dijwar e. Pêşî ezmûn dike, paşê ders dide.", "author": "Jigsaw"}, {"text": "Ti mirovek bêsebeb tevlî jiyana me nabe. Hinek ezmûna me ne, hinek belaya serê me ne, hinek jî, bo me hêjatirîn dîyarî ne.", "author": "Erich Fromm"}, {"text": "Hûn rêyeke bêasteng bibînin, îhtîmal e ku ew rê naçe tu deverê.", "author": "Frank A. Clark"}, {"text": "Li dinyayê herî zêde tu çi bixwazî, ew e ezmûna te.", "author": "Celaleddîn Rûmî"}, {"text": "Jiyan me bi çar kirariyan ezmûn dike: Bi rastiyan car dike, bi fîrqetê par dike, ji mirovatiyê derdixe û kêm dike û di dawiyê de dibêje; xwe bide hev.", "author": "Tolstoy"}]}, {"title": "FAŞÎZM", "quotes": [{"text": "Dema min got “divê Cezayîr bibe welatekî serbixwe,’’ min dît gelek hevalên min ên çêpgir yên nêzî min faşîst derketin.", "author": "Jean Paul Sartre"}, {"text": "Li dewletên faşîst welatî tunene, tenê bendegan (reaya) hene.", "author": "Herman Finer"}, {"text": "-Tu komunîst î?\n-Na, ez antîfaşîst im.\n-Ji kengî ve?\n-Ji roja min faşîzm nas kiriye ve.", "author": "Ernest Hemingway"}, {"text": "Di civakên ku ‘ferd’ tê de tê lawazkirin û bêqîmetkirin, FAŞÎZM zêde dibe. Kesê ku ji takekesîya xwe dûr dikeve, di jêr sembolên stemkar yên faşîzmê de, hebûna xwe ya tirsonek dide nîşandan.", "author": "Erich Fromm"}, {"text": "Herkes dizane keştî av girtiye. Herkes dizane kaptan derewan dike. Û herkes dizane zar bihîle ne.", "author": "Leonard Cohen"}, {"text": "Carinan bi cil û bergên sivîl digere FAŞÎZM. Wezîfeya me ew e ku, em her roj wê tazî bikin û nîşanî her kesî bidin.", "author": "Umberto Eco"}]}, {"title": "FÊDE Û ZERER", "quotes": [{"text": "Kêmkirina tiştên bizerar, ji zêdekirina tiştên bifêde çêtir e.", "author": "Hipokrat"}, {"text": "Piştî şîr rijiya, girî fêde nake.", "author": "Gotina Ingilîzan"}, {"text": "Dema kirin fêde neke, zanyarîyan berhev bike; ku zanyarî jî fêde nekin, rakeve.", "author": "Ursula K. Le Guin"}, {"text": "Esilzade ew e ku, fêdeya wî ya ku dide dinyayê, ji fêdeya ku ji dinyayê dîtiye zêdetir e.", "author": "George Bernard Shaw"}]}, {"title": "FELSEFE – ÎDEOLOJÎ", "quotes": [{"text": "Ji dêvla tu yê bibî berazekî bextewer, bibe Socratesekî dilnerihet.", "author": "John Stuart Mill"}, {"text": "Bêfelsefeyî, asta ehmeqiyê derdixe rêjeya herî bilind. Erka felsefê, têkoşîna li dijî ehmeqiyê ye.", "author": "Deluze"}, {"text": "Navê wê tişta ku dibe sebeb mirov car caran hevûdin dixin şûna Xwedê an jî kêzikan, îdeolojî ye.", "author": "Terry Eagleton"}, {"text": "Mirov xwedîyê xwezayeke dualî ye; beden û aqil. Ji bo bedenê pêdivî bi waneya werzîşê, ji bo aqil jî pêdivî bi waneya felsefê heye.", "author": "İSocrates"}, {"text": "Feylesofan ti carî mamosteyên ayînî nekuştine. Lê mamosteyên ayînî gelek caran feylesof kuştine.", "author": "Denis Diderot"}, {"text": "Şairtî ji min nehat, ez jî bûm feylesof.", "author": "Nietzsche"}]}, {"title": "FEODALÎZM", "quotes": [{"text": "Brêz lord! Ji bo daneheva ewqas saman û serwetê, ji xeynî jidayîkbûnê gelo te çi zehmetî kişand?", "author": "Bertrand Russell"}]}, {"title": "FÊRBÛN", "quotes": [{"text": "Kesên biaqil, ji herkesî û her tiştî fêr dibin, kesên ji rêzê, tenê ji serpêhatiyên xwe fêr dibin, kesên nezan jî, her tiştî dizanin.", "author": "Socrates"}, {"text": "Fêrkirin, dubare fêrbûn e.", "author": "Confucius"}, {"text": "Li dinyayê du cûre mirov hene: yên dixazin hîn bibin û yên dixwazin bawer bikin.", "author": "Nietzsche"}, {"text": "Fêrbûnî mîna avjenîya li dijî şîpê ye. Dema tu bi pêşve neçî tu yê bi paşve biçî.", "author": "Gotina Çîniyan"}, {"text": "Jîyan tiştekî ji we re nabêje, lê her tiştî nişanî we dide.", "author": "Richard Bach"}, {"text": "Stewîn; fêrbûna dûrketina ji wan mirovan e ku mêjiyê te dilewitînin.", "author": "Josh Malerman"}]}, {"title": "GERDÛN", "quotes": [{"text": "Gerdûna di serê min de, ji gerdûna ku serê min te de ye, mezintir e.", "author": "Kafka"}, {"text": "Gerdûn li rex wêrekan e.", "author": "Robin Sharma"}, {"text": "Bêdawîtî, rebenî û pepûkîya îlîzyona zanebûnê teşhîr dike.", "author": "Lesley Hazleton"}, {"text": "Her kesek, di hundirê xwe de gerdûneke mezin e.", "author": "Allen Ginsberg"}, {"text": "Du dibêtî hene; yan em li gerdûnê bi tenê ne, yan jî em ne bitenê ne. Herdu dibêtî jî di heman pileyê de tirsnak in.", "author": "Arthur Charles Clarke"}, {"text": "Bîrkarî ew ziman e ku, Xwedê gerdûn pê ava kiriye.", "author": "Galileo"}]}, {"title": "GÎYAN", "quotes": [{"text": "Di dawiyê de tenê kesên bedewiya giyanê te dibînin li cem te dimînin. Ew yên heyranê bedewiya te ya zahirî ne, yeko yeko ji te direvin.", "author": "Celaleddîn Rûmî"}, {"text": "Ji bo guherîna kesekî xwe newestîne. Li rihekî ku dişibe te, bigere.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Ji mirovekî şaş û devereke şaş zêdetir, tiştek rihê mirov nakuje.", "author": "Fyodor Dostoevsky"}, {"text": "Berê beden ji bo gîyan metaforek bû, piştre bu metafora zayendîyê, lê îro ew, edî teqez ne metafora tiştekî ye jî...", "author": "Jean Baudrillard"}, {"text": "Giyan li ahengê digere, lê jiyan ji serî heya binî tevlîhevî ye.", "author": "Andrei Andrei Tarkovsky"}, {"text": "Giyanê mirov, ji bo Ehrîmen û Yezdan qada şer e.", "author": "Fyodor Dostoevsky"}]}, {"title": "GOTIN", "quotes": [{"text": "Di navbera gotin û kirinê de gelek pêlavên qetiyayî hene.", "author": "Gotina Îtaliyan"}, {"text": "Tiştên ez bêjim pir zêde bûn, ji bo vê min tiştek negot.", "author": "Jeanette Winterson"}, {"text": "Hemû tiştên ku divabû bihatana gotin, ji zû de hatine gotin. Lê ji ber ku kesekî guhdarî nekiriye, divê em dîsa dubare bikin.", "author": "André Paul Guillaume Gide"}, {"text": "Berîya her tiştî “gotin” hebû.", "author": "Încîl"}, {"text": "Ji dengê min ê bilind netirse, dema gotinên ku bêjim nemînin, hingê bitirse.", "author": "J. Iron"}, {"text": "Tiştê tê dîtin, ti carî di hundirê gotinê de bi cih nabe.", "author": "Foucault"}]}, {"title": "GUHERÎN", "quotes": [{"text": "Her fikr û ramanê sabît (neguher) zindana xwediyê xwe ye.", "author": "Nietzsche"}, {"text": "Fikr û ramanên xwe biguherin; lê li prensîbên xwe xwedî derkevin. Pelên xwe biweşînin; lê dest nadin kokên xwe.", "author": "Victor Hugo"}, {"text": "Du tişt nêrîna te ya derbarê jiyanê de diguherin; nexweşî û xerîbî.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Marên ku kirasên xwe naguherînin mehkûmî mirinê ne. Rewşa kesên fikr û ramanên xwe naguherînin jî wisa ye.", "author": "Nietzsche"}, {"text": "Tu nikarî di heman çemî de du caran xwe bişoyî.", "author": "Heraclitus"}, {"text": "Bajar di kavilê bajarên kevin de, mirî jî di axa miriyên beriya xwe de bi cih dibûn.", "author": "Burhan Sonmez"}]}, {"title": "GUNEH", "quotes": [{"text": "Tu wan bi hemî ayet û kitêbên miqedes yên cîhanê binixumînî, dîsa jî guneh tazî dimînin.", "author": "Mahatma Gandhi"}, {"text": "Kesê hez nake û gunehan nake, bila bê binerd kirin.", "author": "Goethe"}, {"text": "Tu dizanî ji bo çi dinya di vî halî de ye? Karên nîvco, axaftinên nîvco, evînên nîvco, gunehên nîvco û qenciyên nîvco. Ka carekê jî heya dawiyê bibe serî gidî!", "author": "Kazancakis"}, {"text": "Dapîra min her tim digot: “mirov gunehên xwe yên hûthûte di çewalan de vedişêrin, çewtîyên te yên biçûçik jî bi dîwaran ve dadileqînin.", "author": "Frida Kahlo"}, {"text": "Jîr bin mîna maran, lê bêguneh bin mîna kevokan.", "author": "Îsa Mesîh"}, {"text": "Kî ji gunehan bêrî be, bila kevirê yekemîn ew biavêje.", "author": "Îsa Mesîh"}]}, {"title": "HEQÎQET", "quotes": [{"text": "Talibê heqîqetê ne ew kes e ku dibe peyrewê kitêbên kevn û wan bê pirs û sûal qebûl dike.\nTalibê heqîqetê ew e ku şik û guman dike, lê dikole û her tim di lêgerîna rastiyê de berdewam e.", "author": "Îbnû’-l Heysem"}, {"text": "Tu bixwazî hemî dinyayê bixapînî, rastiyê bêje.", "author": "Bismarck"}, {"text": "Pêdivîya heqîqetê bi du kesan heye: yek ji bo gotinê; yek jî ji bo fêhmkirinê.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Birîndarbûna bi heqîqetekê, ji mijûlayîya bi derewekê çêtir e.", "author": "Khalid Hosseini"}, {"text": "Heqîqet ne îzafî ye, nêrînên derbareyê heqîqetê îzafî ne.", "author": "Goméz Dávila"}, {"text": "Tekane tiştê ku heta îro bi awayekî sîstematîk hatiye qedexekirin, heqîqet e.", "author": "Nietzsche"}]}, {"title": "HÊRSBÛN", "quotes": [{"text": "Li destê xwe, zimanê xwe û doxîna xwe miqate be. Li nanê xwe, karê xwe û hevjîna xwe xwedî derkeve. Kêmasiyan veşêre, nepeniyan binixûmîne û hêrsa xwe jî daqurtînê.", "author": "Hecî Bektaşê Welî"}, {"text": "Her tiştê di kêliya hêrsbûnê de tê bilêvkirin, berê di hiş û ramanê kesê bilêv dike de derbaz bûye.", "author": "Sigmund Freud"}, {"text": "Dilê hezker, dinyayê hembêz dike. Dilê hêrsok, xwedîyê xwe dixwe.", "author": "Beethoven"}, {"text": "Kesê ku bi pifikê nêzî agir dibe, ku çirûskek jî li holê nebe, ew ê bi xwe agir derxe.", "author": "Isaac Asimov"}, {"text": "Dema em ji bo xetayên ku kesên din dikin hêrs dibin, em ne wan, lê xwe ceza dikin.", "author": "Immanuel Kant"}, {"text": "Hêrs, encama meyl û dilbijîyên astengkirî ye.", "author": "Paramahansa Yogananda"}]}, {"title": "HEST – HESTIYARÎ", "quotes": [{"text": "Carinan ez hestên xwe bo xwe vedişêrim. Ji ber ku ti ziman têra derbirrîna wan nake.", "author": "Jane Austen"}, {"text": "Hestên ku nayên bilêvkirin, qet namirin. Tenê bi zindîtî tên binaxkirin û di pêşerojê de bi awayekî bizdonektir derdikevin holê.", "author": "Sigmund Freud"}, {"text": "Tiştek bi qasî êşa hevpar mirovan nêzîkî hev nake.", "author": "Necîb Mehfûz"}, {"text": "Ji her hîskirinekê re hevok nayê saz kirin.", "author": "Paulo Coelho"}, {"text": "Dema li gel te qehwê vedixwim, hest pê dikim ku dara qehwê ya ewil bo me hatiye çandin.", "author": "Nîzar Qebbanî"}, {"text": "Eger aqilê mêran di teraziyê de bête bi cih kirin, beramberî hestê jinekê nabe.", "author": "Voltaire"}]}, {"title": "HESÛDÎ – ÇAVNEBARÎ", "quotes": [{"text": "Her tim çêniyek nan ji bo me mezintir xuya dike, dema em wî di destê kesên din de dibînin.", "author": "Fyodor Dostoevsky"}, {"text": "Dema hûn bibin xwedîbandor, hûn dibin xwedîdijmin jî. Ji bo hûn bibin yekî jêhezkirî, bibin yekî ji rêzê, bes e.", "author": "Oscar Wilde"}, {"text": "Yekî ku ji te hez neke, teqez taybetmendiyeke te ya ku jê diheside heye.", "author": "Bella Thorne"}, {"text": "Dê ti carî te efû nekin, ji ber ku te ji wan derbas kiriye û ew li paş hiştine.", "author": "Nietzsche"}, {"text": "Evîneke bêhesûdî ne rast e, ne jî paqij e.", "author": "Victor Hugo"}, {"text": "Ji te nefret dikin, lê pir bi dîqqet te dişopînin.", "author": "Shakespeare"}]}, {"title": "HÊVÎ – BÊHÊVÎTÎ", "quotes": [{"text": "Bi hêviyên mirovan neleyizin.Dibe ku ji wê pêve ti tiştekî wanên din tune be.", "author": "Confucius"}, {"text": "Deriyê hêviyê veneke,ew jana herî xedar e!", "author": "Gotina Yewnanan"}, {"text": "Meçe welatê bêhêvîtîyê, hêvî heye. Xwe negihîne tarîtîyê, roj hene.", "author": "Celaleddîn Rûmî"}, {"text": "Hartirîn kujer ew in ku, hêviyên me dikujin.", "author": "Paula Hawkins"}, {"text": "Jiyana min, goristaneke mişt bi hêviyên binaxkirî.", "author": "Lucy Maud Montgomery"}, {"text": "Nedixwest bimre. Jiyan xweş bû. Rojê germ dikir. Lê mirov?", "author": "Virginia Woolf"}]}, {"title": "HEWES - ZEWQ", "quotes": [{"text": "Jiyan pênc ji sedî hêrs e, du ji sedî hewes e, yê mayî hemî mij û moran e.", "author": "Alain Bosquet"}, {"text": "Helwesta kesekî ya di mijarên cinsî de, prototîpa hemî helwestên wî yên din ne.", "author": "Sigmund Freud"}, {"text": "Dema dil bi şehwetê tije dibe, dev jî bi derewan tije dibe.", "author": "Gotina Skotlandiyan"}, {"text": "Mirov ji aqil bêhtir, di bin bandora hewesên demkî de ne.", "author": "Pascal"}, {"text": "Di nav agirê dilçûnên xwe de dimeşe mirov.", "author": "William Blake"}, {"text": "Valakirina kîsikê mîzê, zewqeke herî mezin a mirovahîyê ye.", "author": "Henry Miller"}]}, {"title": "HEYF – TOL Û BEXŞANDIN", "quotes": [{"text": "Agir bi agir nayê tefandin.", "author": "Gotina Yewnanan"}, {"text": "Xwestina efûkirinê nayê wê wateyê ku hûn neheq in. Wateya wê ew e ku; qedr û qîmetê hûn didin mirovan, ji egoya we mezintir e.", "author": "Sigmund Freud"}, {"text": "Fikra “çav bi çav” an go tolhildan, dê hemî cîhanê kor bike.", "author": "Mahatma Gandhi"}, {"text": "Li hember çar kesan tu carî hişk tev negere: jin, zarok, xizmetkar û kesê lêborînê dixwaze.", "author": "Shakespeare"}, {"text": "Fikra “çav bi çav, dinan bi dinan” dê hemî dinyayê kor bike.", "author": "Mahatma Gandhi"}, {"text": "Ez fikirîm ku bizmaran jî di serê te de bikutim, lê min biryarek xirabtir da; ez ê te ‘tune’ bihesi bînim.", "author": "The Libertine"}]}, {"title": "HÊZDARÎ - LAWAZÎ", "quotes": [{"text": "Tu dilê xwe ji camê çêkî, ên ku bişikînin pirr in. ji hesin çêkî, di dawiyê de wê zeng bigire. Dilê xwe ji deryayê çêke da ên ku bikevinê tê de winda bibin, ên avjeniyê nizanibin jî, bixeniqin.", "author": "Julia Roberts"}, {"text": "Belê em ji xwîn û goşt in, lê divê em bijîn weke em ji hesin û pola ne.", "author": "Sigmund Freud"}, {"text": "Ji êşên xwe yên borî re spasdar be. Jixwe pola bi lêdanê, mirov jî bi êşkişandinê hêzdartir dibe.", "author": "Osho"}, {"text": "Dema av radibe, masî moriyan dixwin... Dema av kêm dibe, morî masiyan dixwin... Bila kes bi hêza xwe ya niha nepesine. Çimkî bê kî yê kê bixwe, herikîna avê biryar dide.", "author": "Gotina Efrîqiyan"}, {"text": "Mafdarîya te têr nake, divê hêza te jî hebe.", "author": "Morgan Freeman"}, {"text": "Hêzdar ew e ku, ji herkesî bêhtir aliyên xwe yên lawaz nas dike. Hêzdartirîn kes ew e ku, dikare aliyên xwe yên lawaz kontrol bike.", "author": "Confucius"}]}, {"title": "HEZKIRIN", "quotes": [{"text": "Ger tu ji min bipirsî, “ez çend caran hatim bîra te?” Ez ê bêjim, “yek.” Ji ber ku tu carekê hatî û hew çûyî...", "author": "Celaleddîn Rûmî"}, {"text": "Ku hezkirin gulek be, rêzgirtin jî ew guldank e ku wê diparêze. Eger gul hino hino biçilmise, baldar bin teqez guldank terikî ye.", "author": "Erich Fromm"}, {"text": "Tu rabî û bêjî ez ê ji yekî/ê hez bikim, ev bi tena serê xwe teşebusek e. Ji bo vê jî; hêz divê, dil divê û korbûyîn divê.", "author": "Jean Paul Sartre"}, {"text": "Tu yê sêwî bimînî di tunebûna hezkiriyê xwe de, welew hemî alem te hembêz jî bike.", "author": "Fyodor Dostoevsky"}, {"text": "Hezkirin ne tenê hesteke bihêz e; ew biryarek, darazek û sozek e jî. Heger hezkirin tenê hestek bûya, nedivabû heya mirinê em soza jêhezkirina kesekî/ê bidin.", "author": "Erich Fromm"}, {"text": "Jin; ji hezkirinê zêdetir, ji jêhezkirinê hez dike.", "author": "Sigmund Freud"}]}, {"title": "HIŞ – HIŞMENDÎ", "quotes": [{"text": "Dîroka dinyayê ji pêşveçûyîna hişmendiya azadiyê wêdetir ne tiştekî din e.", "author": "Hegel"}, {"text": "Kesê serwext û têgihiştî, wekî ku di nav ajalan de be, dema digere di nav mirovan de.", "author": "Nietzsche"}, {"text": "Bi rastî jî tu serkevirek î. Ji bo vekirina hişê te ji mucîzeyekê bêhtir, pêdivî bi metqebekê heye.", "author": "AngelA"}, {"text": "Ziman her tim dinanê arihî dipalêne. Mirov her tim janê di hişê xwe de digire.", "author": "Ingmar Bergman"}]}, {"title": "HÎNBÛNÎ", "quotes": [{"text": "Hêdî hêdî dimirin kesên bûne dîlên hînbûyinên xwe: ew yên her roj di heman rêyê de diçin. Ew yên ku asoya xwe berfireh nakin û naguherînin. Ew yên ku hema rengê cil û bergên xwe jî naguherînin û ew yên bi kesekî biyanî re naaxivin.", "author": "Pablo Neruda"}, {"text": "Zincîra hînbûnîyan ewil bi qasî ku neyê hîskirin zirav e, piştre bi qasî ku neyê qetandin sitûr dibe.", "author": "Benjamin Disraeli"}]}, {"title": "HUNER - HUNERMEND", "quotes": [{"text": "Kesê bi destê xwe dixebite, KARKER e. Kesê bi destê xwe û mêjîyê xwe dixebite, HOSTE ye. Kesê bi destê xwe, mêjîyê xwe û dilê xwe dixebite, HÛNERMEND e.", "author": "Goethe"}, {"text": "Min dil û canê xwe tevlî karê xwe kir. Û min di vê oxirê de aqilê xwe jî winda kir.", "author": "Vincent van Gogh"}, {"text": "Eger li welatekî axaftin ji huner û wêjeyê bêhtir li ser siyasete be, ew welat di rêjeya sêyem de ye.", "author": "Nietzsche"}, {"text": "Ger ez careke din bêm dinê; çiqas tank, tifing, çek û sîleh hebin ez ê hemîyan bihelînim û bikim tembûr, cimbiş û zirne.", "author": "Aram Tigran"}, {"text": "Eger li welatekî ji aqil û hunerê bêhtir, girîngî bi serwet û diravan bê dayîn; li wê derê kîsikên pereyan nepixîne, lê mêjî vala mane.", "author": "Nietzsche"}, {"text": "Fîlmekî baş, mina zixurê di hindûrê şekalê de ye.", "author": "Lars von Trier"}]}, {"title": "IŞQ Û EVÎN", "quotes": [{"text": "Işq di hemî dînan de heye, lê dînê işqê tune ye.", "author": "Celaleddîn Rûmî"}, {"text": "Işq: noqbûna deryayê, hezkirin: soberîya tê de.", "author": "Elî Şerîetî"}, {"text": "Kesek tê cem te.\nTiştekî ji te naxwaze,\nqet tiştekî..!\nHezkirinê jî.\nBi vî awayî evîn diwelide.", "author": "Mario Salas"}, {"text": "Heta ku çavên te welatê min bin, ez siltanê zemên im.", "author": "Nîzar Qebbanî"}, {"text": "Dema jin ji mêrekî hez nekin, qet dilê xwe bi wî mêrî naşewitînin. Lê dema ji mêrekî hez dikin, îcar dilê xwe bi xwe naşewitînin.", "author": "Alexsandre Dumas"}, {"text": "Tiştekî ku hûn ne xwedîyê wî ne, hûn dixwazin wî tiştî bidin kesekî ku ew wî ji we nexwaze. Ew jî “işq” e.", "author": "Jacques Lacan"}]}, {"title": "JIBÎR KIRIN", "quotes": [{"text": "Tiştek namîne di bîra me de, ji bilî tiştên em dixwazin ji bîr bikin.", "author": "Fyodor Dostoevsky"}, {"text": "Çûyîn tenê çalakiyek e. Lê ‘jibîr kirin’ şoreşeke qirase ye.", "author": "Nazim Hikmet"}, {"text": "Ji bo birînek baş bibe, divê tu dev ji xwerandina wê berdî.", "author": "Paulo Coelho"}, {"text": "Kesê ji bîr dike, baş dibe.", "author": "Nietzsche"}, {"text": "Yekî ku zêde li kesên din difikire, xwe ji bîr dike.", "author": "Shakespeare"}, {"text": "An êşên xwe jibîr bike,an gora xwe bikole.", "author": "Balzac"}]}, {"title": "JIN Û MÊR", "quotes": [{"text": "Jin ji derewan nefret dikin, mêr jî ji xapandinê. Lê herdu jî di tiştên ku jê nefret dikin de hoste ne!", "author": "Nietzsche"}, {"text": "Jin ji nûra Xwedê ye.Jin ne tenê aferîdek e; afirîner e jî.", "author": "Celaleddîn Rûmî"}, {"text": "Jin, dafikeke xwezayî ye.", "author": "Nietzsche"}, {"text": "Mêrantiya te dikeve, dema jinek ji hezkirina te poşman dibe.", "author": "Nîzar Qebbanî"}, {"text": "Jin wek siyê ye; tu li pey herî,ji te direve, tu jê birevî, li pey te tê.", "author": "Gotina Spaniyan"}, {"text": "Zêr bi agir, jin bi zêr, mêr bi jinê tê ezmûnkirin.", "author": "Shakespeare"}]}, {"title": "JÎYAN", "quotes": [{"text": "Sirf ji bo tu nefesê didî û distînî, tu zen dikî ku tu sax î?", "author": "Celaleddîn Rûmî"}, {"text": "Kesê dizane ku teqez dê li bin sîya wan daran rûnenê, lê dîsa jî daran diçîne. Wî kesî ji bo têgihiştina wateya jîyanê gavek avêtiye.", "author": "Tagore"}, {"text": "Li hêviya mûcîzeyan nesekine,jiyan serapa mûcîze ye.", "author": "Albert Einstein"}, {"text": "Mirin ne tiştek e,afata mezin jiyan e.", "author": "Victor Hugo"}, {"text": "Li dinyayê tiştê herî kêmpeyde,jiyîn e. Gelek kes, tenê hene û hew.", "author": "Oscar Wilde"}, {"text": "Mirov wek xapandîyekî dest bi lîstika mezin a jiyanê dike û wek sextekar û fêlbazekî lîstikê diqedîne.", "author": "Voltaire"}]}, {"title": "KAOS", "quotes": [{"text": "Kesê navinc ji aqilê xwe razî ye.Tenê kesên zîrek pêjna kaosê dikin û hişê wan tevlîhev dibe.", "author": "Osho"}, {"text": "Bawerîyeke tam bi min re çêbûye ku, şarezayî û şaristanîya me tenê tebeqeyek tenik e. Li binê wê, okyanoseke bê ser û bin ji kaos, cehalet û tarîtiyê heye.", "author": "Werner Herzog"}, {"text": "Ger vebe çavên korekî û bibîne van tiştên xirab li ser rûyê erdê; dê nifiran bike li kesê ku çavên wî baş kirine.", "author": "Nietzsche"}]}, {"title": "KAPÎTALÎZM", "quotes": [{"text": "Kapîtalîzm ol e. Banqe perestgeh, banqevan mamosteyên ayînî, dewlemendî beheşt, xizanî dojeh, dewlemend kesayetên pîroz, xizan gunehkar, sermaye pîroz, dirav jî XWEDA ye!", "author": "Miguel D Lewis"}, {"text": "Daneheva sermîyan mîna vexwarina ava şor e. Çiqas vedixwî tî dibî, çiqas tî dibî dîsa vedixwî. Bi kurtasî pençeşêreke bêdawî ye.", "author": "Friedrich Engels"}, {"text": "Hûn tev jî dizanin; Li vî welatî pere jî, ax jî, qanûn jî, fikr jî, bawerî jî ... Hema her tişt ji sermayedaran re xizmetê dikin.", "author": "Karl Marx"}, {"text": "Mirovên serdema modernîteya kapîtalîst guhên xwe kirin pariyek goşt û xwarin! Êdî bi zikê xwe dibihîzin.", "author": "Barin Helim"}, {"text": "Civaka kapîtalîst wiha ye;yên ku bênavber dixebitin,ti carî nabin xwedîyê tiştekî.Yên ku qet naxebitin,bi her awayî li kêfa xwe dinêrin.", "author": "Emma Goldman"}, {"text": "Zêdebûna nirxê tiştan û daketina nirxê mirovan, hevrêje ne.", "author": "Karl Marx"}]}, {"title": "KARAKTER – XÛY", "quotes": [{"text": "Hinek mirovan ji ber ku her timî egoya xwe têr kirine, karaktera wan birçî maye.", "author": "Eliot"}, {"text": "Demên dijwar,karakterê mirov yê rasteqînderdixe holê.", "author": "Mark Manson"}, {"text": "Tobeya gur,mirina wî ye.", "author": "Gotina Îraniyan"}, {"text": "Jêhatbûyîna te dikare tehilkişîne lûtkeyê;lê tiştê te li wir payîdar bihêlekarakterê te ye.", "author": "Zig Ziglar"}, {"text": "Tu nikarî mêşan qanih bikîku kulîlk ji gilêşê çêtir in.", "author": "Shakespeare"}, {"text": "Dinya li dinê,çavê gûr li bizinê.", "author": "Gotina Kurdan"}]}, {"title": "KÊMASÎ", "quotes": [{"text": "Kêmasîyek, kêmasiyekê dinixumîne.", "author": "Lacan"}, {"text": "Hin kes mîna ku li gencîneyan bigerin,li eyb û kêmasiyên mirovan digerin.", "author": "Cicero"}, {"text": "Ti kêmasiya min tune ye,tenê mihtacê xwe me û hew.", "author": "Kafka"}, {"text": "Her kesek, biqasî kêmasiyên xwe ezyetê dide kesên din.", "author": "Nîzar Qebbanî"}, {"text": "Birçîtîya hezkirinê mîna kêmbûna xwê yan jî vîtamînê,nexweşiyeke kêmasîyê ye.", "author": "Abraham Maslow"}, {"text": "Kêmasiyên laşên mirov bi mîtrok qumaş tê nixumandin, lê kêmasiyên mêjî di nîqaşa ewilîn de derdikeve holê.", "author": "Anonîm"}]}, {"title": "KEN Û GIRÎN", "quotes": [{"text": "Kesek dema digirî,ne tenê ji bo bûyera wê kêliyê,ji bo hemî bûyerên ku heta nihali ser wan negiriye, digirî.", "author": "Mario Benedetti"}, {"text": "Carinan her derê te digirî,Ji xeynî çavên te.", "author": "Necîb Mehfûz"}, {"text": "Gewretirîn dijmin bo otorîteyê û rêya herî dijwar bo lawazkirina wê, kenê bi hîqehîq e.", "author": "Hannah Arendt"}, {"text": "Hinek jin bawer dikin kuhinekî bigirîn,dê encama 2+2 bibe 5", "author": "George Bernard Shaw"}, {"text": "Di kenê mirovan dexencer veşartî ne.", "author": "Shakespeare"}, {"text": "Tiştekî ji ken xweştir hebe ew jî kenandin e.", "author": "Fyodor Dostoevsky"}]}, {"title": "KERB Û KESER", "quotes": [{"text": "Kesekî ku bixwaze derd û kûlên te sivik bike, tuneye. Tenê meraq dikin û hew.", "author": "Will Smith"}, {"text": "Jîyan ne li gorhejmara henaseyên kuhûn didin distînin tê pîvan; ;lê li gor kêlîyên “bêhnçikên”tê pîvandin.", "author": "George Carlin"}, {"text": "Bila xema sibê ji sibê re be,derdê her rojekê bes î xwe ye.", "author": "Încîl"}, {"text": "Derd û kûlên xwe ji kesî re mebêje.Ji sedî bîst ne xema wan e,ji sedî heştê jî dema derd û kûlên te dibihîzin, pê kêfxweş dibin.", "author": "Jason Statham"}, {"text": "Mala afirînerê xewê ava be;xew lihêfeke ku hemî derd û kulênme dinixumîne.", "author": "Cervantes"}, {"text": "Xwe bi tiştekî mijûl bikin, ev dermanê herî erzan û herî mifadar e li vê dinê.", "author": "Dale Carnegie"}]}, {"title": "KIRYAR – ÇALAKÎ", "quotes": [{"text": "Ji min re behsa baranê neke, bibare.", "author": "Victor Hugo"}, {"text": "Mirov heya neyê keviya kendal û zinaran, bi per û bask nabe.", "author": "Schopenhauer"}, {"text": "Tu nefirî bazde, baznedî bimeşe, nemeşî bi çarlepkan here. Lê çi bikî bike tu neçar î ku bi pêş de herî.", "author": "Martin Luther King"}, {"text": "Tiştên tu dibêjî girîng in. Lê tiştên tu dikî girîngtir in.", "author": "Nora Roberts"}, {"text": "Kesek bi xweziyan, nagihîje baqê keziyan.", "author": "Gotina Kurdan"}, {"text": "Rabe ser xwe! Ji bo razanê ebedîyet li pêşîya me ye.", "author": "Omar Xeyam"}]}, {"title": "KÎN Û NEFRET", "quotes": [{"text": "Nefreta ku ji sofîtî û oldarîya zêde çêdibe, ji hemî nefretên din kûrtir û dirêjtir e.", "author": "Spinoza"}, {"text": "Berî avê, bi hezkirinê destmêj bigre. Nimêja dilê kîndar qebûl nabe.", "author": "Celaleddîn Rûmî"}, {"text": "Nefret nekin. Nefret barekî wisa giran e ku, nayê ragirtin.", "author": "Martin Luther King"}, {"text": "Kesên ji te nefret dikin, esas ew heyranên te yên veşartî ne ku, tênagihîjin bê çima evqas mirov ji te hez dikin.", "author": "Paulo Coelho"}, {"text": "Qey ji xwe hezkirin her tim ne raserî nefretê bû?", "author": "Charles Dickens"}, {"text": "Ne ku tu ji min nefret dikî,tu ji wî suretê ku te di nav xeyalên xwe de ji bo min çêkiriye nefret dikî.Ew sûret ne yê min e, tu bi xwe yî.", "author": "Adonis"}]}, {"title": "KOLE - XÛLAM", "quotes": [{"text": "Sê xwestek we dikin bendeyê kesên din; xwesteka hezkirinê, xwesteka ecibandinê, xwesteka teqdîrkirinê.", "author": "Osho"}, {"text": "Bendeyên serpêl,kenê xwe bi peyva azadîyê dikin", "author": "J.J. Rousseau"}, {"text": "Eger ji asîmanan azadî bibare,tê bibînî ku hin xûlam bi sîwanan digerin.", "author": "Platon"}, {"text": "Heta xwedî destûr nede,kuçik nareye.", "author": "Gotina Ereban"}, {"text": "Xulam, ew ê ku nikarefikr û ramanên xwe bêje.", "author": "Euripides"}, {"text": "Heger mûçeyê te tenê têra xwarin û razana te bike, tiştê tu dikî ne kar û xebat e. Berê navê vî tiştî koletî bû.", "author": "Django Unchained"}]}, {"title": "KOLONYALÎZM - DAGIRKERÎ", "quotes": [{"text": "Nanê te didizin.Piştre çêniyekî jê didin teû dixwazin tu j bo camêriya wan jî spasiya wan bikî.", "author": "Gassan Kenafani"}, {"text": "Heta hin kes ji hundir derî li barbaran venekin, barbar nikarin têkevin bajêr.", "author": "Christopher Hitchens"}, {"text": "Kesên nikarin li ber mêtingerên xwe rabin, dibin dijminê birayê xwe û hêza xwe li dijî birayê xwe bikar tînin...!", "author": "Frantz Fanon"}, {"text": "Xwekêmdîtin, taybetmendîyeke bindestan e.", "author": "Paulo Freire"}, {"text": "Miletên bindest, exlaqê wan jî xirab dibe. Çiqas tên piştguhkirin, ewqasî dibin wek ajalên ku tenê li êm û alifê xwe difikirin.", "author": "Îbn Xeldûn"}, {"text": "Çermsipî hem pihînan li devê qûna me dixin, hem jî şêweyê bertekdayîna me ya li dijî pihînê dîyar dikin.", "author": "Steve Biko"}]}, {"title": "KOMEDÎ – TRAJEDÎ", "quotes": [{"text": "Komedî bi dawî bû,trajedî destpê dike.Wê dinya bibe cîyekî hişktir,sermatir, dilgivêştir û bêrehmtir.", "author": "Albert Caraco"}, {"text": "Di dîrokê de bûyerû kesayetên mezin ducare dibin:cara yekemîn trajedî,cara duyemîn jî komedî.", "author": "Karl Marx"}, {"text": "Zarokek ji tarîtiyê bitirse, normal e. Lê trajediya mezin ew e ku, kesên qirrase ji ronahiyê ditirsin.", "author": "Platon"}, {"text": "Dinya ji kesên bîrewer re komedî, ji kesên dilzîz re jî trajedî ye.", "author": "Zygmunt Bauman"}]}, {"title": "KOMKUJÎ", "quotes": [{"text": "Jibîrkirina komkujiyekê jî, cûreyek ji komkujiyê ye.", "author": "Jean Baudrilard"}, {"text": "Bizane, em di bin barana xwîna straneke kîndar de ne. Li ser rihê zemên, ji qedera me re, ayetên hezar enfalan xwendine...", "author": "Fatma Savci"}, {"text": "Jenosîd ne tenê qirkirina mirovan e. Xesbkirina mafê ziman û çandê jî jenosîd e.", "author": "Îsmaîl Beşîkçî"}, {"text": "Bi qasî ku î’ya berîya y’yê tê nîqaşkirin, ewqasî bişaftin û qirkirina çandî nayê nîqaşkirin.", "author": "Helîm Barîn"}]}, {"title": "KONTROL – OTOKONTROL", "quotes": [{"text": "Di niqirandin û şayîk kirina peykerê xwe de berdewam be.", "author": "Plotinos"}, {"text": "Kesê nikaribe xwe kontrol bike, ne azad e.", "author": "Pythagoras"}, {"text": "Kesê bi xwe dikare, bi hemî dinyayê jî dikare.", "author": "Shakespeare"}, {"text": "Tu bikaribî kurtedemekê hêrsa xwe kontrol bikî, tu yê xwe ji sed rojên poşmaniyê xilas bikî.", "author": "Gotina Çîniyan"}]}, {"title": "KURD – KURDÎ", "quotes": [{"text": "Derkeve ji dibistanê,derkeve ji mizgeftê,derkeve ji pirtûkxaneyê...Hilkişe sertara çiyayekî û li jêr binêre.Tu çi dibînî?Welatekî dabeşkirîbi ser çar parçeyan.", "author": "Îbrahîm Sediyanî"}, {"text": "“Ûmmet”, dereweke kuji bo xapandina Kurdantê mobîlîzekirin.", "author": "Mücahit Bilici"}, {"text": "Min bi kurdî nivîsî ku ji bilî kurdan û xwedê kesek nikaribe bixwîne.", "author": "Hesenê Metê"}, {"text": "Eger Kurdêk qisey babî nezanî\nMuheqqeq dakî hîz e babî zanî", "author": "Hacî Qadirê Koyî"}, {"text": "Gulê baxê îremê bohtan im,\nŞebçiraxê şevê Kurdistan im.", "author": "Melayê Cizîrî"}, {"text": "Kurdistana min rakişandine çarmixê\nmîna Îsayê kurê Xwedê...", "author": "Rênas Jiyan"}]}, {"title": "LAÎSÎZM", "quotes": [{"text": "Totalîtarîzm, yekbûna bêyom a dîn û dewletê ye.", "author": "Goméz Dáwila"}, {"text": "Qet bawerîya min bi wan kesan tûneye ku, “dîn” ji berjewendiyên xwe yên sîyasî re dikin alet. Tiştê herî pîs û çepel di sîyasetê de, bikaranîna dîn e.", "author": "Christopher Hitchens"}, {"text": "Ku ji Ereban bipirsin, “hûn dewleteke dînî dixwazin, an dewleteke sekûler?” Ew ê dewleta dînî hilbijêrin û biçin di dewleteke sekûler de bijîn.", "author": "Ali Al-Wardi"}, {"text": "Ya rastî îslamcîtî, xizmeta laîsîzmê dike. Ji ber ku nirxên dînî, di rêya berjewendiyên sîyasî de feda dike.", "author": "Olivier Roy"}, {"text": "Dewlet di kêlîyên şer û felaketên mezin de, bêçaretîya xelkê bi oldariyê tepeser dike.", "author": "Nietzsche"}]}, {"title": "LÊKOLÎN", "quotes": [{"text": "Beguman hişekî lêkolîner, ji tiştên ciyawaz hez dike.", "author": "Antony Black"}, {"text": "Hey cûbbereşo, roja te şev e,\nKeviran neavêje lêkoleran.\nEw li hûnera afirîner digerin,\nLê hiş û aqilê te her tim li ser tiştên ku destmêjê dişkînin e.", "author": "Omer Xeyam"}, {"text": "Jiyan ne baweriyek e,lêkolîneke hûr û kûr ali ser rastiyê ye.", "author": "Osho"}, {"text": "Ger tu talibê dirr û gewheran bî, divê noqî binê deryayan bibî. Ma li peravan ji bilî kefikê çi heye?", "author": "Celaleddîn Rûmî"}, {"text": "Kesê qaqilkê gwîzê neşikîne û kakil nebîne, zen dike ku gwîz tenê qaqil e.", "author": "Xezalî"}]}, {"title": "LÊPIRSÎN – KRÎTÎK", "quotes": [{"text": "Gelek ji me, temenê xwe bi lêgerîna nîvê xwe yê din derbas dikin.", "author": "Haruki Murakami"}, {"text": "Cûdahîyeke mezin di navbera lêgerîna “mirovên xweşik” û lêgerîna “xweşikbûyîna mirovan” de heye...", "author": "Farid Farjad"}, {"text": "Ji lêgerên heqîqetê re rêzdar bin, lê xwe dûr bikin ji wan kesên ku dibêjin ‘em heqîqetşînas in.’", "author": "Voltaire"}, {"text": "Em mecbûr in her tim li heqîqetê bigerin... Ji ber ku heqîqet bêdawî ye.", "author": "Sartre"}, {"text": "Êş, aqil mecbûrî lêgerînê dike.", "author": "Deleuze"}, {"text": "Kesek nikare heqîqetêbi ser mêjiyê te de birijîne,heqîqet ew e ku,tu bi xwe lê bigerî û keşf bikî.", "author": "Naom Chomsky"}]}, {"title": "LIV Û TEVGER", "quotes": [{"text": "Eger em ti tiştî nekin,dê her tişt wek xwe bimîne.", "author": "Aimee Carter"}, {"text": "An rêyekê bibîne,An rêyekê veke,An jî xwe ji rê bide alî.", "author": "Confucius"}, {"text": "Di cîhaneke konformîstde liv û tevgerên antîsosyal,nîşaneya zîrekbuyînê ye.", "author": "Nikola Tesla"}, {"text": "Liv û tevgera herî mirovperwer çiye? Rêlibergirtina fedîkirina mirovekî ye.", "author": "Nietzsche"}, {"text": "Raze, rabe... Raze, rabe...Çi jiyanek rezîl!", "author": "Kafka"}, {"text": "Kesê xwe tev nede,bi zincîrên kupê hatiye girêdan nahise.", "author": "Rosa Luxemburg"}]}, {"title": "LÎSTIK", "quotes": [{"text": "Ez fêrî lîstika kişikê nebûm.Ji ber ku min nedixwest leşkerên xwe bo jiyîna mîr û paşayan bidim kuştin.", "author": "Mahatma Gandhi"}, {"text": "Jiyan dişibe lîstika îskambîlan.Kartên tên destê we, determînîzmê (qeder) temsîl dike, bikaranîna wan jî vîna azad e.", "author": "Nehru"}, {"text": "Lîstikeke ku evîn û rik tê de tunebe,jin lîstikvaneke pileya navîn e.", "author": "Nietzsche"}, {"text": "Ji bîr meke,pîyonek dikare hemîlîstikê biguherîne.", "author": "Aimee Carter"}]}, {"title": "LîYAQAT", "quotes": [{"text": "Kesên ne li gor lîyaqetêdibin xwedîyê meqamekî;jêrdestên xwe gez dikin,ji raserên xwe re jî dûv dihejînin.", "author": "Xezalî"}, {"text": "Tiştê dûrî aqilan ew e ku; hûn mirovên zîrek erkdar dikin û piştre ji wan re dibêjin: “wiha bikin.” Lê em mirovên zîrek erkdar dikin, ji bo ku ew ji me re bêjin ka em çi bikin.", "author": "Steve Jobs"}, {"text": "Hezkirin, şayanî her mirovî ye, lê her mirov ne şayanî hezkirinê ye.", "author": "Sigmund Freud"}, {"text": "Mirovatî cileke wisaye ku, li herkesî rûnane.", "author": "Tolstoy"}, {"text": "Kesê te wek bihara xwe nebîne, kulîlkên jiyana xwe pê nede çinîn.", "author": "Al Pacino"}, {"text": "Ker eynî ker e, lê bi kûrtanekî nû.", "author": "Gotina Pêştûnan"}]}, {"title": "MAF – MAFDARÎ", "quotes": [{"text": "Deklerasyona Gerdunî ya Mafên Mirovan dide zanîn ku; bê şert û merc “mafê jîyanê” nirxê herî bingehîn yê mirovahîyê ye. Divê em topyekûn li dijî mirineke ku vî mafê bingehîn binpê dike, têbikoşin.", "author": "Yuval Noah Harari"}, {"text": "Helbet tu dikarî bibî kuçik, lê heqê te tune bi reyyîn û ewtîna xwe me aciz bikî.", "author": "Shakespeare"}, {"text": "Tu mafdar bî, nehewce ye tu dengê xwe bilind bikî.", "author": "Gotina Japonan"}, {"text": "Mafê tu bikaribî bi xwe bi dest bixî, nehêle hin kesên din bidin te.", "author": "Nietzsche"}, {"text": "Mirovên “azad” dibin peyrewên mafdaran. Mirovên “bende” dibin peyrewên hêzdaran.", "author": "Anonîm"}, {"text": "Dibe ku mirin ji her tiştî bêhtir nêzî me be, lê ez ji vê yekê na tirsim. Em ê di têkoşîna bo her mafdarîyê de berdewam bin.", "author": "Maria Teresa Mirabel"}]}, {"title": "MALBAT", "quotes": [{"text": "Heytehola malbatê, aramiya dil e.", "author": "Dostoyevski"}, {"text": "Jîyana hundirê malê dîlîtî ye. Mal qirêj e. Azadî encex bi terk kirina malê tê bidestxistin.", "author": "Buddha"}, {"text": "Di egîdî û mêrxasiyê de tu Rûstemê Zal jî bî, li malê tu hêsîrê hevjîna xwe yî.", "author": "Celaleddîn Rûmî"}, {"text": "Hemî malbatên bextewer dişibin hev. Lê bextreşiya her malbateke besiûd, naşibe ya din.", "author": "Tolstoy"}]}, {"title": "MALDARÎ – DEWLEMENDÎ", "quotes": [{"text": "Heger tiştekî we yê ku bi pereyan nayê kirîn tune be, hûn ne dewlemend in.", "author": "Garth Brooks"}, {"text": "Pere (dirav) tenê dikare ji bo we nivîneke baş bistîne, ne xeweke baş. Dikare xêniyekî baş bistîne, ne malbat. Dikare hevalekî jî bistîne, lê ne dosteki baş.", "author": "Zig Ziglar"}, {"text": "Dibêjin, şadî û kamranî bi sermiyan nayê kirîn. Lê ez dixwazim di tirimpêla Ferrarî de bigirîm.", "author": "Jason Statham"}, {"text": "Beheşta dewlemendan, bi dojeha xizanan hatiye avakirin.", "author": "Victor Hugo"}, {"text": "Pere, xizmetkarekî baş,efendîyekî xirab e.", "author": "Syrus"}, {"text": "Dema ez biçûk bûm, min digot qey maldarî her tişt e. Piştî ku ez mezin bûm, min dît ku ez mafdar im.", "author": "Oscar Wilde"}]}, {"title": "MANTIQ", "quotes": [{"text": "Ji bo pûçkirina îdiayeke bê delîl,pêdivî bi delîlan tuneye.", "author": "Christopher Hitchens"}, {"text": "Ev jî tê de, hemî gelemperîkirin şaş in.", "author": "Nietzsche"}, {"text": "Nebûna palpiştê, ne palpişta “nebûnê”ye. (tunebûna delîlê,ji tunebûnê re nabe delîl)", "author": "Carl Sagan"}, {"text": "Tiştê bi mentiq nayê dermankirin, bi demê derman dibe.", "author": "Seneca"}, {"text": "Dema Xwedê bela xwe dide kesekî,pêşî wî ji mantiq bêpar dike.", "author": "Mihail Bulgakov"}, {"text": "Mantiq we ji A’yê digihîne B’yê,lê xeyal we digihîne her deverê.", "author": "Einstein"}]}, {"title": "MÊJÎ", "quotes": [{"text": "Mêjîyê mirov dişibe kevirê aşan.Ger hûn tiştekî nûjen neavêjin hûndir,dê xwe bi xwe bihêre.", "author": "Îbn Xeldûn"}, {"text": "Mêjiyên mezin ramanan gotûbêj dikin, mêjiyên navinc bûyeran gotûbêj dikin, mêjiyên biçûk jî mirovan giftûgo dikin.", "author": "Eleanor Roosevelt"}, {"text": "Razana mêjî, cinawiran hildiberîne", "author": "Francisco Goya"}, {"text": "Zanebûna hindik, talûke ye.Yan tê ava ferzanebûnê ji kûr bikişînî, yan jî tu yê qet li tehma wê nenêrî.Avên tenik mêjî jehrîn dikin,lê avên kûr mêjî paqij dikin.", "author": "St. Thomas Aquinas"}, {"text": "Ez ji kesên ku mêjiyê wan ji devê wan mezintir e, hez dikim.", "author": "John Verdon"}, {"text": "Di jiyanê de tiştê rêbertiya me dike,ne mêjî ye, xûy û hînbûnîyên me ne.", "author": "Hume"}]}, {"title": "MELAQÎ – ŞELAQÎ", "quotes": [{"text": "Kuçik bi qezenca xwediyên xwe re eleqedar nabin. Tiştê girîng bo wan, mezinahiya hestiyê ku diavêjin ber wan.", "author": "Tayfun Talipoglu"}, {"text": "Dema keştiyek dike ku binav bibe, ewilî mişk wê keşetiyê terk dikin.", "author": "Fyodor Dostoevsky"}, {"text": "Ku li welatekî qezenca melaqî û şelaqiyê, ji ya diristiyê zêdetir be, ew welat helak dibe.", "author": "Montesquieu"}]}, {"title": "MÊVAN – CÎRAN", "quotes": [{"text": "Mêvanê sibehê zêr e. Êvarê dibe zîv, dema dimîne şevê, dibe sifr.", "author": "Mark Twain"}, {"text": "Kurd mirovên mêrxas û camêr in.Goşt, nan û helawîyê pêşkêşî mêvanên xwe dikin.", "author": "İbn Battuta"}, {"text": "Ji cînarên xwe hez dike,lê tixûbê navbera xweû wan raneke.", "author": "Gotina Babîliyan"}]}, {"title": "MIRIN", "quotes": [{"text": "Ne mirîyan dizanibû mirin çi yene zindîyan.", "author": "Carlos Fuentes"}, {"text": "Mirin miqnatîsa Xwedê ye.", "author": "Gotina Swêdiyan"}, {"text": "Nanê ji destê xelkê, tehl e.", "author": "Dante Alighieri"}, {"text": "Em bi êşê hatin çandinû bi mirinê tên çinîn...", "author": "Hesenê Metê"}, {"text": "Bi qasî mirinê fireh in,per û baskên jîyanê.", "author": "Sohrap Sepehrî"}, {"text": "Lê mirî derewan nakin.", "author": "Akira Kurosawa"}]}, {"title": "MIROVV - MIROVAHÎ", "quotes": [{"text": "Ka em bigerin, belkî dawiyêem li mirovekî rast werin.", "author": "Jean Jacques Rousseau"}, {"text": "Duh me azadî winda kir.Îro em hezkirinê winda dikin.Ez ji sibê ditirsim;Ji ber ku em ê mirovahîyêji binî winda bikin.", "author": "Mehmûd Derwîş"}, {"text": "Sê cure mirov hene: Yekemîn: Weke nan e; her tim lê digerî, carinan dibînî. Duyemîn: weke derman e; dema pêdiviyê lê digerî kêm caran dibînî. Sêyemîn: weke mîkrobê ye; tu lê negerî jî dibe, çimkî her tim ew te dibîne.", "author": "Anton Chekhov"}, {"text": "Mirov gurê hev in.", "author": "Hobbes"}, {"text": "Hinek mirov devera diçin xweş dikin, hinek jî devera terk dikin.", "author": "Oscar Wilde"}, {"text": "Mirovahî gelekî pêş ketiye; êdî nema tê xûyakirin.", "author": "Robin Sharma"}]}, {"title": "MÎTOLOJÎ", "quotes": [{"text": "Mirov ji rastiyê û tiştên besît hez nakin, kêfa wan ji efsaneyan û tiştên xapînok re tê.", "author": "Edmond de Goncourt"}, {"text": "Wezîfeya ku di civakên hov de mîtan pêk dianî, di civakên modern de îdeolojî pêk tînin.", "author": "N. Rops"}, {"text": "Herkes ji Zeus hatiye. Çi bîyanî, çi xêzan.", "author": "Homeros"}, {"text": "Girse ji heqîqetê bêhtir, nêzî demagojî, çîrvanok, mîtolojî û xeyalan e.", "author": "Alexis de Tocqueville"}, {"text": "Hûn dikarin di hemî romanên min de şopa Hektor bibînin.", "author": "Mehmet Uzun"}]}, {"title": "MÎZAH", "quotes": [{"text": "Ku jiyan te nede kenandin, xûya ye te henek fêhm nekiriye.", "author": "Anton Chekhov"}, {"text": "Jixwe yê nikaribe tinazê xwe bi xwe bike, dê bibe pêkenok û lêhbokê devê xelqê.", "author": "Carl Gustav Jung"}, {"text": "Henek û xweşî, di seriyekî keregêj de peyde nabin.", "author": "Cervantes"}, {"text": "Bi melkemot re henek nabin.", "author": "Gotina Cihûyan"}, {"text": "Di binê her henekekê de rastiyek heye.", "author": "Gotina Rûsan"}, {"text": "Bi henekekê tu dikarî her tiştî bibêjî, heta bi rastiyê jî.", "author": "Sigmund Freud"}]}, {"title": "MODERNÎZM", "quotes": [{"text": "Cihana kevn dimire; ya nû jî hê di asoyê de nehatiye hilatin. Û di vê tarîgewrikê de cinawir zêde dibin.", "author": "Antonio Gramsci"}, {"text": "...ditirsim, ji vê serdema ku dilê xwe winda kiriye.", "author": "Furûx Ferruxzad"}, {"text": "Koleyê modern, tenduristîyê ji azadî û xweserîyê çêtir dibîne.", "author": "Byung-Chul Han"}, {"text": "Di serdema modern de; Peyv zêde, wate hindik e. Zagon zêde, edelat hindik e. Çenebaz zêde, bêjekar hindik û meş zêde, pêşketin hindik e.", "author": "Jim Carrey"}, {"text": "Mirovê serdema modern, ji yê serdema hoveber bêçaretir û bitenêtir e.", "author": "Jung"}, {"text": "Di van rojan de, divê mirov rahêje gopalê xwe û li serê dinyayê bixe.", "author": "Mayakovski"}]}, {"title": "MOSÎQA", "quotes": [{"text": "Bo guhekî ji muzîkê fêhm dike bêje strana xwe.", "author": "Shakespeare"}, {"text": "Tu dikarî mirov ji mûzîka ku lê guhdarî dike nas bikî.", "author": "Fringe"}, {"text": "Tenêtî ew e ku mûzîk jî li te guhdarî dike.", "author": "Ozdemîr Asaf"}, {"text": "Stranên kesên xirab tune ne.", "author": "Nietzsche"}, {"text": "Çiqas gotinên sivik hene ku em ji bilêvkirina wan şerm dikin, dibin stran.", "author": "Voltaire"}, {"text": "Carinan qehweyekê firr dikî, stranekê vedikî û bêdeng dibî. Û hemî tiştên tu dixwazî vebêjî, ew stran ji dêvla te ve dibêje.", "author": "Winged Creatures"}]}, {"title": "NANKORÎ", "quotes": [{"text": "Nankorî karê kesên zeîf e. Di nav mirovên hêzdar de ez li rastî nankorekî nehatim.", "author": "Goethe"}, {"text": "Mirovê nankor ew e ku bihayê her tiştî dizane, lê qîmetê tu tiştî nizane.", "author": "Oscar Wilde"}, {"text": "Mirov çi ye? Nankorekî duling e.", "author": "Dostoyevski"}, {"text": "Vê ji bîr neke: fedekariya zêde, bêwefatiya zêde bi xwe re tîne.", "author": "José Mauro de Vasconcelos"}, {"text": "Meyla nankoriya mirovî ji zeîfbûna wî te. Lewra barê minetê giran e.", "author": "Ducane Cündioğlu"}, {"text": "Jibîr meke; fedekarîya zêde, bêwefabûna zêde bixwere tîne.", "author": "Eliot"}]}, {"title": "NASNAME", "quotes": [{"text": "Berdêla windakirina nasnameya we; koletî, bindestî û çewisandin e.", "author": "Alija Izetbegović"}, {"text": "Ziman; şanîderê nasnameyê, mîrateya çandê û îfadeya şênber a neteweyî ye.", "author": "Leslie Green"}, {"text": "Nasnameya etnîk bi xetên fîzîkî ava nabe. Ev nasname bi hafizeya parvekirî û qedera hevpar ava dibe.", "author": "Anthony Smith"}, {"text": "Ziman şertê heyînê yê pêşîn e.", "author": "Mîr Celadet Alî Bedirxan"}, {"text": "Zimanê min nasnameya min e. ez... û ez. Ez zimanê xwe me. Ez di zimanê xwe de penaber im û dilê min perengekî kurdî ye li ser çiyayên hêşîn...", "author": "Mehmûd Derwîş"}, {"text": "“ji ber nasnameya min a kurd, kesên dixwestin min lînç bikin ez careke din dubare dibêjim; ew bênamûs, bêhiset û bêşeref in.”", "author": "Ahmet Kaya"}]}, {"title": "NEFS", "quotes": [{"text": "Kesê di nefsa xwe de ji xweşkatiyê bêpar be, di ti tiştekî de xweşkatiyê nabîne...!", "author": "Elia Abu Madi"}, {"text": "Rehetîya bedenê, di kêmxwarînê de ye. Rehetîya nefsê, di kêmgunehan de ye. Rehetîya zimên, di kêmaxaftinê de ye. Rehetîya dil jî di kêmxemîyê de ye.", "author": "Elîyê kurê Ebûtalib"}, {"text": "Em kesên din didarizînin, ji ber ku cesareta me têra darizandina nefsa me nake.", "author": "Oscar Wilde"}, {"text": "Jin ji bo nezanan “nefs,” ji bo zanayan “nefes” e.", "author": "Şemsê Tebrîzî"}, {"text": "Rewşenbîr ew e ku, dikare aqilê xwe bike serpereştê nefsa xwe.", "author": "Albert Camus"}, {"text": "Tu bibî çi bibe. Lê berî her tiştî bibe mamosteyê nefsa xwe û şagirtê ûjdanê xwe.", "author": "Platon"}]}, {"title": "NETEWE", "quotes": [{"text": "Ewilî mirov im, dûvre fransî me.", "author": "Montesquieu"}, {"text": "Fikra netewperwerîyê, pederê azadîyê ye.", "author": "Seîdê Kurdî"}, {"text": "Kesên stranên neteweyekî çêdikin, ji kesên ku yasayan çêdikin hêzdartir in.", "author": "Shakespeare"}, {"text": "Kesê derheqê nijada xwe, jîyan û tekoşîna gelê xwe de dinivîse, nikare bêalî bimîne.", "author": "Abdurrahman Qasimlo"}, {"text": "Ku neteweyek ji bo azadîyê ber xwe bide û di vê rêyê de ji bo dayîna her cûre berdêlan amade be, kî dikare heta hetayê wî neteweyî biçewisîne.", "author": "Jawaharlal Nehru"}, {"text": "Çima em nekevin nav tevgerê ku netewetiya xwe biparêzin da ku winda nebe û bi temamî neyê texrîb kirin?", "author": "Eliezer Ben Yehuda"}]}, {"title": "NIJADPERESTÎ", "quotes": [{"text": "Nijadperestî gefa herî mezin e bo mirovahîyê. Bi sedemeke herî biçûk, nefreta herî mezin encam dide.", "author": "Abraham J. Heschel"}, {"text": "Nijadperestî ne ramanekî îdeolojîk e, nexweşîyeke psîkolojîk e.", "author": "Malcolm X"}, {"text": "Di civakeke nijadperest de, nenijadperestbûna te ne bes e. Divê tû li dijî nijadperestan jî rawestî.", "author": "Angela Davis"}]}, {"title": "NIYET", "quotes": [{"text": "Niyeta baş, ji bo her xirabîyekê vexwendineke cazîb e.", "author": "Marquis de Sade"}, {"text": "Rêya dojehê bi kevirên niyata baş hatiye raxistin.", "author": "Karl Marx"}, {"text": "Xwîn û hestî bi her mirovî re heye. Cûdahî di dil û nîyetê de ye.", "author": "Marlo Morgan"}, {"text": "Ku nîyeta we xerab be, pêdivîya we bi hêz û qewetê heye. Wekî din bo hemî tiştên mayî, hezkirin bes e.", "author": "Charlie Chaplin"}, {"text": "Kesek nikare ji sê heyvan zêdetir deyax bike. Piştî heyva sisêyan mirov rengên xwe yên rasteqîn û niyeta xwe ya heqîqî eşkere dikin. Sebr bike û bişopîne.", "author": "Al Pacino"}]}, {"title": "NÎHÎLÎZM", "quotes": [{"text": "Hemî behremendên gewre derbareyê jîyanê de gihaştine heman encamê: “nehêja ye”", "author": "Nietzsche"}, {"text": "Tiştek bi qasî hîçîtiyê (nîhîlîzm) giyanê mirov naguvêşe.", "author": "Stefan Zweig"}, {"text": "Dojeh ji hîçîtiyê (nîhîlîzm) çêtir e.", "author": "Abert Camus"}, {"text": "Ne hewce ye em xwe bixapînin. Her tişt beradayî ye! Bextewer ew kes e ku hê ji diya xwe neketiye.", "author": "Tolstoy"}, {"text": "Dinya ne biwate ye, ne jî bêwate. Heye û hew.", "author": "Alain Robbe-Grillet"}, {"text": "Jîyana min van rojan mîna kolanên zivistanê ye. Çiqas bête paqijkirin jî, careke din bi pelên hişk û qirş û qalan tije dibe.", "author": "Kafka"}]}, {"title": "NÛJENÎ – XWENÛKIRIN", "quotes": [{"text": "Tu kel û pelên xwe yên kevn diavêjî; çima dev ji fikr û ramanên xwe yên kevnare bernadî?", "author": "Platon"}, {"text": "Her tiştî paqij bike û ji nû ve destpê bike.", "author": "Douglas Adams"}, {"text": "Demildest dest bi jiyanê bikin û her rojeke xwe, wek jiyaneke nû bihesibînin.", "author": "Seneca"}, {"text": "Ger lênûsk heman lênûsk be, vekirina rûpelekî nû bi kêrî çi tê?", "author": "Tom Robbins"}, {"text": "Mejîyê mirov dişibe kevirê aşan. Ger hûn tiştekî nûjen neavêjin hûndir, dê xwe bi xwe bihêre.", "author": "Îbn Xeldûn"}, {"text": "Min dixwest hemî serboriyên navbera min û te tune bikim û em ji nû de vegerin destpêkê.", "author": "Dostoyevski"}]}, {"title": "OL Û AYÎN", "quotes": [{"text": "Goristanên leşgerî, bi cendekê leşgerên ku mêjiyê wan bi slogana “Xwedê bi me re ye” hatibû şûştin, tije ne.", "author": "George Carlin"}, {"text": "Berîya tu xwe wek fileh, misilman, hîndû an jî bûdîst bidî nîşandan, fêrî mirovbûyînê bibe.", "author": "Shannon L. Alder"}, {"text": "Mirov kiriyarên xirab bi kêfxweşiyeke herî mezin dike, dema bi baweriyeke olî dike.", "author": "Blaise Pascal"}, {"text": "Mirovên herî xirab mamosteyên ayînî (keşe û mele) ne. Ew tiştên dijxwezayî fêr dikin û ji delîlan fêhm nakin. Ciyê wan timarxane ye.", "author": "Nietzsche"}, {"text": "Darek ji fêkiyên xwe, baweriyek jî ji bawermendên xwe tê nas kirin.", "author": "Gotina Çîniyan"}, {"text": "Hemû îbadet û rîtûelên ku di dînên semawî û dînen tewhîdê de hene, berê dî dînên pagan û pûtperestan de jî hebûn.", "author": "Khazal Al Maijdi"}]}, {"title": "OLPERESTÎ", "quotes": [{"text": "Di baweriya xwe de bi qasî ku hûn bawerîyên din ‘tune’ bihesibînin winda nebin!", "author": "Muhîddînê Erebî"}, {"text": "Em bi qewmekî wilo tên îmtihan kirin ku dibêjin, “em tenê li ser hîdayetê ne.”", "author": "Îbn Sîna"}, {"text": "Dîmena ku herî zêde olperestên tûndrew jê ditirsin, keçikeke ku di destê wê de pirtûk hebe.", "author": "Malala Yusufzai"}, {"text": "Xwedêyo! Me biparêze ji wan kesên ku dibêjin “em emrê Xwedê bi cih tînin!”", "author": "Aleksey Bykov"}, {"text": "Kesek bi qasî kesê ku naxwaze bibîne ne kor e.", "author": "Îbn Sîna"}, {"text": "Bitirse ji wî kesê ku tenê bi yek kitêbê bawer dike.", "author": "Bertrand Russell"}]}, {"title": "ONTOLOJÎ", "quotes": [{"text": "Ez ew leheng im ku hê di rûpela destpêkê de dimirim.", "author": "Claudio Bossani"}, {"text": "Heta tu ji “xwe” dernekevî û li “xwe” temaşe nekî, tu yê qet nizanibî bê tu “kî” yî.", "author": "José Saramago"}, {"text": "Divê em her tiştî ji nû de pênase bikin û ji pirsa ‘mirov çi ye’ dest pê bikin.", "author": "Slavoj Žižek"}, {"text": "Carinan tê hişê min û dibêjim; gelo gerestêrka me ne timarxaneya gerdûnê be?", "author": "Goethe"}, {"text": "Dinya yekpare ye, ez li derveyî wê me.", "author": "Virginia Woolf"}, {"text": "Nemirime, lê ne sax im jî.", "author": "Dante Alighieri"}]}, {"title": "PARASTIN", "quotes": [{"text": "Ku mar diranên xwe dernexe, zarok weke werîs dê wî li êzingan bipêçin.", "author": "Gotina Efrîqiyan"}, {"text": "Em di rojên wilo de derbas dibin ku, li gel hemî şert û mercên xirab jî, divê em tenduristiya hişê xwe biparêzin.", "author": "Schopenhauer"}, {"text": "Ger artêşa gel nebe, ti tiştekî wî gelî tune ye.", "author": "Mao Zedung"}, {"text": "Her careke ku jin xwe diparêze, îhtîmal e ku bê zanebûn û bê îdîakirin, ji bo hemî jinan radibe pîyan.", "author": "Maya Angelou"}, {"text": "Tiştê tu nikaribî biparêzî,te ew tişt heq nekiriye.", "author": "Erich Fromm"}, {"text": "Min canê kesekî neêşand, lê di gel ku dizanîbûn ez agir im jî, bi ser min de hatin.", "author": "Yilmaz Guney"}]}, {"title": "PAŞBÊJÎ", "quotes": [{"text": "Tiştên Paul derbareyê Peter de dibêje, ji Peter zêdetir Paul bi me dide nasîn.", "author": "Spinoza"}, {"text": "Li paş te diaxivin, ji ber ku bi rastî jî ew li paş te ne.", "author": "Mark Twain"}, {"text": "Girîngiyê nede gotegotên mirovan. Ji ber ku mirov li ser cenazeyê ku hê nû defin kirine jî diaxivin.", "author": "Necîb Mehfûz"}, {"text": "Her derê we kûl û birîn e, hûn li pizrokên kesên din dinêrin.", "author": "Seneca"}, {"text": "Hinek kes, bi qal kirina bênamûsiyên kesên din, xwe binamûs dihesibînin.", "author": "Gustave Flaubert"}, {"text": "Hinek ji me mîna hibrê ne, hinek jî mîna kaxizê. Ku reşbûna hinekan ji me tunebûya, hinekên din wê bêziman bimana. Ku spîbûyîna hinekan ji me tunebûya, hinekên din wê kor bibûna.", "author": "Cîbran Xelîl Cîbran"}]}, {"title": "PAŞVERÛTÎ – KEVNEPERESTÎ", "quotes": [{"text": "Eger tenê fikrekî we hebe, ji wî fikrî talûketir tiştekî din tune ye.", "author": "Emile Chartien"}, {"text": "Dema destê min bigihîje kesekî dîndar, divê destê xwe bişom!", "author": "Nietzsche"}, {"text": "Bawerîyên kur û negûher, dijminê heqîqetê ne û ji bêbawerîyê bi gellekî talûketir in.", "author": "Nietzsche"}, {"text": "Kevneşopî wek tevnepîrikan destpê dikin, lê dawiyê dibin wek zincîrên pola.", "author": "Gotina Danîmarkiyan"}, {"text": "Em têk çûn heyran; li hemberî kirêtî, çorsî û pespayetiyê em têk çûn.", "author": "Ezîz Nesîn"}, {"text": "Tu yê çawa niqaş bikî li gel kesekî ku bawer dike Xwedê şarab heram kiriye, lê kirîn û firotina mirovan helal kiriye.", "author": "Faraj Fouda"}]}, {"title": "PÊBAWERÎ", "quotes": [{"text": "Çiqas baweriya te bi hin mirovan were jî, ji bilî jûra mêvanan, deriyê jiyana xwe li ber kesekî veneke.", "author": "Shakespeare"}, {"text": "Ez ne ber derewa te dikevim; ez ber wê yekê dikevim ku, ez ê careke din ji te bawer nekim.", "author": "Nietzsche"}, {"text": "Yekî ku bawerîya xwe bi te bîne, qet jê re derewan neke. Û yekî ku ji te re derewan bike, qet bawerîya xwe pê neyêne.", "author": "Shakespeare"}, {"text": "Tiştên tu dibînî, nîvî jê bawer bike. Tiştên tu dibihîzî, tiştekî jê bawer neke.", "author": "Edgar Allan Poe"}, {"text": "Me ji kîderê destpê dikir? ewil me jê hez dikir, an em pê ewle dibûn.", "author": "Oguz Atay"}, {"text": "Dema werîsek biqete û hûn girêkekê lê bixin, di werîs de ciyê herî qewîn dibe ew girêk. Lê çi cara hûn destê xwe bidin wî werîsî, devera canê we biêşîne dê ew girêk be.", "author": "Hegel"}]}, {"title": "PÊDIVÎ", "quotes": [{"text": "Pêdivî, dayîka hemî dahênanan e.", "author": "Platon"}, {"text": "Çiraya ku pêdiviya mala te pê heye, nede mizgeftê.", "author": "Gotina Farsan"}, {"text": "Go lazim bû, ne li vir bû; go li vir bû ne lazim bû.", "author": "Bertolt Brecht"}, {"text": "Di navbera nan û azadîyê de, mirov her tim nan hildibijêrin.", "author": "Lenin"}, {"text": "Her tiştê ji pêdiviya te zêdetir, jehr e.", "author": "Celaleddîn Rûmî"}, {"text": "Ku saeta birçîbûnê lê da, xwarina ne xweş tune ye.", "author": "Gotina Japonan"}]}, {"title": "PERESAN - TEKAMÛL", "quotes": [{"text": "Di candaran de ne yên herî zîrek û bihêz; yên ji guherînê re herî quncav li jiyanê dimînin.", "author": "Charles Darwin"}, {"text": "Ez bawer im, dema dibêjin mirov û meymûn ji heman eslî tên, meymûn ji mirovan bêhtir diqehirin.", "author": "Bertrand Russell"}, {"text": "Kirêtiyên meymûnan zêde ne, ji ber ku ew pirr dişibin mirovan.", "author": "Francis Bacon"}, {"text": "Hûn demekê meymûn bûn; lê mixabin hûn vêga jî, ji meymûnekê meymûntir in.", "author": "Nietzsche"}]}, {"title": "PERESTIN (ÎBADET)", "quotes": [{"text": "Di ber dêrekê re derbas bûm, li wir rehbikek hebû. Min jê pirsî: “devereke paqij bo nimêjê heye?” Wiha bersiv da: “dilê xwe paqij bigre û li kuderê bixwazî, nimêja xwe bike.", "author": "Beyazidê Bîstamî"}, {"text": "Min dît mirov bi fermana te li derdora kevirê reş digerin. Lê min te di dilê xwe de dît. Ez rabûm li derdora xwe geriyam.", "author": "Celaleddîn Rûmî"}, {"text": "Li rojî u nimêja mirovan nenêrin, lê binêrin; dema diaxivin derewan dikin, an rastgo ne? Û dema soz didin soza xwe bicî tînin an na?", "author": "Omerê kurê Xettab"}, {"text": "Herkesî lavelav li ber Xwedayê xwe dikir, da ku dengê daxwazên kesên din bibirre.", "author": "Amin Maalouf"}, {"text": "Rojî bo hin kesan, tenê guherîna wextên xwarinê ye.", "author": "Elî Şerîetî"}, {"text": "Ku giyanê te di nav tawanan de xerq bûbe, çi fêdeya nimêjan heye?", "author": "Fyodor Dostoevsky"}]}, {"title": "PERWERDE – PEDAGOJÎ", "quotes": [{"text": "Şagirt heta hetayê şagirt bimîne, qîmetê mamosteyê xwe dadixîne.", "author": "Nietzsche"}, {"text": "Bavek berberî sed mamosteyî ye.", "author": "George Herbert"}, {"text": "Dibêjî qey heya niha nijada mirovan, ji hêla qerdîyan û celadan ve hatiye perwerdrin.", "author": "Nietzsche"}, {"text": "Zarokên xwe terbiye nekin. Ji xwe dê bişibin we. Xwe terbiye bikin bes e.", "author": "Îbn Xeldûn"}, {"text": "Dayik 20 salên xwe xerc dike ji bo ku kurê xwe bike mêrekî baş. Dûvre keçikek tê u di 20 xulekan de wî dike ehmeqek.", "author": "Robert Frost"}, {"text": "Dema em mirovan hînî ramînê dikin, em wan azad dikin. Dema em zanyariyên hazir pêşkêş dikin, em wan tevlî kerî dikin.", "author": "Alija Izetbegović"}]}, {"title": "PESINDAN", "quotes": [{"text": "Yê pesnê kesî nede, kesî biçûk neke, yê gazinan ji kesî neke, yê kesî tewanbar neke... Ew kesekî tekûz e.", "author": "Epiktetos"}, {"text": "Kesekî ku seraqet pesnê xwe bide, xuya ye ku xwe ‘kêm” dibîne.", "author": "Alfred Adler"}, {"text": "Ji bo pesnê stêrkan bidim li erdê rûniştime.", "author": "Furûx Ferruxzad"}, {"text": "Kesê Xwedê nas dikin, ji pênasekirina wî bêzar in. Kesê wî pênase dikin û pesnê wî didin, wî nas nakin.", "author": "Paulo Coelho"}, {"text": "Heta pesnê te bê dayîn, bi zanibe tu ne di rêya xwe de dimeşî. Tu di rêya hin kesên din dimeşî.", "author": "Nietzsche"}, {"text": "Ji min re got: “Xeyyam zindîqekî serxweş e.” Min got: Ev ne kêmasîyeke ji Xeyyamî re, hûn bi vî awayî pesnê serxweşî û zendîqbûnê didin.", "author": "Amin Maalouf"}]}, {"title": "PÊŞKEWTIN", "quotes": [{"text": "Heta tu ji normalîyê dernekevî, pêşveçûn ne pêkan e.", "author": "Frank Zappa"}, {"text": "Dixwazî bi pêşve biçî? Rê bide xwe.", "author": "Nietzsche"}, {"text": "Pirên pey xwe hilweşîne, da ji pêşveçûnê pê ve tu çareyeke te nemîne.", "author": "Fridtjof Nansen"}, {"text": "Ku di navbera duh û îro de şer rû bide, sibe wenda dike.", "author": "Churchill"}, {"text": "Her nifş, zen dike ku ji nifşê beriya xwe zîrektir e û ji nifşê pey xwe bihîkmettir e.", "author": "George Orwell"}, {"text": "Astenga ewil a li hember pêşkewtina takekes, malbat e.", "author": "Tolstoy"}]}, {"title": "PEYV", "quotes": [{"text": "Dema ku bi nezanekî re dikevî gengeşeyê, her peyva tu bêjî, mîna êzingê ku bavêjî nava êgir e.", "author": "Tolstoy"}, {"text": "Kûrahîya jîyanê bi peyvan nayê pênasekirin. Wê pênase neke; bijî û hew!", "author": "Mark Twain"}, {"text": "Tenê sê peyv bûn\nferheng\nli welatê min;\nhezkirin, çiya û mirin\nvan bêbavan\nkuştin lê zêde kirin..", "author": "Berken Bereh"}, {"text": "Peyv bi zincîrên demê nayên girêdan.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Divê her peyva ku ji devê we dertê, rast be. Lê hûn ne mecbûr in her rastîyê bêjin.", "author": "Voltaire"}, {"text": "Peyv di ferhengan de najîn, di hişê mirov de zindî dibin.", "author": "Virginia Woolf"}]}, {"title": "PIRS Û BERSIV", "quotes": [{"text": "Tişta fîlozof pê dibe fîlozof, ew wêrekîye ku qet pirsekê di dilê xwe heps nake.", "author": "Schopenhauer"}, {"text": "Zîrekîya mirovekî ne di bersivan de, di pirsan de tê xuyakirin.", "author": "Einstein"}, {"text": "Te ewqas dereng bersiv da, min pirsa xwe jibîr kir.", "author": "Shakespeare"}, {"text": "Ji bo kêmaqilan, bersiva berfireh hewce nake.", "author": "Confucius"}, {"text": "Carinan bersîvnedan jî bersîvek e. Çimkî her pirs ne hêjayî bersîvê ye.", "author": "Zinarê Xamo"}, {"text": "Fêdeya pirsên bê bersiv, ji fêdeya bersivên bê pirs zehftir e.", "author": "Harari"}]}, {"title": "PIRTÛK", "quotes": [{"text": "Kitêb ji bo wan kesan in ku dixwazin li cîyekî din bin!", "author": "Mark Twain"}, {"text": "Kitêbeke ku me ji hemî kitêban nebihûrîne bi kêrî çi tê?", "author": "Nietzsche"}, {"text": "Kitêb, hiş û aqil kûbar dikin.", "author": "Tolstoy"}, {"text": "Nirxê mirovekî, bi nirxê kitêbên ku dixwîne tê pîvandin.", "author": "Herbert Spencer"}, {"text": "Tu çiqas zêde kitêban nas bikî, ewqasî hejmara kesên derdora te kêm dibe.", "author": "Feuerbach"}, {"text": "Kitêb, ew fanosên deryayê ne ku di deryaya demê de hatine çikandin.", "author": "Hermann Hesse"}]}, {"title": "PÎR Û KAL", "quotes": [{"text": "Kalbûn, zivistana jiyanê ye.", "author": "Diyojen"}, {"text": "Guh nede şîreta her pîr û kalî. Ma tu nizanî, ehmeq jî pîr û kal dibin!", "author": "Gotina Ifrîqîyan"}, {"text": "Şarezayî ew e ku, tu di kalbûnê de jî rihê zaroktiyê winda nekî.", "author": "Victor Hugo"}, {"text": "Xortanî xweş e, lê çi fêde di destê xortan de heba dibe.", "author": "Oscar Wilde"}, {"text": "Xwezî rojekê xortanî li min vegeriyaba; min ê gilîyê kalbûnê li ber bikira.", "author": "Abu AlAtahiya"}, {"text": "Çiqas em di nav salan de diçin, hejmara kesên em ji hev fêhm dikin kêm dibin. Dibe ku rojekê kesek nemîne em pê re biaxivin.", "author": "Cioran"}]}, {"title": "PÎROZÎ", "quotes": [{"text": "Kesên pirtûkên pîroz dixwînin û fêhm nakin, dibin oldar. Yên dixwînin û fêhm dikin, dibin ateîst.", "author": "Nikola Tesla"}, {"text": "Mirov pîrozê her tiştî û rezîlê her tiştî ye.", "author": "Arîstoteles"}, {"text": "Ez ji heqîqetê hez dikim, ji Platon jî hez dikim. Ku herdu ji hev veqetin, heqîqet zêdetir layiqê hezkirinê ye.", "author": "Arîstoteles"}, {"text": "Di civakekê de çiqas mirovên pîroz û bimbarik hebin; bizanibin ewqas jî zilm û stemkarî li pey wan heye. Civakên ku mirov û mirovatiyê pîroz nedêrin, dê di nav zilm û zordarîyê de bixeniqin.", "author": "Elî Şerîetî"}, {"text": "Li Rojava ji xeynî ‘mirov’ tiştekî pîroz tuneye; li cem misilmanan ji xeynî mirov, her tişt pîroz e.", "author": "Taha Huseyn"}, {"text": "Ger ji bilî çekê ti hêviyek din nemîne, çek pîroz e.", "author": "Titus Livius"}]}, {"title": "PLANSAZÎ", "quotes": [{"text": "Tiştê îro dest pêneke, sibê jî naqede.", "author": "Goethe"}, {"text": "Ku plansazîyeke te tune be, tu yê bibî perçeyek ji plansazîya kesên din.", "author": "Samuel Johnson"}, {"text": "Hûn dixwazin çi bikin, divê hûn hema vêgavê bikin. Lewra ew şert û mercên hûn li bendê ne, dê qet neyên.", "author": "Doris Lessing"}, {"text": "Her mirovê serkeftî xwediyê planekê ye, her mirovî têkçûyî jî xwedîyê hêncetekê ye.", "author": "Henry Clausen"}, {"text": "Mirov ji çar behrên jiyana xwe sê behran, bi xwestina tiştên ku dê nikaribe bi dest bixe derbas dike.", "author": "Diderot"}, {"text": "Heger amanca te plansaziya salekê be, birinc biçêne. Ku ya deh salan be, daran biçêne. Ku ya sed salan be, zarokan perwerde bike.", "author": "Confucius"}]}, {"title": "POŞMANÎ", "quotes": [{"text": "Dema tu hêrs bûyî biaxive, tu yê bibînî ku te axaftina herî xweşik a “poşmanîyê” kirîye.", "author": "Ambrose Bierce"}, {"text": "Min çi dabe bila xweş helal be, ji xeynî wî dilê ku min mift û belaş pêşkêş kiribû.", "author": "Furûx Ferruxzad"}, {"text": "Ger tu li trêneke şaş siwar bûbî, li îstasyona ewil dakeve. Ji ber ku çiqas mesafe zêde bibe, mesrefa vegerê jî zêde dibe.", "author": "Fyodor Dostoevsky"}, {"text": "Tu çi bikî bike, tu yê poşman bimirî; an ji kirinên xwe, an ji nekirinên xwe.", "author": "Fyodor Dostoevsky"}, {"text": "Ji bîr meke, ji xweşûbêşîya pêşwext, poşmanî çêdibe.", "author": "Victor Hugo"}, {"text": "Di kêliya bextewerîyê de soz nede. Di kêliya hêrsbûnê de bersiv nede. Di kêliya xemgînîyê de biryar nede.", "author": "Herakleitos"}]}, {"title": "POZBILINDÎ", "quotes": [{"text": "Mirovên qurre u pozbilind zenn dikin ku her kes heyranê wan e.", "author": "Antoine De SaintExupéry"}, {"text": "Encama quretî û pozbilindiyê, têkçûn e.", "author": "Aisopos"}, {"text": "Pêkvejiyan bi wan mirovên ku her tim xwe mafdar dibînin re, pir zehmet e.", "author": "Elî Şerîetî"}, {"text": "Pozbilindî û rikberî ewilî dibe sebeb ku mirov xwe bêqisur bibîne, piştre jî dawîyê li xwedîyê xwe tîne.", "author": "Tolstoy"}, {"text": "Kesê her tim xwe biçûk dibîne, ew herî zêde nêzî quretî û pozbilindîyê ye.", "author": "Baruch Spinoza"}, {"text": "Mirovê pozbilind ji parîxwer, lêbok û qeşmeran pir hez dike. Ji hebuna gîyanên asîl jî nefret dike.", "author": "Spinoza"}]}, {"title": "QEDR Û QÎMET", "quotes": [{"text": "Di nêrînên însanan de li qedr û qîmetê xwe negere. Her roj nêrînên wan diguherin.\nM. Mahmoud\nQîmeta her kesekî bi qasî fikr û ramanên wî ye.", "author": "Celaleddîn Rûmî"}, {"text": "Tu ji bo kesekî girîng bî, ew dikare bi her awayî ji bo te demê veqetîne. Ji bilî vê her tişt biha ne ye.", "author": "Charles Bukowskî"}, {"text": "Em ji nivîskarên serdestên xwe îmzayan digirin, lê ji nivîskarên gelê xwe kînê digrin.", "author": "Firat Aydinkaya"}, {"text": "Bi mîlyonan sifirên kû werin tenişta hev, mixabin encam nake yek.", "author": "Carl Gustav Jung"}, {"text": "Kesê di dema xwe ya vala de tê cem te, wî xweş bibîne. Kesê di dema te ya vala de tê cem te, qedrê wî bigre. Kesê dema xwe bo te vala dike, wî bigre û bernede.", "author": "Goethe"}, {"text": "Werin em qedr û qîmeta hev bizanibin; çimkî em ê rojekê ji nişka ve ji hev biqetin.", "author": "Celaleddîn Rûmî"}]}, {"title": "QENCÎ Û XERABÎ", "quotes": [{"text": "Kesê ji tirsa dojehê û bo çûna bihûştê qencîyê dike, ew qencî ne exlaqî ye.", "author": "Immanuel Kant"}, {"text": "Bila raweste dinya ji bo me. Bê dîtin û bê bihîstin em jê derbas bin. Ne xwîna wê, ne herrîya wê bila nepeke piyên me.", "author": "Amin Maalouf"}, {"text": "Qencî û xerabî du têgihin ku ji hêla mirovî hatine afirandin û ev herdu têgih jî guherbar in.", "author": "Nietzsche"}, {"text": "Ti qîmeta qenciyê namîne, dema tu dibêjî min kiriye.", "author": "Necîb Mehfûz"}, {"text": "Tiştên em ji bo xwe dikin bi me re dimirin. Tiştên em ji bo mirovên din û dinyayê dikin, heta hetayê dijîn.", "author": "Albert Pike"}, {"text": "Bi neqencbûyîna kesên din hûn qenc nabin...!", "author": "Anton Chekhov"}]}, {"title": "QURBANÎ", "quotes": [{"text": "Berî her tiştî, bibe lehengê jîyana xwe, nebe qurbanîyê wê.", "author": "Nora Ephron"}, {"text": "Nexweş nayên beşên psîkiyatriyê, qurbaniyên nexweşan tên.", "author": "Judy Blanco"}, {"text": "Hîletê min ji wan qurbaniyan diçe ku, ji celadên xwe re rêzdar in.", "author": "Sartre"}, {"text": "Qurban Îbrahîm bû, an Îshaq?", "author": "Søren Kierkegaard"}, {"text": "Qurbaniyên herî pîs ew in ku, ji celladên xwe re rêzdar in.", "author": "Albert Camus"}, {"text": "Gelek zarok qurbaniyên dayikbûneke zêde û bavîtiyeke kêm in.", "author": "Gloria Steinem"}]}, {"title": "RABIRDÛ Û DAHATÛ", "quotes": [{"text": "Min li gor rabirdûya min ne darizîne, êdî ez ne li wir im.", "author": "L. J. Smith"}, {"text": "Nekevin heyra siberojê, siberoj tune ye. Tenê “dema niha” heye, bo wê bijîn.", "author": "Tolstoy"}, {"text": "Raboriya min li gel min dimeşe.", "author": "William Golding"}, {"text": "Heval! Li rojê binêre, li axê binêre, li avê binêre; lê li peyî xwe nenêre.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Pêşeroj û paşeroj tune ye. Tenê ‘niha’yeke bêdawî heye.", "author": "Abraham Cowley"}, {"text": "Çenebazîya li ser dahatûyê bêwate ye. Ji ber ku di destê me de tiştekî ku ‘dema niha’ tije bike tuneye.", "author": "Kierkegaard"}]}, {"title": "RASTHATINÎ (TESADÛF)", "quotes": [{"text": "Pêdivî bi lêhatinan heye, bi xweşkatiyên bê wext û bê plan tên...", "author": "José Mauro de Vasconcelos"}, {"text": "Rasthatinî, hêza xwedayî ya herî kevnar e li dinyayê. Dema hûn li yekî/ê rast tên, ew ji bo we carinan xelat, carinan jî celat e.", "author": "Jean Baudrillard"}, {"text": "Tiştek bi navê rasthatinê (tesadufê) tune ye. Her tişt an ezmûn, an xelat, an celat, an jî bergirî ye.", "author": "Voltaire"}, {"text": "Rasthatinî destpêkek e. Fînalê tu dileyizî, lê perdeya dawîn ji hêla qederê ve tê girtin.", "author": "Bob Marley"}, {"text": "“Rasthatinî” peyveke bêwate ye. Tiştekî bêsebeb tune ye.", "author": "Voltaire"}, {"text": "Rasthatinî nesîb e; berdewamkirin,\ntercîh e.", "author": "Necîb Mehfûz"}]}, {"title": "RASTÎ Û DIRÛSTÎ", "quotes": [{"text": "Tenê du kes rastîyê dibêjin; zarok û serxweş.", "author": "Mark Twain"}, {"text": "Hespê rastbêj amade bikin da bireve.", "author": "Gotina Rûsan"}, {"text": "Heger li welatekî mifaya melaqîyê ji ya duristîyê zêdetir be, dê kambaxî li wî welatî rabe.", "author": "Montesquieu"}, {"text": "Seg direyin Sancho, nexwe em di rêya rast de ne.", "author": "Don Quijote"}, {"text": "Tenê du kes rastiyê dibêjin: zarok û serxweş.", "author": "Mark Twain"}, {"text": "Sê cureyên rastiyê hene: Rastiya min, rastiya te û rastî.", "author": "Gotina Çîniyan"}]}, {"title": "REŞBÎNÎ – XWEŞBÎNÎ", "quotes": [{"text": "Ji reşbînan (pesîmîst) dûr bikevin, çimkî ji bo her çareseriyekê pirsgirêkeke wan heye.", "author": "Einstein"}, {"text": "Her gav wêrek bin. Wek şêrekî bimeşin, wek kevokekê bipeyivin, wek fîlekî bijîn û wek zarokekî hez bikin.", "author": "Santosh Kalwar"}, {"text": "Hemî bahoz ne ji bo serûbin kirina jiyana me ne, hinek jî rêya me paqij dikin.", "author": "Mihail Lermontov"}, {"text": "Heta li dinyayê kulîlk, zarok û çivîk hebin, netirse birayê Leo. Dê her tişt têkeve rêya xwe.", "author": "Kazancakis"}, {"text": "Hêdî hêdî dimirin; ew kesên ku naxwînin, mûzîkê guhdarî nakin û di wûjdanê xwe de xweşbîniyê nahewînin.", "author": "Pablo Neruda"}, {"text": "Her tişt dê di dawiyê de baş bibe. Heger baş nebûbe, nexwe hê dawî lê nehatiye.", "author": "John Lennon"}]}, {"title": "RETORÎK", "quotes": [{"text": "Ûslûba şaş, kujerê gotina rast e.", "author": "Sadî Şîrazî"}, {"text": "Axaftin, hunera bikaranîna aqil e.", "author": "Platon"}, {"text": "Her heqîqet, ne li gor her guhî ye.", "author": "Umberto Eco"}, {"text": "Mirovê biaqil ew e ku dizane wê kengê biaxive, çawa biaxive û bi kê re biaxive.", "author": "Socrates"}, {"text": "Mîna zanayan bifikire, mîna ji rêzêyan biaxive.", "author": "Arîstoteles"}, {"text": "Gotarbêjên bêexlaq yên ku ji aliyê gel ve tên qebûlkirin, tenê tiştên ku gel dixwaze seh bike dibêjin.", "author": "Foucault"}]}, {"title": "REWŞA ASAYÎ", "quotes": [{"text": "Tu Ji bo destpêkirinê li benda dema herî guncav bisekinî, dibe ku tu qet destpê nekî; vêgavê dest pê bike, ji devera tu niha lê yî û bi tiştên di dest de.", "author": "Aldous Huxley"}, {"text": "Ji fikr û ramanên ecêb netirsin. Fikrên ku îro normal tên dîtin, dûh ecêb bûn.", "author": "Bertrand Russell"}, {"text": "Eger di rêya hûn tê de dimeşin de zehmetî û astengî tune be. Bizanibin ew rê we nagihîne de verekê.", "author": "Bernard Shaw"}, {"text": "Dê êşa min çiqasî berdewam bike Portuga?\nHerî zêde 40 roj\npiştî 40 rojî dê biqede?\nNa, tê hîn bibî.", "author": "José Mauro De Vasconcelos"}, {"text": "Ku tu ji nêz ve temaşe dikî, kesekî/e normal tune ye.", "author": "Sigmund Freud"}, {"text": "Di şert û mercên asayî de ez kesekî baş bûm, lê şert û merc qet ne asayîbûn.", "author": "Fyodor Dostoevsky"}]}, {"title": "REWŞENBÎRÎ", "quotes": [{"text": "Di her sedsalê de tenê çend kes difikirin. Yên mayî jî, wekî wan difikirin.", "author": "Cemîl Merîç"}, {"text": "Civakeke ku şewqa rewşenbîran nede ser, ji hêla fêlbaz û sextekaran ve tê xapandin.", "author": "Marquis de Condorcet"}, {"text": "Mirovê ku ji hêla çandî û rewşenbîrî ve lawaz be, xwe bi alayiş û nimayîşê derdixe pêş.", "author": "Confucius"}, {"text": "Ji bîr neke, eger tu pişta xwe bidî wan kesên ku ronahiyê didin te, tu yê ji reşahiya xwe pê ve tiştekî din nebînî.", "author": "Descartes"}, {"text": "Pêdiviya me bi şerekî nûjen heye. Şerekî ku çekên wî pirtûk, fermandarên wî rewşenbîr û qurbaniyên wî jî cehalet û paşverûtî ne.", "author": "Fyodor Dostoevsky"}, {"text": "Li welatekî ku rewşenbîr tirsonek bin, stemkar har in.", "author": "Grigory Petrov"}]}, {"title": "REXNE", "quotes": [{"text": "Rexneya zanayekî, ji milyon çepikên nezanan çêtir e.", "author": "Johannes Kepler"}, {"text": "Rexne, ji bo her fikr û ramanekî rasyonel, damara jiyanê ye.", "author": "Karl Popper"}, {"text": "Pirsgirêka me gişkan ew e ku, em pesindariyeke kûjer, ji rexnekirineke hişyarker çêtir dibînin.", "author": "Norman Vincent Peale"}, {"text": "Nebêje her tişt bi ser min de tê, dibe ku tu di aliyê berevajî de diçî.", "author": "Fyodor Dostoevsky"}, {"text": "Mirov ajalekî rexnegir û têkoşer e.", "author": "Kant"}, {"text": "Ew ên ku kesên derdora xwe herî zêde rexne dikin, tewanbar dikin û biçûk dibînin; di rastîyê de ew in ku, herî zêde ji rûbirûbûna şerma nava xwe ditirsin.", "author": "Platon"}]}, {"title": "RIZGARÎ", "quotes": [{"text": "Rizgar kirina mirovan ji qeyd û zincîrên wan yên ku pîroz dihesibînin, zehmet e.", "author": "Voltaire"}, {"text": "Rizgarkirina neteweyekî ji bin destê desthilatdariyeke dirinde, berztirîn hedefa sîyasî ye.", "author": "Jürgen Habermas"}, {"text": "Jiyan bi hewildana têgihiştina her tiştî despê dike û bi hewildana xwe rizgarkirina ji her tiştî diqede.", "author": "Kafka"}, {"text": "Keftarekî birçî li beyabanê, ji şêrekî ziktêr ê di qefesê de bextewartir e.", "author": "Vladimir Bartol"}, {"text": "Rizgarkirina neteweyekî ji bin destê desthilatdariyeke dirinde, berztirîn hedefa sîyasî ye.", "author": "Jürgen Habermas"}, {"text": "Rizgarkirina ehmeqan a ji zincîrên wan, karekî zehmet e.", "author": "Voltaire"}]}, {"title": "RONAHÎ – TARÎTÎ", "quotes": [{"text": "Ey ronahî, tarîtiyê ronî bike!", "author": "Zerdeşt"}, {"text": "Ronahî bi tarîtiyê re li hev nayê.", "author": "George R. R. Martin"}, {"text": "Kesê dixwaze azad bibe, ber bi rojê ve dimeşe.", "author": "Simone de Beauvoir"}, {"text": "Kesên di dilê wan de ronahî tune ye, ji bo bidestxistina ronahîyê tevlî qelebalixan dibin.", "author": "Schopenhauer"}, {"text": "Ji dêvla tu çêr û dijûnan bi tarîtiyê bikî, mûmekê pêxe.", "author": "Gotina Çîniyan"}, {"text": "Kesê bi ronahiya xwe bawer e, ji şewqa kesên din dilteng nabe.", "author": "Victor Hugo"}]}, {"title": "RONDIKÊN ÇAVAN", "quotes": [{"text": "Ji rûyekî ku bi hêsirên çavan hatibe şûştin paqijtir tiştek tune ye.", "author": "Shakespeare"}, {"text": "Rondikên çavan derewan nakin.", "author": "Shakespeare"}, {"text": "Rondikên çavên xwe paqij neke, sersebeban ji jiyana xwe paqij bike.", "author": "Anton Chekhov"}, {"text": "Ji dêvla tu rondikên çavên xwe paqij bikî, kesên bûne sebebê herikandina wan rondikan, ji jîyana xwe paqij bike.", "author": "Gabriel Garcia Marquez"}, {"text": "Rondik nîşaneya hezkirinê ne, lê nabin derman.", "author": "Shakespeare"}, {"text": "Te niha girîn fêrî çavên min kir. Bila ev rondik bibin ristika gerdena min a şermok.", "author": "Ahmet Kaya"}]}, {"title": "RÛKENÎ", "quotes": [{"text": "Heta niha rûyekî kû bikene û xweşik nebe, min nedîtiye.", "author": "Aldous Huxley"}, {"text": "Tu ne beşerxweş bî, nebe dikandar.", "author": "Gotina Çîniyan"}, {"text": "Eger rûyê te bi şilmaqên jiyanê werimî be, bibişire û mîna tu mirovekî qelew î tevbigere.", "author": "Chris Cleave"}, {"text": "Ruyê te bi kê re bikene, dilê te aîdê wî ye.", "author": "Charlie Chaplin"}, {"text": "Bi mirovên ku karibin we ruken bikin re hevaltîyê bikin. Ji ber ku tenê bişirînek dikare rojeke tarî ronî bike.", "author": "Moliere"}]}, {"title": "RÛMET", "quotes": [{"text": "Ko ji dîwarên odeya te pêve hevalên te nemînin jî, ji girambarî û kerameta xwe tawîz nede.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Kesên qîma xwe bi kêzikbûnê tînin, dema di bin pîyan de perçiqîn bila gazinan nekin.", "author": "Schiller"}, {"text": "Heta dijminê xwe jî bi baldarî hilbijêrin. Rûmeta rikberiyê nedin kesên pespaye.", "author": "Che Guevara"}, {"text": "Li hember neheqîyê sernixwîn nebin. Ku hûn serî bitewînin, hûn ê hem mafê xwe, hem jî rûmeta xwe winda bikin.", "author": "Elîyê kurê Ebûtalib"}, {"text": "Kesê xwe dixe şûna kurmikekî ser axê, divê ji erçiqandina binê lingan gilî û gazinan neke.", "author": "Immanuel Kant"}, {"text": "Jiyana rojekê wekî şêran, çêtir e ji ya sed salî wekî hêştirmeyan.", "author": "Bernard Shaw"}]}, {"title": "SEBR", "quotes": [{"text": "Sebr tehl e, mêweyê wê şêrîn e.", "author": "Arîstoteles"}, {"text": "Herî zêde gringîyê didim sê tiş tan: sadebûn – sebr û dilovanî", "author": "Lao Tzu"}, {"text": "Her tişt xwediyê cewherekî ye; cewherê mirov aqil e, cewherê aqil jî sebr e.", "author": "Suhrewerdî"}, {"text": "Sebr çîçek e, li hemî bexçeyan şîn nabe.", "author": "John Haywood"}, {"text": "Hirî hêdî hêdî dibe xalîçe.", "author": "Gotina Îraniyan"}]}, {"title": "SER TEWANDIN- BÊRÛMETÎ", "quotes": [{"text": "Tiştinên bi navê cinawir hene. Lê hejmara wan ne di asteke xeternak de ye. Esas kesên xeternak ew mirovên ji rêzê ne ku, xwedîyê zêhniyeteke karker in û bê pirs û sûwal ji bawerkirin û îtaetê re amade ne.", "author": "Primo Levi"}, {"text": "Kesê tehde lê tê kirin û xwe naparêze, kûmê bênamûsiyê kişandiye serê xwe.", "author": "Îbn Xeldûn"}, {"text": "Balindeyên di qefesan de dijîn, firrînê wek nexweşiyekê dibînin.", "author": "Alejandro Jodorowsky"}, {"text": "Kuçik dostên herî baş yên mirovan in, lê mirovên ku dikevin postê kuçikan, gelkî bêrûmet û xayin in.", "author": "Edip Yüksel"}, {"text": "Bêalîbûn, zaroka bêxîretî û tirsê ye.", "author": "Nicolás Gómez Dávila"}, {"text": "Her careke ku em li rastî bêdadîyê tên û bêbertek dimînin, em xwe fêrî sertewandinê dikin.", "author": "Julian Assange"}]}, {"title": "SERFIRAZÎ", "quotes": [{"text": "Ji bîr neke Kritias, tirsonekan tu carî bîrdariyên serfiraziyê neçikandine.", "author": "Platon"}, {"text": "Serfirazîya herî mezin ew e ku, tu ji vê dinyayê wekî mirovekî azad koç bikî.", "author": "Spartacus"}, {"text": "Serfiraziyên min yên rewşedar tune ne, lê ez dikarim bi têkçûnên xwe yên ku bi saxîtî ji wan filitî me, we şaşwaz bikim.", "author": "Chekhov"}, {"text": "Kesên ji serkeftina xwe bawer in, dawîya dawî ew serfiraz dibin.", "author": "Richard Bach"}]}, {"title": "SERHILDAN – BERXWEDAN", "quotes": [{"text": "Belê dibe ku em carinan nikaribin bi zalimên xwînxwar. Lê her tim hêza me ya tifekê heye ku em li ser çavên wan bixin.", "author": "Jean Paul Sartre"}, {"text": "Nehêle kes pê li piyê te bike, kesê ku îro pê li piyê te kir, sibê dikare pê li stûyê te jî bike.", "author": "Gotina Aşûriyan"}, {"text": "Ne hêjaye ku em di van her du rojên dinyayê de serî li ber wan kesên serpêl û pîsok bitewînin.", "author": "Voltaire"}, {"text": "Tekane rê ji bo mirovmayînê, têkoşîna li hember vê pergala dijmirovane ye.", "author": "Karl Marx"}, {"text": "Nikarim xwe kerr bikim, divê ez xwe kerr nekim.", "author": "Thomas More"}, {"text": "Xwestin me bin ax bikin, lê nizanibûn ku em tov in.", "author": "Che Guevara"}]}, {"title": "SEROK", "quotes": [{"text": "Ga bi çûna qesrê nabe qral, qesr dibe axur.", "author": "Gotina Çerkezan"}, {"text": "Serokên rasteqîn, divê amade bin ku, ji bo azadiya gelê xwe her tiştî feda bikin.", "author": "Nelson Mandela"}, {"text": "Li ser rêça serok here. Û serok tu yî.", "author": "Neale Donald Walsch"}, {"text": "Rêvever keştî ye, gel derya ye. Derya dikare keştiyê hilgire û dikare keştiyê alabora jî bike.", "author": "James A. Robinson"}, {"text": "Girseyên ku li pey serokên nîyetxirab diçin, talûke ne.", "author": "Euripides"}, {"text": "“Qralekî baş çi ye?”\n“Kûçikê şivên e ku destûra gur li kerî nade.”\n“Qralê xirab çi ye?” “Gur bi xwe ye.”", "author": "Thomas More"}]}, {"title": "SERXWEBÛN – XWESERÎ", "quotes": [{"text": "Zerdeşt got, “ez nehatime ku bibim şivanê we; hatime we ji kerî veqetînim.”", "author": "Nietzsche"}, {"text": "Kengê pêdiviya te bi eleqeya kesekî nema, tu yê hingê bisitewî. Kengê te hêviya xwe ji kesên din birî, tu yê hew birîndar bibî. Kengê tu bi kesekî nehatî girêdan, tu yê hingê kar bikî.", "author": "Osho"}, {"text": "Zehfê mirovan, ‘kesên din’ in. Fikr û ramanên wan, yên kesên ‘din in’, jîyana wan, teqlîd kiri na ‘kesên din’ in, heta hestên wan jî kesên din in.", "author": "Oscar Wilde"}, {"text": "Kesê aîdê grubekê ye, mîna malzareke di organîzmayeke biyanî de kesayetiya xwe winda dike.", "author": "John Steinbeck"}, {"text": "Ev rêya te ye, tenê ya te. Dibe ku hin kes li gel te bimeşin, lê kesek ji bo te nameşe.", "author": "Celaleddîn Rûmî"}, {"text": "Ez jin im û jineke li gor dilê xwe me. Ne li gor dilê te.", "author": "Frida Kahlo"}]}, {"title": "SINC – EXLAQ", "quotes": [{"text": "Ji ber ku oldar in, weke ku pêdiviya wan bi exlaq nemaye, tevdigerin.", "author": "Amin Maalouf"}, {"text": "Exlaqê mirov, çawaniya Xwedayê ku jê re perestiyê dike dide nîşandan.", "author": "Gotina Someriyan"}, {"text": "Ûmet bê exlaq, exlaq bê bawerî, bawerî bê têgihiştin çênabe.", "author": "Cemaledîn Efxanî"}, {"text": "Ji kesî re nebe bar. Ev derseke exlaqî ye.", "author": "Fyodor Dostoevsky"}, {"text": "Kesê bi tiştekî nizane, cahil e. Kesê dizane û xwe kerr dike, bêexlaq e.", "author": "Bertolt Brecht"}, {"text": "Her tiştê dizanî, nebêje, Ji her tiştê seh dikî bawer neke, Her tiştê dikarî bikî, neke.", "author": "Gotina Portugaliyan"}]}, {"title": "SIR Û NEPENÎ", "quotes": [{"text": "Kesê her halê xwe dibêje, bêqîmet dibe.Kesî ji herkesî bawer dike, di nîvê rê de dimîne. Kesî hemî nepenîyên xwe eşkere dike, tenê dimîne. Kesî her karînên xwe derpêş dike, diqede. Kesî her zanînên xwe dibêje, nezan dimîne.", "author": "Farabî"}, {"text": "Heta tu têbigihîjî ku her tişt ji herkesî re nayê gotin; tu yê gelek kesan nas bikî, gelkî biaxivî û pir xeletiyan bikî.", "author": "Khalid Hosseini"}, {"text": "Wekî tu dixwazî sir û nepeniyên xwe veşartî bihêlî, tu çima wan ji kesên din re dibêjî?", "author": "Gotina Îtaliyan"}, {"text": "Tu sir û nepeniyên xwe ji lalo re bibêjî, dê zimanê wî vebe!", "author": "Gotina Rûsan"}, {"text": "Tiştekî tu nexwazî dijminê te jê agahdar bibe, ji dostê xwe re nebêje.", "author": "Arthur Schopenhauer"}, {"text": "Sir (nihênî) barê herî giran e. Helal be jî wî kesî re ku dikare hilgire.", "author": "La Fontaine"}]}, {"title": "SÎYASET – POLÎTÎKA", "quotes": [{"text": "Tu ne dizek bî, tu nikarî bi rêya sîyasetê dewlemend bibî.", "author": "Harry S. Truman"}, {"text": "Hikûmet ji bo karkeran, tenê zîrekîyeke ku têra xebitandina mekîneyan bike, dixwaze.", "author": "George Charlin"}, {"text": "Dîplomasî ew e ku, tu bi kuçik re lîstikeke xweşik dikî, heta tu kevirekî dibînî ku pê lê bixî.", "author": "Will Rogers"}, {"text": "Rêveber li derveyî welêt perwerde dibe, dema nexweş dikeve li derve tedawî dibe, ji bo betla neyê diçe derveyî welêt. Tiştê tekane ku li hundirê welêt dike, dizîya welêt e.", "author": "Ehmed Fuad Necm"}, {"text": "Derewker in... û ew jî bi xwe dizanin ku derewker in. Û dizanin ku em bi derewên wan dizanin... Lê dîsa jî bi dengê herî bilind derewan dikin!", "author": "Necîb Mehfûz"}, {"text": "Her miletê dinyayê, bi hikûmeteke ku layiqê wê ye tê birêvebirin.", "author": "Winston Churchill"}]}, {"title": "SÛC Û CEZA", "quotes": [{"text": "Li vê dinyayê ji her tiştî bêhna sûc tê: Rojname, dîwar, rûyê mirovan...", "author": "Baudlaire"}, {"text": "Kî di zeviyên me de xirabiyê biçîne, dê di dawiyê de siza hilberîne.", "author": "Giordano Bruno"}, {"text": "Hûn bixwazin sûcdar nas bikin, binêrin ka sûcê hatiye kirin bi kêrî kê tê.", "author": "Alexandre Dumas"}, {"text": "Sûcên herî mezin, ne ji bo pêdawistîyên sereke; ji bo çavnebarîyên zêde tên kirin.", "author": "Arîstoteles"}, {"text": "Birano! Hûn di nav bobelatekê de ne, birano we ev heq kiribû.", "author": "Albert Camus"}, {"text": "Civakeke ku bingeha xwe ji azadî û wekheviyê girtibe, kêm kiryar wekî sûc tên pênasekirin.", "author": "Marquis de Sade"}]}, {"title": "ŞAREZATÎ Û EHMEQÎ", "quotes": [{"text": "Bi maçkirina mirovek gurî razî me, lê nikarim destê xwe bidim yekî ehmeq.", "author": "Umberto Eco"}, {"text": "Tu dizanî ferqa heqîqî ya di navbera debengî û behremendîyê de çi ye? Ji behremendîyê re sînorek heye, lê debengî bêsînor e.", "author": "Whoopi Goldberg"}, {"text": "Sermîyanê ku hişmend di salekê de berhev dike, ehmeq di rojekê ji dest dide.", "author": "Gotina Swîsrîyan"}, {"text": "Çerxa zordaran bi serê wan cahilên ku mêjiyê xwe naxebitînin digere.", "author": "Victor Hugo"}, {"text": "Ne ecêb e ku zanayek nikare di nav nezanan de bipeyive. Ji ber ku dengê tenbûrê li ber yê daholê dimre û bêhna sîrê, ya enberê winda dike.", "author": "Sadî Şîrazî"}, {"text": "Pera didin kerê me. Dikin bela serê me.", "author": "Cegerxwîn"}]}, {"title": "ŞARISTANÎ", "quotes": [{"text": "Welatê min! Tu hê jî di serdema hovîtî û barbarîyê de dijî!", "author": "Stendhal"}, {"text": "Dîroka şaristaniyê bi Kurdan destpê kiriye.", "author": "Cemşîd Bender"}, {"text": "Bi rastî ‘mirov’ ajalek hov û talûke ye. Em wî, bi halê wî yê kedî nas dikin ku jê re dibêjin şaristanî. Ji ber vê yekê, dema ku car caran kurmê wî yê rasteqîn derdikeve holê, em dibizdin.", "author": "Schopenhauer"}, {"text": "Azadiya mirovan ne diyariya şaristaniyê ye. Dema ku şaristanî qet tunebû, mirov bêhtir azad bûn.", "author": "Sigmund Freud"}, {"text": "Yekemîn kesê ji dêvla pevçûnê sixêf hilbijart, bû damezrînerê şaristaniyê.", "author": "Sigmund Freud"}, {"text": "Şaristanî bi serkêşîyê dest pê kiriye.", "author": "Erich From"}]}, {"title": "ŞAŞÎTÎ – ÇEWTÎ", "quotes": [{"text": "Ji çewtîyên xwe şerm neke, tu mirov î. Ji dubarekirina wan û tewanbarkirina qederê şerm bike.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Mirovê rast, dema şaş. Dema rast, mirovê şaş. Her timî jiyan bi vî hawî bi mirov dilîze.", "author": "Paul Auster"}, {"text": "Xeta, ew bedel in ku em di rêya heqîqetê de didin.", "author": "Hannah Arendt"}, {"text": "Heger tu li ser rêya şaş bî, fêdeya lez û bezê tuneye.", "author": "Gotina Almanan"}, {"text": "Heger di jîyana te de pirsgirêka hevsengîyê hebe, bala xwe bide derdora xwe. Dibe ku te “kesek” di ciyekî şaş de bi cih kiribe.", "author": "Jean Christophe"}, {"text": "Pirî caran sedema hemî çewtiyên mezin quretî ye.", "author": "Alexander Pushkin"}]}, {"title": "ŞENS – FERSEND", "quotes": [{"text": "Li benda “kêlîya gûncav” nesekine, dê tu carî ew kêlî neyê. Ji ciyê niha tu lê yî destpê bike û bi hemî amûrên di dest xwe de bixebite.", "author": "Napoleon Hill"}, {"text": "Tiştekî we yê ku hûn tê de bicîh bikin hebe, hezar berîkên rojekê hene.", "author": "Nietzsche"}, {"text": "Rojên herî xweş yên jîyanê, bi “hê zû ye” derbas dibin. Piştre jî êdî pir dereng e.", "author": "Gustave Flaubert"}, {"text": "Bextreşî weke şewbeke pandemîk e. Divê kesên bêsiûd û belengaz ji hev dûr bikevin.", "author": "Fyodor Dostoevsky"}, {"text": "Lêhatin ji jêhatinê çêtir e.", "author": "Gotina Kurdan"}, {"text": "Dibe kû jîyanê lîmonên tirş pêşkêşî we kiribin; lê bêguman hûn dikarin wan jî bi awayekî baş bikar bînin.", "author": "Stephen Hawking"}]}, {"title": "ŞER Û AŞTî", "quotes": [{"text": "Mirov mîna balindeyên li ezmanan hînî firînê bûn, mîna masîyan di deryayê de hînî avjeniyê bûn, lê pêkvejîyana xwe ya mîna însanan li ser erdê jibîr kirin.", "author": "Muhemmed Îqbal"}, {"text": "Şervanekî çak, qet hêrs nabe.", "author": "Lao Tzu"}, {"text": "Çeka herî gelac a di destê nebaşan de, banga şer e.", "author": "Kafka"}, {"text": "Mirov fêrî gelek tiştan bûne. Mîna balindeyan difirin, mîna masîyan avjenîyê dikin, lê hînî jîyaneke bi biratî û hevbeş nebûn.", "author": "Martin Luther King"}, {"text": "Şer, heqî û neheqiyê ji hev naqetîne; tenê bêhêz û hêzdaran eşkere dike.", "author": "Bertrand Russell"}, {"text": "“Bavo, mirov li çîyayan çawa dikarin şer bikin?”\n“Nikarin şer bikin. Lê mecbûr in.”", "author": "William Faulkner"}]}, {"title": "ŞERAB", "quotes": [{"text": "Şerab helbestê di dil de diçêne.", "author": "Dante Alighieri"}, {"text": "Şeraba li gel te tê vexwarin helal e, bê yî te vexwarina avê jî heram e.", "author": "Omar Xeyam"}, {"text": "Fitne û fesadî ji binê şaşikê derdikeve, ne ji qedeha şerabê.", "author": "Celaleddîn Rûmî"}, {"text": "Gotinên min şerabeke kevnare ne. Lê gotinên wan, tenê ava fêkî ne.", "author": "Sûhrewerdî Kurdî"}, {"text": "Kesê şarabê nas nake, tiştê baş nizane. Şarab xweşî û şahiyê bi xwe re tîne.", "author": "Gotina Someriyan"}, {"text": "Qudreta di ava tirî de, işq bi xwe ye.", "author": "Omar Xeyam"}]}, {"title": "ŞERMÎ", "quotes": [{"text": "Wiha dibêje kesê bîrewer: “şermî, şermî, şermî...” Ev e dîroka mirovahiyê.", "author": "Nietzsche"}, {"text": "Mirov ji ber fikrên xwe yên qirêj şerm nakin. Ji îhtîmala pêhisîna kesên din şerm dikin.", "author": "Nietzsche"}, {"text": "Şermokî, nîvî ji fersendan berhewa dike.", "author": "Shakespeare"}, {"text": "Ji devera hûn jê hatine, şerm nekin.", "author": "Sarah Jio"}, {"text": "Ji çewtîyên xwe şerm neke, tu mirov î. Ji dubarekirina wan û tewanbarkirina qederê şerm bike.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Pînokyoyê ku textikî bu jî, dema derew dikirin pozê wî dirêj dibû. Lê mirovên vêga; ruyên wan jî naêşe.", "author": "Paulo Coelho"}]}, {"title": "ŞEV Û ROJ", "quotes": [{"text": "Şev her tim ji rojê biînsaftir e.", "author": "Henry Miller"}, {"text": "Di xewê de şev rastiyê dipistîne guhê me, sibehê em dibêjin me xewn dîtiye.", "author": "Şintaro Tanekawa"}, {"text": "Mirî careke din vedigerin jiyanê? Kitêb “na” dibêjin, şev bi qêrîn dibêjin “erê.”", "author": "John Fante"}, {"text": "Ewqasî kêfa min ji şevê re dihat ku, min dixwest rojê bi betanîyê binixumînim.", "author": "Eduardo Galeano"}, {"text": "Rabe! em di şevê de winda bibin.", "author": "Edgar Allan Poe"}]}, {"title": "ŞEYTAN", "quotes": [{"text": "Vê baş bizanibe ku, şeytan jî dikare ji bo berjewendiyên xwe, ji kitêba pîroz ayetan bixwîne.", "author": "Shakespeare"}, {"text": "Şeytan tenê pêşkêş dike, mirov hildibijêre.", "author": "Oscar Wilde"}, {"text": "Bi rastî jî şeytan ji mirovên bêhewante re kar derdixe, hûn bi xatirê Xwedê kin, ji bo zarên xwe tiştên baş bibînin bila pê mijûl bibin.", "author": "Emma Chase"}, {"text": "Em dê ti carî çîrokê ji devê şeytên nebihîzin. Kitêbên pîroz yekalî hatine nivîsandin.", "author": "Anatole France"}, {"text": "Serîyekî vala, cihxebata şeytên e.", "author": "Platon"}, {"text": "Dojeh vala bûye, hemî şeytan li vir in.", "author": "Shakespeare"}]}, {"title": "ŞIK Û GUMAN", "quotes": [{"text": "Pirsgirêka dinyayê ev e ku; kesên bêfehm û ehmeq her tim ji aqilê xwe razî ne. Kesên pirzan û xwezan jî her kêlî di nav şik gumanan de ne.", "author": "Bertrand Russell"}, {"text": "Tekane tiştê ez jê goman nakim ew ku, ez ji her tiştî goman dikim.", "author": "Pyrrhon"}, {"text": "Tu nikaribî wan qanih bikî, serê wan tevlîhev bike.\nHarry S. Truman\nŞik û guman me ji pêşdarazî, hişkbawerî û alîgirtina korkorane azad dike.", "author": "Descartes"}, {"text": "Dilpakiya ewil a mirovahiyê şik û guman bû, qisûra ewil jî hişkbawerî bû.", "author": "Carl Sagan"}, {"text": "Kesê bi baweriyan destpê dike, digihîje şik û gumanan. Kesê bi şik û gumanan destpê dike, digihîje baweriyan.", "author": "Francis Bacon"}, {"text": "Tiştê mirov şêt dike ne guman e, teqezî ye.", "author": "Nietzsche"}]}, {"title": "ŞÎRET", "quotes": [{"text": "Şîret li sê kesan fêde nakin: Rewşenbîrê pozbilind, ciwanê nûgihayî û jina bedew.", "author": "Shakespeare"}, {"text": "Kesên herî zêde şîretan guhdar dikin, herî kêm pabendî wan dibin.", "author": "George Chapman"}, {"text": "Şîretan meke, bibe mînak.", "author": "Celaleddîn Rûmî"}, {"text": "Çi fêdeya şîretan heye ji evîndaran re! Hemîyan hişê xwe xwarine û gotinan fêhm nakin.", "author": "Selîm Berekat"}, {"text": "Pir ê caran kesên ku şîretên herî baş dikin, kesên herî xirab in.", "author": "Francis Bacon"}, {"text": "Guhê xwe bi deyn bide min ez şîretekê lê bikim; dema xwe tortore derbas neke.", "author": "Hipponaks"}]}, {"title": "ŞOREŞ", "quotes": [{"text": "Divê hemî sazî û dezgehên olî, aborî û civakî yên heyî bên rûxandin. Di şûna wan de li ser bingeha azadî, aqil, dadmendî û kedkakarîyê civakeke gerdûnî bête avakirin.", "author": "Mikhail Bakunin"}, {"text": "Tekane rêya mirovmayînê, têkoşîna li dijî sîstema dijmirovane ye.", "author": "Karl Marx"}, {"text": "Tu xwarinê bidin feqîran, dibî ezîz. Tu bêjî “çima xwarina feqîran nîne” dibî komûnîst.", "author": "Eduardo Galeano"}, {"text": "Baweriya min bi niviştan nayê, min ji bo gelê xwe li daholê da!", "author": "Şêx Mirşid Xeznewî"}, {"text": "Feqîrek dimre, feqîrên din hêrs dibin. Şoreş tê lidarxistin. Feqîrên mayî ji dimirin.", "author": "Charlie Chaplin"}, {"text": "Kar bixwazin. Ku nedin, nan bixwazin. Ku herduyan jî nedin, wî nanî ji wan bistînin.", "author": "Emma Goldman"}]}, {"title": "TÊGIHÎŞTIN", "quotes": [{"text": "Sond bi qesema navê Xwedê, têgihiştina zêde nexweşî ye.", "author": "Kafka"}, {"text": "Eger tu nikaribî tiştekî bê şîrove fêhm bikî, tu nikarî bi şîrove jî fêhm bikî.", "author": "Haruki Murakami"}, {"text": "Tu bixwazî giloverîya çemberê bibînî, divê tu li derveyî wê bisekinî.", "author": "Salman Rushdie"}, {"text": "Li vê dinyayê kêm caran du mirov hev fêhm dikin.", "author": "Goethe"}, {"text": "Tiştê herî zêde me diwestîne, têgihiştin e.", "author": "Fernando Pessoa"}, {"text": "Ez ne mecbûr im fikr û ramanên xwe nîşanî kesên fêhmkor bikim.", "author": "Sartre"}]}, {"title": "TÊKÇÛN – SERKEFTIN", "quotes": [{"text": "Kes li têkoşîna te ya li dijî pêlan nanêre. Te keştî gihandiye benderê, yan na? Li wê dinêrin.", "author": "Victor Hugo"}, {"text": "Te herdem li ber xwe da, lê tu têk çûyî. Bila be, dîsa li ber xwe bide, dîsa têk biçe. Îcar baştir têk biçe.", "author": "Samuel Beckett"}, {"text": "“Têkçûn” tune di ferhenga çiyê de.", "author": "Selîm Temo"}, {"text": "Ez ti car têk naçim. An biserdikevim, an jî tiştekî nû hîn dibim.", "author": "Mandela"}, {"text": "Nehêle kesek ronîya te vemirîne. Biçirise! Bila tev di ronkayîya te de kor bibin...!", "author": "Lady Gaga"}, {"text": "Serketin, ji mirovahiyê re jehra mişkan e;kêm kes jê difilitin.", "author": "Elias Canetti"}]}, {"title": "TÊKILÎ", "quotes": [{"text": "Têkiliya şefaf, ji hemî dilkêşî û zindîbûnê bêpar e û têkiliyeke mirî ye.", "author": "Byung-Chul Han"}, {"text": "Têkiliya min bi mirovan re mîna pelên dare ye. Yên dimînin fêde dibînin, yen diqetin hew dikarin vegerin.", "author": "Bernard Shaw"}, {"text": "Gelek rê û rêbaz hene ji bo têkiliyeke baş li gel jinên hestiyar. Lê yek ji wan jî bikêr nayê.", "author": "Fyodor Dostoevsky"}, {"text": "Ji min re qala dînê xwe neke. Bihêle ez wî di liv û tevgerên te de, di têkiliyên te de û di civaka te de bibînim!", "author": "Cory Booker"}, {"text": "Dema têkiliya te bi kesekî/ê re qedîya, hemî nepenîyên xwe bicivîne û di quncika dilê xwe de veşêre û ji bîr bike. Exlaq, piştî bidawîbûna pêwendîyê xwe nîşan dide.", "author": "Morgan Freeman"}, {"text": "Kûbarî û duristî bi hev re dimeşin. Ku li ciyekî yek ji wan bi kêr neyê, ya din jî bi kêr nayê.", "author": "Samuel Beckett"}]}, {"title": "TÊKOŞÎN - XEBAT", "quotes": [{"text": "Nebin parsekê merhemetê.", "author": "Seîdê Kurdî"}, {"text": "Ji dêvla ku di nîvê behrê de em li hêviya sekinandina bahoz û pêlan rawestin, divê em li ber bahozên tûnd fêrî vekirina babirkan bibin.", "author": "Arîstoteles"}, {"text": "Min dev jê berneda ye, tenê westiya me û hew.", "author": "Joanne Greenberg"}, {"text": "Hêza berxwedana parastvanên azadîyê, ji hêza stemkaran zêdetir e.", "author": "Malcolm X"}, {"text": "Tenê masiyên mirî ber pêlan dikevin.", "author": "Gotina Swêdiyan"}, {"text": "Kesê têdikoşe, dibe ku têk biçe. Yên ber xwe nadin, jixwe têkçûyî ne.", "author": "Bertolt Brecht"}]}, {"title": "TEKÛZÎ", "quotes": [{"text": "Dengbirrîna mirovekî bi zorê, ji bo wî rumet u şanazî ye. Çimkî ev tê wê wateyê ku hûn tekûziya wî li hemberî xwe qebûl dikin.", "author": "Joseph Sobran"}, {"text": "Ne nûwaze me, ne mecbûr im nûwaze bim jî.", "author": "David Burns"}, {"text": "Ji tekûzîyê netirsin. Ji xwe hûn dê wê qet bidest nexin.", "author": "Salvador Dalí"}, {"text": "Her kesê delal û tekûz, dixwaze delalî û tekûzîya xwe bibîne û bide dîtin.", "author": "Seîdê Kurdî"}, {"text": "Berê jî ez ji rê derketibûm, dikarim dîsa jî derkevim. Mirov bi meşq û rahênanê tekûz dibe.", "author": "Chuck Palahniuk"}, {"text": "Ne hewce ye hûn bibin kesekî tekûz. Bila liv û tevgerên we ne sexte bin bes e.", "author": "Audrey Hepburn"}]}, {"title": "TEMEN", "quotes": [{"text": "Ji bo me temenek din divê, Piştî mirinê. Ji ber ku me ev temen, Tenê bi hêvîyan derbas kir.", "author": "Sadî Şîrazî"}, {"text": "Heta me aqil nas kir, Me temen xelas kir.", "author": "Gotina Kurdan"}, {"text": "Hemî roj ber bi mirinê ve diçin; roja dawî digihîjê.", "author": "Montaigne"}, {"text": "Tiştekî, bo rojeke taybet veneşêre. Her roja tu tê de nefes distînî, taybet e.", "author": "Bernard Shaw"}, {"text": "Temenê meriv her tiştî didize, heta aqilê merivan jî!", "author": "Publius Vergilius"}, {"text": "Di 17 salîya xwe de tu her tiştî dizanî. Di 27 salîya xwe de tu dîsa her tiştî bizanibî, xûya ye tu hê jî 17 salî yî.", "author": "Ray Bradbury"}]}, {"title": "TENBELÎ – TIRALÎ", "quotes": [{"text": "Tiralî rengek ji rengê xwekuştinê ye.", "author": "Bertrand Russell"}, {"text": "Pêkan ji nepêkanîyê pirsî: tu li ku dijî? Nepêkanîyê got; “ez di xewn û xeyalên bêkêran de dijîm.”", "author": "Rabindranath Tagore"}, {"text": "Ji lingên westiyayî re hemî rê û biwar dirêj in.", "author": "Karl Georg Büchner"}, {"text": "Mirov çiqas zexel be, planên wî yên dahatûyê jî zêde ne.", "author": "Gotina Norweciyan"}, {"text": "Bextewarî bi kêferatê tê bidestxistin.", "author": "Elizabeth Gilbert"}, {"text": "Mirovekî tiral, zewqa betlaneyeke heq kirî nizane.", "author": "Jules Payot"}]}, {"title": "TENDÛRISTÎ", "quotes": [{"text": "Bo temenekî dirêj; Nîvî bixwin, Du qat bireve herin, Sê qat bikenin, Bê sînor hez bikin.", "author": "Gotina Tîbetîyan"}, {"text": "Eger morale te xirabe be, derkeve meşê. Ku hê jî xirabe be, derkeve meşeke din.", "author": "Hipokrat"}, {"text": "Ji bo hemwelatiyekî Emerîka yê ji rêzê, Coca-Cola ji rêxistina el Qaîde bi gelkî xeternaktir e.", "author": "Yuval Noah Harari"}, {"text": "Nîv ji nexweşiyê dilwasî ye, nîv ji tenduristiyê dilrehetî ye. Sebr, destpêka şîfayê ye.", "author": "Îbn Sîna"}, {"text": "Hinar şîfa ye.", "author": "Galenos"}, {"text": "Xwarina zêde, ji birçîbûnê bêhtir nêzî mirinê ye.", "author": "Gotina Almanan"}]}, {"title": "TENÊTÎ", "quotes": [{"text": "Tenêtî, kevintirîn esilzadetî û maquliya vê cîhanê ye.", "author": "Nietzsche"}, {"text": "Çendîn roj in di odeya xwe de bi tenê me. Lê tiştek nabe. Ji xwe bi salan e li dinyayê jî ne bi tenê bûm?", "author": "Kafka"}, {"text": "Tenêtî quncikeke biçûk e ku mirov li wê derê li pêşberî aqilê xwe radiweste.", "author": "Fyodor Dostoevsky"}, {"text": "Ev tenêtîya hûn di nav de temirî ne, ne tiştekî baş e. Bawer bikin dê rojek were, hûn dê ji ber vê tenêtîyê janoyî bibin.", "author": "Zola"}, {"text": "Qehwe bi her kesî re nayê vexwarin. Çimkî qehwe “tenêtî” ye. Kesê tu pê re qehwê vedixwî, bila hêja be ku tu tenêtîya xwe ji bo wî/ê xera dikî.", "author": "Natsume Sosaki"}, {"text": "Ji tenêtîya xwe hez bikin.", "author": "R.M. Rilke"}]}, {"title": "TEOLOJÎ", "quotes": [{"text": "Xwedayê mirovxweran dê wekî wan mirovxwer, Xwedayê şerûdan jî şerûd û Xwedayê bazirganan jî dê mîna wan bazirgan be.", "author": "Ralph Waldo Emerson"}, {"text": "Mesele ne hebûn û tunebûna Xwedê ye, mesele lêgerîna wî ye.", "author": "Jiddu Krishnamurti"}, {"text": "Derbareyê mirin û Xwedayan de tiştekî nizanim, û ez dikarim bi her tiştî sond bixwim ku hûn jî di vê meselê de tiştekî nizanin.", "author": "Socrates"}, {"text": "Mêrik bi dizîka got: “Xwedêyo bi min re biaxive.” çivîkekê kire wîtewît li ser darê. Lê mêrik seh nekir.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Dilekî bêrehm, ji Yezdanekî bêrehm re; dilekî birehm jî, Yezdanekî birehm re dia dike.", "author": "Gotina Sumeriyan"}, {"text": "Ji Xwedayê gelên din re rêzdar bin. Bo ku ew jî ji Xwedayê we re rêz bigrin.", "author": "Gotina Sumeriyan"}]}, {"title": "TEVDîR (BERGIRÎ)", "quotes": [{"text": "Hê ti tî nebûyî, bîrê bikole!", "author": "Gotina Çîniyan"}, {"text": "Di jiyanê de şûr dibe ku tenê carekê bi kêrî te were, lê divê tu her tim wî li nik xwe bigerînî.", "author": "Gotina Japonan"}, {"text": "Roviyê ku qala aştiyê dike, bi şev kozikan amade dike.", "author": "Gotina Bolendî"}, {"text": "Marê ku razayî xuya dike, bi rastî dûrahiya navbera xwe lingên te dipîve.", "author": "Gotina Kurdan"}, {"text": "Kesên xwe dispêrin şikefteke yek derî, mirinê heq dikin.", "author": "Frank Herbert"}, {"text": "Ji bo tu ji kermêşan xilas bibî, divê tu ewil teqn û çiravan ziwa bikî.", "author": "Gotina Awistralyan"}]}, {"title": "TEWANBARÎ", "quotes": [{"text": "Berî her tiştî tewanbarkirin hebû. Ademî Hewwa tewanbar kir, Hewayê mar tewanbar kir û ev tişt heya roja îro didome.", "author": "Charlie Champbell"}, {"text": "Dijminê herî mezin ji bo ola îslamê ew e ku, mirovan bi kafirbûnê tewanbar dike.", "author": "Îbn Ruşd"}, {"text": "Tu çawa fêhm bikî, bike; lê bi wê fêhm kirina xwe kesekî tewanbar neke.", "author": "Will Smith"}, {"text": "Beriya tu herriyê biavêjî kesekî din bifikire û tu carî jibîr neke; dê pêşî destê te bilewite.", "author": "Tolstoy"}]}, {"title": "TINAZPÊKIRIN", "quotes": [{"text": "Kenê xwe bi min dikin, ji ber ku ez naşibim wan. Ez jî bi wan dikenim, ji ber ku tev dişibin hev.", "author": "Kurt Cobain"}, {"text": "Tinazpêkirin, ji lêdanê jî xirabtir e.", "author": "John Steinbeck"}, {"text": "Nehêle kes tinazên xwe bi te bike.", "author": "Mario Puzo"}, {"text": "Ne bi bêvileke xaromaro, bi gîyanekî kulek û şapînoz bikenin.", "author": "Gogol"}, {"text": "Ku diranên gur diweşin, dibe pêkenokê kuçikan.", "author": "Gotina Îtaliyan"}]}, {"title": "TIRS Û ENDÎŞE", "quotes": [{"text": "Tirs, kerê ji hespê bezatir dike.", "author": "Gotina Rusan"}, {"text": "Ji çaran sê behr nerihetîyên mirovên zîrek, ji zîrekbûna wan peyda dibin.", "author": "Marcel Proust"}, {"text": "Min çi winda kiribe, ji tirsa windakirinê ye.", "author": "Paulo Coelho"}, {"text": "Tenê qedeha ku ji deste min de ket û şikest ferq kirin, lê kesekî ricifandina deste min ferq nekir.", "author": "Adam Fawer"}, {"text": "Û ev nexweşî! Yên ku pê neketine jî, wê di dilê xwe de digerînin.", "author": "Albert Camus"}, {"text": "Tirs, nexweşîya herî kevn ya mirovahiyê ye.", "author": "Jiddu Krishnamurti"}]}, {"title": "TIRSONEK", "quotes": [{"text": "Tirsonek ew kesê heqîyê dibîne û alîkarîyê nade.", "author": "Confucius"}, {"text": "Kesê bêzirav û bizdonek ku ti carî xwe navêje talûkeyê, dê ti carî bi ser nekeve.", "author": "Kierkegaard"}, {"text": "Tirsonek hezar carî, wêrek carekê dimirin.", "author": "Vladimir Bartol"}, {"text": "Tirsnezanên ku tirsê ditirsînin, bersivê didin tirsonekan.", "author": "Adnan Selçuk Mızraklı"}, {"text": "Têkçûyîn ji bo wêrekan e heval! Çimkî tirsonek ti car nakevin nav cengê.", "author": "Django Unchained"}, {"text": "Fêhtok berî talûkê, tirsonek di kêliya talûkê de, wêrek jî piştî derbasbûna talûkê ditirsin. Gotina Almanan\nKesên tirsonek, sikûneta despotîzmê, ji deryaya azadîyê ya bibahoz çêtir dibînin.", "author": "Thomas Jefferson"}]}, {"title": "TUNDÛTÛJÎ", "quotes": [{"text": "Çanda tundûtûjîyê, ji kesên kêmexlaq re her tim dilniwaz e.", "author": "Albert Einstein"}, {"text": "Em dişibin masiyên ku di goleke genî de hevûdin dixwin û gol çiqas diçe ziwa dibe.", "author": "Adonis"}, {"text": "Kesê kûlma ewil diavêje, kêmaniya fikrên xwe qebûl dike.", "author": "Gotina Çîniyan"}, {"text": "Çeka Qabîl, çeka herî bi talûke ye.", "author": "Géza Gárdonyi"}, {"text": "Dema kermêşek li ser gunikê we deyne, hûn dê hîngê fêhm bikin ku, her pirsgirêk bi tundûtujîyê nayê çareserkirin.", "author": "Confucius"}, {"text": "Li ser vê xakê, tiştekî ji mirin û kuştinê hêsantir tuneye.", "author": "Sabahattin Ali"}]}, {"title": "ÛJDAN", "quotes": [{"text": "Mensûbiyata we ya bi ol u baweriyekê ve, we nake mirovekî baş. Qencbuna mirov bi wijdan ve girêdayî ye. Wijdan xwedayê di hundirê mirov de ye.", "author": "Victor Hugo"}, {"text": "Tiştê rêya herî rast nîşanî mirov dide, wicdanê mirov e.", "author": "Jane Austen"}, {"text": "Ûjdan tenê her timî di halê bêdengîyê de diaxive.", "author": "Martin Heidegger"}, {"text": "Dijminê herî mezin ji bo bêhnvedanê, wujdanekî bêaram e.", "author": "Robert Louis Stevenson"}, {"text": "Wekî wijdanê herkesî rehet e, kê ewqas dil şikandin?", "author": "Kristin Hannah"}, {"text": "Dema dil dimire, dilovanî jî dimire. Dema aqil dimire, hîkmet jî dimire. Dema ûjdan dimire, her tişt dimire.", "author": "Necîb Mehfûz"}]}, {"title": "VEQETÎN", "quotes": [{"text": "Destê me bigihaşta firqetê, me yê êşa wê pê bida tehm kirin.", "author": "Îbn Arabî"}, {"text": "Ku min dîwar di navbera xwe û te de lê kiribe, kevir jî te dane destê min.", "author": "Kafka"}, {"text": "Hûn bi kuderê ve jî biçin, welatê we li dûv we tê. Êdî hûn lê nejîn jî, ew di hundirê we de dijî.", "author": "Khalid Hosseini"}, {"text": "Her veqetîn, dîmenekî mirinê pêşkêşî me dike.", "author": "Schopenhauer"}, {"text": "Oxir be ji te re. Ji niha û şûn de em du biyanî ne...", "author": "Fyodor Dostoevsky"}, {"text": "Her dever bo min xûrbet e.", "author": "Fyodor Dostoevsky"}]}, {"title": "VIR Û DEREW", "quotes": [{"text": "Derew, nîşaneya bixwenebawerî û bêhêzîyê ye.", "author": "Alfred Adler"}, {"text": "Çiqas derew dihatin kirin le ser rûyê erdê; bi gotinê, bi nivîsê, bi wêneyan, an jî bi bêdengmayinê.", "author": "Yusuf Atılgan"}, {"text": "Derew tekane îmtîyaz e ku mirovî ji zîndewerên din vediqetîne.", "author": "Fyodor Dostoevsky"}, {"text": "Bi kesên ji derewên xwe bawer dikin re nekevin niqaşê, da ku dema we bi avê de neçe.", "author": "Paulo Coelho"}, {"text": "Mirov, ji rastiyan hêsantir baweriya xwe bi derewan tînin.", "author": "Agatha Christie"}, {"text": "Hindik derew nayên kirin. Kesê derewekê bike, dikare hemî derewan bike.", "author": "Victor Hugo"}]}, {"title": "VÎN – ÎRADE", "quotes": [{"text": "Herkes heyranê vîna hêzdar e. Ji ber ew ku bi kesekî re tuneye.", "author": "Nietzsche"}, {"text": "Gelek caran, em dilnerihetiya xwe bi destê xwe amade dikin.", "author": "Andre Maurois"}, {"text": "Hêncet tev derew in. Yê bixwaze, dikare.", "author": "Nîzar Qebbanî"}, {"text": "Em ji goşt û xwînê ne, lê divê em bijîn wekî ku ji pola ne.", "author": "Sigmund Freud"}, {"text": "Belê hilgirtina barê jîyanê giran e: lê hûn jî ewqasî ne dilkeçik bin heyran!", "author": "Nietzsche"}, {"text": "Mî bi piyê xwe, bizin bi piyê xwe.", "author": "Gotina Kurdan"}]}, {"title": "WEKHEVÎ", "quotes": [{"text": "Emerîka gelekî bi siûd e ku reşpîst (çerm reş) tenê doza wekhevîyê dikin, ne ya tolhildanê.", "author": "Joel D. Anderson"}, {"text": "Wekhevîya bêazadî, ji azadîya bêwekhevî bêhtir civakeke parsengdar ava dike.", "author": "Eric Hoffer"}, {"text": "Em dixwazin gur jî têr bixwin, berx jî sax bimînin.", "author": "Tolstoy"}, {"text": "Bingeha sosyalîzm û komûnîzmê “wekhevî” ye. “Azadî” bo wan ewqas jî ne girîng e.", "author": "Fernando Pessoa"}, {"text": "Wekhevî! Belê, ez vê têgihê fêhm dikim, lê mînaka wê nabînim.", "author": "Spurgеon"}, {"text": "Yê li wekheviyê digere, bila biçe goristanan.", "author": "Gotina Almanan"}]}, {"title": "WELATPARÊZÎ- NIŞTIMANPERWERÎ", "quotes": [{"text": "Dema tu zimanê gelê xwe diaxivî, gelê te berz dibe. Ji ber ku gelê te bi bêjeyên te dijî.", "author": "Sechu Sende"}, {"text": "Mirov bê al û bê welat be, çi qîmetê wî heye?", "author": "Mehmûd Derwîş"}, {"text": "Vegerîyam da ku segên welatê min li min bireyin.", "author": "Eta Nehayî"}, {"text": "Niştimanperwerê rasteqîn ji her deverî bêhtir, ji bêedaletiya welatê xwe nefret dike.", "author": "Clarence Darrow"}, {"text": "Kesê zik birçî nikare bibe welatparêz.", "author": "John Brown"}, {"text": "Welatparêziya heqîqî ew e ku, tu xemxûrê trajediya gelê xwe bî.", "author": "Marina Tsvetayeva"}]}, {"title": "WÊREKÎ", "quotes": [{"text": "Tirsa xwe ji xwe re veşêrin, lê wêrekiya xwe bi herkesî re parve bikin.", "author": "Robert Louis Stevenson"}, {"text": "Tenê ehmeq şaşîtiyên xwe dubare dikin, kesên bi aqil şaşîtiyên nû dikin.", "author": "Gotina Rûsan"}, {"text": "Şerê te yê li dijî ejdehayan têrê nake, di dema şer de divê tu jî bibî ejdeha!", "author": "Nietzsche"}, {"text": "Carinan ji xwekuştinê zêdetir ji bo jiyanê pêdivî bi wêrekîyê heye.", "author": "Albert Camus"}, {"text": "Her tim tiştê tu jê ditirsî, bike.", "author": "Emerson"}, {"text": "Eger kêfa te ji deryayê re tê, divê tu ji pêlên wê jî hez bikî. Tu bi tirs bijî, tu yê tenê temaşevanê jiyanê bî.", "author": "Nietzsche"}]}, {"title": "XAPANDIN", "quotes": [{"text": "Xapandina mirovan, ji qanihkirina wan ku hatina xapandin hêsantir e.", "author": "Mark Twain"}, {"text": "Hûn dereweke mezin bikin û seraqet vê derewê dubara bikin, dawiyê xelk dê ji vê derewê bawer bike.", "author": "Joseph Goebbels"}, {"text": "Tu kes nikare me bixapîne, tenê em xwe dixapînin.", "author": "Goethe"}, {"text": "Dirûşma “biratîyê” dirûşmeyeke wisa ye ku; hişwindakirinê vedişêre, kûr dike û berbelavtir dike.", "author": "Îsmaîl Beşîkçî"}, {"text": "Şeytan ne bi qiloçan, bi ken nêzîk dibe!", "author": "Gotina Sirbiyan"}, {"text": "Goristan tije ne bi wan kesên difikirîn ku cîhan bêyî wan nabe.", "author": "Gotina Emerîkiyan"}]}, {"title": "XATIRXWESTIN", "quotes": [{"text": "Vê ji bîr nekin; bêdengiya jinê, xatir xwestin e.", "author": "Paul Auster"}, {"text": "Mirovên gewre, xatir dixwazin û diçin. Kesên biçûk xayintîyê dikin û diçin.", "author": "Lao Tzu"}, {"text": "Hey dinyayê! Tu nehêjayî xatirxwestinê yî jî.", "author": "Shakespeare"}]}, {"title": "XELAT", "quotes": [{"text": "Xelata qenciyê, kirina wê ye.", "author": "Seneca"}, {"text": "Mirin, xelata herî dawîn a jiyanê ye.", "author": "Luvenalis"}, {"text": "Xelata dilpakîyê, tenê dilpakî ye.", "author": "Jack London"}, {"text": "Mirovayetî ew e ku; tu qencîyê ne ji bo hêvîya xelat û celata piştî mirinê bikî.", "author": "Kurt Vonnegut"}, {"text": "Dînê min ev e: hemî wezîfeyên xwe bicih bîne û ji bo vê jî, ne li vê dinyayê, ne jî piştî mirinê hêviya xelatekê neke.", "author": "Bertrand Russell"}, {"text": "Ji dêvla tu jiyanê bi rondikên çavê xwe xelat bikî, wê bi kenê xwe ceza bike.", "author": "Tolstoy"}]}, {"title": "XEMGÎNÎ", "quotes": [{"text": "Erê birako! Xembarî nexweşiyeke mîna şewbê ye. Kesên reben û xembar ji bo rewşa wan xirabtir nebe, divê ji hev dûr bikevin.", "author": "Fyodor Dostoevsky"}, {"text": "Tu biçî kuderê, bi embareke tije xem vedigerî.", "author": "Italo Calvin"}, {"text": "Xem çî ye?\nDerya ye.\nŞadî?\nDilopek di hembêza wê de.", "author": "Sàndor Petoti"}, {"text": "Xembarî, mirov kêmhiş û famkor dike.", "author": "Stendhal"}, {"text": "Kesên nearam, bêaramiya kesên din zêdetir hîs dikin.", "author": "Vladimir Bogomolov"}, {"text": "Dema xemgîn dibim, stranan dinehwirînim, ferq dikim ku dengê min ji pirsgireka min xirabtir e; dibişirim.", "author": "Bernard Shaw"}]}, {"title": "XEW - BÊXEWÎ", "quotes": [{"text": "Dilhişk razan, dilşikestîyan şeveke bêxew derbas kirin.", "author": "Taha Hussein"}, {"text": "Dixwazim razêm. Ku hişyar dibim jiyana min serûbin dibe.", "author": "Hemingway"}, {"text": "Bêxewî tiştekî wilo ye. Pûnijîn û xemên te heya sibehê di weşana zindî de ne.", "author": "Chuck Palahniuk"}, {"text": "Tu bêxewîyê hilbijêrî, çêj e. Lê ku bêxewî te hilbijêre, êş e.", "author": "Cîbran Xelîl Cîbran"}, {"text": "Sê sedemên bingehîn ji bo hêrsbûnê: Birçîbûn, bêxewî û axaftina bi ehmeqan re.", "author": "Johnny Depp"}, {"text": "Min di xewna xwe de tivingek berda canê xwe. Dema tiving teqîya, ez ji xew şiyar nebûm û min kêlîyekê li cenazeyê xwe temaşe kir.", "author": "Walter Benjamin"}]}, {"title": "XEWN Û XEYAL", "quotes": [{"text": "Hişyarbûna ji xeyalekê, herî kêm bi qasî zayînê diêşîne.", "author": "James Joyce"}, {"text": "Ku şekala te teng be, çi fêdeya dinyayeke fireh heye?", "author": "John Williams"}, {"text": "Kintirîn rê bo pêkanîna xewnan, şîyarbûn e.", "author": "S.M. Power"}, {"text": "Her mirov, şîroveya xewna xwe ye.", "author": "Sigmund Freud"}, {"text": "Carinan mirov dema hişyar jî bin xewnan dibînin.", "author": "Anton Chekhov"}, {"text": "Xewnexofên min bi gelemperî li ser windakirina te ne.", "author": "Suzanne Collins"}]}, {"title": "XIYANET", "quotes": [{"text": "Kesê carekê xayîntiyê bike, dikare hezar carî jî xayîntîyê bike. Ji bo tu bizanibî ava behrê şor e, ne lazim e tu tevî tehm bikî!", "author": "Che Guevara"}, {"text": "Tu bixwazî dijmin têk bibî, deh guleyan biteqîne; yek ji bo dijmin, neh ji bo xayinan.", "author": "Gotina Gerdûnî"}, {"text": "Kesek bêje, ‘ez wek bira ji te hez dikim’ Habîl û Qabîl bîne bîra xwe.", "author": "Gotina Îrlendiyan"}, {"text": "Pirê caran li binê êşên me, îmzeya kesên ku em herî zêde ji wan hez dikin, heye.", "author": "Paul Auster"}, {"text": "Kesên di nav daristanê de em bi tenê hiştin, bila nepirsin gurgan çi bi serê me aniye!", "author": "Gotina Rûsan"}, {"text": "Dema keştiyek dike ku binav bibe, ewilî mişk keşetiyê terk dikin.", "author": "Dostoyevski"}]}, {"title": "XIZANÎ – HEJARÎ", "quotes": [{"text": "Xizanî, mirovan zû pîr û kal dike.", "author": "Homeros"}, {"text": "Ne bi berxîtî têr şîr xwar, ne bi kavirîtî têr giya xwar.", "author": "Gotina Kurdan"}, {"text": "Kesê birçî, qenciyên xwe dixwe.", "author": "Bertolt Brecht"}, {"text": "Bawerî dikare çîyayan bihêjîne, lê ti çareyeke wê ji bo aborîyeke têkçûyî û kêmanîya sermîyan tuneye.", "author": "Max Weber"}, {"text": "Qet pereyên min tune ne” hemî êşên dinyayê di vê hevokê de kom dibin.", "author": "Balzac"}, {"text": "Çawa hezkirin şairan diafirîne, xizanî jî dizan diafirîne.", "author": "Gotina Hindûyan"}]}, {"title": "XWEDAWEND", "quotes": [{"text": "Ji Xwedawendan hêrs nebin. Erê, dema em ji fersendên ku wan ji bo me hinartine îstîfade nekin, ew sûcê me ye.", "author": "Lewis Wallace"}, {"text": "Hemî Xwedawend mirine, ji xeynî Xwedayê şer.", "author": "Anonîm"}, {"text": "Divê Xwedawend di hêrsbûnê de neşibin mirovan.", "author": "Euripides"}, {"text": "Xwedawendek hat û kumişî ser bajêr. Çirûskên lerzetayeke erjeng reşandin li her derê.", "author": "Sophokles"}, {"text": "Tenê Xwedawendên gunehkaran hene.", "author": "Bertrand Russell"}, {"text": "Bêrêzê heqîqî yê li hemberê olan, ne ew kes e ku xwedawendên gel înkar dike; ew kes e ku bawerîyên gel yên derbareyê xwedawendan de dipejirîne.", "author": "Epicurusus"}]}, {"title": "XWENASÎN", "quotes": [{"text": "Her derê we xwîn û birîn e, lê hûn li pizrokên xelkê meyze dikin.", "author": "Seneca"}, {"text": "Her rewş û kiryareke kesên din ku em pê aciz dibin, rêyeke din li ber me vedike ku em xwe nas bikin.", "author": "Carl Gustav Jung"}, {"text": "Li deryaya xwe û keştiyên xwe vegere Martino, pêşniyara min bo te ev e. Çi karê te heye li van bajarên tije mirovên, gurrî û genî?", "author": "Jack London"}, {"text": "Bi qasî gerestêrkeke nekeşîfkirî, tu dûr î ji xwe.", "author": "Cioran"}, {"text": "Carinan ji bo em bizanibin em kî ne, divê em xwe wenda bikin.", "author": "Paulo Coelho"}, {"text": "Dîtina te ya derheqê te, ji dîtina kesên din girîngtir e.", "author": "Seneca"}]}, {"title": "XWENDIN Û NIVÎSANDIN", "quotes": [{"text": "Dest bi nivîsandinê bikin, êdî bila pênûs ji dêvla we bifikire.", "author": "Umberto Eco"}, {"text": "Bixwînin, dibêjim bixwînin. Devera hibr lê neherike, xwîn lê diherike.", "author": "Elî Şerîetî"}, {"text": "Nivîskar divê devê xwe bigre, bo ku berhema wî devê xwe veke.", "author": "Nietzsche"}, {"text": "Dinivîsim; ji ber ku nikarim dengê dilê xwe bitepisînim.", "author": "Sylvia Plath"}, {"text": "Xwende û nexwende bi qasî mirî û zindîyan ji hev cuda ne.", "author": "Arîstoteles"}, {"text": "Tiştekî tu binivîsî tune be jî, ez bi şandina nameyeke vala jî razî me.", "author": "Kafka"}]}, {"title": "YEKÎTÎ-TIFAQ- PIŞTGIRÎ", "quotes": [{"text": "Go kerî dibe yek, şêr birçî radize.", "author": "Gotina Efrîqiyan"}, {"text": "Ku bira mil didin hev, çiya dibin zêr.", "author": "Gotina Maleziyan"}, {"text": "(Kurdno!) hebûna xwe, bi yekbûna xwe bidin nîşandan.", "author": "Seîdê Kurdî"}, {"text": "Li şêrên welatê xwe xwedî derkevin; naxwe hûn ê ji kuçikên dijminê xwe re bibin nêçîr.", "author": "Gotina Filistînîyan"}]}, {"title": "ZAGON", "quotes": [{"text": "Mirovên baş ji bo ku rast û durist tev bigerin, pêdivîya wan bi zagonan tune ye. Mirovên xirab jî, ji xwe rêyeke binpêkirina zagonan bo xwe dibînin.", "author": "Platon"}, {"text": "Qanûn wek tevna pîrepindê ye, zeîf lê dieliqin, hêzdar jê derbas dibin.", "author": "Anton Chekhov"}, {"text": "Zordestîya herî mezin di bin mertalê zagonan de û bi navê dadmendîyê tê kirin.", "author": "JeanJacques Rousseau"}, {"text": "Qanûn, qehpika rayedaran e.", "author": "Bakunin"}, {"text": "Serkêşîya li dijî qanûnên bêdad, bo her mirovî erkekî exlaqî ye.", "author": "Martin Luther King"}, {"text": "Tevahîya welêt bêqanûn, xeternak, li ber teqînê û şeytanî ye.", "author": "Henry Miller"}]}, {"title": "ZANEBÛN", "quotes": [{"text": "Zanîn, bîrbirina nezanînê ye.", "author": "Fernando Pessoa"}, {"text": "Zanîn jî şehwetek e wek hemî şehwetan.", "author": "Nietzsche"}, {"text": "Fêr bûm û têgihiştim ku, tiştek nehatiye fêrkirin û tiştek nehatiye têgihiştin.", "author": "Îbn Sîna"}, {"text": "Kesê di ciwaniya xwe de dara zanînê neçandibe, di kalbûna xwe de sîyeke ku xwe li berê rehet bike nabîne.", "author": "Seneca"}, {"text": "Tenê başiyek heye, zanîn; û tenê xirabiyek heye, cahilî.", "author": "Socrates"}, {"text": "Tiştek, bi qasî cehaleteke aktîv ne talûke ye û tiştek bi qasî zanîneke pasîv ne bêwate ye.", "author": "Goethe"}]}, {"title": "ZANIST", "quotes": [{"text": "Niha li 179 welatên ku vayrosa koronayê lê heye, ji 50 Xwedayên ji hev cûda alîkarî hatiye xwestin. Lê yek ji wan jî hê bersiv nedaye. Dema zanyaran derman dîtin, herkes dê ji Xwedayê xwe re spasiyê bike.", "author": "Morgan Freeman"}, {"text": "Nîgarxêzî zanistek e û hemî zanist xwe dispêrin bîrkarîyê. Tiştên ji destê mirov dertên, ku bingeha xwe ji bîrkarîyê negirin, nabin Zanist.", "author": "Leonardo da Vinci"}, {"text": "Zanist helbesta aqil e,helbest jî zanista dil e.", "author": "Maxim Gorky"}, {"text": "Her sêwlekekî bêhiş dikare kêzikekê biperçiqîne, lê hemî zanyarên cîhanê nikarin rih bidin wê kêzikê.", "author": "Schopenhauer"}, {"text": "Em cinsekî wisa ecêb in; amûr û alavên ku dê bibin sedemê qelandina koka me, em bi destê xwe çêdikin.", "author": "Carl Sagan"}, {"text": "Civakeke ku huner, zanist û fel sefe lê tune be, Xwedê wê civakê terk dike.", "author": "Ahmet Altan"}]}, {"title": "ZANYARÎ", "quotes": [{"text": "Her çiqasî zanyarî dinyayê ronî bike jî, dawîya dawî dê dilan di tarîtîyê de bihêle. Divê dil ronakbûna xwe bi xwe biafirîne.", "author": "Emile Durkheim"}]}, {"title": "ZAROK – ZAROKATÎ", "quotes": [{"text": "Zarok ne pirtûka boyaxkirinê ne. Mafê te tune ye tu wan bi rengê ku herî zêde jê hez dikî boyax bikî.", "author": "Khalid Hosseini"}, {"text": "Her zarokek hunermendek e, û divê wilo bimîne.", "author": "Pestalozzi"}, {"text": "Zaroktî berîya ku demjimêra reş a mantiqê were, li gor dengan, bêhnan û dîmenan tê pîvandin.", "author": "John betjeman (The Boy in the Striped Pyjamas)"}, {"text": "Roja em dikevin heyra dahatûyê, wê rojê em zaroktîyê li pey xwe dihêlin.", "author": "Patrick Rothfuss"}, {"text": "Zarok ne kuçik in, mezin jî ne xwedawend in.", "author": "Gotina Haîtîyan"}, {"text": "Zaroktiya te bidawî dibe, dema tu têdigihîjê ku xew ne siza ye, xelat e. -Fyodor", "author": "Fyodor Dostoevsky"}]}, {"title": "ZEWAC", "quotes": [{"text": "Kurê min heta bizewice kurê min e. keça min heta mirinê keça min e.", "author": "Emily Giffin"}, {"text": "Kesê ji tenêtiyê ditirse, bila nezewice.", "author": "Anton Chekhov"}, {"text": "Ku pirtûkan nexwîne, pê re nezewice.", "author": "Charles Darwin"}, {"text": "Kesê pişta xwe bi jineke ku jê hez dike ve girê bide, tu carî naterpile.", "author": "Mark Twain"}, {"text": "Tu bixwazî dinyayê biguherînî vêya berî zewacê bike. Piştî zewacê tu karibî kenala televîzyonê biguherînî mêrxasê wek te tune ne.", "author": "Edhem Şerqawî"}, {"text": "Jina mêrê feqîr, tenê bi şev bextewer e.", "author": "Gotina Efrîqiyan"}]}, {"title": "ZIMAN Û FERHENG", "quotes": [{"text": "Eger milletek bi zimanê xelkê jihev fêm bike, trajediya mezin ew e!", "author": "Suleyman Çevîk"}, {"text": "Ziman warê hebûnê ye.", "author": "Heidegger"}, {"text": "Ziman, neynika mêjî ye.", "author": "Leibniz"}, {"text": "Hawara me berî her tiştî heyîna zimanê me dê bide naskirin. Lewma ku ziman şerta heyinê a pêşin e.", "author": "Mîr Celadet Alî Bedirxan"}, {"text": "Ziman cebilxaneya hişê mirov e. Di heman demê de hem xenî metên rabirdûyê, hem jî çekên ji bo serkeftinên dahatûyê di xwe de dihewîne.", "author": "Edward Said"}, {"text": "Kesê zimanê xwe winda dike, dişibe dara bê kok.", "author": "Gotina Abhazyan"}]}];
var AU={"Paulo Coelho": [{"text": "Balindeyên qefesê di ewlehiyê de ne, lê Xwedê balinde ne ji bo qefesê afirandine.", "chapter": "AFIRANDIN"}, {"text": "Eger baweriya te bi rêya ku pê de diçî temam be, astengên ku derkevin pêşberî te, tenê ji bo te cihê bêhnvedanê ne.", "chapter": "BIXWEBAWERÎ"}, {"text": "Ji te hez dikim. Ji ber ku hemî gerdunê bo hevgihîştina min û te hevkarî kiriye.", "chapter": "ÇARENÛS - QEDER"}, {"text": "Ger tu tiştekî bi dil û can bixwazî, ji bo pêkanîna wî tiştî, hemî gerdûn hevkariyê dike.", "chapter": "ÇARENÛS - QEDER"}, {"text": "Nedize. Çimkî hikûmet ji raqîban hez nake.", "chapter": "DIZÎ"}, {"text": "Ji her hîskirinekê re hevok nayê saz kirin.", "chapter": "HEST – HESTIYARÎ"}, {"text": "Ji bo birînek baş bibe, divê tu dev ji xwerandina wê berdî.", "chapter": "JIBÎR KIRIN"}, {"text": "Kesên ji te nefret dikin, esas ew heyranên te yên veşartî ne ku, tênagihîjin bê çima evqas mirov ji te hez dikin.", "chapter": "KÎN Û NEFRET"}, {"text": "Kesê Xwedê nas dikin, ji pênasekirina wî bêzar in. Kesê wî pênase dikin û pesnê wî didin, wî nas nakin.", "chapter": "PESINDAN"}, {"text": "Pînokyoyê ku textikî bu jî, dema derew dikirin pozê wî dirêj dibû. Lê mirovên vêga; ruyên wan jî naêşe.", "chapter": "ŞERMÎ"}, {"text": "Min çi winda kiribe, ji tirsa windakirinê ye.", "chapter": "TIRS Û ENDÎŞE"}, {"text": "Bi kesên ji derewên xwe bawer dikin re nekevin niqaşê, da ku dema we bi avê de neçe.", "chapter": "VIR Û DEREW"}, {"text": "Carinan ji bo em bizanibin em kî ne, divê em xwe wenda bikin.", "chapter": "XWENASÎN"}], "Omar Mokhtar": [{"text": "Xwedê te azad afirandiye. Wekî ku tu hatiye afirandin azad bimîne. Azad ew e ku aqilê xwe, fikrê xwe, helwesta xwe û welatê xwe nafiroşe.", "chapter": "AFIRANDIN"}], "Van Gogh": [{"text": "Eger wêrekîya çêkirina tiştên nûjen bi me re tunebûya, dê jiyana me çawa bûya?", "chapter": "AFIRANDIN"}], "PK (fîlm)": [{"text": "Du Xweda hene.Yek, yê ku em afirandine.Didu, yê ku me ew afirandiye.", "chapter": "AFIRANDIN"}], "Spinoza": [{"text": "Xwedê em di sûretê xwe de neafirandine. Me ew di sûretê xwe de afirandiye.", "chapter": "AFIRANDIN"}, {"text": "Nefreta ku ji sofîtî û oldarîya zêde çêdibe, ji hemî nefretên din kûrtir û dirêjtir e.", "chapter": "KÎN Û NEFRET"}, {"text": "Tiştên Paul derbareyê Peter de dibêje, ji Peter zêdetir Paul bi me dide nasîn.", "chapter": "PAŞBÊJÎ"}, {"text": "Mirovê pozbilind ji parîxwer, lêbok û qeşmeran pir hez dike. Ji hebuna gîyanên asîl jî nefret dike.", "chapter": "POZBILINDÎ"}], "Suhrewerdî": [{"text": "Yekemîn tiştê ku Xwedê ew afirandiye, aqil e.", "chapter": "AFIRANDIN"}, {"text": "Heybet û gewretîya bêdengîyê, nefiroşe bi gotineke ji rêzê.", "chapter": "BÊDENGÎ"}, {"text": "Comerdî dayîna bêbergîdan e. Kesê ji bo pesn û qezenckirina xêrê bide, ev ne comerdî ye, danûstandin e.", "chapter": "COMERDÎ"}, {"text": "Her tişt xwediyê cewherekî ye; cewherê mirov aqil e, cewherê aqil jî sebr e.", "chapter": "SEBR"}], "Anatole France": [{"text": "Beşek ji giyanê mirovî şîyar nabe,heta ji ajalan hez neke.", "chapter": "AJAL"}, {"text": "Em dê ti carî çîrokê ji devê şeytên nebihîzin. Kitêbên pîroz yekalî hatine nivîsandin.", "chapter": "ŞEYTAN"}], "Epiktetos": [{"text": "Heger ga û berazan bikariba biaxivin,dê henekên xwe bi wan kesên ku ji xeynî êm û alîf xeber didin, bikira.", "chapter": "AJAL"}, {"text": "Yê pesnê kesî nede, kesî biçûk neke, yê gazinan ji kesî neke, yê kesî tewanbar neke... Ew kesekî tekûz e.", "chapter": "PESINDAN"}], "JeanJacques Rousseau": [{"text": "Ramîn, dijraberîya xwezayê ye.(Ramîn ne xwezayî ye) mirovê xwedîfikr ajalekî ji rê derketî ye.", "chapter": "AJAL"}, {"text": "Kesê nikaribe erka bavtiyê bicih bîne, mafê wî tune ku bizewice u bibe xwedî zarok.", "chapter": "DAYÎK Û BAV"}, {"text": "Çiqas dostên we yên ji dil hebin, hêz û semaxa we ya li dijî zehmetiyên jîyanê bilindtir dibe.", "chapter": "DOSTANÎ Û HEVALTÎ"}, {"text": "Zordestîya herî mezin di bin mertalê zagonan de û bi navê dadmendîyê tê kirin.", "chapter": "ZAGON"}], "Fyodor Dostoevsky": [{"text": "Ajalek qet nikare mîna mirovekî bibe stemkar; tenê mirov dikarin stemkariyeke bi hostetî û hûnerî pêk bînin.", "chapter": "AJAL"}, {"text": "Tu dikarî bi werîsekîxwe bixeniqînî jîû tu dikarî bi heman werîsîhêlekanê jî çêbikî.Bendikên jiyanêdi destê te de ne.", "chapter": "AMÛR Û ALAV"}, {"text": "-çima niha qet tiştekî nakî?\n-dikim.\n-çi dikî?\n-difikirim.", "chapter": "AQIL - FIKR Û RAMAN"}, {"text": "Kesê ji bîst xulekan zêdetir biaxive, di guhdarvanan de hesta kuştinê peyde dike.", "chapter": "AXAFTINA ZÊDE"}, {"text": "Azadî ji nan xweştir, ji rojê xweşiktir e.", "chapter": "AZADÎ"}, {"text": "Kesê bide dûv çend kîvroşkan,yekê jî bi dest naxe.", "chapter": "AZWERÎ Û ÇAVBIRÇÎTÎ"}, {"text": "Ev serdem, bo mirovên ji rêzê re serdemeke rewnaq e. Lewra ev serdema nifşekî bêhest, nezan, tenbel, bêkêr û bêked e.", "chapter": "BÊKÊRÎ"}, {"text": "Dizanim xwedê barekî ku ez nikaribim hilbigirim li min nake, lê dîsa jî dibêjim, xwezî ewqasî baweriya xwe bi min neanîba.", "chapter": "BERPIRSIYARÎ"}, {"text": "Ji xeynî serpêhatiyên em dixwazin ji bîr bikin, tiştek di hişê me de namîne.", "chapter": "BÎR – BINBÎR"}, {"text": "Ji xeynî tiştên em dixwazin ji bîr bikin, tiştek namîne di bîra me de.", "chapter": "BÎRANÎN"}, {"text": "Ev civak dijminê xwebûn, xwezayîbûn û sadebûnê; evîndarê tevlîhevî, durûtî û rûpoşîyê ye.", "chapter": "DURÛTÎ"}, {"text": "Ji mirovekî şaş û devereke şaş zêdetir, tiştek rihê mirov nakuje.", "chapter": "GÎYAN"}, {"text": "Giyanê mirov, ji bo Ehrîmen û Yezdan qada şer e.", "chapter": "GÎYAN"}, {"text": "Her tim çêniyek nan ji bo me mezintir xuya dike, dema em wî di destê kesên din de dibînin.", "chapter": "HESÛDÎ – ÇAVNEBARÎ"}, {"text": "Tu yê sêwî bimînî di tunebûna hezkiriyê xwe de, welew hemî alem te hembêz jî bike.", "chapter": "HEZKIRIN"}, {"text": "Tiştek namîne di bîra me de, ji bilî tiştên em dixwazin ji bîr bikin.", "chapter": "JIBÎR KIRIN"}, {"text": "Tiştekî ji ken xweştir hebe ew jî kenandin e.", "chapter": "KEN Û GIRÎN"}, {"text": "Dema keştiyek dike ku binav bibe, ewilî mişk wê keşetiyê terk dikin.", "chapter": "MELAQÎ – ŞELAQÎ"}, {"text": "Ku giyanê te di nav tawanan de xerq bûbe, çi fêdeya nimêjan heye?", "chapter": "PERESTIN (ÎBADET)"}, {"text": "Ger tu li trêneke şaş siwar bûbî, li îstasyona ewil dakeve. Ji ber ku çiqas mesafe zêde bibe, mesrefa vegerê jî zêde dibe.", "chapter": "POŞMANÎ"}, {"text": "Tu çi bikî bike, tu yê poşman bimirî; an ji kirinên xwe, an ji nekirinên xwe.", "chapter": "POŞMANÎ"}, {"text": "Di şert û mercên asayî de ez kesekî baş bûm, lê şert û merc qet ne asayîbûn.", "chapter": "REWŞA ASAYÎ"}, {"text": "Pêdiviya me bi şerekî nûjen heye. Şerekî ku çekên wî pirtûk, fermandarên wî rewşenbîr û qurbaniyên wî jî cehalet û paşverûtî ne.", "chapter": "REWŞENBÎRÎ"}, {"text": "Nebêje her tişt bi ser min de tê, dibe ku tu di aliyê berevajî de diçî.", "chapter": "REXNE"}, {"text": "Ji kesî re nebe bar. Ev derseke exlaqî ye.", "chapter": "SINC – EXLAQ"}, {"text": "Bextreşî weke şewbeke pandemîk e. Divê kesên bêsiûd û belengaz ji hev dûr bikevin.", "chapter": "ŞENS – FERSEND"}, {"text": "Gelek rê û rêbaz hene ji bo têkiliyeke baş li gel jinên hestiyar. Lê yek ji wan jî bikêr nayê.", "chapter": "TÊKILÎ"}, {"text": "Tenêtî quncikeke biçûk e ku mirov li wê derê li pêşberî aqilê xwe radiweste.", "chapter": "TENÊTÎ"}, {"text": "Oxir be ji te re. Ji niha û şûn de em du biyanî ne...", "chapter": "VEQETÎN"}, {"text": "Her dever bo min xûrbet e.", "chapter": "VEQETÎN"}, {"text": "Derew tekane îmtîyaz e ku mirovî ji zîndewerên din vediqetîne.", "chapter": "VIR Û DEREW"}, {"text": "Erê birako! Xembarî nexweşiyeke mîna şewbê ye. Kesên reben û xembar ji bo rewşa wan xirabtir nebe, divê ji hev dûr bikevin.", "chapter": "XEMGÎNÎ"}, {"text": "Zaroktiya te bidawî dibe, dema tu têdigihîjê ku xew ne siza ye, xelat e. -Fyodor", "chapter": "ZAROK – ZAROKATÎ"}], "Schopenhauer": [{"text": "Çiqas mirovan nas dikim,hezkirina min bo ajalan zêdetir dibe.", "chapter": "AJAL"}, {"text": "Hema bêje hemî tiştên ku ji aliyê civakê ve “rast” tên dîtin, “şaş” in. Kapasîteya hizirîna civakê kêm e, hêza muhakemeya wê, hê kêmtir e.", "chapter": "CIVAK"}, {"text": "Mirovê ji rêzê, berhemeke fabrîkasyon a xwezayê ye. Û xweza, her roj bi hezaran kesên wisa diafirîne.", "chapter": "CUDAHÎ - RESENÎ"}, {"text": "Mirov heya neyê keviya kendal û zinaran, bi per û bask nabe.", "chapter": "KIRYAR – ÇALAKÎ"}, {"text": "Em di rojên wilo de derbas dibin ku, li gel hemî şert û mercên xirab jî, divê em tenduristiya hişê xwe biparêzin.", "chapter": "PARASTIN"}, {"text": "Tişta fîlozof pê dibe fîlozof, ew wêrekîye ku qet pirsekê di dilê xwe heps nake.", "chapter": "PIRS Û BERSIV"}, {"text": "Kesên di dilê wan de ronahî tune ye, ji bo bidestxistina ronahîyê tevlî qelebalixan dibin.", "chapter": "RONAHÎ – TARÎTÎ"}, {"text": "Bi rastî ‘mirov’ ajalek hov û talûke ye. Em wî, bi halê wî yê kedî nas dikin ku jê re dibêjin şaristanî. Ji ber vê yekê, dema ku car caran kurmê wî yê rasteqîn derdikeve holê, em dibizdin.", "chapter": "ŞARISTANÎ"}, {"text": "Her veqetîn, dîmenekî mirinê pêşkêşî me dike.", "chapter": "VEQETÎN"}, {"text": "Her sêwlekekî bêhiş dikare kêzikekê biperçiqîne, lê hemî zanyarên cîhanê nikarin rih bidin wê kêzikê.", "chapter": "ZANIST"}], "Gotina Çîniyan": [{"text": "Beriya tu tî bibî, bîrê bikole.", "chapter": "AMADEHÎ"}, {"text": "Kesê berî gav avêtinê zêde difikire, jîyana xwe li ser pîyekî derbas dike.", "chapter": "BIRYAR Û BİJARTIN"}, {"text": "Ji bo dilşadî û bexteweriya demjimêrekê, rakeve. ji bo rojekê, masiyan bigre. ji bo mehekê, derkeve bêhnvedanê. ji bo salekê, bizewice. ji bo temenekî, karekî tu jê hez dikî bike.", "chapter": "DILŞADÎ Û BEXTEWERÎ"}, {"text": "Ji bo bexteweriyê rê tune ye, bextewerî rê ye.", "chapter": "DILŞADÎ Û BEXTEWERÎ"}, {"text": "Fêrbûnî mîna avjenîya li dijî şîpê ye. Dema tu bi pêşve neçî tu yê bi paşve biçî.", "chapter": "FÊRBÛN"}, {"text": "Tu bikaribî kurtedemekê hêrsa xwe kontrol bikî, tu yê xwe ji sed rojên poşmaniyê xilas bikî.", "chapter": "KONTROL – OTOKONTROL"}, {"text": "Darek ji fêkiyên xwe, baweriyek jî ji bawermendên xwe tê nas kirin.", "chapter": "OL Û AYÎN"}, {"text": "Sê cureyên rastiyê hene: Rastiya min, rastiya te û rastî.", "chapter": "RASTÎ Û DIRÛSTÎ"}, {"text": "Ji dêvla tu çêr û dijûnan bi tarîtiyê bikî, mûmekê pêxe.", "chapter": "RONAHÎ – TARÎTÎ"}, {"text": "Tu ne beşerxweş bî, nebe dikandar.", "chapter": "RÛKENÎ"}, {"text": "Hê ti tî nebûyî, bîrê bikole!", "chapter": "TEVDîR (BERGIRÎ)"}, {"text": "Kesê kûlma ewil diavêje, kêmaniya fikrên xwe qebûl dike.", "chapter": "TUNDÛTÛJÎ"}], "Abraham Lincoln": [{"text": "Ger ji bo birrîna darekêşeş demjimêran bidin min,ez ê çar demjimêranji bo tûjkirina bivir veqetînim.", "chapter": "AMADEHÎ"}, {"text": "Dema “dilsozî” xisletê te yê herî zeîf be, mirovê herî hêzdar tu yî li vê dinyayê.", "chapter": "DILSOZÎ"}], "Mark Victor Hansen": [{"text": "Tu ji bo çi amade bî,ew ji bo te amade ye.", "chapter": "AMADEHÎ"}], "Nietzsche": [{"text": "Kî dikare te bextewer bike,ger tu ne amade bî?", "chapter": "AMADEHÎ"}, {"text": "Kesê dikare ji bîr bike, dikare aram bibe.", "chapter": "ARAMÎ"}, {"text": "Tenê mirovê ku bê hedef dijî, tehma têkçûnê nahilîne.", "chapter": "ARMANC"}, {"text": "Ev demeke dirêj e ku dinya bûye timarxane.", "chapter": "BÊAQILÎ – DÎNÎTÎ"}, {"text": "Tu jîyaneke rehet dixwazî? Nêzîkî kerîyekî bibe û xwe ji bîr bike.", "chapter": "CEHALET"}, {"text": "Kuçik çawa ji guran nefret dikin, ha wilo civak ji giyanên azad nefret dike.", "chapter": "CIVAK"}, {"text": "Dema em diwestin, an jî cesareta xwe winda dikin; fikr û ramanên ku me berê zora wan biribû, dîsa êrîşî me dikin.", "chapter": "DERÛNNASÎ"}, {"text": "Kesên ti carî nebûne şahidê hilatina rojê, ji avaçûna wê re dibêjin romantîzm.", "chapter": "EKOLOJÎ – XWEZA"}, {"text": "Şairtî ji min nehat, ez jî bûm feylesof.", "chapter": "FELSEFE – ÎDEOLOJÎ"}, {"text": "Li dinyayê du cûre mirov hene: yên dixazin hîn bibin û yên dixwazin bawer bikin.", "chapter": "FÊRBÛN"}, {"text": "Her fikr û ramanê sabît (neguher) zindana xwediyê xwe ye.", "chapter": "GUHERÎN"}, {"text": "Marên ku kirasên xwe naguherînin mehkûmî mirinê ne. Rewşa kesên fikr û ramanên xwe naguherînin jî wisa ye.", "chapter": "GUHERÎN"}, {"text": "Tekane tiştê ku heta îro bi awayekî sîstematîk hatiye qedexekirin, heqîqet e.", "chapter": "HEQÎQET"}, {"text": "Dê ti carî te efû nekin, ji ber ku te ji wan derbas kiriye û ew li paş hiştine.", "chapter": "HESÛDÎ – ÇAVNEBARÎ"}, {"text": "Kesê serwext û têgihiştî, wekî ku di nav ajalan de be, dema digere di nav mirovan de.", "chapter": "HIŞ – HIŞMENDÎ"}, {"text": "Eger li welatekî axaftin ji huner û wêjeyê bêhtir li ser siyasete be, ew welat di rêjeya sêyem de ye.", "chapter": "HUNER - HUNERMEND"}, {"text": "Eger li welatekî ji aqil û hunerê bêhtir, girîngî bi serwet û diravan bê dayîn; li wê derê kîsikên pereyan nepixîne, lê mêjî vala mane.", "chapter": "HUNER - HUNERMEND"}, {"text": "Kesê ji bîr dike, baş dibe.", "chapter": "JIBÎR KIRIN"}, {"text": "Jin ji derewan nefret dikin, mêr jî ji xapandinê. Lê herdu jî di tiştên ku jê nefret dikin de hoste ne!", "chapter": "JIN Û MÊR"}, {"text": "Jin, dafikeke xwezayî ye.", "chapter": "JIN Û MÊR"}, {"text": "Ger vebe çavên korekî û bibîne van tiştên xirab li ser rûyê erdê; dê nifiran bike li kesê ku çavên wî baş kirine.", "chapter": "KAOS"}, {"text": "Dewlet di kêlîyên şer û felaketên mezin de, bêçaretîya xelkê bi oldariyê tepeser dike.", "chapter": "LAÎSÎZM"}, {"text": "Liv û tevgera herî mirovperwer çiye? Rêlibergirtina fedîkirina mirovekî ye.", "chapter": "LIV Û TEVGER"}, {"text": "Lîstikeke ku evîn û rik tê de tunebe,jin lîstikvaneke pileya navîn e.", "chapter": "LÎSTIK"}, {"text": "Mafê tu bikaribî bi xwe bi dest bixî, nehêle hin kesên din bidin te.", "chapter": "MAF – MAFDARÎ"}, {"text": "Ev jî tê de, hemî gelemperîkirin şaş in.", "chapter": "MANTIQ"}, {"text": "Stranên kesên xirab tune ne.", "chapter": "MOSÎQA"}, {"text": "Hemî behremendên gewre derbareyê jîyanê de gihaştine heman encamê: “nehêja ye”", "chapter": "NÎHÎLÎZM"}, {"text": "Mirovên herî xirab mamosteyên ayînî (keşe û mele) ne. Ew tiştên dijxwezayî fêr dikin û ji delîlan fêhm nakin. Ciyê wan timarxane ye.", "chapter": "OL Û AYÎN"}, {"text": "Dema destê min bigihîje kesekî dîndar, divê destê xwe bişom!", "chapter": "PAŞVERÛTÎ – KEVNEPERESTÎ"}, {"text": "Bawerîyên kur û negûher, dijminê heqîqetê ne û ji bêbawerîyê bi gellekî talûketir in.", "chapter": "PAŞVERÛTÎ – KEVNEPERESTÎ"}, {"text": "Ez ne ber derewa te dikevim; ez ber wê yekê dikevim ku, ez ê careke din ji te bawer nekim.", "chapter": "PÊBAWERÎ"}, {"text": "Hûn demekê meymûn bûn; lê mixabin hûn vêga jî, ji meymûnekê meymûntir in.", "chapter": "PERESAN - TEKAMÛL"}, {"text": "Şagirt heta hetayê şagirt bimîne, qîmetê mamosteyê xwe dadixîne.", "chapter": "PERWERDE – PEDAGOJÎ"}, {"text": "Dibêjî qey heya niha nijada mirovan, ji hêla qerdîyan û celadan ve hatiye perwerdrin.", "chapter": "PERWERDE – PEDAGOJÎ"}, {"text": "Heta pesnê te bê dayîn, bi zanibe tu ne di rêya xwe de dimeşî. Tu di rêya hin kesên din dimeşî.", "chapter": "PESINDAN"}, {"text": "Dixwazî bi pêşve biçî? Rê bide xwe.", "chapter": "PÊŞKEWTIN"}, {"text": "Kitêbeke ku me ji hemî kitêban nebihûrîne bi kêrî çi tê?", "chapter": "PIRTÛK"}, {"text": "Qencî û xerabî du têgihin ku ji hêla mirovî hatine afirandin û ev herdu têgih jî guherbar in.", "chapter": "QENCÎ Û XERABÎ"}, {"text": "Zerdeşt got, “ez nehatime ku bibim şivanê we; hatime we ji kerî veqetînim.”", "chapter": "SERXWEBÛN – XWESERÎ"}, {"text": "Tiştekî we yê ku hûn tê de bicîh bikin hebe, hezar berîkên rojekê hene.", "chapter": "ŞENS – FERSEND"}, {"text": "Wiha dibêje kesê bîrewer: “şermî, şermî, şermî...” Ev e dîroka mirovahiyê.", "chapter": "ŞERMÎ"}, {"text": "Mirov ji ber fikrên xwe yên qirêj şerm nakin. Ji îhtîmala pêhisîna kesên din şerm dikin.", "chapter": "ŞERMÎ"}, {"text": "Tiştê mirov şêt dike ne guman e, teqezî ye.", "chapter": "ŞIK Û GUMAN"}, {"text": "Tenêtî, kevintirîn esilzadetî û maquliya vê cîhanê ye.", "chapter": "TENÊTÎ"}, {"text": "Herkes heyranê vîna hêzdar e. Ji ber ew ku bi kesekî re tuneye.", "chapter": "VÎN – ÎRADE"}, {"text": "Belê hilgirtina barê jîyanê giran e: lê hûn jî ewqasî ne dilkeçik bin heyran!", "chapter": "VÎN – ÎRADE"}, {"text": "Şerê te yê li dijî ejdehayan têrê nake, di dema şer de divê tu jî bibî ejdeha!", "chapter": "WÊREKÎ"}, {"text": "Eger kêfa te ji deryayê re tê, divê tu ji pêlên wê jî hez bikî. Tu bi tirs bijî, tu yê tenê temaşevanê jiyanê bî.", "chapter": "WÊREKÎ"}, {"text": "Nivîskar divê devê xwe bigre, bo ku berhema wî devê xwe veke.", "chapter": "XWENDIN Û NIVÎSANDIN"}, {"text": "Zanîn jî şehwetek e wek hemî şehwetan.", "chapter": "ZANEBÛN"}], "Alexandra Udinov": [{"text": "Eger tu ji rûbirûbûnagûran re ne amade bî,noqî daristanê nebe.", "chapter": "AMADEHÎ"}], "Jim Rohn": [{"text": "Heger tu ji rîskeke nepenî rene amade bî,“jirêzêbûna” xwe razî be.", "chapter": "AMADEHÎ"}, {"text": "Devera tu lê yî ger ku te bextewar nake, ciyê xwe biguherîne.", "chapter": "DÛR KETIN"}], "Harold Maslow": [{"text": "Kesê ji bilî çakûç tiştekî dindi destê wî de tune be,her tiştî mîna bizmaran dibîne.", "chapter": "AMÛR Û ALAV"}], "Gotina Romanan": [{"text": "Karkerê xirab,bi amûr û alavan re şer dike.", "chapter": "AMÛR Û ALAV"}], "Donnie Brasco": [{"text": "Kesê gulî û çiqlîyê te bişkêne, tu dara wî ji erq rake. Ev ne psîkopatî ye.", "chapter": "ANARŞÎ"}], "Joseph Proudhon": [{"text": "Anarşî, rizgarîya ji efendî û serweran e.", "chapter": "ANARŞÎ"}], "Goméz Dávila": [{"text": "Anarşiya ku civakeke pespaye tehdît dike, ne siza ye, dewa ye.", "chapter": "ANARŞÎ"}, {"text": "Heqîqet ne îzafî ye, nêrînên derbareyê heqîqetê îzafî ne.", "chapter": "HEQÎQET"}], "Paulo Freire": [{"text": "Mirov bûne du beş:Hinek ji ber birçîbûnê ranazên,hinek jî ji tirsa wan birçîyan ranazên.", "chapter": "ANARŞÎ"}, {"text": "Xwekêmdîtin, taybetmendîyeke bindestan e.", "chapter": "KOLONYALÎZM - DAGIRKERÎ"}], "Lenin": [{"text": "Eger hêza we ji bo şewitandina sindoqan tune be,wateya boykot kirinê tune ye.", "chapter": "ANARŞÎ"}, {"text": "Di navbera nan û azadîyê de, mirov her tim nan hildibijêrin.", "chapter": "PÊDIVÎ"}], "Victor Hugo": [{"text": "Fikr û ramanekî ku dema wî hatibe, jê hêzdartir tiştek tune ye.", "chapter": "AQIL - FIKR Û RAMAN"}, {"text": "Ti artêş bi qasî fikrekî ku dema wî hatibe, ne hêzdar e.", "chapter": "AQIL - FIKR Û RAMAN"}, {"text": "Dînitî, protestoya mirovên hestiyar e.", "chapter": "BÊAQILÎ – DÎNÎTÎ"}, {"text": "Fikr û ramanên xwe biguherin; lê li prensîbên xwe xwedî derkevin. Pelên xwe biweşînin; lê dest nadin kokên xwe.", "chapter": "GUHERÎN"}, {"text": "Evîneke bêhesûdî ne rast e, ne jî paqij e.", "chapter": "HESÛDÎ – ÇAVNEBARÎ"}, {"text": "Mirin ne tiştek e,afata mezin jiyan e.", "chapter": "JÎYAN"}, {"text": "Ji min re behsa baranê neke, bibare.", "chapter": "KIRYAR – ÇALAKÎ"}, {"text": "Beheşta dewlemendan, bi dojeha xizanan hatiye avakirin.", "chapter": "MALDARÎ – DEWLEMENDÎ"}, {"text": "Şarezayî ew e ku, tu di kalbûnê de jî rihê zaroktiyê winda nekî.", "chapter": "PÎR Û KAL"}, {"text": "Ji bîr meke, ji xweşûbêşîya pêşwext, poşmanî çêdibe.", "chapter": "POŞMANÎ"}, {"text": "Kesê bi ronahiya xwe bawer e, ji şewqa kesên din dilteng nabe.", "chapter": "RONAHÎ – TARÎTÎ"}, {"text": "Çerxa zordaran bi serê wan cahilên ku mêjiyê xwe naxebitînin digere.", "chapter": "ŞAREZATÎ Û EHMEQÎ"}, {"text": "Kes li têkoşîna te ya li dijî pêlan nanêre. Te keştî gihandiye benderê, yan na? Li wê dinêrin.", "chapter": "TÊKÇÛN – SERKEFTIN"}, {"text": "Mensûbiyata we ya bi ol u baweriyekê ve, we nake mirovekî baş. Qencbuna mirov bi wijdan ve girêdayî ye. Wijdan xwedayê di hundirê mirov de ye.", "chapter": "ÛJDAN"}, {"text": "Hindik derew nayên kirin. Kesê derewekê bike, dikare hemî derewan bike.", "chapter": "VIR Û DEREW"}], "Îbn Ruşd": [{"text": "Per û baskên fikr û ramanan hene. Kes nikare wan ji bo gihîştina mirovan asteng bike.", "chapter": "AQIL - FIKR Û RAMAN"}, {"text": "Cehalet tirsê, tirs nefretê, nefret tundiyê encam dide. Ev hevsengî ye.", "chapter": "CEHALET"}, {"text": "Dijminê herî mezin ji bo ola îslamê ew e ku, mirovan bi kafirbûnê tewanbar dike.", "chapter": "TEWANBARÎ"}], "Hipokrates": [{"text": "Aqilê xwe bo hemî karên xwe bike serwer; çimkî tevizandina aqil cureyekî mirinê ye.", "chapter": "AQIL - FIKR Û RAMAN"}], "Cenab Şahabettin": [{"text": "Çima ez fikrên xwe diguherînim? Çimkî ez xwediyê fikrên xwe me; ne xûlamê wan.", "chapter": "AQIL - FIKR Û RAMAN"}], "Bernard Shaw": [{"text": "Kesê bi aqil, aqilê xwe bi kar tîne. Kesê biaqiltir, aqilê kesên din jî bi kar tîne.", "chapter": "AQILMENDÎ"}, {"text": "Demokrasî ji civateke cahil re bêfêde ye, ji ber ku pirraniya keran dê biryara çarenûsa te bidin.", "chapter": "DEMOKRASÎ"}, {"text": "Eger di rêya hûn tê de dimeşin de zehmetî û astengî tune be. Bizanibin ew rê we nagihîne de verekê.", "chapter": "REWŞA ASAYÎ"}, {"text": "Jiyana rojekê wekî şêran, çêtir e ji ya sed salî wekî hêştirmeyan.", "chapter": "RÛMET"}, {"text": "Têkiliya min bi mirovan re mîna pelên dare ye. Yên dimînin fêde dibînin, yen diqetin hew dikarin vegerin.", "chapter": "TÊKILÎ"}, {"text": "Tiştekî, bo rojeke taybet veneşêre. Her roja tu tê de nefes distînî, taybet e.", "chapter": "TEMEN"}, {"text": "Dema xemgîn dibim, stranan dinehwirînim, ferq dikim ku dengê min ji pirsgireka min xirabtir e; dibişirim.", "chapter": "XEMGÎNÎ"}], "Gotina Swêdiyan": [{"text": "Ji bo serkeftinê,aqilê rovî ji neynûkên şêr bikêrhatîtir e.", "chapter": "AQILMENDÎ"}, {"text": "Aqilê rovî ji nehperoşkên şêr bikêrhatîtir e.", "chapter": "AQILMENDÎ"}, {"text": "Bi şopandina rêçika kesekî din, tu yê qet nebî yekemîn.", "chapter": "CUDAHÎ - RESENÎ"}, {"text": "Mirin miqnatîsa Xwedê ye.", "chapter": "MIRIN"}, {"text": "Tenê masiyên mirî ber pêlan dikevin.", "chapter": "TÊKOŞÎN - XEBAT"}], "Ebû Ala el-Maarrî": [{"text": "Ji xeynî aqil, ti îmam (pêşeng) tune ye.", "chapter": "AQILMENDÎ"}], "Einstein": [{"text": "Zîrek, pirsgirêkan çareser dike. Aqilmend, pirsgirêkan asteng dike.", "chapter": "AQILMENDÎ"}, {"text": "Eger hûn bixwazin jiyaneke aram bijîn, jiyana xwe bi armancekê ve girê bidin, ne bi kes ûtiştan ve.", "chapter": "ARMANC"}, {"text": "Kesê qet çewtiyek nekiriye, qet tiştekî nûjen neceribandiye.", "chapter": "CERIBANDIN - METOD"}, {"text": "Çîna serdest ji pereyan re, çîna navîn ji serokan re, çîna bindest jî ji xwedawendan re perestîyê dike.", "chapter": "ÇÎN"}, {"text": "Mantiq we ji A’yê digihîne B’yê,lê xeyal we digihîne her deverê.", "chapter": "MANTIQ"}, {"text": "Zîrekîya mirovekî ne di bersivan de, di pirsan de tê xuyakirin.", "chapter": "PIRS Û BERSIV"}, {"text": "Ji reşbînan (pesîmîst) dûr bikevin, çimkî ji bo her çareseriyekê pirsgirêkeke wan heye.", "chapter": "REŞBÎNÎ – XWEŞBÎNÎ"}], "Emile Zola": [{"text": "Dema mirov ne hêzdar be, divê biaqil be.", "chapter": "AQILMENDÎ"}], "Andre Maurois": [{"text": "Dilxweşiya tu li bendê yî, ji ya ku te tehm kiriye xweştir e.", "chapter": "ARAMÎ"}, {"text": "Êşa her rojê, besî xwe ye.", "chapter": "ÊŞ Û JAN"}, {"text": "Gelek caran, em dilnerihetiya xwe bi destê xwe amade dikin.", "chapter": "VÎN – ÎRADE"}], "Oscar Wilde": [{"text": "Kesê xwediyê azadiyê,pirtûkan, kulilkan, rojê û hîvê be,dê çawa bibe bextreş?", "chapter": "ARAMÎ"}, {"text": "Ji niha û şûn de ez bûm wek kişikê: min birc firot, fîlan serî hilda, wezîr xwe kuşt, min hesp jî berdan. Û min ji pîyonên derdora xwe jî ti hêvîyek nekir. Niha ên kû xwe şah dihesibînin, bila derkevin pêşberî min.", "chapter": "BÊMINETÎ"}, {"text": "Çi zû, çi dereng... Her kesek berdêla kiryarên xwe dide.", "chapter": "BERDÊL"}, {"text": "Bihûşt jî dojeh jî di hundirê me de ye.", "chapter": "BIHÛŞT Û DOJEH"}, {"text": "Berê amûr û alavên îşkenceyê hebûn,lê niha êdî rojnameyan ciyê wan girtiye.", "chapter": "ÇAPEMENÎ"}, {"text": "Hinek mirov bextewer in, hinek jî ne bextewar. Yên mayî ew bextreş in ku, xwe mîna bexteweran nîşan didin.", "chapter": "DILŞADÎ Û BEXTEWERÎ"}, {"text": "Ez bawer im em gelekî zêde li xwezayê temaşe dikin, lê em pir hindik tê de û pê re dijîn.", "chapter": "EKOLOJÎ – XWEZA"}, {"text": "Dema hûn bibin xwedîbandor, hûn dibin xwedîdijmin jî. Ji bo hûn bibin yekî jêhezkirî, bibin yekî ji rêzê, bes e.", "chapter": "HESÛDÎ – ÇAVNEBARÎ"}, {"text": "Li dinyayê tiştê herî kêmpeyde,jiyîn e. Gelek kes, tenê hene û hew.", "chapter": "JÎYAN"}, {"text": "Dema ez biçûk bûm, min digot qey maldarî her tişt e. Piştî ku ez mezin bûm, min dît ku ez mafdar im.", "chapter": "MALDARÎ – DEWLEMENDÎ"}, {"text": "Hinek mirov devera diçin xweş dikin, hinek jî devera terk dikin.", "chapter": "MIROVV - MIROVAHÎ"}, {"text": "Mirovê nankor ew e ku bihayê her tiştî dizane, lê qîmetê tu tiştî nizane.", "chapter": "NANKORÎ"}, {"text": "Em kesên din didarizînin, ji ber ku cesareta me têra darizandina nefsa me nake.", "chapter": "NEFS"}, {"text": "Xortanî xweş e, lê çi fêde di destê xortan de heba dibe.", "chapter": "PÎR Û KAL"}, {"text": "Zehfê mirovan, ‘kesên din’ in. Fikr û ramanên wan, yên kesên ‘din in’, jîyana wan, teqlîd kiri na ‘kesên din’ in, heta hestên wan jî kesên din in.", "chapter": "SERXWEBÛN – XWESERÎ"}, {"text": "Şeytan tenê pêşkêş dike, mirov hildibijêre.", "chapter": "ŞEYTAN"}], "Mark Manson": [{"text": "Rêya ku ber bi aramiyê diçe, bi kelem û xeyal şikestinan hatiye raxistin.", "chapter": "ARAMÎ"}, {"text": "Demên dijwar,karakterê mirov yê rasteqînderdixe holê.", "chapter": "KARAKTER – XÛY"}], "Confucius": [{"text": "Aramiya bêqisur tune ye,binêre li ser rojê jî leke heye.", "chapter": "ARAMÎ"}, {"text": "Zana, dike. Kêmzan, şîretan dike. Nezan, rexne dike. Bêkêr, kurtepistê dike.", "chapter": "BÊKÊRÎ"}, {"text": "Mirovên birûmet ji bo edaletê,Mirovên nemerd ji bo menfeetê têdikoşin.", "chapter": "BERJEWENDÎ"}, {"text": "Di jiyanê de sê tiştan baş bifikire; dilekî beriya tu bişkînî, deriyekî beriya tu lêxî, gotineke beriya tu dawiyê lê bînî.", "chapter": "DILPAKÎ"}, {"text": "Fêrkirin, dubare fêrbûn e.", "chapter": "FÊRBÛN"}, {"text": "Bi hêviyên mirovan neleyizin.Dibe ku ji wê pêve ti tiştekî wanên din tune be.", "chapter": "HÊVÎ – BÊHÊVÎTÎ"}, {"text": "Hêzdar ew e ku, ji herkesî bêhtir aliyên xwe yên lawaz nas dike. Hêzdartirîn kes ew e ku, dikare aliyên xwe yên lawaz kontrol bike.", "chapter": "HÊZDARÎ - LAWAZÎ"}, {"text": "An rêyekê bibîne,An rêyekê veke,An jî xwe ji rê bide alî.", "chapter": "LIV Û TEVGER"}, {"text": "Ji bo kêmaqilan, bersiva berfireh hewce nake.", "chapter": "PIRS Û BERSIV"}, {"text": "Heger amanca te plansaziya salekê be, birinc biçêne. Ku ya deh salan be, daran biçêne. Ku ya sed salan be, zarokan perwerde bike.", "chapter": "PLANSAZÎ"}, {"text": "Mirovê ku ji hêla çandî û rewşenbîrî ve lawaz be, xwe bi alayiş û nimayîşê derdixe pêş.", "chapter": "REWŞENBÎRÎ"}, {"text": "Tirsonek ew kesê heqîyê dibîne û alîkarîyê nade.", "chapter": "TIRSONEK"}, {"text": "Dema kermêşek li ser gunikê we deyne, hûn dê hîngê fêhm bikin ku, her pirsgirêk bi tundûtujîyê nayê çareserkirin.", "chapter": "TUNDÛTÛJÎ"}], "Goethe": [{"text": "Ha mîr ha gede, mirovê herî bextewar ew e ku di mala wî de hizûr heye.", "chapter": "ARAMÎ"}, {"text": "Her tişt bi demê tê telafîkirin, lê herikîna demê bi tiştekî din nayê telafîkirin.", "chapter": "DEM"}, {"text": "Ji dêvla ku wê bi qasî stêrkan hevalên te hebin, bila dostekî te yê ku di şevereşê de mîna çardehîvê şewq û biraq jê diçe hebe, bes e.", "chapter": "DOSTANÎ Û HEVALTÎ"}, {"text": "Kulîlk, peyv u hîyeroglîfên delal ên xwezayê ne. Xweza hezkirina xwe bi me dide nîşandan", "chapter": "EKOLOJÎ – XWEZA"}, {"text": "Kesê hez nake û gunehan nake, bila bê binerd kirin.", "chapter": "GUNEH"}, {"text": "Kesê bi destê xwe dixebite, KARKER e. Kesê bi destê xwe û mêjîyê xwe dixebite, HOSTE ye. Kesê bi destê xwe, mêjîyê xwe û dilê xwe dixebite, HÛNERMEND e.", "chapter": "HUNER - HUNERMEND"}, {"text": "Nankorî karê kesên zeîf e. Di nav mirovên hêzdar de ez li rastî nankorekî nehatim.", "chapter": "NANKORÎ"}, {"text": "Carinan tê hişê min û dibêjim; gelo gerestêrka me ne timarxaneya gerdûnê be?", "chapter": "ONTOLOJÎ"}, {"text": "Tiştê îro dest pêneke, sibê jî naqede.", "chapter": "PLANSAZÎ"}, {"text": "Kesê di dema xwe ya vala de tê cem te, wî xweş bibîne. Kesê di dema te ya vala de tê cem te, qedrê wî bigre. Kesê dema xwe bo te vala dike, wî bigre û bernede.", "chapter": "QEDR Û QÎMET"}, {"text": "Li vê dinyayê kêm caran du mirov hev fêhm dikin.", "chapter": "TÊGIHÎŞTIN"}, {"text": "Tu kes nikare me bixapîne, tenê em xwe dixapînin.", "chapter": "XAPANDIN"}, {"text": "Tiştek, bi qasî cehaleteke aktîv ne talûke ye û tiştek bi qasî zanîneke pasîv ne bêwate ye.", "chapter": "ZANEBÛN"}], "Jack Canfield": [{"text": "Keştiyeke ku li benderê ye di ewlehîyê de ye. Lê keştî ne ji bo li benderê rawestin têne çêkirin.", "chapter": "ARMANC"}], "Socrates": [{"text": "Wêrekî ew e ku, tu bi hindiktirîn zerarê bigihîjî amanca xwe.", "chapter": "ARMANC"}, {"text": "Kesên biaqil ji herkesî hîn dibin. Kesên ji rêzê ji serboriyên xwe hîn dibin. Kesên cahil jî, jixwe her tiştî dizanin.", "chapter": "CEHALET"}, {"text": "Ku di civakekê de pizîşk û dadnas biqedr bibin, ew civak çilvirî ye. Nexweşî û bêdadî di wê civakê de zêde bûne.", "chapter": "CIVAK"}, {"text": "Ji kesên berîya xwe êbret bistîne,lê ji yên pişt xwe re nebe êbret.", "chapter": "DERS Û ÊBRET"}, {"text": "Dinya keştiya bobelatan e.", "chapter": "DINYA"}, {"text": "Kesên biaqil, ji herkesî û her tiştî fêr dibin, kesên ji rêzê, tenê ji serpêhatiyên xwe fêr dibin, kesên nezan jî, her tiştî dizanin.", "chapter": "FÊRBÛN"}, {"text": "Mirovê biaqil ew e ku dizane wê kengê biaxive, çawa biaxive û bi kê re biaxive.", "chapter": "RETORÎK"}, {"text": "Derbareyê mirin û Xwedayan de tiştekî nizanim, û ez dikarim bi her tiştî sond bixwim ku hûn jî di vê meselê de tiştekî nizanin.", "chapter": "TEOLOJÎ"}, {"text": "Tenê başiyek heye, zanîn; û tenê xirabiyek heye, cahilî.", "chapter": "ZANEBÛN"}], "Tolstoy": [{"text": "Mirovê ku ji bilî bextewariya wî tu armanceke wî tune be, ew mirovekî neqenc e.", "chapter": "ARMANC"}, {"text": "Tu bixwazî hêzdar bî, hêviya hezkirinê ji kesekî neke.", "chapter": "BÊMINETÎ"}, {"text": "Di nezera min de her tişt bûye wek hev. Êdî tiştek ne xema min e. Gelo ji vê rewşê xirabtir tiştek heye?", "chapter": "BÊXEMÎ – XEMSARÎ"}, {"text": "Em bi ser neketin, ji ber ku me ji xwe re got, em ê bi ser nekevin.", "chapter": "BIXWEBAWERÎ"}, {"text": "Ji herkesî zêdetir keniya, xûya ye dilê wî diêşe.", "chapter": "DIL"}, {"text": "Tu bixwazî bextewer bibî, bibe.", "chapter": "DILŞADÎ Û BEXTEWERÎ"}, {"text": "Kes ji halê xwe ne razî ye, lê her kes ji aqilê xwe razî ye.", "chapter": "EGO – XWEPERESTÎ – EZ EZÎ"}, {"text": "Jiyan me bi çar kirariyan ezmûn dike: Bi rastiyan car dike, bi fîrqetê par dike, ji mirovatiyê derdixe û kêm dike û di dawiyê de dibêje; xwe bide hev.", "chapter": "EZMÛN"}, {"text": "Mirovatî cileke wisaye ku, li herkesî rûnane.", "chapter": "LîYAQAT"}, {"text": "Hemî malbatên bextewer dişibin hev. Lê bextreşiya her malbateke besiûd, naşibe ya din.", "chapter": "MALBAT"}, {"text": "Ne hewce ye em xwe bixapînin. Her tişt beradayî ye! Bextewer ew kes e ku hê ji diya xwe neketiye.", "chapter": "NÎHÎLÎZM"}, {"text": "Astenga ewil a li hember pêşkewtina takekes, malbat e.", "chapter": "PÊŞKEWTIN"}, {"text": "Dema ku bi nezanekî re dikevî gengeşeyê, her peyva tu bêjî, mîna êzingê ku bavêjî nava êgir e.", "chapter": "PEYV"}, {"text": "Kitêb, hiş û aqil kûbar dikin.", "chapter": "PIRTÛK"}, {"text": "Pozbilindî û rikberî ewilî dibe sebeb ku mirov xwe bêqisur bibîne, piştre jî dawîyê li xwedîyê xwe tîne.", "chapter": "POZBILINDÎ"}, {"text": "Nekevin heyra siberojê, siberoj tune ye. Tenê “dema niha” heye, bo wê bijîn.", "chapter": "RABIRDÛ Û DAHATÛ"}, {"text": "Beriya tu herriyê biavêjî kesekî din bifikire û tu carî jibîr neke; dê pêşî destê te bilewite.", "chapter": "TEWANBARÎ"}, {"text": "Em dixwazin gur jî têr bixwin, berx jî sax bimînin.", "chapter": "WEKHEVÎ"}, {"text": "Ji dêvla tu jiyanê bi rondikên çavê xwe xelat bikî, wê bi kenê xwe ceza bike.", "chapter": "XELAT"}], "Malcolm X": [{"text": "Eger hûn ne ji bo armancekêli ser pîyan bin,her derbek dikarewe bavêje erdê.", "chapter": "ARMANC"}, {"text": "Nijadperestî ne ramanekî îdeolojîk e, nexweşîyeke psîkolojîk e.", "chapter": "NIJADPERESTÎ"}, {"text": "Hêza berxwedana parastvanên azadîyê, ji hêza stemkaran zêdetir e.", "chapter": "TÊKOŞÎN - XEBAT"}], "Elî Şerîetî": [{"text": "Asîmîlasyon:kesê bi vê nexweşiyê dikeve,kokên xwe,taybetmendîyen xwe yên neteweyîû karakterê xwe yê çandî jibîr dike. Heger ev tişt bên bîra wî jî,li dijî wan nefreteke mezin hîs dike.", "chapter": "ASÎMÎLASYON"}, {"text": "Ez naxwazim tu wekî min bifikirî.Tenê dixwazim tu bifikirî.", "chapter": "CUDAHÎ - RESENÎ"}, {"text": "Işq: noqbûna deryayê, hezkirin: soberîya tê de.", "chapter": "IŞQ Û EVÎN"}, {"text": "Rojî bo hin kesan, tenê guherîna wextên xwarinê ye.", "chapter": "PERESTIN (ÎBADET)"}, {"text": "Di civakekê de çiqas mirovên pîroz û bimbarik hebin; bizanibin ewqas jî zilm û stemkarî li pey wan heye. Civakên ku mirov û mirovatiyê pîroz nedêrin, dê di nav zilm û zordarîyê de bixeniqin.", "chapter": "PÎROZÎ"}, {"text": "Pêkvejiyan bi wan mirovên ku her tim xwe mafdar dibînin re, pir zehmet e.", "chapter": "POZBILINDÎ"}, {"text": "Bixwînin, dibêjim bixwînin. Devera hibr lê neherike, xwîn lê diherike.", "chapter": "XWENDIN Û NIVÎSANDIN"}], "Îbn Xeldûn": [{"text": "Gelên têkçûyî,sazî û dezgeyên têkbiran teqlîd dikin.", "chapter": "ASÎMÎLASYON"}, {"text": "Di kubariyê de asta herî bilind ew e ku, tu guhdariya tiştekî tu dizanî, dikî.", "chapter": "DILPAKÎ"}, {"text": "Miletên bindest, exlaqê wan jî xirab dibe. Çiqas tên piştguhkirin, ewqasî dibin wek ajalên ku tenê li êm û alifê xwe difikirin.", "chapter": "KOLONYALÎZM - DAGIRKERÎ"}, {"text": "Mêjîyê mirov dişibe kevirê aşan.Ger hûn tiştekî nûjen neavêjin hûndir,dê xwe bi xwe bihêre.", "chapter": "MÊJÎ"}, {"text": "Mejîyê mirov dişibe kevirê aşan. Ger hûn tiştekî nûjen neavêjin hûndir, dê xwe bi xwe bihêre.", "chapter": "NÛJENÎ – XWENÛKIRIN"}, {"text": "Zarokên xwe terbiye nekin. Ji xwe dê bişibin we. Xwe terbiye bikin bes e.", "chapter": "PERWERDE – PEDAGOJÎ"}, {"text": "Kesê tehde lê tê kirin û xwe naparêze, kûmê bênamûsiyê kişandiye serê xwe.", "chapter": "SER TEWANDIN- BÊRÛMETÎ"}], "Remezan Alan": [{"text": "Nûsîna bi kurdî, li hember hemû bêqîmetkirinan qaqiboyek e, berûpaşkirina asîmîlasyonekê ye, zindikirina ruhekî vemirî ye...", "chapter": "ASÎMÎLASYON"}], "Rollo May": [{"text": "Destpêka her avakirinê,xirabkirine.", "chapter": "AVAKIRIN"}], "Suzanne Collins": [{"text": "Xerakirin, ji avakirinê hêsantir e.", "chapter": "AVAKIRIN"}, {"text": "Xewnexofên min bi gelemperî li ser windakirina te ne.", "chapter": "XEWN Û XEYAL"}], "Madeline Miller": [{"text": "Ku dîwarên te ji hundir ve rizîbin,wan ji binî hilweşîne û ji nû ve lê bike.", "chapter": "AVAKIRIN"}], "Eliot": [{"text": "Carinan ji bo hin tişt têkevin rêya xwe, divê her tişt ji rê derkeve.", "chapter": "AVAKIRIN"}, {"text": "Ku durûtiya mirovan ji te re ecêb were, xûya tu hê jî mirovekî baş î.", "chapter": "DURÛTÎ"}, {"text": "Hinek mirovan ji ber ku her timî egoya xwe têr kirine, karaktera wan birçî maye.", "chapter": "KARAKTER – XÛY"}, {"text": "Jibîr meke; fedekarîya zêde, bêwefabûna zêde bixwere tîne.", "chapter": "NANKORÎ"}], "Farabî": [{"text": "Kesê dirêj bipeyive, kin lê guhdarî bike.", "chapter": "AXAFTINA ZÊDE"}, {"text": "Kesê her halê xwe dibêje, bêqîmet dibe.Kesî ji herkesî bawer dike, di nîvê rê de dimîne. Kesî hemî nepenîyên xwe eşkere dike, tenê dimîne. Kesî her karînên xwe derpêş dike, diqede. Kesî her zanînên xwe dibêje, nezan dimîne.", "chapter": "SIR Û NEPENÎ"}], "Voltaire": [{"text": "Nîqaşeke dirêj danîşana neheqiya herdû alîyan e.", "chapter": "AXAFTINA ZÊDE"}, {"text": "Heta aştî bi xwe jî,bi berdêlên mezin tê kirîn.", "chapter": "BERDÊL"}, {"text": "Mirov li hember zîrekîyê xwe ditewîne; lê li hember dilovanîyê çok datîne erdê.", "chapter": "DILOVANÎ"}, {"text": "Eger aqilê mêran di teraziyê de bête bi cih kirin, beramberî hestê jinekê nabe.", "chapter": "HEST – HESTIYARÎ"}, {"text": "Mirov wek xapandîyekî dest bi lîstika mezin a jiyanê dike û wek sextekar û fêlbazekî lîstikê diqedîne.", "chapter": "JÎYAN"}, {"text": "Ji lêgerên heqîqetê re rêzdar bin, lê xwe dûr bikin ji wan kesên ku dibêjin ‘em heqîqetşînas in.’", "chapter": "LÊPIRSÎN – KRÎTÎK"}, {"text": "Çiqas gotinên sivik hene ku em ji bilêvkirina wan şerm dikin, dibin stran.", "chapter": "MOSÎQA"}, {"text": "Divê her peyva ku ji devê we dertê, rast be. Lê hûn ne mecbûr in her rastîyê bêjin.", "chapter": "PEYV"}, {"text": "Tiştek bi navê rasthatinê (tesadufê) tune ye. Her tişt an ezmûn, an xelat, an celat, an jî bergirî ye.", "chapter": "RASTHATINÎ (TESADÛF)"}, {"text": "“Rasthatinî” peyveke bêwate ye. Tiştekî bêsebeb tune ye.", "chapter": "RASTHATINÎ (TESADÛF)"}, {"text": "Rizgar kirina mirovan ji qeyd û zincîrên wan yên ku pîroz dihesibînin, zehmet e.", "chapter": "RIZGARÎ"}, {"text": "Rizgarkirina ehmeqan a ji zincîrên wan, karekî zehmet e.", "chapter": "RIZGARÎ"}, {"text": "Ne hêjaye ku em di van her du rojên dinyayê de serî li ber wan kesên serpêl û pîsok bitewînin.", "chapter": "SERHILDAN – BERXWEDAN"}], "Gotina Çermsoran": [{"text": "Raweste, bihishise... Her tim biaxivî, tu tiştekî seh nakî.", "chapter": "AXAFTINA ZÊDE"}], "Anton Chekhov": [{"text": "Kêmgotin ji zêdegotinê çêtir e.", "chapter": "AXAFTINA ZÊDE"}, {"text": "Bênamûsan têr û sertêra xwe dixwarin û cilên biha li xwe dikirin, kesên dirist bi bermayîyên wan debara xwe dikirin.", "chapter": "ÇÎN"}, {"text": "Sê cure mirov hene: Yekemîn: Weke nan e; her tim lê digerî, carinan dibînî. Duyemîn: weke derman e; dema pêdiviyê lê digerî kêm caran dibînî. Sêyemîn: weke mîkrobê ye; tu lê negerî jî dibe, çimkî her tim ew te dibîne.", "chapter": "MIROVV - MIROVAHÎ"}, {"text": "Ku jiyan te nede kenandin, xûya ye te henek fêhm nekiriye.", "chapter": "MÎZAH"}, {"text": "Bi neqencbûyîna kesên din hûn qenc nabin...!", "chapter": "QENCÎ Û XERABÎ"}, {"text": "Rondikên çavên xwe paqij neke, sersebeban ji jiyana xwe paqij bike.", "chapter": "RONDIKÊN ÇAVAN"}, {"text": "Carinan mirov dema hişyar jî bin xewnan dibînin.", "chapter": "XEWN Û XEYAL"}, {"text": "Qanûn wek tevna pîrepindê ye, zeîf lê dieliqin, hêzdar jê derbas dibin.", "chapter": "ZAGON"}, {"text": "Kesê ji tenêtiyê ditirse, bila nezewice.", "chapter": "ZEWAC"}], "Michael Ende": [{"text": "Kêm kes guhdarvanên baş in.", "chapter": "AXAFTINA ZÊDE"}], "Evelyn Beatrice Hall": [{"text": "Tevlî fikrên te nabim, lê ji bo tu fikrên xwe serbest îfade bikî, dikarim canê xwe bidim.", "chapter": "AZADIYA FIKR Û RAMAN"}], "Mark Twain": [{"text": "Xwedê sê nîmet kirine para me,azadiya ramanê, azadiya beyankirina hizrên cûda û azadiyako em yekê ji wan jî pêkneînin!", "chapter": "AZADIYA FIKR Û RAMAN"}, {"text": "Wekî haya kesekî ji te tune ye dans bike, wekî ku qet dilê te neşikestiye hez bike, wekî ku dengê te naçe tu kesî stranan bibêje, wekî ku dinya bihişt be bijî.", "chapter": "BÊXEMÎ – XEMSARÎ"}, {"text": "Biryarên baş ji pisporiyê tên, lê pisporî bi biryarên xirab çêdibe.", "chapter": "BIRYAR Û BİJARTIN"}, {"text": "Devjêberdana cixarê tiştê herî hêsan e. Heya niha min pêncî carî dev jê berda ye.", "chapter": "BIRYAR Û BİJARTIN"}, {"text": "Kesê naxwaze bixwîne, ji yê nizane bixwîne ne çêtir e.", "chapter": "CEHALET"}, {"text": "Her mirov dişibe hîvê. Aliyekî wî yê tarî heye û wî alî nîşanî kesên din nade.", "chapter": "DIJBERÎ - NAKOKÎ"}, {"text": "Nazikbûn ew ziman e ku, kerr jî dibihîze û kor jî dixwîne.", "chapter": "DILOVANÎ"}, {"text": "Mêvanê sibehê zêr e. Êvarê dibe zîv, dema dimîne şevê, dibe sifr.", "chapter": "MÊVAN – CÎRAN"}, {"text": "Li paş te diaxivin, ji ber ku bi rastî jî ew li paş te ne.", "chapter": "PAŞBÊJÎ"}, {"text": "Kûrahîya jîyanê bi peyvan nayê pênasekirin. Wê pênase neke; bijî û hew!", "chapter": "PEYV"}, {"text": "Kitêb ji bo wan kesan in ku dixwazin li cîyekî din bin!", "chapter": "PIRTÛK"}, {"text": "Tenê du kes rastîyê dibêjin; zarok û serxweş.", "chapter": "RASTÎ Û DIRÛSTÎ"}, {"text": "Tenê du kes rastiyê dibêjin: zarok û serxweş.", "chapter": "RASTÎ Û DIRÛSTÎ"}, {"text": "Xapandina mirovan, ji qanihkirina wan ku hatina xapandin hêsantir e.", "chapter": "XAPANDIN"}, {"text": "Kesê pişta xwe bi jineke ku jê hez dike ve girê bide, tu carî naterpile.", "chapter": "ZEWAC"}], "George Carlin": [{"text": "Ji bo em nikarin rasterast ji mirovan re bêjin “tu tam kerekî çolê yî” em dibêjin; “belê ew jî nêrîna te ye.”", "chapter": "AZADIYA FIKR Û RAMAN"}, {"text": "Jîyan ne li gorhejmara henaseyên kuhûn didin distînin tê pîvan; ;lê li gor kêlîyên “bêhnçikên”tê pîvandin.", "chapter": "KERB Û KESER"}, {"text": "Goristanên leşgerî, bi cendekê leşgerên ku mêjiyê wan bi slogana “Xwedê bi me re ye” hatibû şûştin, tije ne.", "chapter": "OL Û AYÎN"}], "Cîbran Xelîl Cîbran": [{"text": "Balindeyek ji bo ku çêlikên wê hînî dîlbûnê nebin, di qefesê de hêlînê çêneke.", "chapter": "AZADÎ"}, {"text": "Em dilxweşî û kovanên xwe, berîya ceribandinê hildibijêrin.", "chapter": "CERIBANDIN - METOD"}, {"text": "Şêrîntirîn peyva li ser lêvên mirovan, «dê» ye. Xweştirîn bang jî «yadê» ye.", "chapter": "DAYÎK Û BAV"}, {"text": "Heger zivistanê gotiba “bihar di dilê min de ye” kî yê jê bawer bikira.", "chapter": "DIJBERÎ - NAKOKÎ"}, {"text": "Dibêjin, “tu çima guherî? Dibêjim, “ji ber ku min ji heq kirina xwe zêdetir êş kişand.”", "chapter": "ÊŞ Û JAN"}, {"text": "Ji bo guherîna kesekî xwe newestîne. Li rihekî ku dişibe te, bigere.", "chapter": "GÎYAN"}, {"text": "Du tişt nêrîna te ya derbarê jiyanê de diguherin; nexweşî û xerîbî.", "chapter": "GUHERÎN"}, {"text": "Pêdivîya heqîqetê bi du kesan heye: yek ji bo gotinê; yek jî ji bo fêhmkirinê.", "chapter": "HEQÎQET"}, {"text": "Hinek ji me mîna hibrê ne, hinek jî mîna kaxizê. Ku reşbûna hinekan ji me tunebûya, hinekên din wê bêziman bimana. Ku spîbûyîna hinekan ji me tunebûya, hinekên din wê kor bibûna.", "chapter": "PAŞBÊJÎ"}, {"text": "Peyv bi zincîrên demê nayên girêdan.", "chapter": "PEYV"}, {"text": "Heval! Li rojê binêre, li axê binêre, li avê binêre; lê li peyî xwe nenêre.", "chapter": "RABIRDÛ Û DAHATÛ"}, {"text": "Ko ji dîwarên odeya te pêve hevalên te nemînin jî, ji girambarî û kerameta xwe tawîz nede.", "chapter": "RÛMET"}, {"text": "Ji çewtîyên xwe şerm neke, tu mirov î. Ji dubarekirina wan û tewanbarkirina qederê şerm bike.", "chapter": "ŞAŞÎTÎ – ÇEWTÎ"}, {"text": "Ji çewtîyên xwe şerm neke, tu mirov î. Ji dubarekirina wan û tewanbarkirina qederê şerm bike.", "chapter": "ŞERMÎ"}, {"text": "Mêrik bi dizîka got: “Xwedêyo bi min re biaxive.” çivîkekê kire wîtewît li ser darê. Lê mêrik seh nekir.", "chapter": "TEOLOJÎ"}, {"text": "Tu bêxewîyê hilbijêrî, çêj e. Lê ku bêxewî te hilbijêre, êş e.", "chapter": "XEW - BÊXEWÎ"}], "Gorki": [{"text": "Azadî ew her pênc xulekên ewil bûn,ku ez hatibûm dinê...Digiriyam, tazî bûm,bêgûneh bûm, bê qible bûmû nefreta mirovandi dilê min de tune bû.", "chapter": "AZADÎ"}], "La Boètie": [{"text": "Kesê azadiya xwe winda dike, mirovbûna xwe jî winda dike.", "chapter": "AZADÎ"}], "Seîdê Kurdî": [{"text": "Ez dikarim bê nan bijîm, lê ez nikarim bê azadî bijîm.", "chapter": "AZADÎ"}, {"text": "Filîstîn goristana pêxemberên benî Îsraîl e û pêxemberên kevin jî ji qewmê Îsraîl in. Doza yehudiyan hem netewî ye hem jî dînî ye. Ji ber wilo zû bi zû kes nikare zora wan bibe.", "chapter": "CIHÛ(YEHUDÎ)"}, {"text": "Gelek ji van kesên ku dibêjin em medenî ne, eger derveyê wan û hundirê wan bi hev bête guherandin; dê wek gur, hirç, mar, beraz û meymûnan werin xûya kirin.", "chapter": "DURÛTÎ"}, {"text": "Nebêjin “ez” bêjin “em!”", "chapter": "EGO – XWEPERESTÎ – EZ EZÎ"}, {"text": "Fikra netewperwerîyê, pederê azadîyê ye.", "chapter": "NETEWE"}, {"text": "Nebin parsekê merhemetê.", "chapter": "TÊKOŞÎN - XEBAT"}, {"text": "Her kesê delal û tekûz, dixwaze delalî û tekûzîya xwe bibîne û bide dîtin.", "chapter": "TEKÛZÎ"}, {"text": "(Kurdno!) hebûna xwe, bi yekbûna xwe bidin nîşandan.", "chapter": "YEKÎTÎ-TIFAQ- PIŞTGIRÎ"}], "Fernando Pessoa": [{"text": "Ne zewq, ne navdarî, ne hikimdarî. Azad î, tenê azadî.", "chapter": "AZADÎ"}, {"text": "Bê vîna xwe heme, bê vîna xwe dimirim.", "chapter": "ÇARENÛS - QEDER"}, {"text": "Tiştê herî zêde me diwestîne, têgihiştin e.", "chapter": "TÊGIHÎŞTIN"}, {"text": "Bingeha sosyalîzm û komûnîzmê “wekhevî” ye. “Azadî” bo wan ewqas jî ne girîng e.", "chapter": "WEKHEVÎ"}, {"text": "Zanîn, bîrbirina nezanînê ye.", "chapter": "ZANEBÛN"}], "Camus": [{"text": "Mirovên vê serdemêji bo ku ne xwedîyêhemî dinyayê ne dikesirin.", "chapter": "AZWERÎ Û ÇAVBIRÇÎTÎ"}], "Gotina Asûriyan": [{"text": "Çavê mirov dişibe çavkaniyê;heta bi ax û xwelîyê tije nebe,têr nabe.", "chapter": "AZWERÎ Û ÇAVBIRÇÎTÎ"}], "Mahatma Gandhi": [{"text": "Dinya têra pêdiviyênmirovan gişkan dike,lê têra hêrs û azweriyênwan nake.", "chapter": "AZWERÎ Û ÇAVBIRÇÎTÎ"}, {"text": "Kesên te li hember mirovan diparêzin û haya te jî jê tune ye, ew hevalên rasteqîn in.", "chapter": "DOSTANÎ Û HEVALTÎ"}, {"text": "Tu wan bi hemî ayet û kitêbên miqedes yên cîhanê binixumînî, dîsa jî guneh tazî dimînin.", "chapter": "GUNEH"}, {"text": "Fikra “çav bi çav” an go tolhildan, dê hemî cîhanê kor bike.", "chapter": "HEYF – TOL Û BEXŞANDIN"}, {"text": "Fikra “çav bi çav, dinan bi dinan” dê hemî dinyayê kor bike.", "chapter": "HEYF – TOL Û BEXŞANDIN"}, {"text": "Ez fêrî lîstika kişikê nebûm.Ji ber ku min nedixwest leşkerên xwe bo jiyîna mîr û paşayan bidim kuştin.", "chapter": "LÎSTIK"}], "Max Weber": [{"text": "Ku mijar dibe çavbirçîtî,di navbera gundî û esilzade deferq namîne.", "chapter": "AZWERÎ Û ÇAVBIRÇÎTÎ"}, {"text": "Bawerî dikare çîyayan bihêjîne, lê ti çareyeke wê ji bo aborîyeke têkçûyî û kêmanîya sermîyan tuneye.", "chapter": "XIZANÎ – HEJARÎ"}], "Erich Fromm": [{"text": "Çavbirçîtî,encama valahîyeke hundirîn e.", "chapter": "AZWERÎ Û ÇAVBIRÇÎTÎ"}, {"text": "Ti mirovek bêsebeb tevlî jiyana me nabe. Hinek ezmûna me ne, hinek belaya serê me ne, hinek jî, bo me hêjatirîn dîyarî ne.", "chapter": "EZMÛN"}, {"text": "Di civakên ku ‘ferd’ tê de tê lawazkirin û bêqîmetkirin, FAŞÎZM zêde dibe. Kesê ku ji takekesîya xwe dûr dikeve, di jêr sembolên stemkar yên faşîzmê de, hebûna xwe ya tirsonek dide nîşandan.", "chapter": "FAŞÎZM"}, {"text": "Ku hezkirin gulek be, rêzgirtin jî ew guldank e ku wê diparêze. Eger gul hino hino biçilmise, baldar bin teqez guldank terikî ye.", "chapter": "HEZKIRIN"}, {"text": "Hezkirin ne tenê hesteke bihêz e; ew biryarek, darazek û sozek e jî. Heger hezkirin tenê hestek bûya, nedivabû heya mirinê em soza jêhezkirina kesekî/ê bidin.", "chapter": "HEZKIRIN"}, {"text": "Tiştê tu nikaribî biparêzî,te ew tişt heq nekiriye.", "chapter": "PARASTIN"}], "Victor Frankl": [{"text": "Yan hin tişt hene ku dibin sedema winda kirina aqilê we, yan jî aqilekî we yê ku winda bibe, tuneye.", "chapter": "BÊAQILÎ – DÎNÎTÎ"}], "Gustave Le Bon": [{"text": "Yên ku ol çêkirine, dewlet rûxandine, girse rakirine raperînê û mirov sewq û îdare kirine, hemû kesên dîn in. Heger li cîhanê di şuna dînîtiyê de aqil hikûmran bibûya, dê dîrok bi awayekî din bihata nivîsandin.", "chapter": "BÊAQILÎ – DÎNÎTÎ"}], "Dostoyevski": [{"text": "Vêga hemî mirovên rast û durist şêt bûne. Tenê fîke fîka kesên weset û bêkêr e.", "chapter": "BÊAQILÎ – DÎNÎTÎ"}, {"text": "Dijminatîya hin kesan,ji dostanîyê kêrhatîtir e.", "chapter": "DIJMIN - DIJMINATÎ"}, {"text": "Şêrîntirîn çêj, di janê de veşartî ye.", "chapter": "ÊŞ Û JAN"}, {"text": "Heytehola malbatê, aramiya dil e.", "chapter": "MALBAT"}, {"text": "Mirov çi ye? Nankorekî duling e.", "chapter": "NANKORÎ"}, {"text": "Min dixwest hemî serboriyên navbera min û te tune bikim û em ji nû de vegerin destpêkê.", "chapter": "NÛJENÎ – XWENÛKIRIN"}, {"text": "Dema keştiyek dike ku binav bibe, ewilî mişk keşetiyê terk dikin.", "chapter": "XIYANET"}], "Sigmund Freud": [{"text": "Dînbûn, li hemberî raserîya aqil rêzgirtin e.", "chapter": "BÊAQILÎ – DÎNÎTÎ"}, {"text": "Pir ê mirov azadiyê naxwazin. Ji ber ku azadî berpirsiyarî ye, pir ê mirovan ji berpirsiyariyê ditirsin.", "chapter": "BERPIRSIYARÎ"}, {"text": "Nexwazî li kuderê binêrî, hişê te li wir e.", "chapter": "BÎR – BINBÎR"}, {"text": "Her tiştê di kêliya hêrsbûnê de tê bilêvkirin, berê di hiş û ramanê kesê bilêv dike de derbaz bûye.", "chapter": "HÊRSBÛN"}, {"text": "Hestên ku nayên bilêvkirin, qet namirin. Tenê bi zindîtî tên binaxkirin û di pêşerojê de bi awayekî bizdonektir derdikevin holê.", "chapter": "HEST – HESTIYARÎ"}, {"text": "Helwesta kesekî ya di mijarên cinsî de, prototîpa hemî helwestên wî yên din ne.", "chapter": "HEWES - ZEWQ"}, {"text": "Xwestina efûkirinê nayê wê wateyê ku hûn neheq in. Wateya wê ew e ku; qedr û qîmetê hûn didin mirovan, ji egoya we mezintir e.", "chapter": "HEYF – TOL Û BEXŞANDIN"}, {"text": "Belê em ji xwîn û goşt in, lê divê em bijîn weke em ji hesin û pola ne.", "chapter": "HÊZDARÎ - LAWAZÎ"}, {"text": "Jin; ji hezkirinê zêdetir, ji jêhezkirinê hez dike.", "chapter": "HEZKIRIN"}, {"text": "Hezkirin, şayanî her mirovî ye, lê her mirov ne şayanî hezkirinê ye.", "chapter": "LîYAQAT"}, {"text": "Bi henekekê tu dikarî her tiştî bibêjî, heta bi rastiyê jî.", "chapter": "MÎZAH"}, {"text": "Ku tu ji nêz ve temaşe dikî, kesekî/e normal tune ye.", "chapter": "REWŞA ASAYÎ"}, {"text": "Azadiya mirovan ne diyariya şaristaniyê ye. Dema ku şaristanî qet tunebû, mirov bêhtir azad bûn.", "chapter": "ŞARISTANÎ"}, {"text": "Yekemîn kesê ji dêvla pevçûnê sixêf hilbijart, bû damezrînerê şaristaniyê.", "chapter": "ŞARISTANÎ"}, {"text": "Em ji goşt û xwînê ne, lê divê em bijîn wekî ku ji pola ne.", "chapter": "VÎN – ÎRADE"}, {"text": "Her mirov, şîroveya xewna xwe ye.", "chapter": "XEWN Û XEYAL"}], "Sadî Şîrazî": [{"text": "Du tişt nîşandariya aqilê sivik in: Bêdengiya di ciyê axaftinê de û axaftina di ciyê bêdengiyê de.", "chapter": "BÊDENGÎ"}, {"text": "Ûslûba şaş, kujerê gotina rast e.", "chapter": "RETORÎK"}, {"text": "Ne ecêb e ku zanayek nikare di nav nezanan de bipeyive. Ji ber ku dengê tenbûrê li ber yê daholê dimre û bêhna sîrê, ya enberê winda dike.", "chapter": "ŞAREZATÎ Û EHMEQÎ"}, {"text": "Ji bo me temenek din divê, Piştî mirinê. Ji ber ku me ev temen, Tenê bi hêvîyan derbas kir.", "chapter": "TEMEN"}], "Albert Hobart": [{"text": "Kesê bêdengiya te fêhm neke, ji axaftina te qet fêhm nake.", "chapter": "BÊDENGÎ"}], "Pisagor": [{"text": "An bêdeng bimîne, an gotineke ji bêdengîyê biqîmettir bêje.", "chapter": "BÊDENGÎ"}], "Lao Tzu": [{"text": "Beriya tu biaxivî, bifikire: gelo pêdivî bi axaftina te heye? Ew axaftin dilovaniyê di xwe de dihewîne? Ew axaftin dê kesekî biêşîne û bi qasî ku bêdengiyê xira bike, bi qedr e?", "chapter": "BÊDENGÎ"}, {"text": "Hincet wekî mû ye, bi herkesî re heye. Çareserî wekî aqil e, bi kêm kesan re peyde dibe.", "chapter": "ÇARESERÎ Û BÊÇARETÎ"}, {"text": "Herî zêde gringîyê didim sê tiş tan: sadebûn – sebr û dilovanî", "chapter": "SEBR"}, {"text": "Şervanekî çak, qet hêrs nabe.", "chapter": "ŞER Û AŞTî"}, {"text": "Mirovên gewre, xatir dixwazin û diçin. Kesên biçûk xayintîyê dikin û diçin.", "chapter": "XATIRXWESTIN"}], "Umberto Eco": [{"text": "Mirov bi bêdengiyê jî dikare tiştekî bibêje.", "chapter": "BÊDENGÎ"}, {"text": "Tirsa ji mirinê, can dide serpêhatiyan.", "chapter": "BÎRANÎN"}, {"text": "Ev dinyaya ewqas tirsehêz ne bes bû, bi ser de dojeha wê jî heye?", "chapter": "DINYA"}, {"text": "Carinan bi cil û bergên sivîl digere FAŞÎZM. Wezîfeya me ew e ku, em her roj wê tazî bikin û nîşanî her kesî bidin.", "chapter": "FAŞÎZM"}, {"text": "Her heqîqet, ne li gor her guhî ye.", "chapter": "RETORÎK"}, {"text": "Bi maçkirina mirovek gurî razî me, lê nikarim destê xwe bidim yekî ehmeq.", "chapter": "ŞAREZATÎ Û EHMEQÎ"}, {"text": "Dest bi nivîsandinê bikin, êdî bila pênûs ji dêvla we bifikire.", "chapter": "XWENDIN Û NIVÎSANDIN"}], "Gotina Yewnanan": [{"text": "Ker beşdarî pêşbirka hespan nabe, lê her tim tinazê xwe bi hespê têkçûyî dike.", "chapter": "BÊKÊRÎ"}, {"text": "Kesên bi keştiyên biçûk dizî û talanê dikin, ji wan re dibêjin ‘korsan’; yên ku bi keştiyên mezin dizî û talanê dikin ji wan re dibêjin ‘fatîh.’", "chapter": "DIZÎ"}, {"text": "Hêza peyvê, nêzî hêza Xwedê ye.", "chapter": "EDEBÎYAT (WÊJE)"}, {"text": "Deriyê hêviyê veneke,ew jana herî xedar e!", "chapter": "HÊVÎ – BÊHÊVÎTÎ"}, {"text": "Agir bi agir nayê tefandin.", "chapter": "HEYF – TOL Û BEXŞANDIN"}], "Cahiz": [{"text": "Dema tu dênê xwe didî mirovan,tu dibînî zimanê bêkêran ji yê her kesî dirêjtir e.", "chapter": "BÊKÊRÎ"}, {"text": "Axaftina dê û bavan, zarokan, û mirovên dilbikul nebire û li wan guhdarî bike. Çimkî ew ji dil diaxivin.", "chapter": "EDEB Û REZDARÎ"}], "Gotina Japonan": [{"text": "Ji malê belaş bihatir tiştek nîne.", "chapter": "BÊMINETÎ"}, {"text": "Tiştek, ji tiştê ku belaş didin tene bihatir e.", "chapter": "BERDÊL"}, {"text": "Heft caran bikeve, heşt caran rabe.", "chapter": "BIXWEBAWERÎ"}, {"text": "Dilovaniya bav ji sertaran bilindtir e, dilovaniya dayikê ji deryayan kûrtir e.", "chapter": "DAYÎK Û BAV"}, {"text": "Tu mafdar bî, nehewce ye tu dengê xwe bilind bikî.", "chapter": "MAF – MAFDARÎ"}, {"text": "Ku saeta birçîbûnê lê da, xwarina ne xweş tune ye.", "chapter": "PÊDIVÎ"}, {"text": "Di jiyanê de şûr dibe ku tenê carekê bi kêrî te were, lê divê tu her tim wî li nik xwe bigerînî.", "chapter": "TEVDîR (BERGIRÎ)"}], "Milan Kundera": [{"text": "Derheqê min de çi bifikirî, bi kêfa xwe yî. Ez ne ji bo razîkirina te hatime vê dinyayê.", "chapter": "BÊMINETÎ"}], "Woody Allen": [{"text": "Dema zerera min negihaştibe kesekî, heskirin an heznekirina mirovan bo min ne grîng e. Ez ne ji bo kêfxweşkirina hemî mirovan hatime vê dinê.", "chapter": "BÊMINETÎ"}], "Will Smith": [{"text": "Eger tu tenê alîyê min ê xirab dibînî, dibe ku ez her timî tiştên layîqê te nîşanî te didim.", "chapter": "BÊMINETÎ"}, {"text": "Kesekî ku bixwaze derd û kûlên te sivik bike, tuneye. Tenê meraq dikin û hew.", "chapter": "KERB Û KESER"}, {"text": "Tu çawa fêhm bikî, bike; lê bi wê fêhm kirina xwe kesekî tewanbar neke.", "chapter": "TEWANBARÎ"}], "Arthur Schopenhauer": [{"text": "Talibê heqîqetê, divê her berdêlê bide ber çavên xwe.", "chapter": "BERDÊL"}, {"text": "Jibîr neke, dema berjewendiyên mirovan diguherin, nêrîn û tevgerên wan jî zûzûka diguherin.", "chapter": "BERJEWENDÎ"}, {"text": "Tiştekî tu nexwazî dijminê te jê agahdar bibe, ji dostê xwe re nebêje.", "chapter": "SIR Û NEPENÎ"}], "Necîb Mehfûz": [{"text": "Jîyan dersa belaş nade tu kesî. Dema tu dibêjî “jîyanê fêrî min kir,” teqez te berdêlek daye!", "chapter": "BERDÊL"}, {"text": "Ne ku dilê me reş bûye, lê em naxwazin wan ruyên ku roja me kembax û xopan dikin, bibînin.", "chapter": "BÎRANÎN"}, {"text": "Dema tu xwe li nezaniyê deynî, nîvê pirsgirêkên jîyana te çareser dibin.", "chapter": "ÇARESERÎ Û BÊÇARETÎ"}, {"text": "Tu ji derba ewilî ders negirî,ya duyemîn jî heq dikî.", "chapter": "DERS Û ÊBRET"}, {"text": "Her tişt xipxuya eşkere ye,lê heta em şeqaman nexwin em ji îşaretan fêhm nakin.", "chapter": "DERS Û ÊBRET"}, {"text": "Dilsozî nirxekî biha ye.Bi kesên erzan re peyda nabe.", "chapter": "DILSOZÎ"}, {"text": "Tiştek bi qasî êşa hevpar mirovan nêzîkî hev nake.", "chapter": "HEST – HESTIYARÎ"}, {"text": "Carinan her derê te digirî,Ji xeynî çavên te.", "chapter": "KEN Û GIRÎN"}, {"text": "Girîngiyê nede gotegotên mirovan. Ji ber ku mirov li ser cenazeyê ku hê nû defin kirine jî diaxivin.", "chapter": "PAŞBÊJÎ"}, {"text": "Ti qîmeta qenciyê namîne, dema tu dibêjî min kiriye.", "chapter": "QENCÎ Û XERABÎ"}, {"text": "Rasthatinî nesîb e; berdewamkirin,\ntercîh e.", "chapter": "RASTHATINÎ (TESADÛF)"}, {"text": "Derewker in... û ew jî bi xwe dizanin ku derewker in. Û dizanin ku em bi derewên wan dizanin... Lê dîsa jî bi dengê herî bilind derewan dikin!", "chapter": "SÎYASET – POLÎTÎKA"}, {"text": "Dema dil dimire, dilovanî jî dimire. Dema aqil dimire, hîkmet jî dimire. Dema ûjdan dimire, her tişt dimire.", "chapter": "ÛJDAN"}], "Gotina Portugaliyan": [{"text": "Heya tu tiştekî nedî, hêviya tiştekî neke.", "chapter": "BERDÊL"}, {"text": "Ko tu bitirsî, dest pê neke, ko te dest pê kir, netirse.", "chapter": "BIXWEBAWERÎ"}, {"text": "Her tiştê dizanî, nebêje, Ji her tiştê seh dikî bawer neke, Her tiştê dikarî bikî, neke.", "chapter": "SINC – EXLAQ"}], "Khalid Hosseini": [{"text": "Bêrîkirin derdekî bêderman e,di çaya tu vedixwî de,di strana tu dibêjî de tê bîra te.", "chapter": "BÊRÎ KIRIN"}, {"text": "Derew jî dizî ye. Tu mafê rastbihîstina kesên din didizî.", "chapter": "DIZÎ"}, {"text": "Birîndarbûna bi heqîqetekê, ji mijûlayîya bi derewekê çêtir e.", "chapter": "HEQÎQET"}, {"text": "Heta tu têbigihîjî ku her tişt ji herkesî re nayê gotin; tu yê gelek kesan nas bikî, gelkî biaxivî û pir xeletiyan bikî.", "chapter": "SIR Û NEPENÎ"}, {"text": "Hûn bi kuderê ve jî biçin, welatê we li dûv we tê. Êdî hûn lê nejîn jî, ew di hundirê we de dijî.", "chapter": "VEQETÎN"}, {"text": "Zarok ne pirtûka boyaxkirinê ne. Mafê te tune ye tu wan bi rengê ku herî zêde jê hez dikî boyax bikî.", "chapter": "ZAROK – ZAROKATÎ"}], "Samuel Butler": [{"text": "Bêrîkirina herî dijwar ew e ku,tu bêriya ‘xwebûna xwe ya berê’ dikî.Kenê berê, dilê berê...", "chapter": "BÊRÎ KIRIN"}], "Mehmûd Derwîş": [{"text": "Çima weke me bêrî nakin?Qey li welatên wan şev tune ye?", "chapter": "BÊRÎ KIRIN"}, {"text": "Duh me azadî winda kir.Îro em hezkirinê winda dikin.Ez ji sibê ditirsim;Ji ber ku em ê mirovahîyêji binî winda bikin.", "chapter": "MIROVV - MIROVAHÎ"}, {"text": "Zimanê min nasnameya min e. ez... û ez. Ez zimanê xwe me. Ez di zimanê xwe de penaber im û dilê min perengekî kurdî ye li ser çiyayên hêşîn...", "chapter": "NASNAME"}, {"text": "Mirov bê al û bê welat be, çi qîmetê wî heye?", "chapter": "WELATPARÊZÎ- NIŞTIMANPERWERÎ"}], "Suzan Samancî": [{"text": "Bêrîkirinên me yên ku di bin pêlên şerûd û şemûz de dixeniqin, li hêviya rojên zelal in.", "chapter": "BÊRÎ KIRIN"}], "Azîz Nesîn": [{"text": "Carinan tu bêriya kesekî dikî; eger ew kes bi xwe bihise, dê ji nehazirbûna xwe ya li wê derê şerm bike.", "chapter": "BÊRÎ KIRIN"}], "Gotina Efrîqiyan": [{"text": "Ew barana kuderyavan lanetê lê tîninû cotyar bo wê nimêj dikin;heman baran e.", "chapter": "BERJEWENDÎ"}, {"text": "Kesê ji bo te bidize, dê ji te jî bidize.", "chapter": "DIZÎ"}, {"text": "Dîroka ku bi xwînê hatibe nivîsandin, ne mimkûn e bi derewên ku bi hibrê hatine nivîsandin sererast bibe.", "chapter": "DÎROK"}, {"text": "Tu bixwazî bilez herî, bi tena serê xwe here. Tu bixwazî dûr herî, bi hezkiriya/ê xwe re here.", "chapter": "DÛR KETIN"}, {"text": "Dema av radibe, masî moriyan dixwin... Dema av kêm dibe, morî masiyan dixwin... Bila kes bi hêza xwe ya niha nepesine. Çimkî bê kî yê kê bixwe, herikîna avê biryar dide.", "chapter": "HÊZDARÎ - LAWAZÎ"}, {"text": "Ku mar diranên xwe dernexe, zarok weke werîs dê wî li êzingan bipêçin.", "chapter": "PARASTIN"}, {"text": "Go kerî dibe yek, şêr birçî radize.", "chapter": "YEKÎTÎ-TIFAQ- PIŞTGIRÎ"}, {"text": "Jina mêrê feqîr, tenê bi şev bextewer e.", "chapter": "ZEWAC"}], "Gabriel Garcia Marquez": [{"text": "Mirov ji bo firotinê ziman hîn dibe.Lê dema dikire, her kes wî fêhm dike.", "chapter": "BERJEWENDÎ"}, {"text": "Min her tim bawer kiribû û ez hê jî li ser baweriya xwe me ku; ji jineke bedew, xweşiktir tiştek tune ye.", "chapter": "ESTETÎK"}, {"text": "Ji dêvla tu rondikên çavên xwe paqij bikî, kesên bûne sebebê herikandina wan rondikan, ji jîyana xwe paqij bike.", "chapter": "RONDIKÊN ÇAVAN"}], "Charles Bukowskî": [{"text": "Dema mirov herî zêde ji te hez dikin,ew dem e ku herî zêde tu bi kêrî wan tê.", "chapter": "BERJEWENDÎ"}, {"text": "Qerebalix bi kîjan rexî ve here,tu berê xwe bide rexê din.Ji ber ku qerebalixher tim li ser şaşiyê ye.", "chapter": "CIVAK"}, {"text": "Carinan ji bo tu bixwe werî, divê ji hinên din herî. Dûrketin azadî ye.", "chapter": "DÛR KETIN"}, {"text": "Beguman biryara min a herî rast ew bû; ez ji wan kesên ku xwe wekî ‘jêneger’ didîtin, dûr bûm.", "chapter": "DÛR KETIN"}, {"text": "Tu ji bo kesekî girîng bî, ew dikare bi her awayî ji bo te demê veqetîne. Ji bilî vê her tişt biha ne ye.", "chapter": "QEDR Û QÎMET"}], "George Orwell": [{"text": "Mirov, ji xwe pêve li berjewendiyên ti aferîdî miqate nabe.", "chapter": "BERJEWENDÎ"}, {"text": "Civakek ji rastiyê çiqas dûr bikeve,ji rastbêjan ewqas nefret dike.", "chapter": "CIVAK"}, {"text": "Her nifş, zen dike ku ji nifşê beriya xwe zîrektir e û ji nifşê pey xwe bihîkmettir e.", "chapter": "PÊŞKEWTIN"}], "Sartre": [{"text": "Berpirsiyara rewşenbîran, acizkirina desthilatdarîyên har e.", "chapter": "BERPIRSIYARÎ"}, {"text": "Pirrê mirovan li dinyayê di dojehê de dijîn. Ji ber ku gelekî zêde girîngîyê didin nêrîna mirovan.", "chapter": "BIHÛŞT Û DOJEH"}, {"text": "Em mecbûr in her tim li heqîqetê bigerin... Ji ber ku heqîqet bêdawî ye.", "chapter": "LÊPIRSÎN – KRÎTÎK"}, {"text": "Hîletê min ji wan qurbaniyan diçe ku, ji celadên xwe re rêzdar in.", "chapter": "QURBANÎ"}, {"text": "Ez ne mecbûr im fikr û ramanên xwe nîşanî kesên fêhmkor bikim.", "chapter": "TÊGIHÎŞTIN"}], "Naom Chomsky": [{"text": "Rewşenbîr ji gotina heqîqetê û eşkere kirina derewan berpirsiyar in.", "chapter": "BERPIRSIYARÎ"}, {"text": "Kesek nikare heqîqetêbi ser mêjiyê te de birijîne,heqîqet ew e ku,tu bi xwe lê bigerî û keşf bikî.", "chapter": "LÊPIRSÎN – KRÎTÎK"}], "Pauline Phillips": [{"text": "Heger bixwazî piyên zarokê te li ser erdê baş rawestin, hinek berpirsiyarên giran li ser milên wan bar bike.", "chapter": "BERPIRSIYARÎ"}], "Zerdeşt": [{"text": "Pêkanîna qenciyê ne berpirsiyarî ye, bezm û şahî ye.", "chapter": "BERPIRSIYARÎ"}, {"text": "Ey ronahî, tarîtiyê ronî bike!", "chapter": "RONAHÎ – TARÎTÎ"}], "Shakespeare": [{"text": "Ma mirov e, ew kesê jiyana wî tenê bi xwarin-vexwarin û razanê derbas dibe?", "chapter": "BÊXEMÎ – XEMSARÎ"}, {"text": "Nehêle sê tişt bibin serwerê jiyana te: mal, mirov û bîranînên xirab.", "chapter": "BÎRANÎN"}, {"text": "Di jiyanê de zehmettirîn tişt ew e ku; tu mecbûr dimînî xwe bi xwe teselî dikî.", "chapter": "ÇARESERÎ Û BÊÇARETÎ"}, {"text": "Kesê di rewşa te ya herî xirab de ji te hez kiribe, ew layiqê dilê te ye.", "chapter": "DILSOZÎ"}, {"text": "Keçika ku di hevdîtina ewil de bêje “ji te hez dikim,” bêyî xatirxwestinekê jî terka te dike.", "chapter": "DILSOZÎ"}, {"text": "Her xweşik, dê rojekê xweşikahîya xwe winda bike.", "chapter": "ESTETÎK"}, {"text": "Ji te nefret dikin, lê pir bi dîqqet te dişopînin.", "chapter": "HESÛDÎ – ÇAVNEBARÎ"}, {"text": "Li hember çar kesan tu carî hişk tev negere: jin, zarok, xizmetkar û kesê lêborînê dixwaze.", "chapter": "HEYF – TOL Û BEXŞANDIN"}, {"text": "Yekî ku zêde li kesên din difikire, xwe ji bîr dike.", "chapter": "JIBÎR KIRIN"}, {"text": "Zêr bi agir, jin bi zêr, mêr bi jinê tê ezmûnkirin.", "chapter": "JIN Û MÊR"}, {"text": "Tu nikarî mêşan qanih bikîku kulîlk ji gilêşê çêtir in.", "chapter": "KARAKTER – XÛY"}, {"text": "Di kenê mirovan dexencer veşartî ne.", "chapter": "KEN Û GIRÎN"}, {"text": "Kesê bi xwe dikare, bi hemî dinyayê jî dikare.", "chapter": "KONTROL – OTOKONTROL"}, {"text": "Helbet tu dikarî bibî kuçik, lê heqê te tune bi reyyîn û ewtîna xwe me aciz bikî.", "chapter": "MAF – MAFDARÎ"}, {"text": "Bo guhekî ji muzîkê fêhm dike bêje strana xwe.", "chapter": "MOSÎQA"}, {"text": "Kesên stranên neteweyekî çêdikin, ji kesên ku yasayan çêdikin hêzdartir in.", "chapter": "NETEWE"}, {"text": "Çiqas baweriya te bi hin mirovan were jî, ji bilî jûra mêvanan, deriyê jiyana xwe li ber kesekî veneke.", "chapter": "PÊBAWERÎ"}, {"text": "Yekî ku bawerîya xwe bi te bîne, qet jê re derewan neke. Û yekî ku ji te re derewan bike, qet bawerîya xwe pê neyêne.", "chapter": "PÊBAWERÎ"}, {"text": "Te ewqas dereng bersiv da, min pirsa xwe jibîr kir.", "chapter": "PIRS Û BERSIV"}, {"text": "Ji rûyekî ku bi hêsirên çavan hatibe şûştin paqijtir tiştek tune ye.", "chapter": "RONDIKÊN ÇAVAN"}, {"text": "Rondikên çavan derewan nakin.", "chapter": "RONDIKÊN ÇAVAN"}, {"text": "Rondik nîşaneya hezkirinê ne, lê nabin derman.", "chapter": "RONDIKÊN ÇAVAN"}, {"text": "Şermokî, nîvî ji fersendan berhewa dike.", "chapter": "ŞERMÎ"}, {"text": "Vê baş bizanibe ku, şeytan jî dikare ji bo berjewendiyên xwe, ji kitêba pîroz ayetan bixwîne.", "chapter": "ŞEYTAN"}, {"text": "Dojeh vala bûye, hemî şeytan li vir in.", "chapter": "ŞEYTAN"}, {"text": "Şîret li sê kesan fêde nakin: Rewşenbîrê pozbilind, ciwanê nûgihayî û jina bedew.", "chapter": "ŞÎRET"}, {"text": "Hey dinyayê! Tu nehêjayî xatirxwestinê yî jî.", "chapter": "XATIRXWESTIN"}], "Gotina Ukrainan": [{"text": "Tabûta li ser milê kesên din, sivik xûya dike.", "chapter": "BÊXEMÎ – XEMSARÎ"}], "George Herbert": [{"text": "Kes giraniya barê ser milê kesê din nizane.", "chapter": "BÊXEMÎ – XEMSARÎ"}, {"text": "Bavek berberî sed mamosteyî ye.", "chapter": "PERWERDE – PEDAGOJÎ"}], "Ernest Hemingway": [{"text": "Em li welatekî wisa dijîn ku, tu tişt ne xema kesî ye.", "chapter": "BÊXEMÎ – XEMSARÎ"}, {"text": "-Tu komunîst î?\n-Na, ez antîfaşîst im.\n-Ji kengî ve?\n-Ji roja min faşîzm nas kiriye ve.", "chapter": "FAŞÎZM"}], "Adonis": [{"text": "Hin kes ji bo biçin beheştê, radibin kesên din dikujin. Ji vê dojehê dojehtir çi heye?", "chapter": "BIHÛŞT Û DOJEH"}, {"text": "Ne ku tu ji min nefret dikî,tu ji wî suretê ku te di nav xeyalên xwe de ji bo min çêkiriye nefret dikî.Ew sûret ne yê min e, tu bi xwe yî.", "chapter": "KÎN Û NEFRET"}, {"text": "Em dişibin masiyên ku di goleke genî de hevûdin dixwin û gol çiqas diçe ziwa dibe.", "chapter": "TUNDÛTÛJÎ"}], "Thomas Hobbes": [{"text": "Her ûtopya, senaryoya bihûştekê an jî dojehekê ye.", "chapter": "BIHÛŞT Û DOJEH"}, {"text": "Her ûtopya, senaryoya bihûştekê an jî dojehekê ye.", "chapter": "BIHÛŞT Û DOJEH"}], "Borges": [{"text": "Ez her tim bihûştê di şiklê pirtûkxaneyekê de xeyal dikim.", "chapter": "BIHÛŞT Û DOJEH"}], "Aragon": [{"text": "Berî tu biçî, baş bifikire. Ji ber ku dema tu vegeriyayî tiştê tu bibînî û dema tu çûyî tiştê te li pey xwe hiştibû dê ne heman tişt be.", "chapter": "BIRYAR Û BİJARTIN"}], "Chuck Palahniuk": [{"text": "Eger tu nizanibî bê tu çi dixwazî, tu yê bibînî ku vaye gelek tiştên ku te nedixwestin, rû dane.", "chapter": "BIRYAR Û BİJARTIN"}, {"text": "Berê jî ez ji rê derketibûm, dikarim dîsa jî derkevim. Mirov bi meşq û rahênanê tekûz dibe.", "chapter": "TEKÛZÎ"}, {"text": "Bêxewî tiştekî wilo ye. Pûnijîn û xemên te heya sibehê di weşana zindî de ne.", "chapter": "XEW - BÊXEWÎ"}], "Charles Flory": [{"text": "Mezintirîn dizên demê, bêbiryarî û dudilî ne.", "chapter": "BIRYAR Û BİJARTIN"}], "Tony Robbins": [{"text": "Çi mirovên serkeftî ku ez tûşî wan hatime, ji min re wiha gotine: “kengî min bi xwe bawer kir, jîyana min hingê destpê kir.”", "chapter": "BIXWEBAWERÎ"}], "Saramago": [{"text": "Ku keştiya te mezin be, firtoneye te jî mezin dibe.", "chapter": "BIXWEBAWERÎ"}], "Cervantes": [{"text": "Ax bîr! dijmina sereke ya aramiya min.", "chapter": "BÎR – BINBÎR"}, {"text": "Durûtî dişibe şûrekî ku herdu aliyên wî tûj bin. Rexekî wî mirovê ku pê tê xapandin dibirre, rexê din jî, xwediyê xwe dibirre.", "chapter": "DURÛTÎ"}, {"text": "Mala afirînerê xewê ava be;xew lihêfeke ku hemî derd û kulênme dinixumîne.", "chapter": "KERB Û KESER"}, {"text": "Henek û xweşî, di seriyekî keregêj de peyde nabin.", "chapter": "MÎZAH"}], "Kafka": [{"text": "Tu kêrek î, ez jî bê navber hundirê xwe bi wê kêrê diqewêrim.", "chapter": "BÎR – BINBÎR"}, {"text": "Jimalderketin macerayeke xeternak e.", "chapter": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT"}, {"text": "Gerdûna di serê min de, ji gerdûna ku serê min te de ye, mezintir e.", "chapter": "GERDÛN"}, {"text": "Ti kêmasiya min tune ye,tenê mihtacê xwe me û hew.", "chapter": "KÊMASÎ"}, {"text": "Raze, rabe... Raze, rabe...Çi jiyanek rezîl!", "chapter": "LIV Û TEVGER"}, {"text": "Jîyana min van rojan mîna kolanên zivistanê ye. Çiqas bête paqijkirin jî, careke din bi pelên hişk û qirş û qalan tije dibe.", "chapter": "NÎHÎLÎZM"}, {"text": "Jiyan bi hewildana têgihiştina her tiştî despê dike û bi hewildana xwe rizgarkirina ji her tiştî diqede.", "chapter": "RIZGARÎ"}, {"text": "Çeka herî gelac a di destê nebaşan de, banga şer e.", "chapter": "ŞER Û AŞTî"}, {"text": "Sond bi qesema navê Xwedê, têgihiştina zêde nexweşî ye.", "chapter": "TÊGIHÎŞTIN"}, {"text": "Çendîn roj in di odeya xwe de bi tenê me. Lê tiştek nabe. Ji xwe bi salan e li dinyayê jî ne bi tenê bûm?", "chapter": "TENÊTÎ"}, {"text": "Ku min dîwar di navbera xwe û te de lê kiribe, kevir jî te dane destê min.", "chapter": "VEQETÎN"}, {"text": "Tiştekî tu binivîsî tune be jî, ez bi şandina nameyeke vala jî razî me.", "chapter": "XWENDIN Û NIVÎSANDIN"}], "Elîyê kurê Ebûtalib": [{"text": "Mirov ji çi bireve,di reva xwe de rastî wî tiştî tê.", "chapter": "BÎR – BINBÎR"}, {"text": "Rehetîya bedenê, di kêmxwarînê de ye. Rehetîya nefsê, di kêmgunehan de ye. Rehetîya zimên, di kêmaxaftinê de ye. Rehetîya dil jî di kêmxemîyê de ye.", "chapter": "NEFS"}, {"text": "Li hember neheqîyê sernixwîn nebin. Ku hûn serî bitewînin, hûn ê hem mafê xwe, hem jî rûmeta xwe winda bikin.", "chapter": "RÛMET"}], "Isaac B. Singer": [{"text": "Tiştek zû bi zû ji hîşê min dernayê, trajediya min jî ev e.", "chapter": "BÎR – BINBÎR"}], "JeanPaul Sartre": [{"text": "Bîranîn wekî zêrên di tûrikê şeytên de ne; dema tu devê turîk vedikî, dibînî ku ne zêr, lê pelên mirî têde ne...", "chapter": "BÎRANÎN"}], "James Joyce": [{"text": "Min dixwest êdî serboriyên rasteqîn bijîm. Lê difikirîm ku serboriyên rasteqîn nayên serê kesên li malê rûniştî...", "chapter": "BÎRANÎN"}, {"text": "Di awirên wê debirîna dilê wê xwe dida der.", "chapter": "DIL"}, {"text": "Hişyarbûna ji xeyalekê, herî kêm bi qasî zayînê diêşîne.", "chapter": "XEWN Û XEYAL"}], "Antoni Gaudi": [{"text": "Huner tune ye,her tişt matematîk e.", "chapter": "BÎRKARÎ"}], "Galileo": [{"text": "Bîrkarî ew ziman e ku,Xwedê gerdûn pê ava kiriye.", "chapter": "BÎRKARÎ"}, {"text": "Bîrkarî ew ziman e ku, Xwedê gerdûn pê ava kiriye.", "chapter": "GERDÛN"}], "Hemingway": [{"text": "-Te dixwest ji gelê xwe re çi bikî?\n-Min dixwest ji nezaniyê xelas bibin.", "chapter": "CEHALET"}, {"text": "Dixwazim razêm. Ku hişyar dibim jiyana min serûbin dibe.", "chapter": "XEW - BÊXEWÎ"}], "Montaigne": [{"text": "Gewretirîn girtîgeha ser rûyê erdê, hundirê qahfê kesên cahil e.", "chapter": "CEHALET"}, {"text": "Hemî roj ber bi mirinê ve diçin; roja dawî digihîjê.", "chapter": "TEMEN"}], "Celaleddîn Rûmî": [{"text": "Sîr xistiye pozê xwe, li bêhna gulê digere!", "chapter": "CERIBANDIN - METOD"}, {"text": "Deriyê girtî tune ye, kilîta şaş heye.", "chapter": "CERIBANDIN - METOD"}, {"text": "Ji dêvla hûn ji bo xeyd û enirînê li hincetan bigerin, ji bo hezkirin û jêhezkirinê li çareyan bigerin.", "chapter": "ÇARESERÎ Û BÊÇARETÎ"}, {"text": "Bi nezanan re nekeve gengeşî û niqaşê. Yan wê hêrsa te rabe qarçikan, yan jî heyf û xebîneta rêz û edeba te.", "chapter": "EDEB Û REZDARÎ"}, {"text": "Biedeb ji edeba xwe bêdeng dimîne, bêedeb dibêje min dengê wî birî.", "chapter": "EDEB Û REZDARÎ"}, {"text": "Li dinyayê herî zêde tu çi bixwazî, ew e ezmûna te.", "chapter": "EZMÛN"}, {"text": "Di dawiyê de tenê kesên bedewiya giyanê te dibînin li cem te dimînin. Ew yên heyranê bedewiya te ya zahirî ne, yeko yeko ji te direvin.", "chapter": "GÎYAN"}, {"text": "Meçe welatê bêhêvîtîyê, hêvî heye. Xwe negihîne tarîtîyê, roj hene.", "chapter": "HÊVÎ – BÊHÊVÎTÎ"}, {"text": "Ger tu ji min bipirsî, “ez çend caran hatim bîra te?” Ez ê bêjim, “yek.” Ji ber ku tu carekê hatî û hew çûyî...", "chapter": "HEZKIRIN"}, {"text": "Işq di hemî dînan de heye, lê dînê işqê tune ye.", "chapter": "IŞQ Û EVÎN"}, {"text": "Jin ji nûra Xwedê ye.Jin ne tenê aferîdek e; afirîner e jî.", "chapter": "JIN Û MÊR"}, {"text": "Sirf ji bo tu nefesê didî û distînî, tu zen dikî ku tu sax î?", "chapter": "JÎYAN"}, {"text": "Berî avê, bi hezkirinê destmêj bigre. Nimêja dilê kîndar qebûl nabe.", "chapter": "KÎN Û NEFRET"}, {"text": "Ger tu talibê dirr û gewheran bî, divê noqî binê deryayan bibî. Ma li peravan ji bilî kefikê çi heye?", "chapter": "LÊKOLÎN"}, {"text": "Di egîdî û mêrxasiyê de tu Rûstemê Zal jî bî, li malê tu hêsîrê hevjîna xwe yî.", "chapter": "MALBAT"}, {"text": "Her tiştê ji pêdiviya te zêdetir, jehr e.", "chapter": "PÊDIVÎ"}, {"text": "Min dît mirov bi fermana te li derdora kevirê reş digerin. Lê min te di dilê xwe de dît. Ez rabûm li derdora xwe geriyam.", "chapter": "PERESTIN (ÎBADET)"}, {"text": "Di nêrînên însanan de li qedr û qîmetê xwe negere. Her roj nêrînên wan diguherin.\nM. Mahmoud\nQîmeta her kesekî bi qasî fikr û ramanên wî ye.", "chapter": "QEDR Û QÎMET"}, {"text": "Werin em qedr û qîmeta hev bizanibin; çimkî em ê rojekê ji nişka ve ji hev biqetin.", "chapter": "QEDR Û QÎMET"}, {"text": "Ev rêya te ye, tenê ya te. Dibe ku hin kes li gel te bimeşin, lê kesek ji bo te nameşe.", "chapter": "SERXWEBÛN – XWESERÎ"}, {"text": "Fitne û fesadî ji binê şaşikê derdikeve, ne ji qedeha şerabê.", "chapter": "ŞERAB"}, {"text": "Şîretan meke, bibe mînak.", "chapter": "ŞÎRET"}], "Zig Ziglar": [{"text": "Ji bo destpêkirinê ne hewce ye tu nûwaze bî, lê ji bo tu bibî nûwaze, divê tu dest pê bikî.", "chapter": "CERIBANDIN - METOD"}, {"text": "Jêhatbûyîna te dikare tehilkişîne lûtkeyê;lê tiştê te li wir payîdar bihêlekarakterê te ye.", "chapter": "KARAKTER – XÛY"}, {"text": "Pere (dirav) tenê dikare ji bo we nivîneke baş bistîne, ne xeweke baş. Dikare xêniyekî baş bistîne, ne malbat. Dikare hevalekî jî bistîne, lê ne dosteki baş.", "chapter": "MALDARÎ – DEWLEMENDÎ"}], "William Golding": [{"text": "Min hemî pergal mîna şepqeyên nebikêrhatî bi dîwêr ve kirin. Hebek jî ne li gorî min bû.", "chapter": "CERIBANDIN - METOD"}, {"text": "Bi şev di tarîtiyê de hatin û agirê me dizîn. Belê dizîn. Ku xwestibana, me dê agir bida wan. Lê dizîn.", "chapter": "DIZÎ"}, {"text": "Raboriya min li gel min dimeşe.", "chapter": "RABIRDÛ Û DAHATÛ"}], "Eric Hoffer": [{"text": "Cihûyên ku li Almanyayê di serdema Hîtler de bê têkoşîn li benda tunekirina xwe disekinîn, dema hatin Fîlîstînê bi wêrekî şer kirin. Ev tiştekî ecêb e.", "chapter": "CIHÛ(YEHUDÎ)"}, {"text": "Wekhevîya bêazadî, ji azadîya bêwekhevî bêhtir civakeke parsengdar ava dike.", "chapter": "WEKHEVÎ"}], "Yuval Noah Harari": [{"text": "Nifûsa Cihûyan li ser rûyê dinyayê ji hezarî didu ye, lê ji sedî bîst xelatên Nobelê bi dest xistine.", "chapter": "CIHÛ(YEHUDÎ)"}, {"text": "Yan zarokên xwe hînî nivîsandina kodên kompîturê bikin; an jî wan fêrî bikaranîna çekan bikin.", "chapter": "ENDÛSTRÎ"}, {"text": "Hûn wan zombîyên ku rûyê wan bi telefonên biaqil ve hatiye zeliqandin û li kolanan digerin dibînin. Gelo ew teknolojiyê kontrol dikin, an teknolojî wan kontrol dike?", "chapter": "ENDÛSTRÎ"}, {"text": "Deklerasyona Gerdunî ya Mafên Mirovan dide zanîn ku; bê şert û merc “mafê jîyanê” nirxê herî bingehîn yê mirovahîyê ye. Divê em topyekûn li dijî mirineke ku vî mafê bingehîn binpê dike, têbikoşin.", "chapter": "MAF – MAFDARÎ"}, {"text": "Ji bo hemwelatiyekî Emerîka yê ji rêzê, Coca-Cola ji rêxistina el Qaîde bi gelkî xeternaktir e.", "chapter": "TENDÛRISTÎ"}], "Hesen Henefi": [{"text": "Ji hêla disîplînên mîna helbest, gramer, bawerî, felsefe, tib, astronomî, tesewûf û tefsîrê ve cudahiyeke mezin di navbera çanda Îslamiyetê û yahûdîtiyê de tune ye.", "chapter": "CIHÛ(YEHUDÎ)"}], "William Faulkner": [{"text": "Dakeve jêr ey Mûsa,Here welatê Misrê,Bêje wî Fîrewnê gewre,\nBila qewmê min azad bihêle.", "chapter": "CIHÛ(YEHUDÎ)"}, {"text": "“Bavo, mirov li çîyayan çawa dikarin şer bikin?”\n“Nikarin şer bikin. Lê mecbûr in.”", "chapter": "ŞER Û AŞTî"}], "Nawal El Saadawi": [{"text": "Civaka ji jinê ditirse, nexweş e.Jina ji azadiyê ditirse, mirî ye.", "chapter": "CIVAK"}], "Anne Frank": [{"text": "Kesek bi dayînê feqîr nabe.", "chapter": "COMERDÎ"}], "Încîl": [{"text": "Dayîn ji stendinê bixêrtir e.", "chapter": "COMERDÎ"}, {"text": "Berîya her tiştî “gotin” hebû.", "chapter": "GOTIN"}, {"text": "Bila xema sibê ji sibê re be,derdê her rojekê bes î xwe ye.", "chapter": "KERB Û KESER"}], "John Mason": [{"text": "Hûn wek kesayetekî bêhempa hatine dinê. Wekî “teqlîdek” nemirin.", "chapter": "CUDAHÎ - RESENÎ"}], "Moliere": [{"text": "Ew mirovê ku herî zêde li xweşa me diçe, ew kese ku me şibandiye xwe.", "chapter": "CUDAHÎ - RESENÎ"}, {"text": "Bi mirovên ku karibin we ruken bikin re hevaltîyê bikin. Ji ber ku tenê bişirînek dikare rojeke tarî ronî bike.", "chapter": "RÛKENÎ"}], "William Burroughs": [{"text": "Dixwazin te kategorîze bikin. Dixwazin li gor şablona di mêjiyê xwe de, te li deverekê bicih bikin. Û ger tu li gorî wan dernekevî, pir aciz dibin.", "chapter": "CUDAHÎ - RESENÎ"}], "Cabîrî": [{"text": "Piştî te her tişt ji bîr kir,tiştê mayî “çand” e.Ji ber ku tiştên mayî hêmanênsereke yên çandê ne,yên jibîrbûyî jî yên guhêrbar in.Aqilê Netewî jî ew e.", "chapter": "ÇAND"}], "Murray Bookchin": [{"text": "Civakek çiqas di nav mîstîsîzmû eklektîzmê de bimîne,ji hêla çandî veewqasî li paş dikeve.", "chapter": "ÇAND"}, {"text": "Ekolojî, tenê ne tevgereke hawîrparêz e. Di heman demê de felsefeyeke civakî û zanistî, projeyeke komelayetî ya dijhîyerarşîk û dijotorîter û şêwaza jîyaneke çalakger e.", "chapter": "EKOLOJÎ – XWEZA"}], "Humboldt": [{"text": "Neteweyên ku ji hêla zimên ve serkeftin bidest nexistibin, ji hêla çandî ve jî li paş dimînin. Çanda gelên ziman lawaz, tiroviro ye.", "chapter": "ÇAND"}], "Henry Rawlinson": [{"text": "Destana Ferhad û Şîrîn di çand û folklora kurdî de cihekî xwe yê taybet heye. Nemaze di nav kurdên Kirmanşahê de.", "chapter": "ÇAND"}], "MerleauPonty": [{"text": "Axaftina bi zimanekî,hilgirtina giranîya çandekê ye.", "chapter": "ÇAND"}], "Terry Eagleton": [{"text": "Çand di xizmeta olê de ye,ol jî di xizmeta sîyasetê de ye.", "chapter": "ÇAND"}, {"text": "Navê wê tişta ku dibe sebeb mirov car caran hevûdin dixin şûna Xwedê an jî kêzikan, îdeolojî ye.", "chapter": "FELSEFE – ÎDEOLOJÎ"}], "Jim Morrison": [{"text": "Çapemenî di bin kontrola kî de be, mejîyan jî ew kontrol dikin.", "chapter": "ÇAPEMENÎ"}], "Anonîm": [{"text": "Dema desthilatdar bi ser serê gel de dimîzin, çapemenî derdikeve û dibêje baran tê.", "chapter": "ÇAPEMENÎ"}, {"text": "Pir ê caran gotinên şoforê taksîyê yên derbareyê welêt de,ji yên serokê dewletê rasttir in.", "chapter": "DEWLET"}, {"text": "Neteweyên ku çîrok û çîrvanokên wan tune ne, ji sir û sermayê diqufilin", "chapter": "EDEBÎYAT (WÊJE)"}, {"text": "Kêmasiyên laşên mirov bi mîtrok qumaş tê nixumandin, lê kêmasiyên mêjî di nîqaşa ewilîn de derdikeve holê.", "chapter": "KÊMASÎ"}, {"text": "Mirovên “azad” dibin peyrewên mafdaran. Mirovên “bende” dibin peyrewên hêzdaran.", "chapter": "MAF – MAFDARÎ"}, {"text": "Hemî Xwedawend mirine, ji xeynî Xwedayê şer.", "chapter": "XWEDAWEND"}], "Jean-Luc Godard": [{"text": "Êdî tenê amûrên ragihandinê hene, ragihandin tuneye.", "chapter": "ÇAPEMENÎ"}], "Albert Camus": [{"text": "Mişk li kolanan,mirov jî di malên xwe de dimirin.Û rojname tenê bi kolanan vemijûl dibin.", "chapter": "ÇAPEMENÎ"}, {"text": "Bêyî ku bi min bişêwirin, derbarê çarenûsa min de biryar didan.", "chapter": "ÇARENÛS - QEDER"}, {"text": "Em hemî, zîndanên xwe, keskûjîyên xwe, hilweşînên xwe di hundirê xwe de digerînin.", "chapter": "DERÛNNASÎ"}, {"text": "Hûn bixwazin welatekî nas bikin,li şêweyê mirina welatiyan binêrin.", "chapter": "DESTHILATDARÎ"}, {"text": "Tenê li xwe difikirî, ji ber ku tenê xwe nas dikir.", "chapter": "EGO – XWEPERESTÎ – EZ EZÎ"}, {"text": "Rewşenbîr ew e ku, dikare aqilê xwe bike serpereştê nefsa xwe.", "chapter": "NEFS"}, {"text": "Qurbaniyên herî pîs ew in ku, ji celladên xwe re rêzdar in.", "chapter": "QURBANÎ"}, {"text": "Birano! Hûn di nav bobelatekê de ne, birano we ev heq kiribû.", "chapter": "SÛC Û CEZA"}, {"text": "Û ev nexweşî! Yên ku pê neketine jî, wê di dilê xwe de digerînin.", "chapter": "TIRS Û ENDÎŞE"}, {"text": "Carinan ji xwekuştinê zêdetir ji bo jiyanê pêdivî bi wêrekîyê heye.", "chapter": "WÊREKÎ"}], "Gotina Cihûyan": [{"text": "Mirov planan çêdikin, Xwedê dikene.", "chapter": "ÇARENÛS - QEDER"}, {"text": "Bi melkemot re henek nabin.", "chapter": "MÎZAH"}], "Puşkin": [{"text": "Hûn bixwazin siberoja xwe bi xwe binivîsin, pênûsê nedin destê kesên din.", "chapter": "ÇARENÛS - QEDER"}], "Gotina Ingilîzan": [{"text": "Her çareseriyek pirsgirêkeke nû encam dide.", "chapter": "ÇARESERÎ Û BÊÇARETÎ"}, {"text": "Piştî şîr rijiya, girî fêde nake.", "chapter": "FÊDE Û ZERER"}], "Frida Kahlo": [{"text": "We dît girêk venabe,hûn jî ben bibirrin.", "chapter": "ÇARESERÎ Û BÊÇARETÎ"}, {"text": "Delalî û nedelal î leylanok e. Dawîya dawî dê herkes hundirê we bibîne.", "chapter": "ESTETÎK"}, {"text": "Dapîra min her tim digot: “mirov gunehên xwe yên hûthûte di çewalan de vedişêrin, çewtîyên te yên biçûçik jî bi dîwaran ve dadileqînin.", "chapter": "GUNEH"}, {"text": "Ez jin im û jineke li gor dilê xwe me. Ne li gor dilê te.", "chapter": "SERXWEBÛN – XWESERÎ"}], "Karl Marx": [{"text": "Çîna serdest qencî û xerabiya diyar dike.", "chapter": "ÇÎN"}, {"text": "Hûn tev jî dizanin; Li vî welatî pere jî, ax jî, qanûn jî, fikr jî, bawerî jî ... Hema her tişt ji sermayedaran re xizmetê dikin.", "chapter": "KAPÎTALÎZM"}, {"text": "Zêdebûna nirxê tiştan û daketina nirxê mirovan, hevrêje ne.", "chapter": "KAPÎTALÎZM"}, {"text": "Di dîrokê de bûyerû kesayetên mezin ducare dibin:cara yekemîn trajedî,cara duyemîn jî komedî.", "chapter": "KOMEDÎ – TRAJEDÎ"}, {"text": "Rêya dojehê bi kevirên niyata baş hatiye raxistin.", "chapter": "NIYET"}, {"text": "Tekane rê ji bo mirovmayînê, têkoşîna li hember vê pergala dijmirovane ye.", "chapter": "SERHILDAN – BERXWEDAN"}, {"text": "Tekane rêya mirovmayînê, têkoşîna li dijî sîstema dijmirovane ye.", "chapter": "ŞOREŞ"}], "Alî Şerîetî": [{"text": "Ol, êdî ne amûreke ku çîna bindest ber bi azadiyê ve bibe; belkî di destê çîna serdest de bûye amûra bendîkirin û koletiyê.", "chapter": "ÇÎN"}], "Yilmaz Guney": [{"text": "Ji dêvla ez bibim qeşmerê sifreya qral, ez ê bibim eşqîyayê şerê gel.", "chapter": "ÇÎN"}, {"text": "Min canê kesekî neêşand, lê di gel ku dizanîbûn ez agir im jî, bi ser min de hatin.", "chapter": "PARASTIN"}], "Frantz Fanon": [{"text": "Pasîfbûna we,we dike alîgirê çîna serdest.", "chapter": "ÇÎN"}, {"text": "Kesên nikarin li ber mêtingerên xwe rabin, dibin dijminê birayê xwe û hêza xwe li dijî birayê xwe bikar tînin...!", "chapter": "KOLONYALÎZM - DAGIRKERÎ"}], "Hesenê Metê": [{"text": "Keç û lawên ademîji çîrokan hez dikin.", "chapter": "ÇÎROK"}, {"text": "Min bi kurdî nivîsî ku ji bilî kurdan û xwedê kesek nikaribe bixwîne.", "chapter": "KURD – KURDÎ"}, {"text": "Em bi êşê hatin çandinû bi mirinê tên çinîn...", "chapter": "MIRIN"}], "Heidegger": [{"text": "Jîyan çîrok e.Dema tu ji kesekî hez dikî,tu ji çîroka wî hez dikî.", "chapter": "ÇÎROK"}, {"text": "Ziman warê hebûnê ye.", "chapter": "ZIMAN Û FERHENG"}], "Albert Einstein": [{"text": "Hûn bixwazin zarokên we şareza bibin,ji wan re çîrok û çîrvanokan bixwînin.Ku hûn bixwazin ew şarezatir bibin, ji wan re bêhtir çîrok û çîrvanokan bixwînin.", "chapter": "ÇÎROK"}, {"text": "Di şerê cîhanê yê sêyemîn de kîjan çek dê bêtin bikaranîn, ez nizanim; lê yê çaremîn wê bi kevir û daran be.", "chapter": "ENDÛSTRÎ"}, {"text": "Li hêviya mûcîzeyan nesekine,jiyan serapa mûcîze ye.", "chapter": "JÎYAN"}, {"text": "Çanda tundûtûjîyê, ji kesên kêmexlaq re her tim dilniwaz e.", "chapter": "TUNDÛTÛJÎ"}], "Gotina Ereban": [{"text": "Tu gurekî di çîroka pezekî deû pezekî, di çîroka gurekî de.", "chapter": "ÇÎROK"}, {"text": "Heta xwedî destûr nede,kuçik nareye.", "chapter": "KOLE - XÛLAM"}], "José Mauro de Vasconcelos": [{"text": "Kenê xwe bi çîroka kesî meke.Rê dirêj e û hê ya te jî bi dawî nebûye.", "chapter": "ÇÎROK"}, {"text": "Vê ji bîr neke: fedekariya zêde, bêwefatiya zêde bi xwe re tîne.", "chapter": "NANKORÎ"}, {"text": "Pêdivî bi lêhatinan heye, bi xweşkatiyên bê wext û bê plan tên...", "chapter": "RASTHATINÎ (TESADÛF)"}], "Maya Angelou": [{"text": "Êşa herî giran,ew çîrok e ku hûndi hundirê xwe de vedişêrin.", "chapter": "ÇÎROK"}, {"text": "Her careke ku jin xwe diparêze, îhtîmal e ku bê zanebûn û bê îdîakirin, ji bo hemî jinan radibe pîyan.", "chapter": "PARASTIN"}], "Aurelius Agustine": [{"text": "Jiyan pirtûk e. Kesên nagerin û nabînin, her tim heman rûpelî dixwînin.", "chapter": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT"}], "Ferid Amara": [{"text": "Bimeşe, bimeşe û dîsa bimeşe... Heta ku êşa piyê te bi ser hemî êşên din bikeve.", "chapter": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT"}], "R.M. Rilke": [{"text": "Min dixwest bimeşim di rêyeke kesnezan de...", "chapter": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT"}, {"text": "Ji tenêtîya xwe hez bikin.", "chapter": "TENÊTÎ"}], "Kinsun": [{"text": "Kes kesî winda nake. Yê diçe yekî din dibine, yê dimîne xwe dibine.", "chapter": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT"}], "John Williams": [{"text": "Ku pêlava te teng be, çi fêdeya firehiya dinyayê heye.", "chapter": "ÇUYÎN - RÊWÎTÎ – GER Û GEŞT"}, {"text": "Ku şekala te teng be, çi fêdeya dinyayeke fireh heye?", "chapter": "XEWN Û XEYAL"}], "Îbrahîm Sediyanî": [{"text": "Ji bo Kurdan çi dixwazim, heman tiştî ji bo neteweyên din jî dixwazim. Neteweyên din xwediyê çi mafî bin, heman tiştî ji bo Kurdan jî dixwazim. Ne yek kêm ne yek zêde. Gelo ez nijadperest im?", "chapter": "DADMENDÎ"}, {"text": "Derkeve ji dibistanê,derkeve ji mizgeftê,derkeve ji pirtûkxaneyê...Hilkişe sertara çiyayekî û li jêr binêre.Tu çi dibînî?Welatekî dabeşkirîbi ser çar parçeyan.", "chapter": "KURD – KURDÎ"}], "Vladimir Lenin": [{"text": "Mehkeme dezgehekî desthilatê ye; lîberal carinan vê rastiyê jibîr dikin, lê jibîrkirina vê rastiyê ji hêla marksîstekî, sûc e.", "chapter": "DADMENDÎ"}], "Desmond Tutu": [{"text": "Dema hûn li hember bêdadîyê bêalî dimînin, hûn dibin alîgirên zordaran.", "chapter": "DADMENDÎ"}], "Gotina Swîsrîyan": [{"text": "Kesê mala cîranê xwe bihejîne,mala xwe xira dike.", "chapter": "DADMENDÎ"}, {"text": "Sermîyanê ku hişmend di salekê de berhev dike, ehmeq di rojekê ji dest dide.", "chapter": "ŞAREZATÎ Û EHMEQÎ"}], "Charles Dickens": [{"text": "Her tişt berovajî bûye.Kujer bêrîyan didarizînin.", "chapter": "DADMENDÎ"}, {"text": "Qey ji xwe hezkirin her tim ne raserî nefretê bû?", "chapter": "KÎN Û NEFRET"}], "Martin Luther King": [{"text": "Neheqîya li deverekê,ji bo edaleta hemî deveran gef e.", "chapter": "DADMENDÎ"}, {"text": "Tu nefirî bazde, baznedî bimeşe, nemeşî bi çarlepkan here. Lê çi bikî bike tu neçar î ku bi pêş de herî.", "chapter": "KIRYAR – ÇALAKÎ"}, {"text": "Nefret nekin. Nefret barekî wisa giran e ku, nayê ragirtin.", "chapter": "KÎN Û NEFRET"}, {"text": "Mirov fêrî gelek tiştan bûne. Mîna balindeyan difirin, mîna masîyan avjenîyê dikin, lê hînî jîyaneke bi biratî û hevbeş nebûn.", "chapter": "ŞER Û AŞTî"}, {"text": "Serkêşîya li dijî qanûnên bêdad, bo her mirovî erkekî exlaqî ye.", "chapter": "ZAGON"}], "Rudyard Kipling": [{"text": "Destê Xwedê nedigihaşt her derê, ji bo vê jî dayîkan afirand.", "chapter": "DAYÎK Û BAV"}], "J.J. Rousseau": [{"text": "Hemî cîhanê deynin alîyekî û dayîka min deynin alîyekî, ez ê dayîka xwe hilbijêrim.", "chapter": "DAYÎK Û BAV"}, {"text": "Bendeyên serpêl,kenê xwe bi peyva azadîyê dikin", "chapter": "KOLE - XÛLAM"}], "Deleuze": [{"text": "Serhildana li hemberî bav komedî ye, ne trajedî.", "chapter": "DAYÎK Û BAV"}, {"text": "Hişmendiya neteweyî, bi awayekî mecbûrî bi edebiyatê ve girêdayî ye.", "chapter": "EDEBÎYAT (WÊJE)"}, {"text": "Êş, aqil mecbûrî lêgerînê dike.", "chapter": "LÊPIRSÎN – KRÎTÎK"}], "Cioran": [{"text": "Bi saetan em li benda hatina hin saetên din radiwestin.", "chapter": "DEM"}, {"text": "Çiqas em di nav salan de diçin, hejmara kesên em ji hev fêhm dikin kêm dibin. Dibe ku rojekê kesek nemîne em pê re biaxivin.", "chapter": "PÎR Û KAL"}, {"text": "Bi qasî gerestêrkeke nekeşîfkirî, tu dûr î ji xwe.", "chapter": "XWENASÎN"}], "Tagore": [{"text": "Dema vala tune ye, dema ku vala derbas dibe heye.", "chapter": "DEM"}, {"text": "Kesê dizane ku teqez dê li bin sîya wan daran rûnenê, lê dîsa jî daran diçîne. Wî kesî ji bo têgihiştina wateya jîyanê gavek avêtiye.", "chapter": "JÎYAN"}], "Robin Sharma": [{"text": "Heman salê heftê û pênc caran dijîn û jê re dibêjin “jîyan”", "chapter": "DEM"}, {"text": "Gerdûn li rex wêrekan e.", "chapter": "GERDÛN"}, {"text": "Mirovahî gelekî pêş ketiye; êdî nema tê xûyakirin.", "chapter": "MIROVV - MIROVAHÎ"}], "Immanuel Kant": [{"text": "Dem, birrekeke bêdeng e.", "chapter": "DEM"}, {"text": "Dema em ji bo xetayên ku kesên din dikin hêrs dibin, em ne wan, lê xwe ceza dikin.", "chapter": "HÊRSBÛN"}, {"text": "Kesê ji tirsa dojehê û bo çûna bihûştê qencîyê dike, ew qencî ne exlaqî ye.", "chapter": "QENCÎ Û XERABÎ"}, {"text": "Kesê xwe dixe şûna kurmikekî ser axê, divê ji erçiqandina binê lingan gilî û gazinan neke.", "chapter": "RÛMET"}], "Wim Wenders": [{"text": "Dem her birînê derman dike. Lê ku dem bi xwe nexweşîyek be?", "chapter": "DEM"}], "Alija Izetbegović": [{"text": "Eger diktatorî tiştekî guneh jî qedexe bike, bêexlaq e. Heger demokrasî destûra gunehan jî bide xwedî exlaq e. Exlaq û azadî ji hev naqetin. Tenê kiryarên azad, dibin mijara exlaq.", "chapter": "DEMOKRASÎ"}, {"text": "Berdêla windakirina nasnameya we; koletî, bindestî û çewisandin e.", "chapter": "NASNAME"}, {"text": "Dema em mirovan hînî ramînê dikin, em wan azad dikin. Dema em zanyariyên hazir pêşkêş dikin, em wan tevlî kerî dikin.", "chapter": "PERWERDE – PEDAGOJÎ"}], "Slavoj Žižek": [{"text": "Em dê jinûveavakirina demokrasiyê,ji Kurdan hîn bibin.", "chapter": "DEMOKRASÎ"}, {"text": "Divê em her tiştî ji nû de pênase bikin û ji pirsa ‘mirov çi ye’ dest pê bikin.", "chapter": "ONTOLOJÎ"}], "Platon": [{"text": "Berî perwerdeyê, demokrasî çênabe. Civakeke neperwerdekirî derbasî demokrasiyê bibe, dê bibe olîgarşî. Wisa dewam bike, dê demagog peyde bibin. Ji demagogan jî dê dîktator derkevin.", "chapter": "DEMOKRASÎ"}, {"text": "Her tişt bi dijberê xwe tê xwedî kirin;ti fêdeya hevşêwe ji hevşêwe re tune ye.", "chapter": "DIJBERÎ - NAKOKÎ"}, {"text": "Baş guh bide gotinên neyarê xwe.Di wan gotinan de gelek rastî hene ku, dostên te ji te vedişêrin.", "chapter": "DIJMIN - DIJMINATÎ"}, {"text": "Bênfireh bin; çimkî her mirovekî ku hûn li rastî wî/ê tên, bawer bikin herî kêm bi qasî we di nav kefteleftê de ye.", "chapter": "EDEB Û REZDARÎ"}, {"text": "Eger ji asîmanan azadî bibare,tê bibînî ku hin xûlam bi sîwanan digerin.", "chapter": "KOLE - XÛLAM"}, {"text": "Zarokek ji tarîtiyê bitirse, normal e. Lê trajediya mezin ew e ku, kesên qirrase ji ronahiyê ditirsin.", "chapter": "KOMEDÎ – TRAJEDÎ"}, {"text": "Tu bibî çi bibe. Lê berî her tiştî bibe mamosteyê nefsa xwe û şagirtê ûjdanê xwe.", "chapter": "NEFS"}, {"text": "Tu kel û pelên xwe yên kevn diavêjî; çima dev ji fikr û ramanên xwe yên kevnare bernadî?", "chapter": "NÛJENÎ – XWENÛKIRIN"}, {"text": "Pêdivî, dayîka hemî dahênanan e.", "chapter": "PÊDIVÎ"}, {"text": "Axaftin, hunera bikaranîna aqil e.", "chapter": "RETORÎK"}, {"text": "Ew ên ku kesên derdora xwe herî zêde rexne dikin, tewanbar dikin û biçûk dibînin; di rastîyê de ew in ku, herî zêde ji rûbirûbûna şerma nava xwe ditirsin.", "chapter": "REXNE"}, {"text": "Ji bîr neke Kritias, tirsonekan tu carî bîrdariyên serfiraziyê neçikandine.", "chapter": "SERFIRAZÎ"}, {"text": "Serîyekî vala, cihxebata şeytên e.", "chapter": "ŞEYTAN"}, {"text": "Mirovên baş ji bo ku rast û durist tev bigerin, pêdivîya wan bi zagonan tune ye. Mirovên xirab jî, ji xwe rêyeke binpêkirina zagonan bo xwe dibînin.", "chapter": "ZAGON"}], "Abdurrahman Qasimlo": [{"text": "Bê demokrasîyê,ne pirsgirêka Kurdan çareser dibe,ne jî Kurd dikarin mafê serxwebûnêbi dest bixin.", "chapter": "DEMOKRASÎ"}, {"text": "Kesê derheqê nijada xwe, jîyan û tekoşîna gelê xwe de dinivîse, nikare bêalî bimîne.", "chapter": "NETEWE"}], "Robert Byrne": [{"text": "Demokrasî ew e ku,tu li hember namzetê xirabtir dengê xwe didî namzetê xirab.", "chapter": "DEMOKRASÎ"}], "Robin Williams": [{"text": "“Zikekî birçî, berîkeke vala û dilekî şikestî dersa herî mezin a jiyanê fêrî te dike.”", "chapter": "DERS Û ÊBRET"}], "Hans-Georg Gadamer": [{"text": "Kesê ku tiştekî bi her awayî red dike,bi rastî ew di bin bandora wî tiştî de ye.", "chapter": "DERÛNNASÎ"}], "Emile Ajar": [{"text": "Têrnebûna zaroktiyê şûnên gelekî kûr ku qet jê neçin, li pey xwe dihêle.Di pêşerojê de dabînkirina van têrnebûnan ne pêkan e.", "chapter": "DERÛNNASÎ"}], "Carl Gustav Jung": [{"text": "Her mirovek di hundirê xwe de potansiyela xerabîyê dihewîne.Kesên haya wan ji vî tiştî tune ye,ji yên din talûketir in.", "chapter": "DERÛNNASÎ"}, {"text": "“Dewlet” ketîye şûna Xwedê.Hemî dîktatorî bûne ol û koletiya ji dewletê re, ketiye şûna îbadetê.", "chapter": "DEWLET"}, {"text": "Jixwe yê nikaribe tinazê xwe bi xwe bike, dê bibe pêkenok û lêhbokê devê xelqê.", "chapter": "MÎZAH"}, {"text": "Bi mîlyonan sifirên kû werin tenişta hev, mixabin encam nake yek.", "chapter": "QEDR Û QÎMET"}, {"text": "Her rewş û kiryareke kesên din ku em pê aciz dibin, rêyeke din li ber me vedike ku em xwe nas bikin.", "chapter": "XWENASÎN"}], "Erich Maria Remarque": [{"text": "Di hundirê serê her kesekî de,li gor xwe odeyeke îşkenceyê heye.", "chapter": "DERÛNNASÎ"}], "Gotina Aşûriyan": [{"text": "Tu xaniyê xwe li ser rondikê çavê mezlûman ava bikî, wê dîwar bi ser te de bihêrivin!", "chapter": "DESPOTÎZM – ZORDESTÎ"}, {"text": "Tu xaniyê xwe li ser rondikê çavê mezlûman ava bikî, wê dîwar bi ser te de bihêrivin!", "chapter": "DESPOTÎZM – ZORDESTÎ"}, {"text": "Nehêle kes pê li piyê te bike, kesê ku îro pê li piyê te kir, sibê dikare pê li stûyê te jî bike.", "chapter": "SERHILDAN – BERXWEDAN"}], "Walter Benjamin": [{"text": "Mirovên ku li vî welatî bi ser hev de hatine dewisandin, hew dikarin xetên sereke yên mirovahîyê ji hev veqetînin. Her mirovek azadî ji wan re “ecêb” tê.", "chapter": "DESPOTÎZM – ZORDESTÎ"}, {"text": "Min di xewna xwe de tivingek berda canê xwe. Dema tiving teqîya, ez ji xew şiyar nebûm û min kêlîyekê li cenazeyê xwe temaşe kir.", "chapter": "XEW - BÊXEWÎ"}], "Cemaledîn Efxanî": [{"text": "Kesê mafê mirovan binpê dike, welew ku hemî temenê xwe bi rojî, nimêj û xwendina Quranê jî derbas bike, li gor hemî baweriyan lanetkirî ye.”", "chapter": "DESPOTÎZM – ZORDESTÎ"}, {"text": "Ûmet bê exlaq, exlaq bê bawerî, bawerî bê têgihiştin çênabe.", "chapter": "SINC – EXLAQ"}], "Ursula K. Le Guin": [{"text": "Zordarî, rêya herî bêkêr e ji bo dabînkirina asayîşê.", "chapter": "DESPOTÎZM – ZORDESTÎ"}, {"text": "Dema kirin fêde neke, zanyarîyan berhev bike; ku zanyarî jî fêde nekin, rakeve.", "chapter": "FÊDE Û ZERER"}], "Diderot": [{"text": "Heta qralê dawîn bi rûvîkên rehbikê dawîn neyê xeniqandin, ademîzad azad nabe.", "chapter": "DESPOTÎZM – ZORDESTÎ"}, {"text": "Mirov ji çar behrên jiyana xwe sê behran, bi xwestina tiştên ku dê nikaribe bi dest bixe derbas dike.", "chapter": "PLANSAZÎ"}], "Jean Jacques Rousseau": [{"text": "Serwerî (hikûmranî) bê qeyd û şert ya gel e.", "chapter": "DESTHILATDARÎ"}, {"text": "Ka em bigerin, belkî dawiyêem li mirovekî rast werin.", "chapter": "MIROVV - MIROVAHÎ"}], "Étienne de La Boétie": [{"text": "Serkeftina herî mezin a desthilatdariyê ew e ku; zordariyê normal, koletiyê mecbûrî û bêdengmayînê jî wekî xûypakî û dilpakiyê dide nîşandan.", "chapter": "DESTHILATDARÎ"}], "Jack London": [{"text": "Dar di destê kê de be, hukimdar ew e.", "chapter": "DESTHILATDARÎ"}, {"text": "Xelata dilpakîyê, tenê dilpakî ye.", "chapter": "XELAT"}, {"text": "Li deryaya xwe û keştiyên xwe vegere Martino, pêşniyara min bo te ev e. Çi karê te heye li van bajarên tije mirovên, gurrî û genî?", "chapter": "XWENASÎN"}], "Thomas Jefferson": [{"text": "Gava hikûmet ji gelê xwe bitirse,ev azadî ye. Gava gel ji hikûmetê bitirse, ev zorbetî ye.", "chapter": "DESTHILATDARÎ"}, {"text": "Fêhtok berî talûkê, tirsonek di kêliya talûkê de, wêrek jî piştî derbasbûna talûkê ditirsin. Gotina Almanan\nKesên tirsonek, sikûneta despotîzmê, ji deryaya azadîyê ya bibahoz çêtir dibînin.", "chapter": "TIRSONEK"}], "Selahaddîn Eyyûbî el- Kurdî": [{"text": "Desthilatdar û rayedarên herî kirêt û bêbext ew in ku, zik û berîkên wan tije ne û gelê wan birçî ye.", "chapter": "DESTHILATDARÎ"}], "Epicurusus": [{"text": "Heger Xwedê diayên wan erê bikira,ji ber ku her tim li dijî hev dia dikirin dê koka mirovan biqeliya.", "chapter": "DEWLET"}, {"text": "Bêrêzê heqîqî yê li hemberê olan, ne ew kes e ku xwedawendên gel înkar dike; ew kes e ku bawerîyên gel yên derbareyê xwedawendan de dipejirîne.", "chapter": "XWEDAWEND"}], "Charles de Gaulle": [{"text": "Dostên dewletan tune ne, berjewendiyên wan hene.", "chapter": "DEWLET"}], "Evdilrehman Durre": [{"text": "Dewleta te tune be,dîn û îmana te jî nîne.", "chapter": "DEWLET"}], "Friedrich Dürrenmatt": [{"text": "Dewlet dema amadekariya cînayetekê dike, her tim navê “welat” li xwe dike.", "chapter": "DEWLET"}], "Gotina Frensiyan": [{"text": "Kesê mal bi deyn dide hevalê xwe, herdûyan jî winda dike.", "chapter": "DEYN"}], "Gotina Almanan": [{"text": "Malê tu bi deyn didî dostekî,tê ji dijminekî bistînî.", "chapter": "DEYN"}, {"text": "Heger tu li ser rêya şaş bî, fêdeya lez û bezê tuneye.", "chapter": "ŞAŞÎTÎ – ÇEWTÎ"}, {"text": "Xwarina zêde, ji birçîbûnê bêhtir nêzî mirinê ye.", "chapter": "TENDÛRISTÎ"}, {"text": "Yê li wekheviyê digere, bila biçe goristanan.", "chapter": "WEKHEVÎ"}], "John Maynard Keynes": [{"text": "Eger 1000 dolar deynê banqê li we hebe û hûn nikaribin bidin, hûn rûbirûyî pirsgirêkeke cidî ne. Eger 1 mîlyon dolar deynê banqê li we hebe û hûn nikaribin bidin, banqe rûbirûyî pirsgirêkeke cidî ye.", "chapter": "DEYN"}], "Gotina Sumeriyan": [{"text": "Deynkirin bi qasî ganê hêsan e,deyndan bi qasî zanyinê zehmet e.", "chapter": "DEYN"}, {"text": "Dilekî bêrehm, ji Yezdanekî bêrehm re; dilekî birehm jî, Yezdanekî birehm re dia dike.", "chapter": "TEOLOJÎ"}, {"text": "Ji Xwedayê gelên din re rêzdar bin. Bo ku ew jî ji Xwedayê we re rêz bigrin.", "chapter": "TEOLOJÎ"}], "Gotina Someriyan": [{"text": "Kesê ne deyndar,mirovê herî bextewer e.", "chapter": "DEYN"}, {"text": "Exlaqê mirov, çawaniya Xwedayê ku jê re perestiyê dike dide nîşandan.", "chapter": "SINC – EXLAQ"}, {"text": "Kesê şarabê nas nake, tiştê baş nizane. Şarab xweşî û şahiyê bi xwe re tîne.", "chapter": "ŞERAB"}], "Paul Auster": [{"text": "Mirovê rast, dema şaş. Dema rast, mirovê şaş. Her timî jiyan bi vî hawî bi mirov dilîze.", "chapter": "DIJBERÎ - NAKOKÎ"}, {"text": "Mirovê rast, dema şaş. Dema rast, mirovê şaş. Her timî jiyan bi vî hawî bi mirov dilîze.", "chapter": "ŞAŞÎTÎ – ÇEWTÎ"}, {"text": "Vê ji bîr nekin; bêdengiya jinê, xatir xwestin e.", "chapter": "XATIRXWESTIN"}, {"text": "Pirê caran li binê êşên me, îmzeya kesên ku em herî zêde ji wan hez dikin, heye.", "chapter": "XIYANET"}], "Vincent van Gogh": [{"text": "Ji bo rabûnê ketin, ji bo dîtinê jî windabûn divê.", "chapter": "DIJBERÎ - NAKOKÎ"}, {"text": "Êdî dinya pîr bûye û qermîçonkê wê zêde bûne.", "chapter": "DINYA"}, {"text": "Min dil û canê xwe tevlî karê xwe kir. Û min di vê oxirê de aqilê xwe jî winda kir.", "chapter": "HUNER - HUNERMEND"}], "Che Guevara": [{"text": "Raqîbên xwe jî bi baldarî hilbijêrin. Payeya dijberiyê nedin pîs û çepelan û wan neyînin qama xwe.", "chapter": "DIJBERÎ - NAKOKÎ"}, {"text": "Heta dijminê xwe jî bi baldarî hilbijêrin. Rûmeta rikberiyê nedin kesên pespaye.", "chapter": "RÛMET"}, {"text": "Xwestin me bin ax bikin, lê nizanibûn ku em tov in.", "chapter": "SERHILDAN – BERXWEDAN"}, {"text": "Kesê carekê xayîntiyê bike, dikare hezar carî jî xayîntîyê bike. Ji bo tu bizanibî ava behrê şor e, ne lazim e tu tevî tehm bikî!", "chapter": "XIYANET"}], "Gernas Koçer": [{"text": "Yê ku bi dijminê xwe\nAnî bîr û bawerî\nÇerxa wî çep digere\nDoza wî naçe serî", "chapter": "DIJMIN - DIJMINATÎ"}], "Zabel Yesayan": [{"text": "Di rojên giran tu serê xwe li kevirekî bixî, dê ji kevir rondik bibarin. Lê hêvîya merhemetê ji dijmin neke.", "chapter": "DIJMIN - DIJMINATÎ"}], "Gotina Sirbiyan": [{"text": "Ku dijminê te nebin,tu mirovekî bêqîmet î.", "chapter": "DIJMIN - DIJMINATÎ"}, {"text": "Şeytan ne bi qiloçan, bi ken nêzîk dibe!", "chapter": "XAPANDIN"}], "Descartes": [{"text": "Ji bîr meke, dijmin nîşangirekî kor e.Lê dost dizane dê kuderê nîşan bigre.", "chapter": "DIJMIN - DIJMINATÎ"}, {"text": "Ji bîr neke, eger tu pişta xwe bidî wan kesên ku ronahiyê didin te, tu yê ji reşahiya xwe pê ve tiştekî din nebînî.", "chapter": "REWŞENBÎRÎ"}, {"text": "Tu nikaribî wan qanih bikî, serê wan tevlîhev bike.\nHarry S. Truman\nŞik û guman me ji pêşdarazî, hişkbawerî û alîgirtina korkorane azad dike.", "chapter": "ŞIK Û GUMAN"}], "John Green": [{"text": "Dil li kuderê be, hêlîn li wir e.", "chapter": "DIL"}, {"text": "Xuya ye dinya ne kargeha mirazan e.", "chapter": "DINYA"}], "Nikos Kazancaskis": [{"text": "Dilê kesekî neşikînin,sitargeha Xwedê ye ew.", "chapter": "DIL"}], "Harper Lee": [{"text": "Dilekî aram, rû jî ronak dike.", "chapter": "DIL"}], "Hermann Hesse": [{"text": "Heger derîyê dil hebûya, dê li ser ev bihata nivîsandin: bikeve hundir, lê neêşîne.", "chapter": "DIL"}, {"text": "Kitêb, ew fanosên deryayê ne ku di deryaya demê de hatine çikandin.", "chapter": "PIRTÛK"}], "Sirius Black": [{"text": "Tu bixwazî mirovekî baş nas bikî, binêre ka ew bi kesên ji xwe zeîftir re çawa tevdigere.", "chapter": "DILOVANÎ"}], "Buddha": [{"text": "Tu bi xwe, bi qasî hemû kesên di gerdûnê de, hezkirin û dilovaniya xwe heq dikî.", "chapter": "DILOVANÎ"}, {"text": "Jîyana hundirê malê dîlîtî ye. Mal qirêj e. Azadî encex bi terk kirina malê tê bidestxistin.", "chapter": "MALBAT"}], "Xellacê Mensûr": [{"text": "Dema fêr bûn ku dilovaniya Yusiv bi te re ye, gelek caran te avêtin binê bîran.", "chapter": "DILOVANÎ"}], "Audrey Hepburn": [{"text": "Dilovanî, Empatî, Nazikbûn... Ev ji makyajê û ji cil û bergên biha bêhtir, mirovan xweşik dikin.", "chapter": "DILOVANÎ"}, {"text": "Ne hewce ye hûn bibin kesekî tekûz. Bila liv û tevgerên we ne sexte bin bes e.", "chapter": "TEKÛZÎ"}], "Jean de La Bruyère": [{"text": "Mirovên dilpak qet nikarin jiyaneke asûde bijîn. Ji ber ku xwe ji bo jîyana kesên din feda dikin.", "chapter": "DILPAKÎ"}], "Platinos": [{"text": "Dev ji niqirandina peykerê xwe bernede. Ta ku şemla dilpakiya Xwedayî li ser te bibiriqe û belav bibe.", "chapter": "DILPAKÎ"}], "Frank Clark": [{"text": "Camêriya heqîqî ew e, tu qenciyê bi kesekî ku qet haya wî jî te çênebe bikî.", "chapter": "DILPAKÎ"}], "Nelson Mandela": [{"text": "Mêjiyekî baş û dilekî pak, her tim kombînasyoneke zehmet e.", "chapter": "DILPAKÎ"}, {"text": "Serokên rasteqîn, divê amade bin ku, ji bo azadiya gelê xwe her tiştî feda bikin.", "chapter": "SEROK"}], "Maxim Gorky": [{"text": "Pişt bide pişta min, bila ji paş ve li me nexin.", "chapter": "DILSOZÎ"}, {"text": "Zanist helbesta aqil e,helbest jî zanista dil e.", "chapter": "ZANIST"}], "Elbert Hubbard": [{"text": "Hevalê rasteqîn ew e ku bi her tiştê te dizane, dîsa jî ji te hez dike...", "chapter": "DILSOZÎ"}], "Marcel Proust": [{"text": "Divê em ji wan kesên ku me şad û bextewar dikin re spasdar bin. Ew bexçevanên wisa şîrîn in ku, di dilê me de kulîlkan vedikin.", "chapter": "DILŞADÎ Û BEXTEWERÎ"}, {"text": "Ji çaran sê behr nerihetîyên mirovên zîrek, ji zîrekbûna wan peyda dibin.", "chapter": "TIRS Û ENDÎŞE"}], "John Locke": [{"text": "Bextewarî û bextreşî du rewş in ku em sînorên wan nizanin.", "chapter": "DILŞADÎ Û BEXTEWERÎ"}], "Charles Baudelaire": [{"text": "Dinya nexweşxaneyeke dêwasa ye û hemî mirovên tê de, dixwazin nivîna xwe biguherinîn.", "chapter": "DINYA"}], "Chinghiz Aitmatov": [{"text": "... û ji xwe ev der dinya ye. Li vê derê dê her tim tiştin nîvco bimînin.", "chapter": "DINYA"}], "Ezop": [{"text": "Dizên biçûk siza dikin, dizên mezin jî tînin ser karên fermî.", "chapter": "DIZÎ"}], "Noam Chomsky": [{"text": "Dersa herî ron û eşkere ya dîrokê: heq nayê dayîn, tê stendin.", "chapter": "DÎROK"}, {"text": "Endûstrîbûn çiqasî pêş bikeve, fanatîzma olî ewqasî kêm dibe.", "chapter": "ENDÛSTRÎ"}], "John Berger": [{"text": "Sedsala me sîtileke qirase ye ku, hemû serdemên dîrokî tê de li hev dikevin û tevdigerin.", "chapter": "DÎROK"}], "Karl Popper": [{"text": "Dîrok, ji berzkirina kûjer û şêlînkeran pêve ne tiştekî din e.", "chapter": "DÎROK"}, {"text": "Rexne, ji bo her fikr û ramanekî rasyonel, damara jiyanê ye.", "chapter": "REXNE"}], "Nasr Hamîd Ebuzeyd": [{"text": "Dîroka mirovahîyê ji şerê navbera serdest û bindestan pêk tê.", "chapter": "DÎROK"}], "Amin Al-Saadani": [{"text": "Ku ewqas vir û derew li ber çavên me tên kirin, em çawa baweriya xwe bi dîrokê bînin?", "chapter": "DÎROK"}], "Gore Vidal": [{"text": "Kêlîya moralê te xirab be, ne yên ku dibêjin “çima?” yên dibêjin “tu li kuderê yî?” heval in.", "chapter": "DOSTANÎ Û HEVALTÎ"}], "Machiavelli": [{"text": "Dostên têkberan pir in, lê dostên têkçûyîyan ji dil in.", "chapter": "DOSTANÎ Û HEVALTÎ"}], "Francis Bacon": [{"text": "Ger dostekî te tune be ji bo tu derd û kulên xwe parve bikî, tu dibî goştxwer û dilê xwe dikeritînî.", "chapter": "DOSTANÎ Û HEVALTÎ"}, {"text": "Kirêtiyên meymûnan zêde ne, ji ber ku ew pirr dişibin mirovan.", "chapter": "PERESAN - TEKAMÛL"}, {"text": "Kesê bi baweriyan destpê dike, digihîje şik û gumanan. Kesê bi şik û gumanan destpê dike, digihîje baweriyan.", "chapter": "ŞIK Û GUMAN"}, {"text": "Pir ê caran kesên ku şîretên herî baş dikin, kesên herî xirab in.", "chapter": "ŞÎRET"}], "Prison Break": [{"text": "Carinan ji bo em zirerê nedin hezkiriyên xwe, tenê yek rê li ber me dimîne: “dûrketin”", "chapter": "DÛR KETIN"}], "La Case De Papel": [{"text": "Hêla dûrbûyînê ya herî baş ev e ku; nikarin lêpirsînê li biryarên te bikin, nikarin fikr û ramanên te darizînin û heta tu destûr nedî, nikarin tevlî jiyana te bibin.", "chapter": "DÛR KETIN"}], "Gotina Kurdan": [{"text": "Bi gur re dixwe, bi kuçik re direye û bi şivan re digirî.", "chapter": "DURÛTÎ"}, {"text": "Dinya li dinê,çavê gûr li bizinê.", "chapter": "KARAKTER – XÛY"}, {"text": "Kesek bi xweziyan, nagihîje baqê keziyan.", "chapter": "KIRYAR – ÇALAKÎ"}, {"text": "Lêhatin ji jêhatinê çêtir e.", "chapter": "ŞENS – FERSEND"}, {"text": "Heta me aqil nas kir, Me temen xelas kir.", "chapter": "TEMEN"}, {"text": "Marê ku razayî xuya dike, bi rastî dûrahiya navbera xwe lingên te dipîve.", "chapter": "TEVDîR (BERGIRÎ)"}, {"text": "Mî bi piyê xwe, bizin bi piyê xwe.", "chapter": "VÎN – ÎRADE"}, {"text": "Ne bi berxîtî têr şîr xwar, ne bi kavirîtî têr giya xwar.", "chapter": "XIZANÎ – HEJARÎ"}], "Omer Lutfî": [{"text": "Sanamê herkesî pê şîrîn e Herkes Îbrahîmê putê kesên din e", "chapter": "DURÛTÎ"}], "Qur’an": [{"text": "Gotinên ne xweş ji Xwedayên wan re nebêjin. Ji bo ku ew jî gotinên ne xweş ji Xwedayê we re nebêjin.", "chapter": "EDEB Û REZDARÎ"}], "Nikolay Vasilyeviç Gogol": [{"text": "Ku li pêşberî min kesekî/e baş hebe ez ê bi dil û can pê re biaxivim û di cî de bibim heval. Ez dê li gel wî/wê çayê jî vexwim. Tu dizanî çima? Ji ber ku mirovên qenc rêzdar in.", "chapter": "EDEB Û REZDARÎ"}], "Îbn Sîna": [{"text": "Xweşikbûna gotinê, di kûrtbûna wê de ye.", "chapter": "EDEBÎYAT (WÊJE)"}, {"text": "Em bi qewmekî wilo tên îmtihan kirin ku dibêjin, “em tenê li ser hîdayetê ne.”", "chapter": "OLPERESTÎ"}, {"text": "Kesek bi qasî kesê ku naxwaze bibîne ne kor e.", "chapter": "OLPERESTÎ"}, {"text": "Nîv ji nexweşiyê dilwasî ye, nîv ji tenduristiyê dilrehetî ye. Sebr, destpêka şîfayê ye.", "chapter": "TENDÛRISTÎ"}, {"text": "Fêr bûm û têgihiştim ku, tiştek nehatiye fêrkirin û tiştek nehatiye têgihiştin.", "chapter": "ZANEBÛN"}], "Mikhail Bakhtin": [{"text": "Ziman, bi helbestê pêş dikeve û geş û gûrr dibe.", "chapter": "EDEBÎYAT (WÊJE)"}], "Ahmed Arîf": [{"text": "Di vê erdnîgariya ku temenê perperokan ji yên zarokan dirêjtir e de, ez kîjan helbestê ji we re binivîsim?", "chapter": "EDEBÎYAT (WÊJE)"}], "Alexandre Dumas": [{"text": "Gazinan ji kesê ku gelekî qala xwe dike, neke. Ji ber ku ew nizane qala tiştekî din bike.", "chapter": "EGO – XWEPERESTÎ – EZ EZÎ"}, {"text": "Hûn bixwazin sûcdar nas bikin, binêrin ka sûcê hatiye kirin bi kêrî kê tê.", "chapter": "SÛC Û CEZA"}], "Theodor Fontane": [{"text": "Çiqas keleşêr (dîk) hene ku bawer dikin roj bi banga wan hiltê!", "chapter": "EGO – XWEPERESTÎ – EZ EZÎ"}], "Bertolt Brecht": [{"text": "Temam me fêhm kir tu qenc î, lê bi kêrî çi tê qenciya te?", "chapter": "EGO – XWEPERESTÎ – EZ EZÎ"}, {"text": "Go lazim bû, ne li vir bû; go li vir bû ne lazim bû.", "chapter": "PÊDIVÎ"}, {"text": "Kesê bi tiştekî nizane, cahil e. Kesê dizane û xwe kerr dike, bêexlaq e.", "chapter": "SINC – EXLAQ"}, {"text": "Kesê têdikoşe, dibe ku têk biçe. Yên ber xwe nadin, jixwe têkçûyî ne.", "chapter": "TÊKOŞÎN - XEBAT"}, {"text": "Kesê birçî, qenciyên xwe dixwe.", "chapter": "XIZANÎ – HEJARÎ"}], "Hubert Reeves": [{"text": "Em li dijî xwezayê di têkoşînê de ne. Eger em bi ser kevin, em ê têk biçin.", "chapter": "EKOLOJÎ – XWEZA"}], "Seneca": [{"text": "Li ser rûyê erdê gelek mirovên ne layîqê şewqa rojê hene. Lê roj her sibê ji nû ve hiltê.", "chapter": "EKOLOJÎ – XWEZA"}, {"text": "Tiştê bi mentiq nayê dermankirin, bi demê derman dibe.", "chapter": "MANTIQ"}, {"text": "Demildest dest bi jiyanê bikin û her rojeke xwe, wek jiyaneke nû bihesibînin.", "chapter": "NÛJENÎ – XWENÛKIRIN"}, {"text": "Her derê we kûl û birîn e, hûn li pizrokên kesên din dinêrin.", "chapter": "PAŞBÊJÎ"}, {"text": "Xelata qenciyê, kirina wê ye.", "chapter": "XELAT"}, {"text": "Her derê we xwîn û birîn e, lê hûn li pizrokên xelkê meyze dikin.", "chapter": "XWENASÎN"}, {"text": "Dîtina te ya derheqê te, ji dîtina kesên din girîngtir e.", "chapter": "XWENASÎN"}, {"text": "Kesê di ciwaniya xwe de dara zanînê neçandibe, di kalbûna xwe de sîyeke ku xwe li berê rehet bike nabîne.", "chapter": "ZANEBÛN"}], "Larry Niven": [{"text": "Ajara dînazoran qeliya, ji ber ku bernemeyeke wan ya fezayê tune bû.", "chapter": "ENDÛSTRÎ"}], "Dorothy Parker": [{"text": "Xweşikatî, tenê tebeqeyeke derveyî ye. Lê kirêtî û pîsîtî heta ser hestûyan jî reng vedide.", "chapter": "ESTETÎK"}], "Gotina Estoniyan": [{"text": "Jina delal bihûşta çavan, dojeha giyanan û paqijkera berîkan e.", "chapter": "ESTETÎK"}], "Robert A. Heinlein": [{"text": "Sererastkirin: Jina ne xweşik tune ye, lê hin ji yên din xweşiktir in.", "chapter": "ESTETÎK"}], "Denis Diderot": [{"text": "Êşên kûr, bêziman in.", "chapter": "ÊŞ Û JAN"}, {"text": "Feylesofan ti carî mamosteyên ayînî nekuştine. Lê mamosteyên ayînî gelek caran feylesof kuştine.", "chapter": "FELSEFE – ÎDEOLOJÎ"}], "Jean Baudrillard": [{"text": "Di her xweşî û êşê de nîyazeke nepenî heye ku, dixwazin zû bi zû bidawî bibin.", "chapter": "ÊŞ Û JAN"}, {"text": "Berê beden ji bo gîyan metaforek bû, piştre bu metafora zayendîyê, lê îro ew, edî teqez ne metafora tiştekî ye jî...", "chapter": "GÎYAN"}, {"text": "Rasthatinî, hêza xwedayî ya herî kevnar e li dinyayê. Dema hûn li yekî/ê rast tên, ew ji bo we carinan xelat, carinan jî celat e.", "chapter": "RASTHATINÎ (TESADÛF)"}], "André Malraux": [{"text": "Her kesek dişibe êşa xwe.", "chapter": "ÊŞ Û JAN"}], "Karl Georg Büchner": [{"text": "Xwedêyo min çi guneh kiriye ku, hema serê kêlîyekê tu min wek şagirtekî radikî ber dep?", "chapter": "EZMÛN"}, {"text": "Ji lingên westiyayî re hemî rê û biwar dirêj in.", "chapter": "TENBELÎ – TIRALÎ"}], "Jigsaw": [{"text": "Tecrûbe, mamosteyekî dijwar e. Pêşî ezmûn dike, paşê ders dide.", "chapter": "EZMÛN"}], "Frank A. Clark": [{"text": "Hûn rêyeke bêasteng bibînin, îhtîmal e ku ew rê naçe tu deverê.", "chapter": "EZMÛN"}], "Jean Paul Sartre": [{"text": "Dema min got “divê Cezayîr bibe welatekî serbixwe,’’ min dît gelek hevalên min ên çêpgir yên nêzî min faşîst derketin.", "chapter": "FAŞÎZM"}, {"text": "Tu rabî û bêjî ez ê ji yekî/ê hez bikim, ev bi tena serê xwe teşebusek e. Ji bo vê jî; hêz divê, dil divê û korbûyîn divê.", "chapter": "HEZKIRIN"}, {"text": "Belê dibe ku em carinan nikaribin bi zalimên xwînxwar. Lê her tim hêza me ya tifekê heye ku em li ser çavên wan bixin.", "chapter": "SERHILDAN – BERXWEDAN"}], "Herman Finer": [{"text": "Li dewletên faşîst welatî tunene, tenê bendegan (reaya) hene.", "chapter": "FAŞÎZM"}], "Leonard Cohen": [{"text": "Herkes dizane keştî av girtiye. Herkes dizane kaptan derewan dike. Û herkes dizane zar bihîle ne.", "chapter": "FAŞÎZM"}], "Hipokrat": [{"text": "Kêmkirina tiştên bizerar, ji zêdekirina tiştên bifêde çêtir e.", "chapter": "FÊDE Û ZERER"}, {"text": "Eger morale te xirabe be, derkeve meşê. Ku hê jî xirabe be, derkeve meşeke din.", "chapter": "TENDÛRISTÎ"}], "George Bernard Shaw": [{"text": "Esilzade ew e ku, fêdeya wî ya ku dide dinyayê, ji fêdeya ku ji dinyayê dîtiye zêdetir e.", "chapter": "FÊDE Û ZERER"}, {"text": "Hinek jin bawer dikin kuhinekî bigirîn,dê encama 2+2 bibe 5", "chapter": "KEN Û GIRÎN"}], "John Stuart Mill": [{"text": "Ji dêvla tu yê bibî berazekî bextewer, bibe Socratesekî dilnerihet.", "chapter": "FELSEFE – ÎDEOLOJÎ"}], "Deluze": [{"text": "Bêfelsefeyî, asta ehmeqiyê derdixe rêjeya herî bilind. Erka felsefê, têkoşîna li dijî ehmeqiyê ye.", "chapter": "FELSEFE – ÎDEOLOJÎ"}], "İSocrates": [{"text": "Mirov xwedîyê xwezayeke dualî ye; beden û aqil. Ji bo bedenê pêdivî bi waneya werzîşê, ji bo aqil jî pêdivî bi waneya felsefê heye.", "chapter": "FELSEFE – ÎDEOLOJÎ"}], "Bertrand Russell": [{"text": "Brêz lord! Ji bo daneheva ewqas saman û serwetê, ji xeynî jidayîkbûnê gelo te çi zehmetî kişand?", "chapter": "FEODALÎZM"}, {"text": "Bitirse ji wî kesê ku tenê bi yek kitêbê bawer dike.", "chapter": "OLPERESTÎ"}, {"text": "Ez bawer im, dema dibêjin mirov û meymûn ji heman eslî tên, meymûn ji mirovan bêhtir diqehirin.", "chapter": "PERESAN - TEKAMÛL"}, {"text": "Ji fikr û ramanên ecêb netirsin. Fikrên ku îro normal tên dîtin, dûh ecêb bûn.", "chapter": "REWŞA ASAYÎ"}, {"text": "Şer, heqî û neheqiyê ji hev naqetîne; tenê bêhêz û hêzdaran eşkere dike.", "chapter": "ŞER Û AŞTî"}, {"text": "Pirsgirêka dinyayê ev e ku; kesên bêfehm û ehmeq her tim ji aqilê xwe razî ne. Kesên pirzan û xwezan jî her kêlî di nav şik gumanan de ne.", "chapter": "ŞIK Û GUMAN"}, {"text": "Tiralî rengek ji rengê xwekuştinê ye.", "chapter": "TENBELÎ – TIRALÎ"}, {"text": "Dînê min ev e: hemî wezîfeyên xwe bicih bîne û ji bo vê jî, ne li vê dinyayê, ne jî piştî mirinê hêviya xelatekê neke.", "chapter": "XELAT"}, {"text": "Tenê Xwedawendên gunehkaran hene.", "chapter": "XWEDAWEND"}], "Richard Bach": [{"text": "Jîyan tiştekî ji we re nabêje, lê her tiştî nişanî we dide.", "chapter": "FÊRBÛN"}, {"text": "Kesên ji serkeftina xwe bawer in, dawîya dawî ew serfiraz dibin.", "chapter": "SERFIRAZÎ"}], "Josh Malerman": [{"text": "Stewîn; fêrbûna dûrketina ji wan mirovan e ku mêjiyê te dilewitînin.", "chapter": "FÊRBÛN"}], "Lesley Hazleton": [{"text": "Bêdawîtî, rebenî û pepûkîya îlîzyona zanebûnê teşhîr dike.", "chapter": "GERDÛN"}], "Allen Ginsberg": [{"text": "Her kesek, di hundirê xwe de gerdûneke mezin e.", "chapter": "GERDÛN"}], "Arthur Charles Clarke": [{"text": "Du dibêtî hene; yan em li gerdûnê bi tenê ne, yan jî em ne bitenê ne. Herdu dibêtî jî di heman pileyê de tirsnak in.", "chapter": "GERDÛN"}], "Andrei Andrei Tarkovsky": [{"text": "Giyan li ahengê digere, lê jiyan ji serî heya binî tevlîhevî ye.", "chapter": "GÎYAN"}], "Gotina Îtaliyan": [{"text": "Di navbera gotin û kirinê de gelek pêlavên qetiyayî hene.", "chapter": "GOTIN"}, {"text": "Wekî tu dixwazî sir û nepeniyên xwe veşartî bihêlî, tu çima wan ji kesên din re dibêjî?", "chapter": "SIR Û NEPENÎ"}, {"text": "Ku diranên gur diweşin, dibe pêkenokê kuçikan.", "chapter": "TINAZPÊKIRIN"}], "Jeanette Winterson": [{"text": "Tiştên ez bêjim pir zêde bûn, ji bo vê min tiştek negot.", "chapter": "GOTIN"}], "André Paul Guillaume Gide": [{"text": "Hemû tiştên ku divabû bihatana gotin, ji zû de hatine gotin. Lê ji ber ku kesekî guhdarî nekiriye, divê em dîsa dubare bikin.", "chapter": "GOTIN"}], "J. Iron": [{"text": "Ji dengê min ê bilind netirse, dema gotinên ku bêjim nemînin, hingê bitirse.", "chapter": "GOTIN"}], "Foucault": [{"text": "Tiştê tê dîtin, ti carî di hundirê gotinê de bi cih nabe.", "chapter": "GOTIN"}, {"text": "Gotarbêjên bêexlaq yên ku ji aliyê gel ve tên qebûlkirin, tenê tiştên ku gel dixwaze seh bike dibêjin.", "chapter": "RETORÎK"}], "Heraclitus": [{"text": "Tu nikarî di heman çemî de du caran xwe bişoyî.", "chapter": "GUHERÎN"}], "Burhan Sonmez": [{"text": "Bajar di kavilê bajarên kevin de, mirî jî di axa miriyên beriya xwe de bi cih dibûn.", "chapter": "GUHERÎN"}], "Kazancakis": [{"text": "Tu dizanî ji bo çi dinya di vî halî de ye? Karên nîvco, axaftinên nîvco, evînên nîvco, gunehên nîvco û qenciyên nîvco. Ka carekê jî heya dawiyê bibe serî gidî!", "chapter": "GUNEH"}, {"text": "Heta li dinyayê kulîlk, zarok û çivîk hebin, netirse birayê Leo. Dê her tişt têkeve rêya xwe.", "chapter": "REŞBÎNÎ – XWEŞBÎNÎ"}], "Îsa Mesîh": [{"text": "Jîr bin mîna maran, lê bêguneh bin mîna kevokan.", "chapter": "GUNEH"}, {"text": "Kî ji gunehan bêrî be, bila kevirê yekemîn ew biavêje.", "chapter": "GUNEH"}], "Îbnû’-l Heysem": [{"text": "Talibê heqîqetê ne ew kes e ku dibe peyrewê kitêbên kevn û wan bê pirs û sûal qebûl dike.\nTalibê heqîqetê ew e ku şik û guman dike, lê dikole û her tim di lêgerîna rastiyê de berdewam e.", "chapter": "HEQÎQET"}], "Bismarck": [{"text": "Tu bixwazî hemî dinyayê bixapînî, rastiyê bêje.", "chapter": "HEQÎQET"}], "Hecî Bektaşê Welî": [{"text": "Li destê xwe, zimanê xwe û doxîna xwe miqate be. Li nanê xwe, karê xwe û hevjîna xwe xwedî derkeve. Kêmasiyan veşêre, nepeniyan binixûmîne û hêrsa xwe jî daqurtînê.", "chapter": "HÊRSBÛN"}], "Beethoven": [{"text": "Dilê hezker, dinyayê hembêz dike. Dilê hêrsok, xwedîyê xwe dixwe.", "chapter": "HÊRSBÛN"}], "Isaac Asimov": [{"text": "Kesê ku bi pifikê nêzî agir dibe, ku çirûskek jî li holê nebe, ew ê bi xwe agir derxe.", "chapter": "HÊRSBÛN"}], "Paramahansa Yogananda": [{"text": "Hêrs, encama meyl û dilbijîyên astengkirî ye.", "chapter": "HÊRSBÛN"}], "Jane Austen": [{"text": "Carinan ez hestên xwe bo xwe vedişêrim. Ji ber ku ti ziman têra derbirrîna wan nake.", "chapter": "HEST – HESTIYARÎ"}, {"text": "Tiştê rêya herî rast nîşanî mirov dide, wicdanê mirov e.", "chapter": "ÛJDAN"}], "Nîzar Qebbanî": [{"text": "Dema li gel te qehwê vedixwim, hest pê dikim ku dara qehwê ya ewil bo me hatiye çandin.", "chapter": "HEST – HESTIYARÎ"}, {"text": "Heta ku çavên te welatê min bin, ez siltanê zemên im.", "chapter": "IŞQ Û EVÎN"}, {"text": "Mêrantiya te dikeve, dema jinek ji hezkirina te poşman dibe.", "chapter": "JIN Û MÊR"}, {"text": "Her kesek, biqasî kêmasiyên xwe ezyetê dide kesên din.", "chapter": "KÊMASÎ"}, {"text": "Hêncet tev derew in. Yê bixwaze, dikare.", "chapter": "VÎN – ÎRADE"}], "Bella Thorne": [{"text": "Yekî ku ji te hez neke, teqez taybetmendiyeke te ya ku jê diheside heye.", "chapter": "HESÛDÎ – ÇAVNEBARÎ"}], "Paula Hawkins": [{"text": "Hartirîn kujer ew in ku, hêviyên me dikujin.", "chapter": "HÊVÎ – BÊHÊVÎTÎ"}], "Lucy Maud Montgomery": [{"text": "Jiyana min, goristaneke mişt bi hêviyên binaxkirî.", "chapter": "HÊVÎ – BÊHÊVÎTÎ"}], "Virginia Woolf": [{"text": "Nedixwest bimre. Jiyan xweş bû. Rojê germ dikir. Lê mirov?", "chapter": "HÊVÎ – BÊHÊVÎTÎ"}, {"text": "Dinya yekpare ye, ez li derveyî wê me.", "chapter": "ONTOLOJÎ"}, {"text": "Peyv di ferhengan de najîn, di hişê mirov de zindî dibin.", "chapter": "PEYV"}], "Alain Bosquet": [{"text": "Jiyan pênc ji sedî hêrs e, du ji sedî hewes e, yê mayî hemî mij û moran e.", "chapter": "HEWES - ZEWQ"}], "Gotina Skotlandiyan": [{"text": "Dema dil bi şehwetê tije dibe, dev jî bi derewan tije dibe.", "chapter": "HEWES - ZEWQ"}], "Pascal": [{"text": "Mirov ji aqil bêhtir, di bin bandora hewesên demkî de ne.", "chapter": "HEWES - ZEWQ"}], "William Blake": [{"text": "Di nav agirê dilçûnên xwe de dimeşe mirov.", "chapter": "HEWES - ZEWQ"}], "Henry Miller": [{"text": "Valakirina kîsikê mîzê, zewqeke herî mezin a mirovahîyê ye.", "chapter": "HEWES - ZEWQ"}, {"text": "Şev her tim ji rojê biînsaftir e.", "chapter": "ŞEV Û ROJ"}, {"text": "Tevahîya welêt bêqanûn, xeternak, li ber teqînê û şeytanî ye.", "chapter": "ZAGON"}], "The Libertine": [{"text": "Ez fikirîm ku bizmaran jî di serê te de bikutim, lê min biryarek xirabtir da; ez ê te ‘tune’ bihesi bînim.", "chapter": "HEYF – TOL Û BEXŞANDIN"}], "Julia Roberts": [{"text": "Tu dilê xwe ji camê çêkî, ên ku bişikînin pirr in. ji hesin çêkî, di dawiyê de wê zeng bigire. Dilê xwe ji deryayê çêke da ên ku bikevinê tê de winda bibin, ên avjeniyê nizanibin jî, bixeniqin.", "chapter": "HÊZDARÎ - LAWAZÎ"}], "Osho": [{"text": "Ji êşên xwe yên borî re spasdar be. Jixwe pola bi lêdanê, mirov jî bi êşkişandinê hêzdartir dibe.", "chapter": "HÊZDARÎ - LAWAZÎ"}, {"text": "Kesê navinc ji aqilê xwe razî ye.Tenê kesên zîrek pêjna kaosê dikin û hişê wan tevlîhev dibe.", "chapter": "KAOS"}, {"text": "Sê xwestek we dikin bendeyê kesên din; xwesteka hezkirinê, xwesteka ecibandinê, xwesteka teqdîrkirinê.", "chapter": "KOLE - XÛLAM"}, {"text": "Jiyan ne baweriyek e,lêkolîneke hûr û kûr ali ser rastiyê ye.", "chapter": "LÊKOLÎN"}, {"text": "Kengê pêdiviya te bi eleqeya kesekî nema, tu yê hingê bisitewî. Kengê te hêviya xwe ji kesên din birî, tu yê hew birîndar bibî. Kengê tu bi kesekî nehatî girêdan, tu yê hingê kar bikî.", "chapter": "SERXWEBÛN – XWESERÎ"}], "Morgan Freeman": [{"text": "Mafdarîya te têr nake, divê hêza te jî hebe.", "chapter": "HÊZDARÎ - LAWAZÎ"}, {"text": "Dema têkiliya te bi kesekî/ê re qedîya, hemî nepenîyên xwe bicivîne û di quncika dilê xwe de veşêre û ji bîr bike. Exlaq, piştî bidawîbûna pêwendîyê xwe nîşan dide.", "chapter": "TÊKILÎ"}, {"text": "Niha li 179 welatên ku vayrosa koronayê lê heye, ji 50 Xwedayên ji hev cûda alîkarî hatiye xwestin. Lê yek ji wan jî hê bersiv nedaye. Dema zanyaran derman dîtin, herkes dê ji Xwedayê xwe re spasiyê bike.", "chapter": "ZANIST"}], "Hegel": [{"text": "Dîroka dinyayê ji pêşveçûyîna hişmendiya azadiyê wêdetir ne tiştekî din e.", "chapter": "HIŞ – HIŞMENDÎ"}, {"text": "Dema werîsek biqete û hûn girêkekê lê bixin, di werîs de ciyê herî qewîn dibe ew girêk. Lê çi cara hûn destê xwe bidin wî werîsî, devera canê we biêşîne dê ew girêk be.", "chapter": "PÊBAWERÎ"}], "AngelA": [{"text": "Bi rastî jî tu serkevirek î. Ji bo vekirina hişê te ji mucîzeyekê bêhtir, pêdivî bi metqebekê heye.", "chapter": "HIŞ – HIŞMENDÎ"}], "Ingmar Bergman": [{"text": "Ziman her tim dinanê arihî dipalêne. Mirov her tim janê di hişê xwe de digire.", "chapter": "HIŞ – HIŞMENDÎ"}], "Pablo Neruda": [{"text": "Hêdî hêdî dimirin kesên bûne dîlên hînbûyinên xwe: ew yên her roj di heman rêyê de diçin. Ew yên ku asoya xwe berfireh nakin û naguherînin. Ew yên ku hema rengê cil û bergên xwe jî naguherînin û ew yên bi kesekî biyanî re naaxivin.", "chapter": "HÎNBÛNÎ"}, {"text": "Hêdî hêdî dimirin; ew kesên ku naxwînin, mûzîkê guhdarî nakin û di wûjdanê xwe de xweşbîniyê nahewînin.", "chapter": "REŞBÎNÎ – XWEŞBÎNÎ"}], "Benjamin Disraeli": [{"text": "Zincîra hînbûnîyan ewil bi qasî ku neyê hîskirin zirav e, piştre bi qasî ku neyê qetandin sitûr dibe.", "chapter": "HÎNBÛNÎ"}], "Aram Tigran": [{"text": "Ger ez careke din bêm dinê; çiqas tank, tifing, çek û sîleh hebin ez ê hemîyan bihelînim û bikim tembûr, cimbiş û zirne.", "chapter": "HUNER - HUNERMEND"}], "Lars von Trier": [{"text": "Fîlmekî baş, mina zixurê di hindûrê şekalê de ye.", "chapter": "HUNER - HUNERMEND"}], "Mario Salas": [{"text": "Kesek tê cem te.\nTiştekî ji te naxwaze,\nqet tiştekî..!\nHezkirinê jî.\nBi vî awayî evîn diwelide.", "chapter": "IŞQ Û EVÎN"}], "Alexsandre Dumas": [{"text": "Dema jin ji mêrekî hez nekin, qet dilê xwe bi wî mêrî naşewitînin. Lê dema ji mêrekî hez dikin, îcar dilê xwe bi xwe naşewitînin.", "chapter": "IŞQ Û EVÎN"}], "Jacques Lacan": [{"text": "Tiştekî ku hûn ne xwedîyê wî ne, hûn dixwazin wî tiştî bidin kesekî ku ew wî ji we nexwaze. Ew jî “işq” e.", "chapter": "IŞQ Û EVÎN"}], "Nazim Hikmet": [{"text": "Çûyîn tenê çalakiyek e. Lê ‘jibîr kirin’ şoreşeke qirase ye.", "chapter": "JIBÎR KIRIN"}], "Balzac": [{"text": "An êşên xwe jibîr bike,an gora xwe bikole.", "chapter": "JIBÎR KIRIN"}, {"text": "Qet pereyên min tune ne” hemî êşên dinyayê di vê hevokê de kom dibin.", "chapter": "XIZANÎ – HEJARÎ"}], "Gotina Spaniyan": [{"text": "Jin wek siyê ye; tu li pey herî,ji te direve, tu jê birevî, li pey te tê.", "chapter": "JIN Û MÊR"}], "Werner Herzog": [{"text": "Bawerîyeke tam bi min re çêbûye ku, şarezayî û şaristanîya me tenê tebeqeyek tenik e. Li binê wê, okyanoseke bê ser û bin ji kaos, cehalet û tarîtiyê heye.", "chapter": "KAOS"}], "Miguel D Lewis": [{"text": "Kapîtalîzm ol e. Banqe perestgeh, banqevan mamosteyên ayînî, dewlemendî beheşt, xizanî dojeh, dewlemend kesayetên pîroz, xizan gunehkar, sermaye pîroz, dirav jî XWEDA ye!", "chapter": "KAPÎTALÎZM"}], "Friedrich Engels": [{"text": "Daneheva sermîyan mîna vexwarina ava şor e. Çiqas vedixwî tî dibî, çiqas tî dibî dîsa vedixwî. Bi kurtasî pençeşêreke bêdawî ye.", "chapter": "KAPÎTALÎZM"}], "Barin Helim": [{"text": "Mirovên serdema modernîteya kapîtalîst guhên xwe kirin pariyek goşt û xwarin! Êdî bi zikê xwe dibihîzin.", "chapter": "KAPÎTALÎZM"}], "Emma Goldman": [{"text": "Civaka kapîtalîst wiha ye;yên ku bênavber dixebitin,ti carî nabin xwedîyê tiştekî.Yên ku qet naxebitin,bi her awayî li kêfa xwe dinêrin.", "chapter": "KAPÎTALÎZM"}, {"text": "Kar bixwazin. Ku nedin, nan bixwazin. Ku herduyan jî nedin, wî nanî ji wan bistînin.", "chapter": "ŞOREŞ"}], "Gotina Îraniyan": [{"text": "Tobeya gur,mirina wî ye.", "chapter": "KARAKTER – XÛY"}, {"text": "Hirî hêdî hêdî dibe xalîçe.", "chapter": "SEBR"}], "Lacan": [{"text": "Kêmasîyek, kêmasiyekê dinixumîne.", "chapter": "KÊMASÎ"}], "Cicero": [{"text": "Hin kes mîna ku li gencîneyan bigerin,li eyb û kêmasiyên mirovan digerin.", "chapter": "KÊMASÎ"}], "Abraham Maslow": [{"text": "Birçîtîya hezkirinê mîna kêmbûna xwê yan jî vîtamînê,nexweşiyeke kêmasîyê ye.", "chapter": "KÊMASÎ"}], "Mario Benedetti": [{"text": "Kesek dema digirî,ne tenê ji bo bûyera wê kêliyê,ji bo hemî bûyerên ku heta nihali ser wan negiriye, digirî.", "chapter": "KEN Û GIRÎN"}], "Hannah Arendt": [{"text": "Gewretirîn dijmin bo otorîteyê û rêya herî dijwar bo lawazkirina wê, kenê bi hîqehîq e.", "chapter": "KEN Û GIRÎN"}, {"text": "Xeta, ew bedel in ku em di rêya heqîqetê de didin.", "chapter": "ŞAŞÎTÎ – ÇEWTÎ"}], "Jason Statham": [{"text": "Derd û kûlên xwe ji kesî re mebêje.Ji sedî bîst ne xema wan e,ji sedî heştê jî dema derd û kûlên te dibihîzin, pê kêfxweş dibin.", "chapter": "KERB Û KESER"}, {"text": "Dibêjin, şadî û kamranî bi sermiyan nayê kirîn. Lê ez dixwazim di tirimpêla Ferrarî de bigirîm.", "chapter": "MALDARÎ – DEWLEMENDÎ"}], "Dale Carnegie": [{"text": "Xwe bi tiştekî mijûl bikin, ev dermanê herî erzan û herî mifadar e li vê dinê.", "chapter": "KERB Û KESER"}], "Nora Roberts": [{"text": "Tiştên tu dibêjî girîng in. Lê tiştên tu dikî girîngtir in.", "chapter": "KIRYAR – ÇALAKÎ"}], "Omar Xeyam": [{"text": "Rabe ser xwe! Ji bo razanê ebedîyet li pêşîya me ye.", "chapter": "KIRYAR – ÇALAKÎ"}, {"text": "Şeraba li gel te tê vexwarin helal e, bê yî te vexwarina avê jî heram e.", "chapter": "ŞERAB"}, {"text": "Qudreta di ava tirî de, işq bi xwe ye.", "chapter": "ŞERAB"}], "Euripides": [{"text": "Xulam, ew ê ku nikarefikr û ramanên xwe bêje.", "chapter": "KOLE - XÛLAM"}, {"text": "Girseyên ku li pey serokên nîyetxirab diçin, talûke ne.", "chapter": "SEROK"}, {"text": "Divê Xwedawend di hêrsbûnê de neşibin mirovan.", "chapter": "XWEDAWEND"}], "Django Unchained": [{"text": "Heger mûçeyê te tenê têra xwarin û razana te bike, tiştê tu dikî ne kar û xebat e. Berê navê vî tiştî koletî bû.", "chapter": "KOLE - XÛLAM"}, {"text": "Têkçûyîn ji bo wêrekan e heval! Çimkî tirsonek ti car nakevin nav cengê.", "chapter": "TIRSONEK"}], "Gassan Kenafani": [{"text": "Nanê te didizin.Piştre çêniyekî jê didin teû dixwazin tu j bo camêriya wan jî spasiya wan bikî.", "chapter": "KOLONYALÎZM - DAGIRKERÎ"}], "Christopher Hitchens": [{"text": "Heta hin kes ji hundir derî li barbaran venekin, barbar nikarin têkevin bajêr.", "chapter": "KOLONYALÎZM - DAGIRKERÎ"}, {"text": "Qet bawerîya min bi wan kesan tûneye ku, “dîn” ji berjewendiyên xwe yên sîyasî re dikin alet. Tiştê herî pîs û çepel di sîyasetê de, bikaranîna dîn e.", "chapter": "LAÎSÎZM"}, {"text": "Ji bo pûçkirina îdiayeke bê delîl,pêdivî bi delîlan tuneye.", "chapter": "MANTIQ"}], "Steve Biko": [{"text": "Çermsipî hem pihînan li devê qûna me dixin, hem jî şêweyê bertekdayîna me ya li dijî pihînê dîyar dikin.", "chapter": "KOLONYALÎZM - DAGIRKERÎ"}], "Albert Caraco": [{"text": "Komedî bi dawî bû,trajedî destpê dike.Wê dinya bibe cîyekî hişktir,sermatir, dilgivêştir û bêrehmtir.", "chapter": "KOMEDÎ – TRAJEDÎ"}], "Zygmunt Bauman": [{"text": "Dinya ji kesên bîrewer re komedî, ji kesên dilzîz re jî trajedî ye.", "chapter": "KOMEDÎ – TRAJEDÎ"}], "Jean Baudrilard": [{"text": "Jibîrkirina komkujiyekê jî, cûreyek ji komkujiyê ye.", "chapter": "KOMKUJÎ"}], "Fatma Savci": [{"text": "Bizane, em di bin barana xwîna straneke kîndar de ne. Li ser rihê zemên, ji qedera me re, ayetên hezar enfalan xwendine...", "chapter": "KOMKUJÎ"}], "Îsmaîl Beşîkçî": [{"text": "Jenosîd ne tenê qirkirina mirovan e. Xesbkirina mafê ziman û çandê jî jenosîd e.", "chapter": "KOMKUJÎ"}, {"text": "Dirûşma “biratîyê” dirûşmeyeke wisa ye ku; hişwindakirinê vedişêre, kûr dike û berbelavtir dike.", "chapter": "XAPANDIN"}], "Helîm Barîn": [{"text": "Bi qasî ku î’ya berîya y’yê tê nîqaşkirin, ewqasî bişaftin û qirkirina çandî nayê nîqaşkirin.", "chapter": "KOMKUJÎ"}], "Plotinos": [{"text": "Di niqirandin û şayîk kirina peykerê xwe de berdewam be.", "chapter": "KONTROL – OTOKONTROL"}], "Pythagoras": [{"text": "Kesê nikaribe xwe kontrol bike, ne azad e.", "chapter": "KONTROL – OTOKONTROL"}], "Mücahit Bilici": [{"text": "“Ûmmet”, dereweke kuji bo xapandina Kurdantê mobîlîzekirin.", "chapter": "KURD – KURDÎ"}], "Hacî Qadirê Koyî": [{"text": "Eger Kurdêk qisey babî nezanî\nMuheqqeq dakî hîz e babî zanî", "chapter": "KURD – KURDÎ"}], "Melayê Cizîrî": [{"text": "Gulê baxê îremê bohtan im,\nŞebçiraxê şevê Kurdistan im.", "chapter": "KURD – KURDÎ"}], "Rênas Jiyan": [{"text": "Kurdistana min rakişandine çarmixê\nmîna Îsayê kurê Xwedê...", "chapter": "KURD – KURDÎ"}], "Goméz Dáwila": [{"text": "Totalîtarîzm, yekbûna bêyom a dîn û dewletê ye.", "chapter": "LAÎSÎZM"}], "Ali Al-Wardi": [{"text": "Ku ji Ereban bipirsin, “hûn dewleteke dînî dixwazin, an dewleteke sekûler?” Ew ê dewleta dînî hilbijêrin û biçin di dewleteke sekûler de bijîn.", "chapter": "LAÎSÎZM"}], "Olivier Roy": [{"text": "Ya rastî îslamcîtî, xizmeta laîsîzmê dike. Ji ber ku nirxên dînî, di rêya berjewendiyên sîyasî de feda dike.", "chapter": "LAÎSÎZM"}], "Antony Black": [{"text": "Beguman hişekî lêkolîner, ji tiştên ciyawaz hez dike.", "chapter": "LÊKOLÎN"}], "Omer Xeyam": [{"text": "Hey cûbbereşo, roja te şev e,\nKeviran neavêje lêkoleran.\nEw li hûnera afirîner digerin,\nLê hiş û aqilê te her tim li ser tiştên ku destmêjê dişkînin e.", "chapter": "LÊKOLÎN"}], "Xezalî": [{"text": "Kesê qaqilkê gwîzê neşikîne û kakil nebîne, zen dike ku gwîz tenê qaqil e.", "chapter": "LÊKOLÎN"}, {"text": "Kesên ne li gor lîyaqetêdibin xwedîyê meqamekî;jêrdestên xwe gez dikin,ji raserên xwe re jî dûv dihejînin.", "chapter": "LîYAQAT"}], "Haruki Murakami": [{"text": "Gelek ji me, temenê xwe bi lêgerîna nîvê xwe yê din derbas dikin.", "chapter": "LÊPIRSÎN – KRÎTÎK"}, {"text": "Eger tu nikaribî tiştekî bê şîrove fêhm bikî, tu nikarî bi şîrove jî fêhm bikî.", "chapter": "TÊGIHÎŞTIN"}], "Farid Farjad": [{"text": "Cûdahîyeke mezin di navbera lêgerîna “mirovên xweşik” û lêgerîna “xweşikbûyîna mirovan” de heye...", "chapter": "LÊPIRSÎN – KRÎTÎK"}], "Aimee Carter": [{"text": "Eger em ti tiştî nekin,dê her tişt wek xwe bimîne.", "chapter": "LIV Û TEVGER"}, {"text": "Ji bîr meke,pîyonek dikare hemîlîstikê biguherîne.", "chapter": "LÎSTIK"}], "Nikola Tesla": [{"text": "Di cîhaneke konformîstde liv û tevgerên antîsosyal,nîşaneya zîrekbuyînê ye.", "chapter": "LIV Û TEVGER"}, {"text": "Kesên pirtûkên pîroz dixwînin û fêhm nakin, dibin oldar. Yên dixwînin û fêhm dikin, dibin ateîst.", "chapter": "PÎROZÎ"}], "Rosa Luxemburg": [{"text": "Kesê xwe tev nede,bi zincîrên kupê hatiye girêdan nahise.", "chapter": "LIV Û TEVGER"}], "Nehru": [{"text": "Jiyan dişibe lîstika îskambîlan.Kartên tên destê we, determînîzmê (qeder) temsîl dike, bikaranîna wan jî vîna azad e.", "chapter": "LÎSTIK"}], "Steve Jobs": [{"text": "Tiştê dûrî aqilan ew e ku; hûn mirovên zîrek erkdar dikin û piştre ji wan re dibêjin: “wiha bikin.” Lê em mirovên zîrek erkdar dikin, ji bo ku ew ji me re bêjin ka em çi bikin.", "chapter": "LîYAQAT"}], "Al Pacino": [{"text": "Kesê te wek bihara xwe nebîne, kulîlkên jiyana xwe pê nede çinîn.", "chapter": "LîYAQAT"}, {"text": "Kesek nikare ji sê heyvan zêdetir deyax bike. Piştî heyva sisêyan mirov rengên xwe yên rasteqîn û niyeta xwe ya heqîqî eşkere dikin. Sebr bike û bişopîne.", "chapter": "NIYET"}], "Gotina Pêştûnan": [{"text": "Ker eynî ker e, lê bi kûrtanekî nû.", "chapter": "LîYAQAT"}], "Maria Teresa Mirabel": [{"text": "Dibe ku mirin ji her tiştî bêhtir nêzî me be, lê ez ji vê yekê na tirsim. Em ê di têkoşîna bo her mafdarîyê de berdewam bin.", "chapter": "MAF – MAFDARÎ"}], "Garth Brooks": [{"text": "Heger tiştekî we yê ku bi pereyan nayê kirîn tune be, hûn ne dewlemend in.", "chapter": "MALDARÎ – DEWLEMENDÎ"}], "Syrus": [{"text": "Pere, xizmetkarekî baş,efendîyekî xirab e.", "chapter": "MALDARÎ – DEWLEMENDÎ"}], "Carl Sagan": [{"text": "Nebûna palpiştê, ne palpişta “nebûnê”ye. (tunebûna delîlê,ji tunebûnê re nabe delîl)", "chapter": "MANTIQ"}, {"text": "Dilpakiya ewil a mirovahiyê şik û guman bû, qisûra ewil jî hişkbawerî bû.", "chapter": "ŞIK Û GUMAN"}, {"text": "Em cinsekî wisa ecêb in; amûr û alavên ku dê bibin sedemê qelandina koka me, em bi destê xwe çêdikin.", "chapter": "ZANIST"}], "Mihail Bulgakov": [{"text": "Dema Xwedê bela xwe dide kesekî,pêşî wî ji mantiq bêpar dike.", "chapter": "MANTIQ"}], "Eleanor Roosevelt": [{"text": "Mêjiyên mezin ramanan gotûbêj dikin, mêjiyên navinc bûyeran gotûbêj dikin, mêjiyên biçûk jî mirovan giftûgo dikin.", "chapter": "MÊJÎ"}], "Francisco Goya": [{"text": "Razana mêjî, cinawiran hildiberîne", "chapter": "MÊJÎ"}], "St. Thomas Aquinas": [{"text": "Zanebûna hindik, talûke ye.Yan tê ava ferzanebûnê ji kûr bikişînî, yan jî tu yê qet li tehma wê nenêrî.Avên tenik mêjî jehrîn dikin,lê avên kûr mêjî paqij dikin.", "chapter": "MÊJÎ"}], "John Verdon": [{"text": "Ez ji kesên ku mêjiyê wan ji devê wan mezintir e, hez dikim.", "chapter": "MÊJÎ"}], "Hume": [{"text": "Di jiyanê de tiştê rêbertiya me dike,ne mêjî ye, xûy û hînbûnîyên me ne.", "chapter": "MÊJÎ"}], "Tayfun Talipoglu": [{"text": "Kuçik bi qezenca xwediyên xwe re eleqedar nabin. Tiştê girîng bo wan, mezinahiya hestiyê ku diavêjin ber wan.", "chapter": "MELAQÎ – ŞELAQÎ"}], "Montesquieu": [{"text": "Ku li welatekî qezenca melaqî û şelaqiyê, ji ya diristiyê zêdetir be, ew welat helak dibe.", "chapter": "MELAQÎ – ŞELAQÎ"}, {"text": "Ewilî mirov im, dûvre fransî me.", "chapter": "NETEWE"}, {"text": "Heger li welatekî mifaya melaqîyê ji ya duristîyê zêdetir be, dê kambaxî li wî welatî rabe.", "chapter": "RASTÎ Û DIRÛSTÎ"}], "İbn Battuta": [{"text": "Kurd mirovên mêrxas û camêr in.Goşt, nan û helawîyê pêşkêşî mêvanên xwe dikin.", "chapter": "MÊVAN – CÎRAN"}], "Gotina Babîliyan": [{"text": "Ji cînarên xwe hez dike,lê tixûbê navbera xweû wan raneke.", "chapter": "MÊVAN – CÎRAN"}], "Carlos Fuentes": [{"text": "Ne mirîyan dizanibû mirin çi yene zindîyan.", "chapter": "MIRIN"}], "Dante Alighieri": [{"text": "Nanê ji destê xelkê, tehl e.", "chapter": "MIRIN"}, {"text": "Nemirime, lê ne sax im jî.", "chapter": "ONTOLOJÎ"}, {"text": "Şerab helbestê di dil de diçêne.", "chapter": "ŞERAB"}], "Sohrap Sepehrî": [{"text": "Bi qasî mirinê fireh in,per û baskên jîyanê.", "chapter": "MIRIN"}], "Akira Kurosawa": [{"text": "Lê mirî derewan nakin.", "chapter": "MIRIN"}], "Hobbes": [{"text": "Mirov gurê hev in.", "chapter": "MIROVV - MIROVAHÎ"}], "Edmond de Goncourt": [{"text": "Mirov ji rastiyê û tiştên besît hez nakin, kêfa wan ji efsaneyan û tiştên xapînok re tê.", "chapter": "MÎTOLOJÎ"}], "N. Rops": [{"text": "Wezîfeya ku di civakên hov de mîtan pêk dianî, di civakên modern de îdeolojî pêk tînin.", "chapter": "MÎTOLOJÎ"}], "Homeros": [{"text": "Herkes ji Zeus hatiye. Çi bîyanî, çi xêzan.", "chapter": "MÎTOLOJÎ"}, {"text": "Xizanî, mirovan zû pîr û kal dike.", "chapter": "XIZANÎ – HEJARÎ"}], "Alexis de Tocqueville": [{"text": "Girse ji heqîqetê bêhtir, nêzî demagojî, çîrvanok, mîtolojî û xeyalan e.", "chapter": "MÎTOLOJÎ"}], "Mehmet Uzun": [{"text": "Hûn dikarin di hemî romanên min de şopa Hektor bibînin.", "chapter": "MÎTOLOJÎ"}], "Gotina Rûsan": [{"text": "Di binê her henekekê de rastiyek heye.", "chapter": "MÎZAH"}, {"text": "Hespê rastbêj amade bikin da bireve.", "chapter": "RASTÎ Û DIRÛSTÎ"}, {"text": "Tu sir û nepeniyên xwe ji lalo re bibêjî, dê zimanê wî vebe!", "chapter": "SIR Û NEPENÎ"}, {"text": "Tenê ehmeq şaşîtiyên xwe dubare dikin, kesên bi aqil şaşîtiyên nû dikin.", "chapter": "WÊREKÎ"}, {"text": "Kesên di nav daristanê de em bi tenê hiştin, bila nepirsin gurgan çi bi serê me aniye!", "chapter": "XIYANET"}], "Antonio Gramsci": [{"text": "Cihana kevn dimire; ya nû jî hê di asoyê de nehatiye hilatin. Û di vê tarîgewrikê de cinawir zêde dibin.", "chapter": "MODERNÎZM"}], "Furûx Ferruxzad": [{"text": "...ditirsim, ji vê serdema ku dilê xwe winda kiriye.", "chapter": "MODERNÎZM"}, {"text": "Ji bo pesnê stêrkan bidim li erdê rûniştime.", "chapter": "PESINDAN"}, {"text": "Min çi dabe bila xweş helal be, ji xeynî wî dilê ku min mift û belaş pêşkêş kiribû.", "chapter": "POŞMANÎ"}], "Byung-Chul Han": [{"text": "Koleyê modern, tenduristîyê ji azadî û xweserîyê çêtir dibîne.", "chapter": "MODERNÎZM"}, {"text": "Têkiliya şefaf, ji hemî dilkêşî û zindîbûnê bêpar e û têkiliyeke mirî ye.", "chapter": "TÊKILÎ"}], "Jim Carrey": [{"text": "Di serdema modern de; Peyv zêde, wate hindik e. Zagon zêde, edelat hindik e. Çenebaz zêde, bêjekar hindik û meş zêde, pêşketin hindik e.", "chapter": "MODERNÎZM"}], "Jung": [{"text": "Mirovê serdema modern, ji yê serdema hoveber bêçaretir û bitenêtir e.", "chapter": "MODERNÎZM"}], "Mayakovski": [{"text": "Di van rojan de, divê mirov rahêje gopalê xwe û li serê dinyayê bixe.", "chapter": "MODERNÎZM"}], "Fringe": [{"text": "Tu dikarî mirov ji mûzîka ku lê guhdarî dike nas bikî.", "chapter": "MOSÎQA"}], "Ozdemîr Asaf": [{"text": "Tenêtî ew e ku mûzîk jî li te guhdarî dike.", "chapter": "MOSÎQA"}], "Winged Creatures": [{"text": "Carinan qehweyekê firr dikî, stranekê vedikî û bêdeng dibî. Û hemî tiştên tu dixwazî vebêjî, ew stran ji dêvla te ve dibêje.", "chapter": "MOSÎQA"}], "Ducane Cündioğlu": [{"text": "Meyla nankoriya mirovî ji zeîfbûna wî te. Lewra barê minetê giran e.", "chapter": "NANKORÎ"}], "Leslie Green": [{"text": "Ziman; şanîderê nasnameyê, mîrateya çandê û îfadeya şênber a neteweyî ye.", "chapter": "NASNAME"}], "Anthony Smith": [{"text": "Nasnameya etnîk bi xetên fîzîkî ava nabe. Ev nasname bi hafizeya parvekirî û qedera hevpar ava dibe.", "chapter": "NASNAME"}], "Mîr Celadet Alî Bedirxan": [{"text": "Ziman şertê heyînê yê pêşîn e.", "chapter": "NASNAME"}, {"text": "Hawara me berî her tiştî heyîna zimanê me dê bide naskirin. Lewma ku ziman şerta heyinê a pêşin e.", "chapter": "ZIMAN Û FERHENG"}], "Ahmet Kaya": [{"text": "“ji ber nasnameya min a kurd, kesên dixwestin min lînç bikin ez careke din dubare dibêjim; ew bênamûs, bêhiset û bêşeref in.”", "chapter": "NASNAME"}, {"text": "Te niha girîn fêrî çavên min kir. Bila ev rondik bibin ristika gerdena min a şermok.", "chapter": "RONDIKÊN ÇAVAN"}], "Elia Abu Madi": [{"text": "Kesê di nefsa xwe de ji xweşkatiyê bêpar be, di ti tiştekî de xweşkatiyê nabîne...!", "chapter": "NEFS"}], "Şemsê Tebrîzî": [{"text": "Jin ji bo nezanan “nefs,” ji bo zanayan “nefes” e.", "chapter": "NEFS"}], "Jawaharlal Nehru": [{"text": "Ku neteweyek ji bo azadîyê ber xwe bide û di vê rêyê de ji bo dayîna her cûre berdêlan amade be, kî dikare heta hetayê wî neteweyî biçewisîne.", "chapter": "NETEWE"}], "Eliezer Ben Yehuda": [{"text": "Çima em nekevin nav tevgerê ku netewetiya xwe biparêzin da ku winda nebe û bi temamî neyê texrîb kirin?", "chapter": "NETEWE"}], "Abraham J. Heschel": [{"text": "Nijadperestî gefa herî mezin e bo mirovahîyê. Bi sedemeke herî biçûk, nefreta herî mezin encam dide.", "chapter": "NIJADPERESTÎ"}], "Angela Davis": [{"text": "Di civakeke nijadperest de, nenijadperestbûna te ne bes e. Divê tû li dijî nijadperestan jî rawestî.", "chapter": "NIJADPERESTÎ"}], "Marquis de Sade": [{"text": "Niyeta baş, ji bo her xirabîyekê vexwendineke cazîb e.", "chapter": "NIYET"}, {"text": "Civakeke ku bingeha xwe ji azadî û wekheviyê girtibe, kêm kiryar wekî sûc tên pênasekirin.", "chapter": "SÛC Û CEZA"}], "Marlo Morgan": [{"text": "Xwîn û hestî bi her mirovî re heye. Cûdahî di dil û nîyetê de ye.", "chapter": "NIYET"}], "Charlie Chaplin": [{"text": "Ku nîyeta we xerab be, pêdivîya we bi hêz û qewetê heye. Wekî din bo hemî tiştên mayî, hezkirin bes e.", "chapter": "NIYET"}, {"text": "Ruyê te bi kê re bikene, dilê te aîdê wî ye.", "chapter": "RÛKENÎ"}, {"text": "Feqîrek dimre, feqîrên din hêrs dibin. Şoreş tê lidarxistin. Feqîrên mayî ji dimirin.", "chapter": "ŞOREŞ"}], "Stefan Zweig": [{"text": "Tiştek bi qasî hîçîtiyê (nîhîlîzm) giyanê mirov naguvêşe.", "chapter": "NÎHÎLÎZM"}], "Abert Camus": [{"text": "Dojeh ji hîçîtiyê (nîhîlîzm) çêtir e.", "chapter": "NÎHÎLÎZM"}], "Alain Robbe-Grillet": [{"text": "Dinya ne biwate ye, ne jî bêwate. Heye û hew.", "chapter": "NÎHÎLÎZM"}], "Douglas Adams": [{"text": "Her tiştî paqij bike û ji nû ve destpê bike.", "chapter": "NÛJENÎ – XWENÛKIRIN"}], "Tom Robbins": [{"text": "Ger lênûsk heman lênûsk be, vekirina rûpelekî nû bi kêrî çi tê?", "chapter": "NÛJENÎ – XWENÛKIRIN"}], "Shannon L. Alder": [{"text": "Berîya tu xwe wek fileh, misilman, hîndû an jî bûdîst bidî nîşandan, fêrî mirovbûyînê bibe.", "chapter": "OL Û AYÎN"}], "Blaise Pascal": [{"text": "Mirov kiriyarên xirab bi kêfxweşiyeke herî mezin dike, dema bi baweriyeke olî dike.", "chapter": "OL Û AYÎN"}], "Khazal Al Maijdi": [{"text": "Hemû îbadet û rîtûelên ku di dînên semawî û dînen tewhîdê de hene, berê dî dînên pagan û pûtperestan de jî hebûn.", "chapter": "OL Û AYÎN"}], "Muhîddînê Erebî": [{"text": "Di baweriya xwe de bi qasî ku hûn bawerîyên din ‘tune’ bihesibînin winda nebin!", "chapter": "OLPERESTÎ"}], "Malala Yusufzai": [{"text": "Dîmena ku herî zêde olperestên tûndrew jê ditirsin, keçikeke ku di destê wê de pirtûk hebe.", "chapter": "OLPERESTÎ"}], "Aleksey Bykov": [{"text": "Xwedêyo! Me biparêze ji wan kesên ku dibêjin “em emrê Xwedê bi cih tînin!”", "chapter": "OLPERESTÎ"}], "Claudio Bossani": [{"text": "Ez ew leheng im ku hê di rûpela destpêkê de dimirim.", "chapter": "ONTOLOJÎ"}], "José Saramago": [{"text": "Heta tu ji “xwe” dernekevî û li “xwe” temaşe nekî, tu yê qet nizanibî bê tu “kî” yî.", "chapter": "ONTOLOJÎ"}], "Mao Zedung": [{"text": "Ger artêşa gel nebe, ti tiştekî wî gelî tune ye.", "chapter": "PARASTIN"}], "Gustave Flaubert": [{"text": "Hinek kes, bi qal kirina bênamûsiyên kesên din, xwe binamûs dihesibînin.", "chapter": "PAŞBÊJÎ"}, {"text": "Rojên herî xweş yên jîyanê, bi “hê zû ye” derbas dibin. Piştre jî êdî pir dereng e.", "chapter": "ŞENS – FERSEND"}], "Emile Chartien": [{"text": "Eger tenê fikrekî we hebe, ji wî fikrî talûketir tiştekî din tune ye.", "chapter": "PAŞVERÛTÎ – KEVNEPERESTÎ"}], "Gotina Danîmarkiyan": [{"text": "Kevneşopî wek tevnepîrikan destpê dikin, lê dawiyê dibin wek zincîrên pola.", "chapter": "PAŞVERÛTÎ – KEVNEPERESTÎ"}], "Ezîz Nesîn": [{"text": "Em têk çûn heyran; li hemberî kirêtî, çorsî û pespayetiyê em têk çûn.", "chapter": "PAŞVERÛTÎ – KEVNEPERESTÎ"}], "Faraj Fouda": [{"text": "Tu yê çawa niqaş bikî li gel kesekî ku bawer dike Xwedê şarab heram kiriye, lê kirîn û firotina mirovan helal kiriye.", "chapter": "PAŞVERÛTÎ – KEVNEPERESTÎ"}], "Edgar Allan Poe": [{"text": "Tiştên tu dibînî, nîvî jê bawer bike. Tiştên tu dibihîzî, tiştekî jê bawer neke.", "chapter": "PÊBAWERÎ"}, {"text": "Rabe! em di şevê de winda bibin.", "chapter": "ŞEV Û ROJ"}], "Oguz Atay": [{"text": "Me ji kîderê destpê dikir? ewil me jê hez dikir, an em pê ewle dibûn.", "chapter": "PÊBAWERÎ"}], "Gotina Farsan": [{"text": "Çiraya ku pêdiviya mala te pê heye, nede mizgeftê.", "chapter": "PÊDIVÎ"}], "Charles Darwin": [{"text": "Di candaran de ne yên herî zîrek û bihêz; yên ji guherînê re herî quncav li jiyanê dimînin.", "chapter": "PERESAN - TEKAMÛL"}, {"text": "Ku pirtûkan nexwîne, pê re nezewice.", "chapter": "ZEWAC"}], "Beyazidê Bîstamî": [{"text": "Di ber dêrekê re derbas bûm, li wir rehbikek hebû. Min jê pirsî: “devereke paqij bo nimêjê heye?” Wiha bersiv da: “dilê xwe paqij bigre û li kuderê bixwazî, nimêja xwe bike.", "chapter": "PERESTIN (ÎBADET)"}], "Omerê kurê Xettab": [{"text": "Li rojî u nimêja mirovan nenêrin, lê binêrin; dema diaxivin derewan dikin, an rastgo ne? Û dema soz didin soza xwe bicî tînin an na?", "chapter": "PERESTIN (ÎBADET)"}], "Amin Maalouf": [{"text": "Herkesî lavelav li ber Xwedayê xwe dikir, da ku dengê daxwazên kesên din bibirre.", "chapter": "PERESTIN (ÎBADET)"}, {"text": "Ji min re got: “Xeyyam zindîqekî serxweş e.” Min got: Ev ne kêmasîyeke ji Xeyyamî re, hûn bi vî awayî pesnê serxweşî û zendîqbûnê didin.", "chapter": "PESINDAN"}, {"text": "Bila raweste dinya ji bo me. Bê dîtin û bê bihîstin em jê derbas bin. Ne xwîna wê, ne herrîya wê bila nepeke piyên me.", "chapter": "QENCÎ Û XERABÎ"}, {"text": "Ji ber ku oldar in, weke ku pêdiviya wan bi exlaq nemaye, tevdigerin.", "chapter": "SINC – EXLAQ"}], "Robert Frost": [{"text": "Dayik 20 salên xwe xerc dike ji bo ku kurê xwe bike mêrekî baş. Dûvre keçikek tê u di 20 xulekan de wî dike ehmeqek.", "chapter": "PERWERDE – PEDAGOJÎ"}], "Alfred Adler": [{"text": "Kesekî ku seraqet pesnê xwe bide, xuya ye ku xwe ‘kêm” dibîne.", "chapter": "PESINDAN"}, {"text": "Derew, nîşaneya bixwenebawerî û bêhêzîyê ye.", "chapter": "VIR Û DEREW"}], "Frank Zappa": [{"text": "Heta tu ji normalîyê dernekevî, pêşveçûn ne pêkan e.", "chapter": "PÊŞKEWTIN"}], "Fridtjof Nansen": [{"text": "Pirên pey xwe hilweşîne, da ji pêşveçûnê pê ve tu çareyeke te nemîne.", "chapter": "PÊŞKEWTIN"}], "Churchill": [{"text": "Ku di navbera duh û îro de şer rû bide, sibe wenda dike.", "chapter": "PÊŞKEWTIN"}], "Berken Bereh": [{"text": "Tenê sê peyv bûn\nferheng\nli welatê min;\nhezkirin, çiya û mirin\nvan bêbavan\nkuştin lê zêde kirin..", "chapter": "PEYV"}], "Zinarê Xamo": [{"text": "Carinan bersîvnedan jî bersîvek e. Çimkî her pirs ne hêjayî bersîvê ye.", "chapter": "PIRS Û BERSIV"}], "Harari": [{"text": "Fêdeya pirsên bê bersiv, ji fêdeya bersivên bê pirs zehftir e.", "chapter": "PIRS Û BERSIV"}], "Herbert Spencer": [{"text": "Nirxê mirovekî, bi nirxê kitêbên ku dixwîne tê pîvandin.", "chapter": "PIRTÛK"}], "Feuerbach": [{"text": "Tu çiqas zêde kitêban nas bikî, ewqasî hejmara kesên derdora te kêm dibe.", "chapter": "PIRTÛK"}], "Diyojen": [{"text": "Kalbûn, zivistana jiyanê ye.", "chapter": "PÎR Û KAL"}], "Gotina Ifrîqîyan": [{"text": "Guh nede şîreta her pîr û kalî. Ma tu nizanî, ehmeq jî pîr û kal dibin!", "chapter": "PÎR Û KAL"}], "Abu AlAtahiya": [{"text": "Xwezî rojekê xortanî li min vegeriyaba; min ê gilîyê kalbûnê li ber bikira.", "chapter": "PÎR Û KAL"}], "Arîstoteles": [{"text": "Mirov pîrozê her tiştî û rezîlê her tiştî ye.", "chapter": "PÎROZÎ"}, {"text": "Ez ji heqîqetê hez dikim, ji Platon jî hez dikim. Ku herdu ji hev veqetin, heqîqet zêdetir layiqê hezkirinê ye.", "chapter": "PÎROZÎ"}, {"text": "Mîna zanayan bifikire, mîna ji rêzêyan biaxive.", "chapter": "RETORÎK"}, {"text": "Sebr tehl e, mêweyê wê şêrîn e.", "chapter": "SEBR"}, {"text": "Sûcên herî mezin, ne ji bo pêdawistîyên sereke; ji bo çavnebarîyên zêde tên kirin.", "chapter": "SÛC Û CEZA"}, {"text": "Ji dêvla ku di nîvê behrê de em li hêviya sekinandina bahoz û pêlan rawestin, divê em li ber bahozên tûnd fêrî vekirina babirkan bibin.", "chapter": "TÊKOŞÎN - XEBAT"}, {"text": "Xwende û nexwende bi qasî mirî û zindîyan ji hev cuda ne.", "chapter": "XWENDIN Û NIVÎSANDIN"}], "Taha Huseyn": [{"text": "Li Rojava ji xeynî ‘mirov’ tiştekî pîroz tuneye; li cem misilmanan ji xeynî mirov, her tişt pîroz e.", "chapter": "PÎROZÎ"}], "Titus Livius": [{"text": "Ger ji bilî çekê ti hêviyek din nemîne, çek pîroz e.", "chapter": "PÎROZÎ"}], "Samuel Johnson": [{"text": "Ku plansazîyeke te tune be, tu yê bibî perçeyek ji plansazîya kesên din.", "chapter": "PLANSAZÎ"}], "Doris Lessing": [{"text": "Hûn dixwazin çi bikin, divê hûn hema vêgavê bikin. Lewra ew şert û mercên hûn li bendê ne, dê qet neyên.", "chapter": "PLANSAZÎ"}], "Henry Clausen": [{"text": "Her mirovê serkeftî xwediyê planekê ye, her mirovî têkçûyî jî xwedîyê hêncetekê ye.", "chapter": "PLANSAZÎ"}], "Ambrose Bierce": [{"text": "Dema tu hêrs bûyî biaxive, tu yê bibînî ku te axaftina herî xweşik a “poşmanîyê” kirîye.", "chapter": "POŞMANÎ"}], "Herakleitos": [{"text": "Di kêliya bextewerîyê de soz nede. Di kêliya hêrsbûnê de bersiv nede. Di kêliya xemgînîyê de biryar nede.", "chapter": "POŞMANÎ"}], "Antoine De SaintExupéry": [{"text": "Mirovên qurre u pozbilind zenn dikin ku her kes heyranê wan e.", "chapter": "POZBILINDÎ"}], "Aisopos": [{"text": "Encama quretî û pozbilindiyê, têkçûn e.", "chapter": "POZBILINDÎ"}], "Baruch Spinoza": [{"text": "Kesê her tim xwe biçûk dibîne, ew herî zêde nêzî quretî û pozbilindîyê ye.", "chapter": "POZBILINDÎ"}], "Firat Aydinkaya": [{"text": "Em ji nivîskarên serdestên xwe îmzayan digirin, lê ji nivîskarên gelê xwe kînê digrin.", "chapter": "QEDR Û QÎMET"}], "Albert Pike": [{"text": "Tiştên em ji bo xwe dikin bi me re dimirin. Tiştên em ji bo mirovên din û dinyayê dikin, heta hetayê dijîn.", "chapter": "QENCÎ Û XERABÎ"}], "Nora Ephron": [{"text": "Berî her tiştî, bibe lehengê jîyana xwe, nebe qurbanîyê wê.", "chapter": "QURBANÎ"}], "Judy Blanco": [{"text": "Nexweş nayên beşên psîkiyatriyê, qurbaniyên nexweşan tên.", "chapter": "QURBANÎ"}], "Søren Kierkegaard": [{"text": "Qurban Îbrahîm bû, an Îshaq?", "chapter": "QURBANÎ"}], "Gloria Steinem": [{"text": "Gelek zarok qurbaniyên dayikbûneke zêde û bavîtiyeke kêm in.", "chapter": "QURBANÎ"}], "L. J. Smith": [{"text": "Min li gor rabirdûya min ne darizîne, êdî ez ne li wir im.", "chapter": "RABIRDÛ Û DAHATÛ"}], "Abraham Cowley": [{"text": "Pêşeroj û paşeroj tune ye. Tenê ‘niha’yeke bêdawî heye.", "chapter": "RABIRDÛ Û DAHATÛ"}], "Kierkegaard": [{"text": "Çenebazîya li ser dahatûyê bêwate ye. Ji ber ku di destê me de tiştekî ku ‘dema niha’ tije bike tuneye.", "chapter": "RABIRDÛ Û DAHATÛ"}, {"text": "Kesê bêzirav û bizdonek ku ti carî xwe navêje talûkeyê, dê ti carî bi ser nekeve.", "chapter": "TIRSONEK"}], "Bob Marley": [{"text": "Rasthatinî destpêkek e. Fînalê tu dileyizî, lê perdeya dawîn ji hêla qederê ve tê girtin.", "chapter": "RASTHATINÎ (TESADÛF)"}], "Don Quijote": [{"text": "Seg direyin Sancho, nexwe em di rêya rast de ne.", "chapter": "RASTÎ Û DIRÛSTÎ"}], "Santosh Kalwar": [{"text": "Her gav wêrek bin. Wek şêrekî bimeşin, wek kevokekê bipeyivin, wek fîlekî bijîn û wek zarokekî hez bikin.", "chapter": "REŞBÎNÎ – XWEŞBÎNÎ"}], "Mihail Lermontov": [{"text": "Hemî bahoz ne ji bo serûbin kirina jiyana me ne, hinek jî rêya me paqij dikin.", "chapter": "REŞBÎNÎ – XWEŞBÎNÎ"}], "John Lennon": [{"text": "Her tişt dê di dawiyê de baş bibe. Heger baş nebûbe, nexwe hê dawî lê nehatiye.", "chapter": "REŞBÎNÎ – XWEŞBÎNÎ"}], "Aldous Huxley": [{"text": "Tu Ji bo destpêkirinê li benda dema herî guncav bisekinî, dibe ku tu qet destpê nekî; vêgavê dest pê bike, ji devera tu niha lê yî û bi tiştên di dest de.", "chapter": "REWŞA ASAYÎ"}, {"text": "Heta niha rûyekî kû bikene û xweşik nebe, min nedîtiye.", "chapter": "RÛKENÎ"}], "José Mauro De Vasconcelos": [{"text": "Dê êşa min çiqasî berdewam bike Portuga?\nHerî zêde 40 roj\npiştî 40 rojî dê biqede?\nNa, tê hîn bibî.", "chapter": "REWŞA ASAYÎ"}], "Cemîl Merîç": [{"text": "Di her sedsalê de tenê çend kes difikirin. Yên mayî jî, wekî wan difikirin.", "chapter": "REWŞENBÎRÎ"}], "Marquis de Condorcet": [{"text": "Civakeke ku şewqa rewşenbîran nede ser, ji hêla fêlbaz û sextekaran ve tê xapandin.", "chapter": "REWŞENBÎRÎ"}], "Grigory Petrov": [{"text": "Li welatekî ku rewşenbîr tirsonek bin, stemkar har in.", "chapter": "REWŞENBÎRÎ"}], "Johannes Kepler": [{"text": "Rexneya zanayekî, ji milyon çepikên nezanan çêtir e.", "chapter": "REXNE"}], "Norman Vincent Peale": [{"text": "Pirsgirêka me gişkan ew e ku, em pesindariyeke kûjer, ji rexnekirineke hişyarker çêtir dibînin.", "chapter": "REXNE"}], "Kant": [{"text": "Mirov ajalekî rexnegir û têkoşer e.", "chapter": "REXNE"}], "Jürgen Habermas": [{"text": "Rizgarkirina neteweyekî ji bin destê desthilatdariyeke dirinde, berztirîn hedefa sîyasî ye.", "chapter": "RIZGARÎ"}, {"text": "Rizgarkirina neteweyekî ji bin destê desthilatdariyeke dirinde, berztirîn hedefa sîyasî ye.", "chapter": "RIZGARÎ"}], "Vladimir Bartol": [{"text": "Keftarekî birçî li beyabanê, ji şêrekî ziktêr ê di qefesê de bextewartir e.", "chapter": "RIZGARÎ"}, {"text": "Tirsonek hezar carî, wêrek carekê dimirin.", "chapter": "TIRSONEK"}], "George R. R. Martin": [{"text": "Ronahî bi tarîtiyê re li hev nayê.", "chapter": "RONAHÎ – TARÎTÎ"}], "Simone de Beauvoir": [{"text": "Kesê dixwaze azad bibe, ber bi rojê ve dimeşe.", "chapter": "RONAHÎ – TARÎTÎ"}], "Chris Cleave": [{"text": "Eger rûyê te bi şilmaqên jiyanê werimî be, bibişire û mîna tu mirovekî qelew î tevbigere.", "chapter": "RÛKENÎ"}], "Schiller": [{"text": "Kesên qîma xwe bi kêzikbûnê tînin, dema di bin pîyan de perçiqîn bila gazinan nekin.", "chapter": "RÛMET"}], "John Haywood": [{"text": "Sebr çîçek e, li hemî bexçeyan şîn nabe.", "chapter": "SEBR"}], "Primo Levi": [{"text": "Tiştinên bi navê cinawir hene. Lê hejmara wan ne di asteke xeternak de ye. Esas kesên xeternak ew mirovên ji rêzê ne ku, xwedîyê zêhniyeteke karker in û bê pirs û sûwal ji bawerkirin û îtaetê re amade ne.", "chapter": "SER TEWANDIN- BÊRÛMETÎ"}], "Alejandro Jodorowsky": [{"text": "Balindeyên di qefesan de dijîn, firrînê wek nexweşiyekê dibînin.", "chapter": "SER TEWANDIN- BÊRÛMETÎ"}], "Edip Yüksel": [{"text": "Kuçik dostên herî baş yên mirovan in, lê mirovên ku dikevin postê kuçikan, gelkî bêrûmet û xayin in.", "chapter": "SER TEWANDIN- BÊRÛMETÎ"}], "Nicolás Gómez Dávila": [{"text": "Bêalîbûn, zaroka bêxîretî û tirsê ye.", "chapter": "SER TEWANDIN- BÊRÛMETÎ"}], "Julian Assange": [{"text": "Her careke ku em li rastî bêdadîyê tên û bêbertek dimînin, em xwe fêrî sertewandinê dikin.", "chapter": "SER TEWANDIN- BÊRÛMETÎ"}], "Spartacus": [{"text": "Serfirazîya herî mezin ew e ku, tu ji vê dinyayê wekî mirovekî azad koç bikî.", "chapter": "SERFIRAZÎ"}], "Chekhov": [{"text": "Serfiraziyên min yên rewşedar tune ne, lê ez dikarim bi têkçûnên xwe yên ku bi saxîtî ji wan filitî me, we şaşwaz bikim.", "chapter": "SERFIRAZÎ"}], "Thomas More": [{"text": "Nikarim xwe kerr bikim, divê ez xwe kerr nekim.", "chapter": "SERHILDAN – BERXWEDAN"}, {"text": "“Qralekî baş çi ye?”\n“Kûçikê şivên e ku destûra gur li kerî nade.”\n“Qralê xirab çi ye?” “Gur bi xwe ye.”", "chapter": "SEROK"}], "Gotina Çerkezan": [{"text": "Ga bi çûna qesrê nabe qral, qesr dibe axur.", "chapter": "SEROK"}], "Neale Donald Walsch": [{"text": "Li ser rêça serok here. Û serok tu yî.", "chapter": "SEROK"}], "James A. Robinson": [{"text": "Rêvever keştî ye, gel derya ye. Derya dikare keştiyê hilgire û dikare keştiyê alabora jî bike.", "chapter": "SEROK"}], "John Steinbeck": [{"text": "Kesê aîdê grubekê ye, mîna malzareke di organîzmayeke biyanî de kesayetiya xwe winda dike.", "chapter": "SERXWEBÛN – XWESERÎ"}, {"text": "Tinazpêkirin, ji lêdanê jî xirabtir e.", "chapter": "TINAZPÊKIRIN"}], "La Fontaine": [{"text": "Sir (nihênî) barê herî giran e. Helal be jî wî kesî re ku dikare hilgire.", "chapter": "SIR Û NEPENÎ"}], "Harry S. Truman": [{"text": "Tu ne dizek bî, tu nikarî bi rêya sîyasetê dewlemend bibî.", "chapter": "SÎYASET – POLÎTÎKA"}], "George Charlin": [{"text": "Hikûmet ji bo karkeran, tenê zîrekîyeke ku têra xebitandina mekîneyan bike, dixwaze.", "chapter": "SÎYASET – POLÎTÎKA"}], "Will Rogers": [{"text": "Dîplomasî ew e ku, tu bi kuçik re lîstikeke xweşik dikî, heta tu kevirekî dibînî ku pê lê bixî.", "chapter": "SÎYASET – POLÎTÎKA"}], "Ehmed Fuad Necm": [{"text": "Rêveber li derveyî welêt perwerde dibe, dema nexweş dikeve li derve tedawî dibe, ji bo betla neyê diçe derveyî welêt. Tiştê tekane ku li hundirê welêt dike, dizîya welêt e.", "chapter": "SÎYASET – POLÎTÎKA"}], "Winston Churchill": [{"text": "Her miletê dinyayê, bi hikûmeteke ku layiqê wê ye tê birêvebirin.", "chapter": "SÎYASET – POLÎTÎKA"}], "Baudlaire": [{"text": "Li vê dinyayê ji her tiştî bêhna sûc tê: Rojname, dîwar, rûyê mirovan...", "chapter": "SÛC Û CEZA"}], "Giordano Bruno": [{"text": "Kî di zeviyên me de xirabiyê biçîne, dê di dawiyê de siza hilberîne.", "chapter": "SÛC Û CEZA"}], "Whoopi Goldberg": [{"text": "Tu dizanî ferqa heqîqî ya di navbera debengî û behremendîyê de çi ye? Ji behremendîyê re sînorek heye, lê debengî bêsînor e.", "chapter": "ŞAREZATÎ Û EHMEQÎ"}], "Cegerxwîn": [{"text": "Pera didin kerê me. Dikin bela serê me.", "chapter": "ŞAREZATÎ Û EHMEQÎ"}], "Stendhal": [{"text": "Welatê min! Tu hê jî di serdema hovîtî û barbarîyê de dijî!", "chapter": "ŞARISTANÎ"}, {"text": "Xembarî, mirov kêmhiş û famkor dike.", "chapter": "XEMGÎNÎ"}], "Cemşîd Bender": [{"text": "Dîroka şaristaniyê bi Kurdan destpê kiriye.", "chapter": "ŞARISTANÎ"}], "Erich From": [{"text": "Şaristanî bi serkêşîyê dest pê kiriye.", "chapter": "ŞARISTANÎ"}], "Jean Christophe": [{"text": "Heger di jîyana te de pirsgirêka hevsengîyê hebe, bala xwe bide derdora xwe. Dibe ku te “kesek” di ciyekî şaş de bi cih kiribe.", "chapter": "ŞAŞÎTÎ – ÇEWTÎ"}], "Alexander Pushkin": [{"text": "Pirî caran sedema hemî çewtiyên mezin quretî ye.", "chapter": "ŞAŞÎTÎ – ÇEWTÎ"}], "Napoleon Hill": [{"text": "Li benda “kêlîya gûncav” nesekine, dê tu carî ew kêlî neyê. Ji ciyê niha tu lê yî destpê bike û bi hemî amûrên di dest xwe de bixebite.", "chapter": "ŞENS – FERSEND"}], "Stephen Hawking": [{"text": "Dibe kû jîyanê lîmonên tirş pêşkêşî we kiribin; lê bêguman hûn dikarin wan jî bi awayekî baş bikar bînin.", "chapter": "ŞENS – FERSEND"}], "Muhemmed Îqbal": [{"text": "Mirov mîna balindeyên li ezmanan hînî firînê bûn, mîna masîyan di deryayê de hînî avjeniyê bûn, lê pêkvejîyana xwe ya mîna însanan li ser erdê jibîr kirin.", "chapter": "ŞER Û AŞTî"}], "Sûhrewerdî Kurdî": [{"text": "Gotinên min şerabeke kevnare ne. Lê gotinên wan, tenê ava fêkî ne.", "chapter": "ŞERAB"}], "Sarah Jio": [{"text": "Ji devera hûn jê hatine, şerm nekin.", "chapter": "ŞERMÎ"}], "Şintaro Tanekawa": [{"text": "Di xewê de şev rastiyê dipistîne guhê me, sibehê em dibêjin me xewn dîtiye.", "chapter": "ŞEV Û ROJ"}], "John Fante": [{"text": "Mirî careke din vedigerin jiyanê? Kitêb “na” dibêjin, şev bi qêrîn dibêjin “erê.”", "chapter": "ŞEV Û ROJ"}], "Eduardo Galeano": [{"text": "Ewqasî kêfa min ji şevê re dihat ku, min dixwest rojê bi betanîyê binixumînim.", "chapter": "ŞEV Û ROJ"}, {"text": "Tu xwarinê bidin feqîran, dibî ezîz. Tu bêjî “çima xwarina feqîran nîne” dibî komûnîst.", "chapter": "ŞOREŞ"}], "Emma Chase": [{"text": "Bi rastî jî şeytan ji mirovên bêhewante re kar derdixe, hûn bi xatirê Xwedê kin, ji bo zarên xwe tiştên baş bibînin bila pê mijûl bibin.", "chapter": "ŞEYTAN"}], "Pyrrhon": [{"text": "Tekane tiştê ez jê goman nakim ew ku, ez ji her tiştî goman dikim.", "chapter": "ŞIK Û GUMAN"}], "George Chapman": [{"text": "Kesên herî zêde şîretan guhdar dikin, herî kêm pabendî wan dibin.", "chapter": "ŞÎRET"}], "Selîm Berekat": [{"text": "Çi fêdeya şîretan heye ji evîndaran re! Hemîyan hişê xwe xwarine û gotinan fêhm nakin.", "chapter": "ŞÎRET"}], "Hipponaks": [{"text": "Guhê xwe bi deyn bide min ez şîretekê lê bikim; dema xwe tortore derbas neke.", "chapter": "ŞÎRET"}], "Mikhail Bakunin": [{"text": "Divê hemî sazî û dezgehên olî, aborî û civakî yên heyî bên rûxandin. Di şûna wan de li ser bingeha azadî, aqil, dadmendî û kedkakarîyê civakeke gerdûnî bête avakirin.", "chapter": "ŞOREŞ"}], "Şêx Mirşid Xeznewî": [{"text": "Baweriya min bi niviştan nayê, min ji bo gelê xwe li daholê da!", "chapter": "ŞOREŞ"}], "Salman Rushdie": [{"text": "Tu bixwazî giloverîya çemberê bibînî, divê tu li derveyî wê bisekinî.", "chapter": "TÊGIHÎŞTIN"}], "Samuel Beckett": [{"text": "Te herdem li ber xwe da, lê tu têk çûyî. Bila be, dîsa li ber xwe bide, dîsa têk biçe. Îcar baştir têk biçe.", "chapter": "TÊKÇÛN – SERKEFTIN"}, {"text": "Kûbarî û duristî bi hev re dimeşin. Ku li ciyekî yek ji wan bi kêr neyê, ya din jî bi kêr nayê.", "chapter": "TÊKILÎ"}], "Selîm Temo": [{"text": "“Têkçûn” tune di ferhenga çiyê de.", "chapter": "TÊKÇÛN – SERKEFTIN"}], "Mandela": [{"text": "Ez ti car têk naçim. An biserdikevim, an jî tiştekî nû hîn dibim.", "chapter": "TÊKÇÛN – SERKEFTIN"}], "Lady Gaga": [{"text": "Nehêle kesek ronîya te vemirîne. Biçirise! Bila tev di ronkayîya te de kor bibin...!", "chapter": "TÊKÇÛN – SERKEFTIN"}], "Elias Canetti": [{"text": "Serketin, ji mirovahiyê re jehra mişkan e;kêm kes jê difilitin.", "chapter": "TÊKÇÛN – SERKEFTIN"}], "Cory Booker": [{"text": "Ji min re qala dînê xwe neke. Bihêle ez wî di liv û tevgerên te de, di têkiliyên te de û di civaka te de bibînim!", "chapter": "TÊKILÎ"}], "Joanne Greenberg": [{"text": "Min dev jê berneda ye, tenê westiya me û hew.", "chapter": "TÊKOŞÎN - XEBAT"}], "Joseph Sobran": [{"text": "Dengbirrîna mirovekî bi zorê, ji bo wî rumet u şanazî ye. Çimkî ev tê wê wateyê ku hûn tekûziya wî li hemberî xwe qebûl dikin.", "chapter": "TEKÛZÎ"}], "David Burns": [{"text": "Ne nûwaze me, ne mecbûr im nûwaze bim jî.", "chapter": "TEKÛZÎ"}], "Salvador Dalí": [{"text": "Ji tekûzîyê netirsin. Ji xwe hûn dê wê qet bidest nexin.", "chapter": "TEKÛZÎ"}], "Publius Vergilius": [{"text": "Temenê meriv her tiştî didize, heta aqilê merivan jî!", "chapter": "TEMEN"}], "Ray Bradbury": [{"text": "Di 17 salîya xwe de tu her tiştî dizanî. Di 27 salîya xwe de tu dîsa her tiştî bizanibî, xûya ye tu hê jî 17 salî yî.", "chapter": "TEMEN"}], "Rabindranath Tagore": [{"text": "Pêkan ji nepêkanîyê pirsî: tu li ku dijî? Nepêkanîyê got; “ez di xewn û xeyalên bêkêran de dijîm.”", "chapter": "TENBELÎ – TIRALÎ"}], "Gotina Norweciyan": [{"text": "Mirov çiqas zexel be, planên wî yên dahatûyê jî zêde ne.", "chapter": "TENBELÎ – TIRALÎ"}], "Elizabeth Gilbert": [{"text": "Bextewarî bi kêferatê tê bidestxistin.", "chapter": "TENBELÎ – TIRALÎ"}], "Jules Payot": [{"text": "Mirovekî tiral, zewqa betlaneyeke heq kirî nizane.", "chapter": "TENBELÎ – TIRALÎ"}], "Gotina Tîbetîyan": [{"text": "Bo temenekî dirêj; Nîvî bixwin, Du qat bireve herin, Sê qat bikenin, Bê sînor hez bikin.", "chapter": "TENDÛRISTÎ"}], "Galenos": [{"text": "Hinar şîfa ye.", "chapter": "TENDÛRISTÎ"}], "Zola": [{"text": "Ev tenêtîya hûn di nav de temirî ne, ne tiştekî baş e. Bawer bikin dê rojek were, hûn dê ji ber vê tenêtîyê janoyî bibin.", "chapter": "TENÊTÎ"}], "Natsume Sosaki": [{"text": "Qehwe bi her kesî re nayê vexwarin. Çimkî qehwe “tenêtî” ye. Kesê tu pê re qehwê vedixwî, bila hêja be ku tu tenêtîya xwe ji bo wî/ê xera dikî.", "chapter": "TENÊTÎ"}], "Ralph Waldo Emerson": [{"text": "Xwedayê mirovxweran dê wekî wan mirovxwer, Xwedayê şerûdan jî şerûd û Xwedayê bazirganan jî dê mîna wan bazirgan be.", "chapter": "TEOLOJÎ"}], "Jiddu Krishnamurti": [{"text": "Mesele ne hebûn û tunebûna Xwedê ye, mesele lêgerîna wî ye.", "chapter": "TEOLOJÎ"}, {"text": "Tirs, nexweşîya herî kevn ya mirovahiyê ye.", "chapter": "TIRS Û ENDÎŞE"}], "Gotina Bolendî": [{"text": "Roviyê ku qala aştiyê dike, bi şev kozikan amade dike.", "chapter": "TEVDîR (BERGIRÎ)"}], "Frank Herbert": [{"text": "Kesên xwe dispêrin şikefteke yek derî, mirinê heq dikin.", "chapter": "TEVDîR (BERGIRÎ)"}], "Gotina Awistralyan": [{"text": "Ji bo tu ji kermêşan xilas bibî, divê tu ewil teqn û çiravan ziwa bikî.", "chapter": "TEVDîR (BERGIRÎ)"}], "Charlie Champbell": [{"text": "Berî her tiştî tewanbarkirin hebû. Ademî Hewwa tewanbar kir, Hewayê mar tewanbar kir û ev tişt heya roja îro didome.", "chapter": "TEWANBARÎ"}], "Kurt Cobain": [{"text": "Kenê xwe bi min dikin, ji ber ku ez naşibim wan. Ez jî bi wan dikenim, ji ber ku tev dişibin hev.", "chapter": "TINAZPÊKIRIN"}], "Mario Puzo": [{"text": "Nehêle kes tinazên xwe bi te bike.", "chapter": "TINAZPÊKIRIN"}], "Gogol": [{"text": "Ne bi bêvileke xaromaro, bi gîyanekî kulek û şapînoz bikenin.", "chapter": "TINAZPÊKIRIN"}], "Gotina Rusan": [{"text": "Tirs, kerê ji hespê bezatir dike.", "chapter": "TIRS Û ENDÎŞE"}], "Adam Fawer": [{"text": "Tenê qedeha ku ji deste min de ket û şikest ferq kirin, lê kesekî ricifandina deste min ferq nekir.", "chapter": "TIRS Û ENDÎŞE"}], "Adnan Selçuk Mızraklı": [{"text": "Tirsnezanên ku tirsê ditirsînin, bersivê didin tirsonekan.", "chapter": "TIRSONEK"}], "Géza Gárdonyi": [{"text": "Çeka Qabîl, çeka herî bi talûke ye.", "chapter": "TUNDÛTÛJÎ"}], "Sabahattin Ali": [{"text": "Li ser vê xakê, tiştekî ji mirin û kuştinê hêsantir tuneye.", "chapter": "TUNDÛTÛJÎ"}], "Martin Heidegger": [{"text": "Ûjdan tenê her timî di halê bêdengîyê de diaxive.", "chapter": "ÛJDAN"}], "Robert Louis Stevenson": [{"text": "Dijminê herî mezin ji bo bêhnvedanê, wujdanekî bêaram e.", "chapter": "ÛJDAN"}, {"text": "Tirsa xwe ji xwe re veşêrin, lê wêrekiya xwe bi herkesî re parve bikin.", "chapter": "WÊREKÎ"}], "Kristin Hannah": [{"text": "Wekî wijdanê herkesî rehet e, kê ewqas dil şikandin?", "chapter": "ÛJDAN"}], "Îbn Arabî": [{"text": "Destê me bigihaşta firqetê, me yê êşa wê pê bida tehm kirin.", "chapter": "VEQETÎN"}], "Yusuf Atılgan": [{"text": "Çiqas derew dihatin kirin le ser rûyê erdê; bi gotinê, bi nivîsê, bi wêneyan, an jî bi bêdengmayinê.", "chapter": "VIR Û DEREW"}], "Agatha Christie": [{"text": "Mirov, ji rastiyan hêsantir baweriya xwe bi derewan tînin.", "chapter": "VIR Û DEREW"}], "Joel D. Anderson": [{"text": "Emerîka gelekî bi siûd e ku reşpîst (çerm reş) tenê doza wekhevîyê dikin, ne ya tolhildanê.", "chapter": "WEKHEVÎ"}], "Spurgеon": [{"text": "Wekhevî! Belê, ez vê têgihê fêhm dikim, lê mînaka wê nabînim.", "chapter": "WEKHEVÎ"}], "Sechu Sende": [{"text": "Dema tu zimanê gelê xwe diaxivî, gelê te berz dibe. Ji ber ku gelê te bi bêjeyên te dijî.", "chapter": "WELATPARÊZÎ- NIŞTIMANPERWERÎ"}], "Eta Nehayî": [{"text": "Vegerîyam da ku segên welatê min li min bireyin.", "chapter": "WELATPARÊZÎ- NIŞTIMANPERWERÎ"}], "Clarence Darrow": [{"text": "Niştimanperwerê rasteqîn ji her deverî bêhtir, ji bêedaletiya welatê xwe nefret dike.", "chapter": "WELATPARÊZÎ- NIŞTIMANPERWERÎ"}], "John Brown": [{"text": "Kesê zik birçî nikare bibe welatparêz.", "chapter": "WELATPARÊZÎ- NIŞTIMANPERWERÎ"}], "Marina Tsvetayeva": [{"text": "Welatparêziya heqîqî ew e ku, tu xemxûrê trajediya gelê xwe bî.", "chapter": "WELATPARÊZÎ- NIŞTIMANPERWERÎ"}], "Emerson": [{"text": "Her tim tiştê tu jê ditirsî, bike.", "chapter": "WÊREKÎ"}], "Joseph Goebbels": [{"text": "Hûn dereweke mezin bikin û seraqet vê derewê dubara bikin, dawiyê xelk dê ji vê derewê bawer bike.", "chapter": "XAPANDIN"}], "Gotina Emerîkiyan": [{"text": "Goristan tije ne bi wan kesên difikirîn ku cîhan bêyî wan nabe.", "chapter": "XAPANDIN"}], "Luvenalis": [{"text": "Mirin, xelata herî dawîn a jiyanê ye.", "chapter": "XELAT"}], "Kurt Vonnegut": [{"text": "Mirovayetî ew e ku; tu qencîyê ne ji bo hêvîya xelat û celata piştî mirinê bikî.", "chapter": "XELAT"}], "Italo Calvin": [{"text": "Tu biçî kuderê, bi embareke tije xem vedigerî.", "chapter": "XEMGÎNÎ"}], "Sàndor Petoti": [{"text": "Xem çî ye?\nDerya ye.\nŞadî?\nDilopek di hembêza wê de.", "chapter": "XEMGÎNÎ"}], "Vladimir Bogomolov": [{"text": "Kesên nearam, bêaramiya kesên din zêdetir hîs dikin.", "chapter": "XEMGÎNÎ"}], "Taha Hussein": [{"text": "Dilhişk razan, dilşikestîyan şeveke bêxew derbas kirin.", "chapter": "XEW - BÊXEWÎ"}], "Johnny Depp": [{"text": "Sê sedemên bingehîn ji bo hêrsbûnê: Birçîbûn, bêxewî û axaftina bi ehmeqan re.", "chapter": "XEW - BÊXEWÎ"}], "S.M. Power": [{"text": "Kintirîn rê bo pêkanîna xewnan, şîyarbûn e.", "chapter": "XEWN Û XEYAL"}], "Gotina Gerdûnî": [{"text": "Tu bixwazî dijmin têk bibî, deh guleyan biteqîne; yek ji bo dijmin, neh ji bo xayinan.", "chapter": "XIYANET"}], "Gotina Îrlendiyan": [{"text": "Kesek bêje, ‘ez wek bira ji te hez dikim’ Habîl û Qabîl bîne bîra xwe.", "chapter": "XIYANET"}], "Gotina Hindûyan": [{"text": "Çawa hezkirin şairan diafirîne, xizanî jî dizan diafirîne.", "chapter": "XIZANÎ – HEJARÎ"}], "Lewis Wallace": [{"text": "Ji Xwedawendan hêrs nebin. Erê, dema em ji fersendên ku wan ji bo me hinartine îstîfade nekin, ew sûcê me ye.", "chapter": "XWEDAWEND"}], "Sophokles": [{"text": "Xwedawendek hat û kumişî ser bajêr. Çirûskên lerzetayeke erjeng reşandin li her derê.", "chapter": "XWEDAWEND"}], "Sylvia Plath": [{"text": "Dinivîsim; ji ber ku nikarim dengê dilê xwe bitepisînim.", "chapter": "XWENDIN Û NIVÎSANDIN"}], "Gotina Maleziyan": [{"text": "Ku bira mil didin hev, çiya dibin zêr.", "chapter": "YEKÎTÎ-TIFAQ- PIŞTGIRÎ"}], "Gotina Filistînîyan": [{"text": "Li şêrên welatê xwe xwedî derkevin; naxwe hûn ê ji kuçikên dijminê xwe re bibin nêçîr.", "chapter": "YEKÎTÎ-TIFAQ- PIŞTGIRÎ"}], "Bakunin": [{"text": "Qanûn, qehpika rayedaran e.", "chapter": "ZAGON"}], "Leonardo da Vinci": [{"text": "Nîgarxêzî zanistek e û hemî zanist xwe dispêrin bîrkarîyê. Tiştên ji destê mirov dertên, ku bingeha xwe ji bîrkarîyê negirin, nabin Zanist.", "chapter": "ZANIST"}], "Ahmet Altan": [{"text": "Civakeke ku huner, zanist û fel sefe lê tune be, Xwedê wê civakê terk dike.", "chapter": "ZANIST"}], "Emile Durkheim": [{"text": "Her çiqasî zanyarî dinyayê ronî bike jî, dawîya dawî dê dilan di tarîtîyê de bihêle. Divê dil ronakbûna xwe bi xwe biafirîne.", "chapter": "ZANYARÎ"}], "Pestalozzi": [{"text": "Her zarokek hunermendek e, û divê wilo bimîne.", "chapter": "ZAROK – ZAROKATÎ"}], "John betjeman (The Boy in the Striped Pyjamas)": [{"text": "Zaroktî berîya ku demjimêra reş a mantiqê were, li gor dengan, bêhnan û dîmenan tê pîvandin.", "chapter": "ZAROK – ZAROKATÎ"}], "Patrick Rothfuss": [{"text": "Roja em dikevin heyra dahatûyê, wê rojê em zaroktîyê li pey xwe dihêlin.", "chapter": "ZAROK – ZAROKATÎ"}], "Gotina Haîtîyan": [{"text": "Zarok ne kuçik in, mezin jî ne xwedawend in.", "chapter": "ZAROK – ZAROKATÎ"}], "Emily Giffin": [{"text": "Kurê min heta bizewice kurê min e. keça min heta mirinê keça min e.", "chapter": "ZEWAC"}], "Edhem Şerqawî": [{"text": "Tu bixwazî dinyayê biguherînî vêya berî zewacê bike. Piştî zewacê tu karibî kenala televîzyonê biguherînî mêrxasê wek te tune ne.", "chapter": "ZEWAC"}], "Suleyman Çevîk": [{"text": "Eger milletek bi zimanê xelkê jihev fêm bike, trajediya mezin ew e!", "chapter": "ZIMAN Û FERHENG"}], "Leibniz": [{"text": "Ziman, neynika mêjî ye.", "chapter": "ZIMAN Û FERHENG"}], "Edward Said": [{"text": "Ziman cebilxaneya hişê mirov e. Di heman demê de hem xenî metên rabirdûyê, hem jî çekên ji bo serkeftinên dahatûyê di xwe de dihewîne.", "chapter": "ZIMAN Û FERHENG"}], "Gotina Abhazyan": [{"text": "Kesê zimanê xwe winda dike, dişibe dara bê kok.", "chapter": "ZIMAN Û FERHENG"}]};
